import{_ as a,c as s,o as e,f as p}from"./plugin-vue_export-helper.ecc8ebe5.js";const o='{"title":"\u041F\u0440\u0430\u0442\u044C\u044F\u0431\u0445\u0438\u0434\u0436\u043D\u044F\u0445\u0440\u0438\u0434\u0430\u044F\u043C","description":"","frontmatter":{"title":"\u041F\u0440\u0430\u0442\u044C\u044F\u0431\u0445\u0438\u0434\u0436\u043D\u044F\u0445\u0440\u0438\u0434\u0430\u044F\u043C","subtitle":"\u0421\u0443\u0449\u043D\u043E\u0441\u0442\u044C \u0443\u0437\u043D\u0430\u0432\u0430\u043D\u0438\u044F","sans":"\u092A\u094D\u0930\u0924\u094D\u092F\u092D\u093F\u091C\u094D\u091E\u093E\u0939\u0943\u0926\u092F\u092E\u094D","trans":"Pratyabhij\xF1\u0101h\u1E5Bdayam","tags":"text","date":"2021-06-07T00:00:00.000Z"},"relativePath":"texts/pratyabhijnya/index.md","lastUpdated":1631200284669}',m={},n=p('<p>\u041F\u0435\u0440\u0435\u0432\u043E\u0434 \u0441 \u0441\u0430\u043D\u0441\u043A\u0440\u0438\u0442\u0430 \u0438 \u043A\u043E\u043C\u043C\u0435\u043D\u0442\u0430\u0440\u0438\u0438 \u0421. \u0412. \u041F\u0430\u0445\u043E\u043C\u043E\u0432\u0430. \u041F\u0435\u0440\u0435\u0432\u043E\u0434 \u043A\u043E\u0440\u0435\u043D\u043D\u043E\u0433\u043E \u0442\u0435\u043A\u0441\u0442\u0430 \u043E\u0442\u043A\u043E\u0440\u0440\u0435\u043A\u0442\u0438\u0440\u043E\u0432\u0430\u043D \u0438 \u0434\u043E\u043F\u043E\u043B\u043D\u0435\u043D \u043D\u0430 \u043E\u0441\u043D\u043E\u0432\u0435 <a href="https://www.sanskrit-sanscrito.com/en/pratyabhijnahrdayam-only-the-20-sutra-s-trika-scriptures-non-dual-shaivism-of-kashmir/541" class="external-link" target="_blank" rel="noopener noreferrer">\u043F\u043E\u0441\u043B\u043E\u0432\u043D\u043E\u0433\u043E \u043F\u0435\u0440\u0435\u0432\u043E\u0434\u0430 \u043D\u0430 \u0430\u043D\u0433\u043B\u0438\u0439\u0441\u043A\u0438\u0439 \u0413\u0443\u0440\u0443 \u0413\u0430\u0431\u0440\u0438\u044D\u043B\u044F \u041F\u0440\u0430\u0434\u0438\u0438\u043F\u0430\u043A\u0438</a>.</p><div class="stanza"><p>\u041E\u043C, \u0441\u043B\u0430\u0432\u0430 [\u0428\u0438\u0432\u0435], \u0432\u043E\u043F\u043B\u043E\u0449\u0435\u043D\u0438\u044E \u0441\u0447\u0430\u0441\u0442\u044C\u044F! \u0418\u0442\u0430\u043A, \u0421\u0443\u0449\u043D\u043E\u0441\u0442\u044C \u0423\u0437\u043D\u0430\u0432\u0430\u043D\u0438\u044F.</p><p class="eng">\u0421\u043B\u0430\u0432\u0430 \u0428\u0438\u0432\u0435, \u0432\u0435\u0447\u043D\u043E \u0441\u043E\u0432\u0435\u0440\u0448\u0430\u044E\u0449\u0435\u043C\u0443 \u043F\u044F\u0442\u044C \u0434\u0435\u044F\u043D\u0438\u0439, [\u0415\u043C\u0443], \u0447\u044C\u044F \u043F\u0440\u0438\u0440\u043E\u0434\u0430 [\u0441\u043E\u0441\u0442\u043E\u0438\u0442] \u0438\u0437 \u0446\u0435\u043B\u043E\u043A\u0443\u043F\u043D\u043E\u0441\u0442\u0438 \u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F \u0438 \u0431\u043B\u0430\u0436\u0435\u043D\u0441\u0442\u0432\u0430, \u0421\u0438\u044F\u044E\u0449\u0435\u043C\u0443 \u0412\u044B\u0441\u0448\u0435\u0439 \u0440\u0435\u0430\u043B\u044C\u043D\u043E\u0441\u0442\u044C\u044E!</p><p class="eng">\u0418\u0437 \u0432\u0435\u043B\u0438\u043A\u043E\u0433\u043E \u043E\u043A\u0435\u0430\u043D\u0430 \u0441\u0430\u043C\u043E\u0443\u0437\u043D\u0430\u0432\u0430\u043D\u0438\u044F \u2013 \u043E\u0441\u043D\u043E\u0432\u044B \u0442\u0430\u0439\u043D\u043E\u0433\u043E \u0443\u0447\u0435\u043D\u0438\u044F \u0428\u0430\u043D\u043A\u0430\u0440\u044B \u2013 \u0418\u0437\u0432\u043B\u0435\u043A \u041A\u0448\u0435\u043C\u0430\u0440\u0430\u0434\u0436\u0430 \u044D\u0441\u0441\u0435\u043D\u0446\u0438\u044E \u0440\u0430\u0434\u0438 \u0438\u0437\u0431\u0430\u0432\u043B\u0435\u043D\u0438\u044F [\u0441\u0443\u0449\u0435\u0441\u0442\u0432] \u043E\u0442 \u044F\u0434\u0430 \u0441\u0430\u043D\u0441\u0430\u0440\u044B. \u0417\u0434\u0435\u0441\u044C, [\u0432 \u044D\u0442\u043E\u043C \u043C\u0438\u0440\u0435,] \u0435\u0441\u0442\u044C \u043D\u0435\u043A\u043E\u0442\u043E\u0440\u044B\u0435 [\u043B\u044E\u0434\u0438], \u043A\u043E\u0442\u043E\u0440\u044B\u0435, [\u0445\u043E\u0442\u044F \u043E\u043D\u0438 \u0438] \u043D\u0435 \u0443\u043C\u0435\u044E\u0442 \u043C\u044B\u0441\u043B\u0438\u0442\u044C \u0441\u0442\u0440\u043E\u0433\u043E \u0438 \u043D\u0435 \u043C\u043E\u0433\u0443\u0442 \u0440\u0430\u0437\u043E\u0431\u0440\u0430\u0442\u044C\u0441\u044F \u0432 \u0442\u043E\u043D\u043A\u043E\u0441\u0442\u044F\u0445 \u043B\u043E\u0433\u0438\u0447\u0435\u0441\u043A\u043E\u0433\u043E \u043F\u043E\u0437\u043D\u0430\u043D\u0438\u044F, \u043D\u0430\u0434\u0435\u043B\u0435\u043D\u044B \u0433\u043B\u0443\u0431\u043E\u043A\u0438\u043C \u0431\u043B\u0430\u0433\u043E\u0447\u0435\u0441\u0442\u0438\u0435\u043C \u0438 \u0436\u0435\u043B\u0430\u044E\u0442 \u0441\u0442\u0430\u0442\u044C \u0435\u0434\u0438\u043D\u044B\u043C\u0438 \u0441 \u0412\u0435\u0440\u0445\u043E\u0432\u043D\u044B\u043C \u0413\u043E\u0441\u043F\u043E\u0434\u043E\u043C \u0447\u0435\u0440\u0435\u0437 \u043D\u0438\u0441\u0445\u043E\u0436\u0434\u0435\u043D\u0438\u0435 \u0428\u0430\u043A\u0442\u0438.\u0414\u043B\u044F \u043D\u0438\u0445 \u0438 \u0438\u0437\u043B\u0430\u0433\u0430\u0435\u0442\u0441\u044F \u0432\u043A\u0440\u0430\u0442\u0446\u0435 \u0438\u0441\u0442\u0438\u043D\u0430 \u0423\u0437\u043D\u0430\u0432\u0430\u043D\u0438\u044F \u0411\u043E\u0433\u0430. \u0427\u0442\u043E\u0431\u044B \u043F\u043E\u043A\u0430\u0437\u0430\u0442\u044C, [\u043F\u043E\u0447\u0435\u043C\u0443] \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u043D\u0430\u044F \u043F\u0440\u0438\u0440\u043E\u0434\u0430 \u0411\u043E\u0436\u0435\u0441\u0442\u0432\u0430 [\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] \u0443\u043D\u0438\u0432\u0435\u0440\u0441\u0430\u043B\u044C\u043D\u043E\u0439 \u043F\u0440\u0438\u0447\u0438\u043D\u043E\u0439, [\u043A\u0430\u043A\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C \u043E\u043D\u0430] \u043B\u0435\u0433\u043A\u043E \u0434\u043E\u0441\u0442\u0438\u0433\u0430\u0435\u0442\u0441\u044F, [\u043F\u043E\u0447\u0435\u043C\u0443 \u043E\u043D\u0430 \u0435\u0441\u0442\u044C] \u0432\u0435\u043B\u0438\u043A\u0438\u0439 \u043F\u043B\u043E\u0434, \u0433\u043E\u0432\u043E\u0440\u0438\u0442\u0441\u044F:</p></div><div class="stanza"><a href="#s1" id="s1" class="num">1</a><p class="sans">\u091A\u093F\u0924\u093F\u0903 \u0938\u094D\u0935\u0924\u0928\u094D\u0924\u094D\u0930\u093E \u0935\u093F\u0936\u094D\u0935\u0938\u093F\u0926\u094D\u0927\u093F\u0939\u0947\u0924\u0941\u0903 \u0965\u0967\u0965</p><p class="trans">Citi\u1E25 svatantr\u0101 vi\u015Bvasiddhihetu\u1E25 \u09651\u0965</p><p>\u0421\u0430\u043C\u043E\u0435\u0441\u0442\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u0430\u044F <em>(svatantr\u0101)</em> \u0421\u0438\u043B\u0430 \u0410\u0431\u0441\u043E\u043B\u044E\u0442\u043D\u043E\u0433\u043E \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F <em>(citi\u1E25)</em> \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u043F\u0440\u0438\u0447\u0438\u043D\u043E\u0439 <em>(hetu\u1E25)</em> \u0440\u0435\u0430\u043B\u0438\u0437\u0430\u0446\u0438\u0438 <em>(siddhi)</em> \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u043E\u0439 <em>(vi\u015Bva)</em>.</p><p class="eng"><strong>\u041A\u043E\u043C\u043C\u0435\u043D\u0442\u0430\u0440\u0438\u0439</strong><br> [\u0421\u043B\u043E\u0432\u043E] \xAB\u0432\u0441\u0435\u043B\u0435\u043D\u043D\u0430\u044F\xBB \u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442 [\u0441\u043E\u0432\u043E\u043A\u0443\u043F\u043D\u043E\u0441\u0442\u044C \u044D\u043B\u0435\u043C\u0435\u043D\u0442\u043E\u0432], \u043E\u0442 \u0421\u0430\u0434\u0430\u0448\u0438\u0432\u044B \u0434\u043E \u0437\u0435\u043C\u043B\u0438. \xAB\u0420\u0435\u0430\u043B\u0438\u0437\u0430\u0446\u0438\u044F\xBB \u2013 \u044D\u0442\u043E \xAB\u0438\u0441\u043F\u043E\u043B\u043D\u0435\u043D\u0438\u0435\xBB, \u0442. \u0435. \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u0435 [\u043C\u0438\u0440\u0430], \u0441\u043E\u0445\u0440\u0430\u043D\u0435\u043D\u0438\u0435 [\u0435\u0433\u043E] \u0438 \u0443\u043D\u0438\u0447\u0442\u043E\u0436\u0435\u043D\u0438\u0435, \u0443\u0441\u043F\u043E\u043A\u043E\u0435\u043D\u0438\u0435 [\u0435\u0433\u043E] \u0432 \u0412\u044B\u0441\u0448\u0435\u043C \u0421\u0443\u0431\u044A\u0435\u043A\u0442\u0435. \xAB\u0421\u0438\u043B\u0430 \u0410\u0431\u0441\u043E\u043B\u044E\u0442\u043D\u043E\u0433\u043E \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F\xBB \u2013 \u0444\u043E\u0440\u043C\u0430 \u0412\u0435\u0440\u0445\u043E\u0432\u043D\u043E\u0439 \u0428\u0430\u043A\u0442\u0438 \u043A\u0430\u043A \u0411\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439 \u044D\u043D\u0435\u0440\u0433\u0438\u0438, \u0438 \u0441\u043E\u0441\u0442\u043E\u0438\u0442 [\u044D\u0442\u0430 \u0421\u0438\u043B\u0430] \u0438\u0437 \u043D\u0430\u0438\u0432\u044B\u0441\u0448\u0435\u0439 \u0432\u0438\u043C\u0430\u0440\u0448\u0438, [\u043A\u043E\u0442\u043E\u0440\u0430\u044F] \u043D\u0435 \u043E\u0442\u0434\u0435\u043B\u0438\u043C\u0430 \u043E\u0442 \u0411\u043B\u0430\u0433\u043E\u0441\u043B\u043E\u0432\u0435\u043D\u043D\u043E\u0433\u043E \u0428\u0438\u0432\u044B \u0438 \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \xAB\u043F\u0440\u0438\u0447\u0438\u043D\u043E\u0439\xBB, \u0438\u0441\u0442\u043E\u0447\u043D\u0438\u043A\u043E\u043C [\u0440\u0435\u0430\u043B\u0438\u0437\u0430\u0446\u0438\u0438 \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u043E\u0439]. \u0418\u043C\u0435\u043D\u043D\u043E \u043A\u043E\u0433\u0434\u0430 \u041E\u043D\u0430 \u0440\u0430\u0437\u0432\u0435\u0440\u0442\u044B\u0432\u0430\u0435\u0442\u0441\u044F, \u043C\u0438\u0440 \u0432\u043E\u0437\u043D\u0438\u043A\u0430\u0435\u0442 \u0438 \u0441\u043E\u0445\u0440\u0430\u043D\u044F\u0435\u0442\u0441\u044F, \u0430 \u043A\u043E\u0433\u0434\u0430 \u041E\u043D\u0430 \u0441\u0432\u043E\u0440\u0430\u0447\u0438\u0432\u0430\u0435\u0442\u0441\u044F, \u043E\u043D \u043F\u0440\u043E\u043F\u0430\u0434\u0430\u0435\u0442 \u0438\u0437 \u0432\u0438\u0434\u0443. \u041B\u0438\u0447\u043D\u044B\u0439 \u0437\u0440\u0438\u0442\u0435\u043B\u044C\u043D\u044B\u0439 \u043E\u043F\u044B\u0442 \u043C\u043E\u0436\u0435\u0442 \u043F\u043E\u0434\u0442\u0432\u0435\u0440\u0434\u0438\u0442\u044C \u044D\u0442\u043E. \u0414\u0440\u0443\u0433\u0438\u0435 [\u043D\u0430\u0447\u0430\u043B\u0430] \u2013 \u043C\u0430\u0439\u044F, \u043F\u0440\u0430\u043A\u0440\u0438\u0442\u0438 \u0438 \u0442. \u0434. \u2013 \u043D\u0435 \u043C\u043E\u0433\u0443\u0442 \u044F\u0432\u043B\u044F\u0442\u044C\u0441\u044F [\u0433\u043B\u0430\u0432\u043D\u044B\u043C] \u0438\u0441\u0442\u043E\u0447\u043D\u0438\u043A\u043E\u043C, \u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u043E\u043D\u0438 [\u043F\u0440\u0435\u0434\u043F\u043E\u043B\u0430\u0433\u0430\u044E\u0442\u0441\u044F] \u043E\u0442\u0434\u0435\u043B\u0435\u043D\u043D\u044B\u043C\u0438 \u043E\u0442 \u0421\u0432\u0435\u0442\u0430 \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F, [\u043D\u043E \u0432\u0435\u0434\u044C \u0442\u043E, \u0447\u0442\u043E] \u043E\u0442\u0434\u0435\u043B\u0435\u043D\u043E \u043E\u0442 \u044D\u0442\u043E\u0433\u043E \u0421\u0432\u0435\u0442\u0430, \u043D\u0435 \u043C\u043E\u0436\u0435\u0442 \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u043E\u0432\u0430\u0442\u044C. \u041F\u0440\u043E\u044F\u0432\u0438\u0442\u044C\u0441\u044F \u043C\u043E\u0436\u0435\u0442 \u0442\u043E\u043B\u044C\u043A\u043E \u0442\u043E, \u0447\u0442\u043E \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0435\u0434\u0438\u043D\u044B\u043C \u0441\u043E \u0421\u0432\u0435\u0442\u043E\u043C \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F.[\u0422\u0430\u043A\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C,] \u0442\u043E\u043B\u044C\u043A\u043E \u0427\u0438\u0442\u0438, \u0438\u043C\u0435\u044E\u0449\u0430\u044F \u0444\u043E\u0440\u043C\u0443 \u0421\u0432\u0435\u0442\u0430 \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F, \u0438 \u0435\u0441\u0442\u044C [\u044D\u0442\u0430] \u043F\u0440\u0438\u0447\u0438\u043D\u0430, \u0438 \u043D\u0438\u0447\u0442\u043E \u0434\u0440\u0443\u0433\u043E\u0435. \u041F\u043E\u044D\u0442\u043E\u043C\u0443 \u043F\u0440\u043E\u0441\u0442\u0440\u0430\u043D\u0441\u0442\u0432\u043E, \u0432\u0440\u0435\u043C\u044F \u0438 [\u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u0430\u044F] \u0444\u043E\u0440\u043C\u0430, \u0431\u0443\u0434\u0443\u0447\u0438 \u0441\u043E\u0437\u0434\u0430\u043D\u044B \u0438 \u043E\u0436\u0438\u0432\u043B\u0435\u043D\u044B \u044D\u0442\u043E\u0439 [\u0421\u0438\u043B\u043E\u0439 \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F], \u043D\u0435 \u0441\u043F\u043E\u0441\u043E\u0431\u043D\u044B \u0440\u0430\u0437\u0434\u0435\u043B\u0438\u0442\u044C [\u0441 \u041D\u0435\u0439] \u0415\u0435 \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u044C, \u0442\u043E\u0433\u0434\u0430 \u043A\u0430\u043A \u041E\u043D\u0430 \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0432\u0441\u0435\u043F\u0440\u043E\u043D\u0438\u043A\u0430\u044E\u0449\u0435\u0439, \u0432\u0435\u0447\u043D\u043E\u0439, \u043D\u0430\u0434\u0435\u043B\u0435\u043D\u043D\u043E\u0439 \u043D\u0430\u0438\u0432\u044B\u0441\u0448\u0435\u0439 \u043F\u043E\u043B\u043D\u043E\u0442\u043E\u0439. \u0422\u0430\u043A\u043E\u0432 \u0441\u043C\u044B\u0441\u043B c\u043A\u0430\u0437\u0430\u043D\u043D\u043E\u0433\u043E.</p><p class="eng">\u041C\u043E\u0433\u0443\u0442 \u0432\u043E\u0437\u0440\u0430\u0437\u0438\u0442\u044C: \u0415\u0441\u043B\u0438 \u043C\u0438\u0440 \u043D\u0435 \u043E\u0442\u0434\u0435\u043B\u0435\u043D \u043E\u0442 \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F, \u0442\u043E \u0442\u043E\u0433\u0434\u0430 \u043D\u0438\u0447\u0435\u0433\u043E \u043D\u0435 \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0443\u0435\u0442 [\u043F\u043E\u043C\u0438\u043C\u043E \u041D\u0435\u0433\u043E]. \u0410 \u0440\u0430\u0437 [\u043C\u0438\u0440] \u043D\u0435 \u043E\u0442\u0434\u0435\u043B\u0435\u043D, \u043A\u0430\u043A \u0442\u043E\u0433\u0434\u0430 [\u0432\u043E\u0437\u043C\u043E\u0436\u043D\u044B] \u043F\u0440\u0438\u0447\u0438\u043D\u043D\u043E-\u0441\u043B\u0435\u0434\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u0435 \u043E\u0442\u043D\u043E\u0448\u0435\u043D\u0438\u044F [\u043C\u0435\u0436\u0434\u0443 \u043D\u0438\u043C\u0438]?</p><p class="eng">[\u041E\u0442\u0432\u0435\u0442]: \u0442\u043E\u043B\u044C\u043A\u043E \u0421\u0438\u043B\u0430 \u0411\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0433\u043E \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F, \u043F\u043E \u0441\u0432\u043E\u0435\u043C\u0443 \u0436\u0435\u043B\u0430\u043D\u0438\u044E, \u0441\u043E\u0432\u0435\u0440\u0448\u0435\u043D\u043D\u043E \u0441\u0432\u043E\u0431\u043E\u0434\u043D\u043E \u043F\u0440\u043E\u044F\u0432\u043B\u044F\u0435\u0442 \u0441\u0435\u0431\u044F \u0432 \u0444\u043E\u0440\u043C\u0435 \u0431\u0435\u0441\u0447\u0438\u0441\u043B\u0435\u043D\u043D\u044B\u0445 \u043C\u0438\u0440\u043E\u0432. \u0422\u0430\u043A\u043E\u0432 \u0432\u044B\u0441\u0448\u0438\u0439 \u0441\u043C\u044B\u0441\u043B \u043F\u0440\u0438\u0447\u0438\u043D\u043D\u043E-\u0441\u043B\u0435\u0434\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u0445 \u043E\u0442\u043D\u043E\u0448\u0435\u043D\u0438\u0439. \u041F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 [\u0421\u0438\u043B\u0430 \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F] \u043E\u0434\u043D\u0430 \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u043F\u0440\u0438\u0447\u0438\u043D\u043E\u0439 \u0440\u0435\u0430\u043B\u0438\u0437\u0430\u0446\u0438\u0438, \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u044F \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u043E\u0439, [\u043F\u043E\u0434\u0440\u0430\u0437\u0434\u0435\u043B\u044F\u044E\u0449\u0435\u0439\u0441\u044F \u043D\u0430] \u0441\u0443\u0431\u044A\u0435\u043A\u0442, \u0438\u0441\u0442\u043E\u0447\u043D\u0438\u043A \u0438 \u043E\u0431\u044A\u0435\u043A\u0442 \u043F\u043E\u0437\u043D\u0430\u043D\u0438\u044F, \u0442\u043E \u0415\u0435, \u0430\u0431\u0441\u043E\u043B\u044E\u0442\u043D\u0443\u044E, \u0431\u0435\u0437\u0433\u0440\u0430\u043D\u0438\u0447\u043D\u0443\u044E, \u0441\u0430\u043C\u043E\u0441\u0432\u0435\u0442\u044F\u0449\u0443\u044E\u0441\u044F, \u043D\u0435\u0432\u043E\u0437\u043C\u043E\u0436\u043D\u043E \u0443\u0445\u0432\u0430\u0442\u0438\u0442\u044C \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u044B\u043C\u0438 \u0441\u0440\u0435\u0434\u0441\u0442\u0432\u0430\u043C\u0438 \u043F\u043E\u0437\u043D\u0430\u043D\u0438\u044F, \u0441 \u043F\u043E\u043C\u043E\u0449\u044C\u044E \u043A\u043E\u0442\u043E\u0440\u044B\u0445 [\u043C\u043E\u0436\u043D\u043E \u0440\u0430\u0437\u0432\u0435 \u0447\u0442\u043E] \u043F\u043E\u0441\u0442\u0438\u0433\u0430\u0442\u044C \u0432\u043D\u0435\u0448\u043D\u0438\u0435 \u043E\u0431\u044A\u0435\u043A\u0442\u044B.</p><p class="eng">\u0422\u0430\u043A \u0433\u043E\u0432\u043E\u0440\u0438\u0442\u0441\u044F \u0432 \u0422\u0440\u0438\u043A\u0430\u0441\u0430\u0440\u0435: \xAB\u041F\u043E\u0434\u043E\u0431\u043D\u043E \u0442\u043E\u043C\u0443, \u043A\u0430\u043A \u043F\u0440\u0438 \u043F\u043E\u043F\u044B\u0442\u043A\u0435 \u043F\u0435\u0440\u0435\u043F\u0440\u044B\u0433\u043D\u0443\u0442\u044C \u0442\u0435\u043D\u044C \u043E\u0442 \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439 \u0433\u043E\u043B\u043E\u0432\u044B [\u043D\u0435\u0432\u043E\u0437\u043C\u043E\u0436\u043D\u043E \u0443\u0445\u0432\u0430\u0442\u0438\u0442\u044C \u044D\u0442\u0443] \u0442\u0435\u043D\u044C, [\u043A\u043E\u0442\u043E\u0440\u0430\u044F] \u0432\u0441\u0435 \u0432\u0440\u0435\u043C\u044F \u0431\u0443\u0434\u0435\u0442 \u043F\u0435\u0440\u0435\u0434\u0432\u0438\u0433\u0430\u0442\u044C\u0441\u044F \u0434\u0430\u043B\u044C\u0448\u0435, [\u043D\u0435\u0432\u043E\u0437\u043C\u043E\u0436\u043D\u043E \u0443\u0445\u0432\u0430\u0442\u0438\u0442\u044C] \u0438 \u0421\u0438\u043B\u0443 \u0423\u043D\u0438\u0432\u0435\u0440\u0441\u0430\u043B\u044C\u043D\u043E\u0433\u043E \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F \xBB. \u041F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u041E\u043D\u0430 (\u0421\u0438\u043B\u0430 \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F \u2013 \u0421. \u041F.) \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0438\u0441\u0442\u043E\u0447\u043D\u0438\u043A\u043E\u043C \u043C\u0430\u043D\u0438\u0444\u0435\u0441\u0442\u0430\u0446\u0438\u0438 \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u043E\u0439, \u0430 \u0442\u0430\u043A\u0436\u0435 [\u043F\u0440\u0438\u0447\u0438\u043D\u043E\u0439 \u0435\u0435] \u0443\u043D\u0438\u0447\u0442\u043E\u0436\u0435\u043D\u0438\u044F, [\u0431\u043B\u0430\u0433\u043E\u0434\u0430\u0440\u044F \u043A\u043E\u0442\u043E\u0440\u043E\u043C\u0443] \u0434\u043E\u0441\u0442\u0438\u0433\u0430\u0435\u0442\u0441\u044F \u0441\u043E\u0435\u0434\u0438\u043D\u0435\u043D\u0438\u0435 \u0441 \u0432\u044B\u0441\u0448\u0435\u0439 \u043D\u0435\u0434\u0432\u043E\u0439\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0441\u0442\u044C\u044E, \u0415\u0435 [\u043D\u0430\u0437\u044B\u0432\u0430\u044E\u0442] \u0441\u0430\u043C\u043E\u0435\u0441\u0442\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439. \u041A\u043E\u0433\u0434\u0430 \u0415\u0435 \u0443\u0437\u043D\u0430\u044E\u0442 \u043A\u0430\u043A \u0441\u0430\u043C\u043E\u0435\u0441\u0442\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u0443\u044E, \u0442\u043E [\u0432\u0438\u0434\u044F\u0442 \u0432 \u043D\u0435\u0439] \u043F\u0440\u0438\u0447\u0438\u043D\u0443 \u0440\u0435\u0430\u043B\u0438\u0437\u0430\u0446\u0438\u0438 \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u043E\u0439 \u0432 \u0444\u043E\u0440\u043C\u0435 \u043D\u0430\u0441\u043B\u0430\u0436\u0434\u0435\u043D\u0438\u044F \u0438 \u043E\u0441\u0432\u043E\u0431\u043E\u0436\u0434\u0435\u043D\u0438\u044F. \u0422\u0430\u043A \u0432\u0442\u043E\u0440\u0438\u0447\u043D\u043E \u043C\u043E\u0436\u043D\u043E \u0438\u0441\u0442\u043E\u043B\u043A\u043E\u0432\u0430\u0442\u044C \u044D\u0442\u0443 \u0441\u0443\u0442\u0440\u0443. \u0414\u0430\u043B\u0435\u0435, [\u0441\u043B\u043E\u0432\u043E] \xAB\u0432\u0441\u0435\u043B\u0435\u043D\u043D\u0430\u044F\xBB [\u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442 \u0432\u043D\u0435\u0448\u043D\u0438\u0435 \u043E\u0431\u044A\u0435\u043A\u0442\u044B, \u043D\u0430\u043F\u0440\u0438\u043C\u0435\u0440,] \u0433\u043E\u043B\u0443\u0431\u043E\u0439 [\u0446\u0432\u0435\u0442], [\u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0438\u0435, \u043D\u0430\u043F\u0440\u0438\u043C\u0435\u0440,] \u0443\u0434\u043E\u0432\u043E\u043B\u044C\u0441\u0442\u0432\u0438\u0435, [\u0430 \u0442\u0430\u043A\u0436\u0435] \u0442\u0435\u043B\u043E, \u043F\u0440\u0430\u043D\u0443 \u0438 \u0442. \u043F. \u0420\u0435\u0430\u043B\u0438\u0437\u0430\u0446\u0438\u044F \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u043E\u0439, \u0441\u043E\u0441\u0442\u043E\u044F\u0449\u0430\u044F \u0432 \u043F\u043E\u0441\u0442\u0435\u043F\u0435\u043D\u043D\u043E\u043C \u0432\u043E\u0437\u0432\u044B\u0448\u0435\u043D\u0438\u0438 \u043E\u0442 [\u0441\u0442\u0443\u043F\u0435\u043D\u0438] \u0438\u0441\u0442\u043E\u0447\u043D\u0438\u043A\u0430 \u043F\u043E\u0437\u043D\u0430\u043D\u0438\u044F \u0434\u043E [\u0441\u0442\u0443\u043F\u0435\u043D\u0438] \u043F\u043E\u0433\u0440\u0443\u0436\u0435\u043D\u0438\u044F \u0432 [\u0412\u044B\u0441\u0448\u0435\u0433\u043E] \u0441\u043E\u0437\u043D\u0430\u044E\u0449\u0435\u0433\u043E \u0441\u0443\u0431\u044A\u0435\u043A\u0442\u0430, \u0438\u043C\u0435\u044E\u0449\u0435\u0433\u043E \u0444\u043E\u0440\u043C\u0443 \u0432\u0438\u043C\u0430\u0440\u0448\u0438 \u2013 [\u0442\u0430\u043A\u0430\u044F \u0440\u0435\u0430\u043B\u0438\u0437\u0430\u0446\u0438\u044F \u0441\u0443\u0442\u044C] \u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E [\u0434\u043E\u0441\u0442\u0438\u0436\u0435\u043D\u0438\u044F] \u0432\u044B\u0441\u0448\u0435\u0433\u043E \u0437\u043D\u0430\u043D\u0438\u044F. \u0418\u043C\u0435\u0435\u0442\u0441\u044F \u0432 \u0432\u0438\u0434\u0443 \xAB\u043B\u0435\u0433\u043A\u043E\u0435 \u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\xBB.</p><p class="eng">\u041A\u0430\u043A \u0433\u043E\u0432\u043E\u0440\u0438\u0442 \u0412\u0438\u0434\u0436\u043D\u044F\u043D\u0430\u0431\u0445\u0430\u0442\u0442\u0430\u0440\u0430\u043A\u0430, \xAB\u0412\u0441\u0435 \u0442\u0435\u043B\u0435\u0441\u043D\u044B\u0435 \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0430 \u043D\u0430\u0434\u0435\u043B\u0435\u043D\u044B \u0437\u043D\u0430\u043D\u0438\u0435\u043C \u0441\u0443\u0431\u044A\u0435\u043A\u0442\u0430 \u0438 \u043E\u0431\u044A\u0435\u043A\u0442\u0430, \u043D\u043E \u0442\u043E\u043B\u044C\u043A\u043E \u0439\u043E\u0433\u0438\u043D\u044B \u043C\u043E\u0433\u0443\u0442 \u0432\u043E\u0441\u043F\u0440\u0438\u043D\u0438\u043C\u0430\u0442\u044C \u0438\u0445 \u0432 \u0435\u0434\u0438\u043D\u0441\u0442\u0432\u0435\xBB. [\u0422\u0435\u0440\u043C\u0438\u043D] \xAB\u0421\u0438\u043B\u0430 \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F\xBB, [\u0443\u043F\u043E\u0442\u0440\u0435\u0431\u043B\u0435\u043D\u043D\u044B\u0439 \u0432 \u0441\u0443\u0442\u0440\u0435] \u0432 \u0435\u0434\u0438\u043D\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u043C \u0447\u0438\u0441\u043B\u0435, \u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442 \u043D\u0435 \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u043E\u0441\u0442\u044C \u043F\u0440\u043E\u0441\u0442\u0440\u0430\u043D\u0441\u0442\u0432\u043E\u043C, \u0432\u0440\u0435\u043C\u0435\u043D\u0435\u043C \u0438 \u0442. \u0434., [\u0438 \u044D\u0442\u043E] \u0434\u0435\u043C\u043E\u043D\u0441\u0442\u0440\u0438\u0440\u0443\u0435\u0442 \u043B\u043E\u0436\u043D\u043E\u0441\u0442\u044C \u0432\u0441\u0435\u0445 \u0434\u0443\u0430\u043B\u0438\u0441\u0442\u0438\u0447\u0435\u0441\u043A\u0438\u0445 \u0443\u0447\u0435\u043D\u0438\u0439.</p><p class="eng">\u0422\u0435\u0440\u043C\u0438\u043D \xAB\u0441\u0430\u043C\u043E\u0435\u0441\u0442\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u0430\u044F\xBB, \u043E \u043A\u043E\u0442\u043E\u0440\u043E\u043C \u043D\u0435 \u0437\u043D\u0430\u0435\u0442 \u0443\u0447\u0435\u043D\u0438\u0435 \u043E \u0411\u0440\u0430\u0445\u043C\u0430\u043D\u0435, \u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442 \u0442\u043E, \u0447\u0442\u043E \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u044C\u044E \u0412\u0435\u043B\u0438\u043A\u043E\u0433\u043E \u0413\u043E\u0441\u043F\u043E\u0434\u0430 \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u0435. \xAB\u0412\u0441\u0435\u043B\u0435\u043D\u043D\u0430\u044F\xBB \u0438 \u0442. \u0434. \u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442, \u0447\u0442\u043E [\u0421\u043E\u0437\u043D\u0430\u043D\u0438\u0435] \u043D\u0430\u0434\u0435\u043B\u0435\u043D\u043E \u0431\u0435\u0437\u0433\u0440\u0430\u043D\u0438\u0447\u043D\u043E\u0439 \u0441\u0438\u043B\u043E\u0439, \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u043F\u0440\u0438\u0447\u0438\u043D\u043E\u0439 \u0432\u0441\u0435\u0433\u043E, \u043B\u0435\u0433\u043A\u0438\u043C \u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C [\u0434\u043E\u0441\u0442\u0438\u0436\u0435\u043D\u0438\u044F \u043E\u0441\u0432\u043E\u0431\u043E\u0436\u0434\u0435\u043D\u0438\u044F] \u0438 \u0432\u0435\u043B\u0438\u043A\u043E\u0439 \u043D\u0430\u0433\u0440\u0430\u0434\u043E\u0439.</p><p class="eng">\u041D\u0430 \u044D\u0442\u043E \u0432\u043E\u0437\u0440\u0430\u0437\u044F\u0442: \u0415\u0441\u043B\u0438 \u0421\u0438\u043B\u0430 \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u043F\u0440\u0438\u0447\u0438\u043D\u043E\u0439 \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u043E\u0439, \u0442\u043E \u044D\u0442\u043E \u043F\u0440\u0435\u0434\u0443\u0441\u043C\u0430\u0442\u0440\u0438\u0432\u0430\u0435\u0442 \u043C\u0430\u0442\u0435\u0440\u0438\u0430\u043B\u044C\u043D\u0443\u044E \u043F\u0440\u0438\u0447\u0438\u043D\u0443 \u0438 \u0442. \u043F., \u0447\u0442\u043E \u043E\u0441\u0442\u0430\u0432\u043B\u044F\u0435\u0442 \u0434\u0443\u0430\u043B\u0438\u0437\u043C \u0432 \u0441\u0438\u043B\u0435. \u0412 [\u043E\u0442\u0432\u0435\u0442\u0435] \u043D\u0430 \u044D\u0442\u043E \u0432\u043E\u0437\u0440\u0430\u0436\u0435\u043D\u0438\u0435 \u0433\u043E\u0432\u043E\u0440\u0438\u0442\u0441\u044F:</p></div><div class="stanza"><a href="#s2" id="s2" class="num">2</a><p class="sans">\u0938\u094D\u0935\u0947\u091A\u094D\u091B\u092F\u093E \u0938\u094D\u0935\u092D\u093F\u0924\u094D\u0924\u094C \u0935\u093F\u0936\u094D\u0935\u092E\u0941\u0928\u094D\u092E\u0940\u0932\u092F\u0924\u093F \u0965\u0968\u0965</p><p class="trans">Svecchay\u0101 svabhittau vi\u015Bvamunm\u012Blayati \u09652\u0965</p><p>\u041F\u043E \u0441\u0432\u043E\u0435\u0439 <em>(sva)</em> \u0432\u043E\u043B\u0435 <em>(icchay\u0101)</em>, \u043D\u0430 \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439 <em>(sva)</em> \u043F\u043E\u0432\u0435\u0440\u0445\u043D\u043E\u0441\u0442\u0438 <em>(bhittau)</em>, [\u0421\u0438\u043B\u0430 \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F] \u0440\u0430\u0437\u0432\u043E\u0440\u0430\u0447\u0438\u0432\u0430\u0435\u0442 <em>(unm\u012Blayati)</em> \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u0443\u044E <em>(vi\u015Bvam)</em>.</p><p class="eng"><strong>\u041A\u043E\u043C\u043C\u0435\u043D\u0442\u0430\u0440\u0438\u0439</strong><br> \xAB\u041F\u043E \u0441\u0432\u043E\u0435\u0439 \u0432\u043E\u043B\u0435\xBB \u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442, \u0447\u0442\u043E [\u044D\u0442\u043E \u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u0438\u0442] \u043D\u0435 \u043F\u043E \u0432\u043E\u043B\u0435 \u0434\u0440\u0443\u0433\u043E\u0433\u043E, \u043A\u0430\u043A \u043F\u043E\u043B\u0430\u0433\u0430\u044E\u0442 \u0441\u0442\u043E\u0440\u043E\u043D\u043D\u0438\u043A\u0438 \u0443\u0447\u0435\u043D\u0438\u044F \u043E \u0411\u0440\u0430\u0445\u043C\u0430\u043D\u0435 \u0438 \u0438\u043C \u043F\u043E\u0434\u043E\u0431\u043D\u044B\u0435; \u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442 [\u0442\u0430\u043A\u0436\u0435, \u0447\u0442\u043E \u041E\u043D\u0430 \u043F\u0440\u043E\u0438\u0437\u0432\u043E\u0434\u0438\u0442 \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u0443\u044E \u0441\u0430\u043C\u0430, \u0430] \u043D\u0435 \u0441 \u043F\u043E\u043C\u043E\u0448\u044C\u044E \u043C\u0430\u0442\u0435\u0440\u0438\u0430\u043B\u044C\u043D\u043E\u0439 \u043F\u0440\u0438\u0447\u0438\u043D\u044B \u0438 \u0442. \u0434. \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u0435 \u043D\u0435 \u043C\u043E\u0436\u0435\u0442 \u0444\u0443\u043D\u043A\u0446\u0438\u043E\u043D\u0438\u0440\u043E\u0432\u0430\u0442\u044C, \u0435\u0441\u043B\u0438 \u043D\u0435 \u043E\u0431\u043B\u0430\u0434\u0430\u0435\u0442 \u0432\u044B\u0448\u0435\u043D\u0430\u0437\u0432\u0430\u043D\u043D\u044B\u043C [\u0430\u0441\u043F\u0435\u043A\u0442\u043E\u043C] \u0441\u0430\u043C\u043E\u0435\u0441\u0442\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0441\u0442\u0438.</p><p class="eng">\xAB\u041D\u0430 \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439 \u043F\u043E\u0432\u0435\u0440\u0445\u043D\u043E\u0441\u0442\u0438\xBB \u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442, \u0447\u0442\u043E \u044D\u0442\u043E \u043D\u0435 \u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u0438\u0442 \u043D\u0438\u0433\u0434\u0435 \u0431\u043E\u043B\u044C\u0448\u0435. \u041E\u043D\u0430 [\u0427\u0438\u0442\u0438] \xAB\u0434\u0435\u043B\u0430\u0435\u0442 \u0432\u0438\u0434\u0438\u043C\u043E\u0439\xBB \u0432\u044B\u0448\u0435\u0443\u043F\u043E\u043C\u044F\u043D\u0443\u0442\u0443\u044E \xAB\u0432\u0441\u0435\u043B\u0435\u043D\u043D\u0443\u044E\xBB, \u043A\u0430\u043A, [\u043D\u0430\u043F\u0440\u0438\u043C\u0435\u0440] \u0433\u043E\u0440\u043E\u0434 [\u0434\u0435\u043B\u0430\u0435\u0442\u0441\u044F \u0432\u0438\u0434\u0438\u043C\u044B\u043C] \u0432 \u0437\u0435\u0440\u043A\u0430\u043B\u0435, [\u0438 \u043E\u0442\u0440\u0430\u0436\u0435\u043D\u0438\u0435 \u044D\u0442\u043E\u0433\u043E \u0433\u043E\u0440\u043E\u0434\u0430], \u0445\u043E\u0442\u044F \u0438 \u043D\u0435 \u043E\u0442\u043B\u0438\u0447\u043D\u043E\u0435 [\u043E\u0442 \u0437\u0435\u0440\u043A\u0430\u043B\u044C\u043D\u043E\u0439 \u043F\u043E\u0432\u0435\u0440\u0445\u043D\u043E\u0441\u0442\u0438], \u0432\u0441\u0435 \u0436\u0435 [\u0432\u044B\u0433\u043B\u044F\u0434\u0438\u0442] \u043A\u0430\u043A \u043E\u0442\u043B\u0438\u0447\u043D\u043E\u0435 [\u043E\u0442 \u043D\u0435\u0433\u043E]. [\u0427\u0438\u0442\u0438 \u043A\u0430\u043A] \u043F\u0440\u0438\u0447\u0438\u043D\u0430 \u043C\u0430\u043D\u0438\u0444\u0435\u0441\u0442\u0430\u0446\u0438\u0438 [\u0432\u0441\u0435\u043B\u0435\u043D\u043D\u043E\u0439] \u0434\u0435\u043B\u0430\u0435\u0442 \u0435\u0435 \u0432\u0438\u0434\u0438\u043C\u043E\u0439 \u0438 \u0441\u0442\u0430\u0431\u0438\u043B\u044C\u043D\u043E\u0439.</p><p class="eng">\u0421\u043C\u044B\u0441\u043B \u0441\u043A\u0430\u0437\u0430\u043D\u043D\u043E\u0433\u043E \u0442\u0430\u043A\u043E\u0432: \u043C\u0438\u0440 \u0438\u0434\u0435\u043D\u0442\u0438\u0447\u0435\u043D \u0421\u0432\u0435\u0442\u0443 \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F. \u0414\u043B\u044F \u0442\u043E\u0433\u043E, \u0447\u0442\u043E\u0431\u044B \u043F\u0440\u043E\u044F\u0441\u043D\u0438\u0442\u044C \u0432 \u0434\u0435\u0442\u0430\u043B\u044F\u0445 \u043F\u0440\u0438\u0440\u043E\u0434\u0443 \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u043E\u0439, [\u0430\u0432\u0442\u043E\u0440] \u0433\u043E\u0432\u043E\u0440\u0438\u0442:</p></div><div class="stanza"><a href="#s3" id="s3" class="num">3</a><p class="sans">\u0924\u0928\u094D\u0928\u093E\u0928\u093E\u0928\u0941\u0930\u0942\u092A\u0917\u094D\u0930\u093E\u0939\u094D\u092F\u0917\u094D\u0930\u093E\u0939\u0915\u092D\u0947\u0926\u093E\u0924\u094D \u0965\u0969\u0965</p><p class="trans">Tann\u0101n\u0101nur\u016Bpagr\u0101hyagr\u0101hakabhed\u0101t \u09653\u0965</p><p>\u041E\u043D\u0430 <em>(tad)</em> \u043C\u043D\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u0430 <em>(n\u0101n\u0101)</em> \u0438\u0437-\u0437\u0430 \u0434\u0438\u0444\u0444\u0435\u0440\u0435\u043D\u0446\u0438\u0430\u0446\u0438\u0438 <em>(bhed\u0101t)</em> \u043D\u0430 \u0441\u043E\u043E\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0443\u044E\u0449\u0438\u0435 <em>(anur\u016Bpa)</em> \u0441\u0443\u0431\u044A\u0435\u043A\u0442\u044B <em>(gr\u0101haka)</em> \u0438 \u043E\u0431\u044A\u0435\u043A\u0442\u044B <em>(gr\u0101hya)</em> .</p><p class="eng"><strong>\u041A\u043E\u043C\u043C\u0435\u043D\u0442\u0430\u0440\u0438\u0439</strong><br> \xAB\u041E\u043D\u0430\xBB \u2013 \u044D\u0442\u043E \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u0430\u044F. \xAB\u041C\u043D\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u0430\xBB \u2013 [\u0442. \u0435. \u0438\u043C\u0435\u0435\u0442] \u043F\u0440\u0438\u0440\u043E\u0434\u0443 \u0438\u043D\u043E\u0433\u043E. \u041F\u043E\u0447\u0435\u043C\u0443 [\u043C\u043D\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u0430]? \u041F\u043E\u0442\u043E\u043C\u0443 \u0447\u0442\u043E \u0435\u0441\u0442\u044C \u0440\u0430\u0437\u043B\u0438\u0447\u0438\u0435, \xAB\u0434\u0438\u0444\u0444\u0435\u0440\u0435\u043D\u0446\u0438\u0430\u0446\u0438\u044F\xBB \u043C\u0435\u0436\u0434\u0443 \xAB\u0441\u0443\u0431\u044A\u0435\u043A\u0442\u0430\u043C\u0438 \u0438 \u043E\u0431\u044A\u0435\u043A\u0442\u0430\u043C\u0438\xBB, \u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u043D\u0430\u0445\u043E\u0434\u044F\u0442\u0441\u044F \u0432 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0438 \xAB\u0441\u043E\u043E\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0438\u044F\xBB [\u043C\u0435\u0436\u0434\u0443 \u0441\u043E\u0431\u043E\u0439], \u0442. \u0435. \u0432\u0437\u0430\u0438\u043C\u043D\u043E \u0441\u043E\u043E\u0442\u043D\u0435\u0441\u0435\u043D\u044B. \u041D\u0430 \u0441\u0442\u0443\u043F\u0435\u043D\u0438 \u0441\u0430\u0434\u0430\u0448\u0438\u0432\u0430, \u0433\u0434\u0435 \u0434\u043E\u043C\u0438\u043D\u0438\u0440\u0443\u0435\u0442 \u0441\u043E\u0432\u0435\u0440\u0448\u0435\u043D\u0441\u0442\u0432\u043E \u042F \u0438 \u043E\u0431\u044A\u0435\u043A\u0442\u043D\u043E\u0441\u0442\u044C \u0432 \u0435\u0435 \u043F\u043E\u043B\u043D\u043E\u0442\u0435 [\u0435\u0449\u0435] \u043D\u0435 \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0430, \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u0430\u044F \u043A\u0430\u043A \u043E\u0431\u044A\u0435\u043A\u0442 \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0438 \u043E\u0442\u043B\u0438\u0447\u043D\u043E\u0439, \u0438 \u043D\u0435 \u043E\u0442\u043B\u0438\u0447\u043D\u043E\u0439 [\u043E\u0442 \u042F], \u0438 \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u0435\u0442 \u0442\u0430\u043C (\u043D\u0430 \u044D\u0442\u043E\u0439 \u0441\u0442\u0443\u043F\u0435\u043D\u0438 \u2013 \u0421. \u041F.) \u0440\u0430\u0437\u0440\u044F\u0434 \u0441\u043E\u0437\u043D\u0430\u044E\u0449\u0438\u0445 \u0441\u0443\u0431\u044A\u0435\u043A\u0442\u043E\u0432, \u043D\u0430\u0437\u044B\u0432\u0430\u0435\u043C\u044B\u0445 \u043C\u0430\u043D\u0442\u0440\u0430\u043C\u0430\u0445\u0435\u0448\u0432\u0430\u0440\u0430\u043C\u0438, \u0437\u0430\u0432\u0438\u0441\u044F\u0449\u0438\u0445 \u043E\u0442 \u0411\u043B\u0430\u0433\u043E\u0441\u043B\u043E\u0432\u0435\u043D\u043D\u043E\u0433\u043E \u0412\u0435\u0447\u043D\u043E\u0433\u043E \u0428\u0438\u0432\u044B.</p><p class="eng">\u0421\u0432\u043E\u0438\u043C \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u043E\u0432\u0430\u043D\u0438\u0435\u043C \u043E\u043D\u0438 \u043E\u0431\u044F\u0437\u0430\u043D\u044B \u0432\u043E\u043B\u0435 \u0412\u0435\u0440\u0445\u043E\u0432\u043D\u043E\u0433\u043E \u0413\u043E\u0441\u043F\u043E\u0434\u0430. \u041D\u0430 \u0441\u0442\u0443\u043F\u0435\u043D\u0438 \u0438\u0448\u0432\u0430\u0440\u0430 \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u0430\u044F \u043F\u043E\u043D\u0438\u043C\u0430\u0435\u0442\u0441\u044F \u043A\u0430\u043A [\u0441\u043E\u0434\u0435\u0440\u0436\u0430\u0449\u0430\u044F] \u0440\u0430\u0437\u043B\u0438\u0447\u0438\u0435 \u043C\u0435\u0436\u0434\u0443 \u043F\u043E\u043B\u043D\u043E\u0442\u043E\u0439 \u042F \u0438 \u043D\u0435-\u042F, [\u0445\u043E\u0442\u044F \u042F \u0438 \u043D\u0435-\u042F \u043F\u0440\u043E\u0434\u043E\u043B\u0436\u0430\u044E\u0442 \u043D\u0430\u0445\u043E\u0434\u0438\u0442\u044C\u0441\u044F] \u0432 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0438 \u0438\u0434\u0435\u043D\u0442\u0438\u0447\u043D\u043E\u0441\u0442\u0438 [\u0434\u0440\u0443\u0433 \u0441 \u0434\u0440\u0443\u0433\u043E\u043C]; \u0438 \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u0435\u0442 \u0442\u0430\u043C \u0440\u0430\u0437\u0440\u044F\u0434 \u043C\u0430\u043D\u0442\u0440\u0435\u0448\u0432\u0430\u0440, \u043F\u043E\u043A\u043E\u0440\u043D\u044B\u0445 \u0432\u043E\u043B\u0435 \u0411\u043E\u0433\u0430-\u0422\u0432\u043E\u0440\u0446\u0430. \u041D\u0430 \u0443\u0440\u043E\u0432\u043D\u0435 \u0432\u0438\u0434\u044C\u044F \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u044E\u0442 \u0441\u0443\u0431\u044A\u0435\u043A\u0442\u044B \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u043D\u0438\u044F, [\u043D\u0430\u0437\u044B\u0432\u0430\u0435\u043C\u044B\u0435] \u043C\u0430\u043D\u0442\u0440\u0430\u043C\u0438, \u0438\u043C\u0438 \u0443\u043F\u0440\u0430\u0432\u043B\u044F\u0435\u0442 \u0411\u043B\u0430\u0433\u043E\u0441\u043B\u043E\u0432\u0435\u043D\u043D\u044B\u0439 \u0410\u043D\u0430\u043D\u0442\u0430, \u0438 \u043C\u043D\u043E\u0433\u0438\u043C \u0432\u0438\u0434\u0430\u043C \u0440\u0430\u0437\u043D\u044B\u0445 \u043F\u043E\u0434\u0440\u0430\u0437\u0434\u0435\u043B\u0435\u043D\u0438\u0439 [\u044D\u0442\u0438\u0445 \u043C\u0430\u043D\u0442\u0440] \u0441\u043E\u043E\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0443\u0435\u0442 \u043E\u0431\u044A\u0435\u043A\u0442 \u0437\u043D\u0430\u043D\u0438\u044F \u0432 \u0444\u043E\u0440\u043C\u0435 \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u043E\u0439, \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u044C \u043A\u043E\u0442\u043E\u0440\u043E\u0439 [\u043D\u0430 \u044D\u0442\u043E\u0439 \u0441\u0442\u0443\u043F\u0435\u043D\u0438] \u0441\u043E\u0441\u0442\u043E\u0438\u0442 \u0432 \u0440\u0430\u0437\u0434\u0435\u043B\u0435\u043D\u0438\u0438 \u0435\u0434\u0438\u043D\u043E\u0433\u043E. \u041D\u0430\u0434 [\u0441\u0442\u0443\u043F\u0435\u043D\u044C\u044E] \u043C\u0430\u0439\u0438 [\u043F\u0440\u0435\u0431\u044B\u0432\u0430\u044E\u0442 \u0441\u0443\u0431\u044A\u0435\u043A\u0442\u044B, \u043D\u0430\u0437\u044B\u0432\u0430\u0435\u043C\u044B\u0435] \u0432\u0438\u0434\u0436\u043D\u044F\u043D\u0430\u043A\u0430\u043B\u044B; \u0443 \u043D\u0438\u0445 \u043D\u0435\u0442 [\u0441\u0442\u0440\u0435\u043C\u043B\u0435\u043D\u0438\u044F] \u043A \u0434\u0435\u044F\u0442\u0435\u043B\u044C\u043D\u043E\u0441\u0442\u0438, \u0430 \u0435\u0441\u0442\u044C \u043F\u0440\u0438\u0440\u043E\u0434\u0430 \u0447\u0438\u0441\u0442\u043E\u0433\u043E \u0441\u043E\u0437\u043D\u0430\u0432\u0430\u043D\u0438\u044F. \u041E\u0431\u044A\u0435\u043A\u0442 [\u043F\u043E\u0437\u043D\u0430\u043D\u0438\u044F] \u043D\u0435 \u043E\u0442\u043B\u0438\u0447\u0435\u043D \u043E\u0442 \u043D\u0438\u0445 \u0438 \u0441\u043E\u0441\u0442\u043E\u0438\u0442 \u0432 \u043E\u043F\u044B\u0442\u0435 \u043F\u0435\u0440\u0435\u0436\u0438\u0432\u0430\u043D\u0438\u044F [\u0438\u043C\u0438] \u043F\u0440\u043E\u0448\u043B\u044B\u0445 \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u043E\u0432\u0430\u043D\u0438\u0439, \u0432\u043E \u0432\u0440\u0435\u043C\u044F \u043A\u043E\u0442\u043E\u0440\u044B\u0445 \u043E\u043D\u0438 \u043D\u0430\u0445\u043E\u0434\u0438\u043B\u0438\u0441\u044C \u043D\u0430 \u0441\u0442\u0443\u043F\u0435\u043D\u044F\u0445 \u0441\u0430\u043A\u0430\u043B\u0430 \u0438 \u043F\u0440\u0430\u043B\u0430\u044F\u043A\u0430\u043B\u0430. \u041D\u0430 \u0441\u0442\u0443\u043F\u0435\u043D\u0438 \u043C\u0430\u0439\u044F \u043D\u0430\u0445\u043E\u0434\u044F\u0442\u0441\u044F \u0441\u0443\u0431\u044A\u0435\u043A\u0442\u044B, \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u044E\u0449\u0438\u0435 \u043F\u0443\u0441\u0442\u043E\u0442\u0443, \u0438\u043B\u0438 \xAB\u043E\u0441\u0432\u043E\u0431\u043E\u0434\u0438\u0432\u0448\u0438\u0435\u0441\u044F \u043E\u0442 \u043F\u0440\u0430\u043B\u0430\u0438\xBB; \u0438\u043C \u0441\u043E\u043E\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0443\u0435\u0442 \u0432 \u043A\u0430\u0447\u0435\u0441\u0442\u0432\u0435 \u043E\u0431\u044A\u0435\u043A\u0442\u0430 \u0442\u043E, \u0447\u0442\u043E \u043D\u0435 \u0432\u043E\u0441\u043F\u0440\u0438\u043D\u0438\u043C\u0430\u0435\u0442\u0441\u044F \u0447\u0443\u0432\u0441\u0442\u0432\u0430\u043C\u0438. [\u0414\u0430\u043B\u0435\u0435], \u0432\u043F\u043B\u043E\u0442\u044C \u0434\u043E [\u044D\u043B\u0435\u043C\u0435\u043D\u0442\u0430] \u0437\u0435\u043C\u043B\u0438 \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u044E\u0442 \u043E\u0442\u0434\u0435\u043B\u0435\u043D\u043D\u044B\u0435 \u043E\u0442 \u0432\u0441\u0435\u0445 \u0432\u0435\u0449\u0435\u0439, \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u044B\u0435 \u0441\u0430\u043A\u0430\u043B\u044B, \u0438 \u0438\u043C [\u0432 \u043E\u043F\u044B\u0442\u0435] \u0441\u043E\u043E\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0443\u044E\u0442 \u0442\u0430\u043A\u0438\u0435 \u0436\u0435 [\u0438\u0437\u043E\u043B\u0438\u0440\u043E\u0432\u0430\u043D\u043D\u044B\u0435] \u043E\u0431\u044A\u0435\u043A\u0442\u044B. \u041D\u0430\u0434 \u0432\u0441\u0435\u043C \u0436\u0435 \u044D\u0442\u0438\u043C [\u0440\u0430\u0441\u043F\u043E\u043B\u0430\u0433\u0430\u044E\u0442\u0441\u044F] \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0430, \u043A\u043E\u0442\u043E\u0440\u044B\u0445 \u043D\u0430\u043F\u0440\u0430\u0432\u043B\u044F\u0435\u0442 \u0411\u043B\u0430\u0433\u043E\u0441\u043B\u043E\u0432\u0435\u043D\u043D\u044B\u0439 \u0428\u0438\u0432\u0430 \u0438 \u043F\u043B\u043E\u0442\u044C \u043A\u043E\u0442\u043E\u0440\u044B\u0445 \u0441\u0443\u0442\u044C \u0442\u043E\u043B\u044C\u043A\u043E \u0447\u0438\u0441\u0442\u044B\u0439 \u0441\u0432\u0435\u0442. \u041D\u043E \u0438\u043C\u0435\u043D\u043D\u043E \u0432 \u044D\u0442\u043E\u043C \u0432\u0435\u043B\u0438\u043A\u043E\u043C \u041F\u0430\u0440\u0430\u043C\u0430\u0448\u0438\u0432\u0435, [\u043E\u0434\u043D\u043E\u0432\u0440\u0435\u043C\u0435\u043D\u043D\u043E] \u0438 \u0442\u0440\u0430\u043D\u0441\u0446\u0435\u043D\u0434\u0435\u043D\u0442\u043D\u043E\u043C, \u0438 \u0438\u043C\u043C\u0430\u043D\u0435\u043D\u0442\u043D\u043E\u043C \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u043E\u0439, \u043D\u0430\u0434\u0435\u043B\u0435\u043D\u043D\u043E\u043C \u0432\u044B\u0441\u0448\u0438\u043C \u0431\u043B\u0430\u0436\u0435\u043D\u0441\u0442\u0432\u043E\u043C, \u0441\u043E\u0441\u0442\u043E\u044F\u0449\u0435\u043C \u0438\u0437 \u0441\u0432\u0435\u0442\u043E\u0432\u043E\u0439 \u043C\u0430\u0441\u0441\u044B, \u043F\u0440\u043E\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F, \u043D\u0435 \u043E\u0442\u0434\u0435\u043B\u044F\u044F\u0441\u044C [\u043E\u0442 \u041D\u0435\u0433\u043E], \xAB\u0432\u0441\u0435\xBB [\u0432 \u043C\u0438\u0440\u0435], \u043D\u0430\u0447\u0438\u043D\u0430\u044F [\u043E\u0442 \u0442\u0430\u0442\u0442\u0432\u044B] \u0428\u0438\u0432\u0430 \u0438 \u0437\u0430\u043A\u0430\u043D\u0447\u0438\u0432\u0430\u044F [\u0442\u0430\u0442\u0442\u0432\u043E\u0439] \u0437\u0435\u043C\u043B\u044F. \u0412 \u0440\u0435\u0430\u043B\u044C\u043D\u043E\u0441\u0442\u0438 \u043D\u0435\u0442 \u043D\u0438\u043A\u0430\u043A\u043E\u0433\u043E \u0440\u0430\u0437\u043B\u0438\u0447\u0438\u044F \u043C\u0435\u0436\u0434\u0443 \u0441\u0445\u0432\u0430\u0442\u044B\u0432\u0430\u044E\u0449\u0438\u043C \u0438 \u0441\u0445\u0432\u0430\u0442\u044B\u0432\u0430\u0435\u043C\u044B\u043C; \u0442\u0435\u043C \u043D\u0435 \u043C\u0435\u043D\u0435\u0435, \u0411\u043B\u0430\u0433\u043E\u0441\u043B\u043E\u0432\u0435\u043D\u043D\u044B\u0439 \u0428\u0440\u0438 \u041F\u0430\u0440\u0430\u043C\u0430\u0448\u0438\u0432\u0430 \u043C\u0430\u043D\u0438\u0444\u0435\u0441\u0442\u0438\u0440\u0443\u0435\u0442\u0441\u044F \u0432 \u0442\u044B\u0441\u044F\u0447\u0430\u0445 \u0440\u0430\u0437\u043D\u043E\u043E\u0431\u0440\u0430\u0437\u043D\u044B\u0445 [\u0444\u043E\u0440\u043C]. \u0422\u0430\u043A \u044D\u0442\u043E \u0434\u043E\u043B\u0436\u043D\u043E \u0431\u044B\u0442\u044C \u043F\u043E\u043D\u044F\u0442\u043E.</p></div><div class="stanza"><a href="#s4" id="s4" class="num">4</a><p class="sans">\u091A\u093F\u0924\u093F\u0938\u0919\u094D\u0915\u094B\u091A\u093E\u0924\u094D\u092E\u093E \u091A\u0947\u0924\u0928\u094B\u093D\u092A\u093F \u0938\u0919\u094D\u0915\u0941\u091A\u093F\u0924\u0935\u093F\u0936\u094D\u0935\u092E\u092F\u0903 \u0965\u096A\u0965</p><p class="trans">Citisa\u1E45koc\u0101tm\u0101 cetano&#39;pi sa\u1E45kucitavi\u015Bvamaya\u1E25 \u09654\u0965</p><p>\u041E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u0430\u044F <em>(sa\u1E45kucita)</em> \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u0430\u044F \u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u0441\u044F \u0442\u0435\u043B\u043E\u043C <em>(vi\u015Bva-maya\u1E25)</em> \u0410\u0431\u0441\u043E\u043B\u044E\u0442\u043D\u043E\u0433\u043E \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F <em>(citi)</em>, \u0442\u0430\u043A\u0436\u0435 <em>(api)</em> \u0441\u0436\u0430\u0442\u043E\u0433\u043E <em>(sa\u1E45koca-\u0101tm\u0101)</em> \u0434\u043E \u0412\u044B\u0441\u0448\u0435\u0433\u043E \u0440\u0430\u0437\u0443\u043C\u0430 <em>(cetana\u1E25)</em>.</p><p class="eng"><strong>\u041A\u043E\u043C\u043C\u0435\u043D\u0442\u0430\u0440\u0438\u0439</strong><br> \u041A\u043E\u0433\u0434\u0430 \u0428\u0440\u0438 \u041F\u0430\u0440\u0430\u043C\u0430\u0448\u0438\u0432\u0430 \u0436\u0435\u043B\u0430\u0435\u0442 \u043F\u0440\u043E\u044F\u0432\u0438\u0442\u044C \u0441\u043E\u0434\u0435\u0440\u0436\u0430\u0449\u0443\u044E\u0441\u044F \u0432 \u043D\u0435\u043C \u0438 \u0438\u0434\u0435\u043D\u0442\u0438\u0447\u043D\u0443\u044E \u0435\u043C\u0443 \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u0443\u044E \u2013 \u0432 \u0444\u043E\u0440\u043C\u0435 \u0412\u0435\u0447\u043D\u043E\u0433\u043E \u0428\u0438\u0432\u044B \u0438 \u0434\u0440\u0443\u0433\u0438\u0445 \u0441\u043E\u043E\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0443\u044E\u0449\u0438\u0445 \u0444\u043E\u0440\u043C\u0430\u0445 \u2013 \u043E\u043D \u043F\u0440\u043E\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0432 [\u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u043C] \u0421\u0432\u0435\u0442\u0435 \u0441\u043D\u0430\u0447\u0430\u043B\u0430 \u043A\u0430\u043A \u043D\u0435\u0441\u043E\u0437\u043D\u0430\u044E\u0449\u0438\u0439 \u0435\u0434\u0438\u043D\u0441\u0442\u0432\u043E \u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F, \u0442. \u0435. \u043A\u0430\u043A \u0410\u043D\u0430\u0448\u0440\u0438\u0442\u0430-\u0428\u0438\u0432\u0430.</p><p class="eng">\u042D\u0442\u043E [\u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435] \u0430\u0431\u0441\u043E\u043B\u044E\u0442\u043D\u043E\u0439 \u043F\u0443\u0441\u0442\u043E\u0442\u044B, [\u043D\u043E \u043E\u043D\u043E \u0432\u0441\u0435 \u0436\u0435] \u043D\u0435\u043E\u0442\u0434\u0435\u043B\u0438\u043C\u043E \u043E\u0442 \u0421\u0432\u0435\u0442\u0430 \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F. \u0417\u0430\u0442\u0435\u043C \u043E\u043D \u0440\u0430\u0441\u043A\u0440\u044B\u0432\u0430\u0435\u0442 \u0441\u0432\u043E\u044E \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u044C \u0432\u043E \u043C\u043D\u043E\u0436\u0435\u0441\u0442\u0432\u0435 \u043C\u0430\u043D\u0438\u0444\u0435\u0441\u0442\u0430\u0446\u0438\u0439: \u043F\u0440\u0438\u043D\u0446\u0438\u043F\u0430\u0445, \u043C\u0438\u0440\u0430\u0445, \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u044F\u0445, [\u0430 \u0442\u0430\u043A\u0436\u0435] \u0432 \u0441\u043E\u043E\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0443\u044E\u0449\u0438\u0445 \u0438\u043C \u0441\u0443\u0431\u044A\u0435\u043A\u0442\u0430\u0445. [\u0412\u0441\u0435 \u043E\u043D\u0438] \u2013 \u0442\u043E\u043B\u044C\u043A\u043E \u0437\u0430\u0442\u0432\u0435\u0440\u0434\u0435\u0432\u0448\u0438\u0435 \u0444\u043E\u0440\u043C\u044B \u043A\u0432\u0438\u043D\u0442\u044D\u0441\u0441\u0435\u043D\u0446\u0438\u0438 \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F. \u041F\u043E\u0434\u043E\u0431\u043D\u043E \u0442\u043E\u043C\u0443, \u043A\u0430\u043A \u0442\u0435\u043B\u043E\u043C \u0411\u0445\u0430\u0433\u0430\u0432\u0430\u043D\u0430 \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u0430\u044F, \u0442\u0430\u043A \u0438 \u0442\u0435\u043B\u043E\u043C \xAB\u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u043E\u0433\u043E \u0441\u0443\u0431\u044A\u0435\u043A\u0442\u0430\xBB, \u0438\u043C\u0435\u044E\u0449\u0435\u0433\u043E \xAB\u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u043E\u0435 \u0441\u043E\u0437\u043D\u0430\u043D\u0438\u0435\xBB, \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u0430\u044F \u0444\u043E\u0440\u043C\u0430 \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u043E\u0439, \u043F\u043E\u0434\u043E\u0431\u043D\u043E \u0442\u043E\u043C\u0443, \u043A\u0430\u043A [\u0434\u0435\u0440\u0435\u0432\u043E] \u0432\u0430\u0442\u0430 [\u0432 \u0441\u0436\u0430\u0442\u043E\u043C \u0432\u0438\u0434\u0435] \u0441\u043E\u0434\u0435\u0440\u0436\u0438\u0442\u0441\u044F \u0432 \u0441\u0435\u043C\u0435\u043D\u0438.</p><p class="eng">\u0422\u0430\u043A \u0433\u043E\u0432\u043E\u0440\u0438\u0442\u0441\u044F \u0432 \u0421\u0438\u0434\u0434\u0445\u0430\u043D\u0442\u0435: \xAB\u041E\u0434\u043D\u043E \u0442\u0435\u043B\u043E, \u043E\u0434\u043D\u0430 \u0444\u043E\u0440\u043C\u0430 \u0441\u0443\u0442\u044C \u0432\u0441\u0435 \u0442\u0435\u043B\u0430, \u0432\u0441\u0435 \u0444\u043E\u0440\u043C\u044B\xBB. \u0422\u0430\u043A\u0436\u0435 \u0432 \u0422\u0440\u0438\u0448\u0438\u0440\u043E\u043C\u0430\u0442\u0435, [\u043A\u043E\u0442\u043E\u0440\u0430\u044F \u043D\u0430\u0447\u0438\u043D\u0430\u0435\u0442\u0441\u044F \u0442\u0430\u043A]: \xAB\u0412 \u0442\u0435\u043B\u0435 \u0441\u043E\u0434\u0435\u0440\u0436\u0430\u0442\u0441\u044F \u0432\u0441\u0435 \u0431\u043E\u0436\u0435\u0441\u0442\u0432\u0430; \u043F\u043E\u0441\u043B\u0443\u0448\u0430\u0439 \u043E\u0431 \u044D\u0442\u043E\u043C, \u0434\u043E\u0440\u043E\u0433\u0430\u044F. \u0417\u0435\u043C\u043B\u044F \u043D\u0430\u0437\u044B\u0432\u0430\u0435\u0442\u0441\u044F [\u0442\u0430\u043A] \u0438\u0437-\u0437\u0430 [\u0441\u0432\u043E \u0435\u0439] \u0442\u0432\u0435\u0440\u0434\u043E\u0441\u0442\u0438, \u0432\u043E\u0434\u0430 \u2013 \u0442\u0435\u043A\u0443\u0447\u0435\u0441\u0442\u0438\u2026\xBB, \u0438 \u0437\u0430\u043A\u0430\u043D\u0447\u0438\u0432\u0430\u0435\u0442\u0441\u044F [\u0441\u043B\u0435\u0434\u0443\u044E\u0449\u0438\u043C]: \xAB\u0422\u0440\u0435\u0445\u0433\u043E\u043B\u043E\u0432\u044B\u0439 \u0411\u0445\u0430\u0439\u0440\u0430\u0432\u0430 \u043F\u0440\u0438\u0441\u0443\u0442\u0441\u0442\u0432\u0443\u0435\u0442 \u0432 \u0438\u043D\u0434\u0438\u0432\u0438\u0434\u0435 \u043A\u0430\u043A \u043F\u0440\u043E\u043D\u0438\u0437\u044B\u0432\u0430\u044E\u0449\u0438\u0439 \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u0443\u044E\xBB.</p><p class="eng">\u0422\u0430\u043A\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C, \u0432 [\u0434\u0430\u043D\u043D\u043E\u043C] \u0442\u0435\u043A\u0441\u0442\u0435 \u0433\u043E\u0432\u043E\u0440\u0438\u0442\u0441\u044F \u043E \u0442\u043E\u043C, \u0447\u0442\u043E \u0438\u043D\u0434\u0438\u0432\u0438\u0434 \u0435\u0441\u0442\u044C \u043F\u043E \u0441\u0432\u043E\u0435\u0439 \u0444\u043E\u0440\u043C\u0435 \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u0430\u044F \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u0430\u044F. \u041A \u044D\u0442\u043E\u043C\u0443 \u0435\u0441\u0442\u044C \u0434\u043E\u043F\u043E\u043B\u043D\u0435\u043D\u0438\u0435: \u0418\u043D\u0434\u0438\u0432\u0438\u0434 \u044D\u0442\u043E\u0442 \u0442\u043E\u0436\u0434\u0435\u0441\u0442\u0432\u0435\u043D\u0435\u043D \u0428\u0438\u0432\u0435, \u0442\u0435\u043B\u043E\u043C \u043A\u043E\u0442\u043E\u0440\u043E\u0433\u043E \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u0430\u044F, \u0438\u0437-\u0437\u0430 \u0442\u043E\u0433\u043E, \u0447\u0442\u043E \u0438\u0441\u0442\u0438\u043D\u043D\u0430\u044F \u0435\u0433\u043E \u043F\u0440\u0438\u0440\u043E\u0434\u0430 \u2013 \u0421\u0432\u0435\u0442 \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F, \u043E \u0447\u0435\u043C \u0433\u043E\u0432\u043E\u0440\u0438\u0442\u0441\u044F \u0432 \u0443\u043F\u043E\u043C\u044F\u043D\u0443\u0442\u044B\u0445 \u0430\u0433\u0430\u043C\u0430\u0445. \u0422\u043E\u043B\u044C\u043A\u043E \u0438\u0437-\u0437\u0430 \u0434\u0435\u044F\u0442\u0435\u043B\u044C\u043D\u043E\u0441\u0442\u0438 \u0415\u0433\u043E [\u0428\u0438\u0432\u044B] \u043C\u0430\u0439\u044F-\u0448\u0430\u043A\u0442\u0438 [\u0438\u043D\u0434\u0438\u0432\u0438\u0434] \u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u0441\u044F \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u044B\u043C, \u0432\u0435\u0434\u044C \u0435\u0433\u043E \u0438\u0441\u0442\u0438\u043D\u043D\u0430\u044F \u043F\u0440\u0438\u0440\u043E\u0434\u0430 \u043D\u0435 \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0430. \u041D\u043E \u044D\u0442\u043E \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u0438\u0435 \u0442\u043E\u0436\u0435 [\u0441\u043E\u0441\u0442\u043E\u0438\u0442] \u0438\u0437 \u043E\u0434\u043D\u043E\u0433\u043E \u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F, \u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u043E\u043D\u043E \u043F\u043E\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u043A\u0430\u043A \u0438\u043C\u0435\u044E\u0449\u0435\u0435 \u043F\u0440\u0438\u0440\u043E\u0434\u0443 \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F \u2013 \u0432 \u043F\u0440\u043E\u0442\u0438\u0432\u043D\u043E\u043C \u0441\u043B\u0443\u0447\u0430\u0435 \u043E\u043D\u043E \u043D\u0435 \u0431\u044B\u043B\u043E \u0431\u044B \u043D\u0438\u0447\u0435\u043C.</p><p class="eng">\u0422\u0430\u043A \u0447\u0442\u043E \u0432\u0441\u044F\u043A\u0438\u0439 \u0441\u0443\u0431\u044A\u0435\u043A\u0442 \u2013 \u044D\u0442\u043E \u0438 \u0435\u0441\u0442\u044C \u0411\u043B\u0430\u0433\u043E\u0441\u043B\u043E\u0432\u0435\u043D\u043D\u044B\u0439 \u0428\u0438\u0432\u0430, \u0447\u044C\u0438\u043C \u0442\u0435\u043B\u043E\u043C \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u0430\u044F. \u041C\u043D\u043E\u044E \u0431\u044B\u043B\u043E \u0441\u043A\u0430\u0437\u0430\u043D\u043E [\u0432 \u0434\u0440\u0443\u0433\u043E\u043C \u043C\u0435\u0441\u0442\u0435]: \xAB\u0415\u0441\u043B\u0438 \u043D\u0435\u0437\u043D\u0430\u043D\u0438\u0435 \u043D\u0435 [\u043F\u043E\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0432 \u0444\u043E\u0440\u043C\u0435] \u0437\u043D\u0430\u043D\u0438\u044F, \u0442\u043E \u043E\u0441\u0442\u0430\u0435\u0442\u0441\u044F \u0442\u043E\u043B\u044C\u043A\u043E \u0437\u043D\u0430\u043D\u0438\u0435. \u0415\u0441\u043B\u0438 [\u043D\u0435\u0437\u043D\u0430\u043D\u0438\u0435] \u043F\u043E\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0432 \u0444\u043E\u0440\u043C\u0435 \u0437\u043D\u0430\u043D\u0438\u044F, \u0442\u043E [\u043E\u043F\u044F\u0442\u044C] \u043E\u0441\u0442\u0430\u0435\u0442\u0441\u044F \u043E\u0434\u043D\u043E \u0442\u043E\u043B\u044C\u043A\u043E \u0437\u043D\u0430\u043D\u0438\u0435\xBB.</p><p class="eng">\u041E\u0431 \u044D\u0442\u043E\u043C \u0436\u0435 \u043E\u0441\u043E\u0431\u043E [\u0441\u043A\u0430\u0437\u0430\u043D\u043E] \u0432 \u0421\u043F\u0430\u043D\u0434\u0430-\u0448\u0430\u0441\u0442\u0440\u0435, \u0432 \u0441\u0442\u0438\u0445\u0430\u0445, \u043D\u0430\u0447\u0438\u043D\u0430\u044E\u0449\u0438\u0445\u0441\u044F \u0442\u0430\u043A: \xAB\u0414\u0436\u0438\u0432\u0430, [\u0438\u0434\u0435\u043D\u0442\u0438\u0447\u043D\u044B\u0439] \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u043E\u0439\u2026\xBB \u0438 \u0437\u0430\u043A\u0430\u043D\u0447\u0438\u0432\u0430\u044E\u0449\u0438\u0445\u0441\u044F \xAB\u043D\u0438 \u0432 \u0441\u043B\u043E\u0432\u0435, \u043D\u0438 \u0432 \u043E\u0431\u044A\u0435\u043A\u0442\u0435, \u043D\u0438 \u0432 \u043C\u044B\u0448\u043B\u0435\u043D\u0438\u0438 \u043D\u0435\u0442 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F, \u0432 \u043A\u043E\u0442\u043E\u0440\u043E\u043C \u043E\u0442\u0441\u0443\u0442\u0441\u0442\u0432\u043E\u0432\u0430\u043B \u0431\u044B \u0428\u0438\u0432\u0430\xBB.</p><p class="eng">\u0422\u0435\u043C \u0441\u0430\u043C\u044B\u043C \u0433\u043E\u0432\u043E\u0440\u0438\u0442\u0441\u044F \u043E \u043D\u0435\u0440\u0430\u0437\u0434\u0435\u043B\u0435\u043D\u043D\u043E\u0441\u0442\u0438 \u0428\u0438\u0432\u044B \u0438 \u0434\u0436\u0438\u0432\u044B. \u041E\u0434\u043D\u043E \u043F\u043E\u043D\u0438\u043C\u0430\u043D\u0438\u0435 \u044D\u0442\u043E\u0439 \u0438\u0441\u0442\u0438\u043D\u044B [\u043F\u0440\u0438\u043D\u043E\u0441\u0438\u0442] \u043E\u0441\u0432\u043E\u0431\u043E\u0436\u0434\u0435\u043D\u0438\u0435; \u043D\u0435\u0437\u043D\u0430\u043D\u0438\u0435 \u0436\u0435 \u044D\u0442\u043E\u0439 \u0438\u0441\u0442\u0438\u043D\u044B [\u0432\u0432\u0435\u0440\u0433\u0430\u0435\u0442] \u0432\u043E \u043C\u0440\u0430\u043A.</p><p class="eng">\u041E\u0431 \u044D\u0442\u043E\u043C \u0431\u0443\u0434\u0435\u0442 \u0435\u0449\u0435 \u0441\u043A\u0430\u0437\u0430\u043D\u043E [\u043D\u0438\u0436\u0435]. \u041D\u0430 \u044D\u0442\u043E \u043C\u043E\u0433\u0443\u0442 \u0432\u043E\u0437\u0440\u0430\u0437\u0438\u0442\u044C: \u0432\u0435\u0434\u044C \u0441\u0443\u0431\u044A\u0435\u043A\u0442\u0443 \u0441\u0432\u043E\u0439\u0441\u0442\u0432\u0435\u043D\u043D\u043E \u0434\u0438\u0444\u0444\u0435\u0440\u0435\u043D\u0446\u0438\u0440\u043E\u0432\u0430\u0442\u044C [\u043E\u0431\u044A\u0435\u043A\u0442\u044B], \u0430 \u044D\u0442\u043E \u0441\u0432\u043E\u0439\u0441\u0442\u0432\u043E \u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u0438\u0442 \u043E\u0442 \u0447\u0438\u0442\u0442\u044B, \u043F\u043E\u0447\u0435\u043C\u0443 \u0442\u043E\u0433\u0434\u0430 [\u0433\u043E\u0432\u043E\u0440\u0438\u0442\u0441\u044F], \u0447\u0442\u043E \u043E\u043D \u0438\u0434\u0435\u043D\u0442\u0438\u0447\u0435\u043D \u0428\u0438\u0432\u0435? \u041E\u0442\u0432\u0435\u0447\u0430\u044F \u043D\u0430 \u043F\u043E\u0434\u043E\u0431\u043D\u043E\u0435 \u0432\u043E\u0437\u0440\u0430\u0436\u0435\u043D\u0438\u0435, [\u0430\u0432\u0442\u043E\u0440] \u0433\u043E\u0432\u043E\u0440\u0438\u0442, \u0443\u0441\u0442\u0430\u043D\u0430\u0432\u043B\u0438\u0432\u0430\u044F [\u0437\u043D\u0430\u0447\u0435\u043D\u0438\u0435] \u0447\u0438\u0442\u0442\u044B:</p></div><div class="stanza"><a href="#s5" id="s5" class="num">5</a><p class="sans">\u091A\u093F\u0924\u093F\u0930\u0947\u0935 \u091A\u0947\u0924\u0928\u092A\u0926\u093E\u0935\u0930\u0942\u0922\u093E \u091A\u0947\u0924\u094D\u092F\u0938\u0919\u094D\u0915\u094B\u091A\u093F\u0928\u0940 \u091A\u093F\u0924\u094D\u0924\u092E\u094D \u0965\u096B\u0965</p><p class="trans">Citireva cetanapad\u0101davar\u016B\u1E0Dh\u0101 cetyasa\u1E45kocin\u012B cittam \u09655\u0965</p><p>\u0422\u043E\u043B\u044C\u043A\u043E <em>(eva)</em> \u0410\u0431\u0441\u043E\u043B\u044E\u0442\u043D\u043E\u0435 \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u0435 <em>(citi\u1E25)</em>, \u043D\u0438\u0441\u0445\u043E\u0434\u044F <em>(avar\u016B\u1E0Dh\u0101)</em> \u0441\u043E \u0441\u0442\u0443\u043F\u0435\u043D\u0438 <em>(pad\u0101t)</em> \u0412\u044B\u0441\u0448\u0435\u0433\u043E \u0440\u0430\u0437\u0443\u043C\u0430 <em>(cetana)</em>, \u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u0441\u044F \u0441\u043E\u0437\u043D\u0430\u043D\u0438\u0435\u043C <em>(cittam)</em>, \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u044B\u043C <em>(sa\u1E45kocin\u012B)</em> \u043E\u0431\u044A\u0435\u043A\u0442\u0430\u043C\u0438 <em>(cetya)</em>.</p><p class="eng"><strong>\u041A\u043E\u043C\u043C\u0435\u043D\u0442\u0430\u0440\u0438\u0439</strong><br> \u0422\u043E, \u0447\u0442\u043E \u043D\u0430\u0437\u044B\u0432\u0430\u0435\u0442\u0441\u044F \u0438\u043D\u0434\u0438\u0432\u0438\u0434\u0443\u0430\u043B\u044C\u043D\u044B\u043C \u0441\u043E\u0437\u043D\u0430\u043D\u0438\u0435\u043C, \u0435\u0441\u0442\u044C \u043D\u0435 \u0447\u0442\u043E \u0438\u043D\u043E\u0435 \u043A\u0430\u043A \u0441\u0430\u043C\u0430 \u0411\u0445\u0430\u0433\u0430\u0432\u0430\u0442\u0438.</p><p class="eng">\u041A\u043E\u0433\u0434\u0430 \u041E\u043D\u0430, \u0441\u043A\u0440\u044B\u0432\u0430\u044F \u0441\u0432\u043E\u044E \u0438\u0441\u0442\u0438\u043D\u043D\u0443\u044E \u043F\u0440\u0438\u0440\u043E\u0434\u0443, \u043F\u0440\u0438\u043D\u0438\u043C\u0430\u0435\u0442 \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u0438\u0435, \u0442\u043E\u0433\u0434\u0430 \u041E\u043D\u0430 \u0432\u044B\u0441\u0442\u0443\u043F\u0430\u0435\u0442 \u0432 \u0434\u0432\u0443\u0445 \u0430\u0441\u043F\u0435\u043A\u0442\u0430\u0445. \u0418\u043D\u043E\u0433\u0434\u0430 \u0432 \u041D\u0435\u0439 \u043F\u0440\u0435\u043E\u0431\u043B\u0430\u0434\u0430\u0435\u0442 \u0447\u0438\u0442, \u0438 \u0442\u043E\u0433\u0434\u0430 \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u0438\u0435, \u0441\u0434\u0435\u043B\u0430\u0432\u0448\u0435\u0435 \u0415\u0435 \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u0435, \u043E\u0441\u0432\u0435\u0449\u0435\u043D\u043E \u044D\u0442\u0438\u043C \u0447\u0438\u0442; \u0438\u043D\u043E\u0433\u0434\u0430 \u043F\u0440\u0435\u043E\u0431\u043B\u0430\u0434\u0430\u0435\u0442 \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u0438\u0435. \u041A\u043E\u0433\u0434\u0430 \u0447\u0438\u0442 \u0434\u043E\u043C\u0438\u043D\u0438\u0440\u0443\u0435\u0442 \u0432 \u0435\u0441\u0442\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u043C \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0438, [\u043F\u0440\u0438 \u043A\u043E\u0442\u043E\u0440\u043E\u043C] \u043F\u0440\u0435\u043E\u0431\u043B\u0430\u0434\u0430\u0435\u0442 \u0421\u0432\u0435\u0442 \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F, \u0442\u043E \u0441\u0443\u0431\u044A\u0435\u043A\u0442\u043E\u043C \u0435\u0433\u043E \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0432\u0438\u0434\u0436\u043D\u044F\u043D\u0430\u043A\u0430\u043B\u0430.</p><p class="eng">\u0415\u0441\u043B\u0438 \u0421\u0432\u0435\u0442 \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F [\u0432\u044B\u0441\u0442\u0443\u043F\u0430\u0435\u0442 \u0441\u043E\u0432\u043C\u0435\u0441\u0442\u043D\u043E] \u0441 \u0421\u0438\u043B\u043E\u0439 \u0420\u0435\u0444\u043B\u0435\u043A\u0441\u0438\u0438, \u0442\u043E \u0441\u0443\u0431\u044A\u0435\u043A\u0442 [\u0432 \u044D\u0442\u043E\u043C \u0441\u043B\u0443\u0447\u0430\u0435] \u2013 \u0432\u0438\u0434\u044C\u044F. \u041F\u043E \u043C\u0435\u0440\u0435 \u043F\u043E\u0441\u0442\u0435\u043F\u0435\u043D\u043D\u043E\u0433\u043E \u0443\u0431\u044B\u0432\u0430\u043D\u0438\u044F \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u0438\u044F [\u0435\u0441\u0442\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u043C \u043F\u0443\u0442\u0435\u043C] \u043F\u043E\u044F\u0432\u043B\u044F\u044E\u0442\u0441\u044F \u0442\u0430\u043A\u0438\u0435 \u0444\u043E\u0440\u043C\u044B [\u0428\u0438\u0432\u044B], \u043A\u0430\u043A \u0418\u0448\u0430, \u0421\u0430\u0434\u0430\u0448\u0438\u0432\u0430 \u0438 \u0410\u043D\u0430\u0448\u0440\u0438\u0442\u0430. \u041D\u043E \u043A\u043E\u0433\u0434\u0430 \u0430\u0441\u043F\u0435\u043A\u0442 \u0447\u0438\u0442 \u0434\u043E\u0441\u0442\u0438\u0433\u0430\u0435\u0442\u0441\u044F \u043F\u0440\u0438 \u043F\u043E\u043C\u043E\u0449\u0438 \u0441\u0430\u043C\u0430\u0434\u0445\u0438, \u0441\u0443\u0431\u044A\u0435\u043A\u0442\u044B \u0427\u0438\u0441\u0442\u043E\u0433\u043E \u043F\u0443\u0442\u0438 [\u043E\u0431\u0440\u0435\u0442\u0430\u044E\u0442] \u0412\u044B\u0441\u0448\u0435\u0435 [\u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435] \u043F\u043E\u0441\u043B\u0435\u0434\u043E\u0432\u0430\u0442\u0435\u043B\u044C\u043D\u043E. \u0413\u0434\u0435 \u043F\u0440\u0435\u043E\u0431\u043B\u0430\u0434\u0430\u0435\u0442 \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u0438\u0435, \u0442\u0430\u043C \u043F\u043E\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0441\u0443\u0431\u044A\u0435\u043A\u0442\u043D\u043E\u0441\u0442\u044C \u043F\u0443\u0441\u0442\u043E\u0442\u044B \u0438 \u0442. \u0434.</p><p class="eng">\u041D\u0430\u0445\u043E\u0434\u044F\u0441\u044C \u0432 \u0442\u0430\u043A\u043E\u043C \u043F\u043E\u043B\u043E\u0436\u0435\u043D\u0438\u0438, \u0412\u044B\u0441\u0448\u0435\u0435 \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u0435, \u0432 \u0444\u043E\u0440\u043C\u0435 \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u043E\u0433\u043E \u0441\u0443\u0431\u044A\u0435\u043A\u0442\u0430, \xAB\u043D\u0438\u0441\u0445\u043E\u0434\u044F \u0441\u043E \u0441\u0442\u0443\u043F\u0435\u043D\u0438 \u0447\u0435\u0442\u0430\u043D\u0430\xBB, \u043E\u0431\u0440\u0430\u0449\u0430\u0435\u0442\u0441\u044F \u043A \u0432\u043E\u0441\u043F\u0440\u0438\u043D\u0438\u043C\u0430\u0435\u043C\u044B\u043C \xAB\u043E\u0431\u044A\u0435\u043A\u0442\u0430\u043C\xBB, \u0442\u0430\u043A\u0438\u043C \u043A\u0430\u043A \u0433\u043E\u043B\u0443\u0431\u043E\u043C\u0443, \u0441\u0447\u0430\u0441\u0442\u044C\u044E \u0438 \u0442. \u0434. \u0438 \u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u0441\u044F \xAB\u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u044B\u043C\xBB \u043E\u0431\u043E\u0438\u043C\u0438 [\u0432\u0438\u0434\u0430\u043C\u0438] \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u0438\u0439 [\u0432\u043D\u0435\u0448\u043D\u0438\u043C \u0438 \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0438\u043C], \u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u0441\u044F \u0447\u0438\u0442\u0442\u043E\u0439. \u041A\u0430\u043A \u0441\u043A\u0430\u0437\u0430\u043D\u043E: \xAB\u0422\u043E, \u0447\u0442\u043E \u0432 \u0415\u0433\u043E \u0447\u043B\u0435\u043D\u0430\u0445 \u044F\u0432\u043B\u0435\u043D\u043E \u043A\u0430\u043A \u0434\u0436\u043D\u044F\u043D\u0430, \u043A\u0440\u0438\u044F \u0438 \u043C\u0430\u0439\u044F, \u0443 \u043F\u0430\u0448\u0443 \u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u0441\u044F \u0441\u0430\u0442\u0442\u0432\u043E\u0439, \u0440\u0430\u0434\u0436\u0430\u0441\u043E\u043C \u0438 \u0442\u0430\u043C\u0430\u0441\u043E\u043C\xBB.</p><p class="eng">\u0422\u0430\u043A\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C, \u0447\u0438\u0442\u0438-\u0448\u0430\u043A\u0442\u0438, \u0438\u043C\u0435\u044E\u0449\u0430\u044F \u043F\u0440\u0438\u0440\u043E\u0434\u0443 \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u0438\u044F, \u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u0441\u044F \u0432 \u0438\u043D\u0434\u0438\u0432\u0438\u0434\u0443\u0430\u043B\u044C\u043D\u043E\u043C \u0441\u043E\u0437\u043D\u0430\u043D\u0438\u0438 \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u044C\u044E, \u0438\u043C\u0435\u044E\u0449\u0435\u0439 [\u043A\u0430\u0447\u0435\u0441\u0442\u0432\u0430] \u0441\u0430\u0442\u0442\u0432\u0430, \u0440\u0430\u0434\u0436\u0430\u0441 \u0438 \u0442\u0430\u043C\u0430\u0441 \u2013 \u0442\u0430\u043A \u0433\u043E\u0432\u043E\u0440\u0438\u0442\u0441\u044F \u0432 \u041F\u0440\u0430\u0442\u044C\u044F\u0431\u0445\u0438\u0434\u0436\u043D\u0435. \u041F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u0438\u0441\u0442\u0438\u043D\u043D\u0430\u044F \u043F\u0440\u0438\u0440\u043E\u0434\u0430 \xAB\u043D\u0430\u0434\u0435\u043B\u0435\u043D\u043D\u043E\u0433\u043E \u0442\u0430\u0442\u0442\u0432\u0430\u043C\u0438\xBB, [\u0442. \u0435. \u0438\u043D\u0434\u0438\u0432\u0438\u0434\u0430, \u0441\u043E\u0445\u0440\u0430\u043D\u044F\u0435\u0442\u0441\u044F] \u0434\u0430\u0436\u0435 \u0432 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0438 \u0432\u0438\u043A\u0430\u043B\u044C\u043F\u044B, \u0442\u043E \u0441 \u0446\u0435\u043B\u044C\u044E \u043F\u0440\u043E\u044F\u0441\u043D\u0438\u0442\u044C \u044D\u0442\u043E \u0432 \u0422\u0430\u0442\u0442\u0432\u0430 \u0433\u0430\u0440\u0431\u0445\u0430-\u0441\u0442\u043E\u0442\u0440\u0435 \u0433\u043E\u0432\u043E\u0440\u0438\u0442\u0441\u044F: \xAB\u041F\u043E\u044D\u0442\u043E\u043C\u0443 \u0441\u0432\u0435\u0442\u043E\u0437\u0430\u0440\u043D\u0430\u044F \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u044C \u0442\u0435\u0445, \u043A\u0442\u043E \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0432\u044B\u0441\u0448\u0435\u0439 \u0438\u0441\u0442\u0438\u043D\u0435, \u043D\u0438\u043A\u043E\u0433\u0434\u0430 \u043D\u0435 \u043E\u043C\u0440\u0430\u0447\u0430\u0435\u0442\u0441\u044F\xBB.</p></div><div class="stanza"><a href="#s6" id="s6" class="num">6</a><p class="sans">\u0924\u0928\u094D\u092E\u092F\u094B \u092E\u093E\u092F\u093E\u092A\u094D\u0930\u092E\u093E\u0924\u093E \u0965\u096C\u0965</p><p class="trans">Tanmayo m\u0101y\u0101pram\u0101t\u0101 \u09656\u0965</p><p>\u0418\u0437 \u044D\u0442\u043E\u0433\u043E <em>(tad)</em> \u0441\u043E\u0441\u0442\u043E\u0438\u0442 <em>(maya\u1E25)</em> \u0441\u0443\u0431\u044A\u0435\u043A\u0442 <em>(pram\u0101t\u0101)</em> \u043C\u0430\u0439\u0438 <em>(m\u0101y\u0101)</em>.</p><p class="eng"><strong>\u041A\u043E\u043C\u043C\u0435\u043D\u0442\u0430\u0440\u0438\u0439</strong><br> \u0427\u0438\u0442\u0442\u0430 \u0434\u043E\u043C\u0438\u043D\u0438\u0440\u0443\u0435\u0442 \u0431\u043E\u043B\u044C\u0448\u0435 \u0432\u0441\u0435\u0433\u043E \u0432 \u0442\u0435\u043B\u0435 \u0438 \u0432 \u0434\u044B\u0445\u0430\u043D\u0438\u0438. \u041E\u0431\u043B\u0430\u0441\u0442\u044C \u043F\u0443\u0441\u0442\u043E\u0442\u044B \u0442\u043E\u0436\u0435 \u0441\u043E\u0434\u0435\u0440\u0436\u0438\u0442 \u043E\u0441\u0442\u0430\u0442\u043E\u0447\u043D\u044B\u0435 \u0441\u043B\u0435\u0434\u044B \u0447\u0438\u0442\u0442\u044B \u2013 \u0432 \u043F\u0440\u043E\u0442\u0438\u0432\u043D\u043E\u043C \u0441\u043B\u0443\u0447\u0430\u0435 \u043D\u0435 \u0441\u043C\u043E\u0433 \u0431\u044B \u0434\u0435\u0439\u0441\u0442\u0432\u043E\u0432\u0430\u0442\u044C \u043E\u0447\u043D\u0443\u0432\u0448\u0438\u0439\u0441\u044F [\u043E\u0442 \u043F\u0435\u0440\u0435\u0436\u0438\u0432\u0430\u043D\u0438\u044F \u043F\u0443\u0441\u0442\u043E\u0442\u044B] \u0438\u043D\u0434\u0438\u0432\u0438\u0434.</p><p class="eng">\u041F\u043E\u044D\u0442\u043E\u043C\u0443 \u0441\u0443\u0431\u044A\u0435\u043A\u0442 \u043C\u0430\u0439\u0438 \u0441\u043E\u0441\u0442\u043E\u0438\u0442 \u0442\u043E\u043B\u044C\u043A\u043E \u0438\u0437 \u0447\u0438\u0442\u0442\u044B. \u0421 \u044D\u0442\u043E\u0439 \u0446\u0435\u043B\u044C\u044E \u0432 \u0428\u0438\u0432\u0430-\u0441\u0443\u0442\u0440\u0435 (1. 1), \u043F\u0440\u0438 \u043E\u0431\u0441\u0443\u0436\u0434\u0435\u043D\u0438\u0438 \u0432\u043E\u043F\u0440\u043E\u0441\u0430 \u043E \u0440\u0435\u0430\u043B\u044C\u043D\u043E\u0441\u0442\u0438, \u0433\u043E\u0432\u043E\u0440\u0438\u0442\u0441\u044F:</p><p class="eng"><strong>\xAB\u0410\u0431\u0441\u043E\u043B\u044E\u0442\u043D\u043E\u0435 \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u0435 \u0441\u0443\u0442\u044C \u042F\xBB</strong>,</p><p class="eng">\u0430 \u0434\u0430\u043B\u0435\u0435, \u043E\u0431\u0441\u0443\u0436\u0434\u0430\u044F \u0442\u0435\u043C\u0443 \u043F\u0440\u0438\u0437\u043D\u0430\u043A\u043E\u0432 \u0441\u0443\u0431\u044A\u0435\u043A\u0442\u0430 \u043C\u0430\u0439\u0438, \u0441\u043D\u043E\u0432\u0430 \u0433\u043E\u0432\u043E\u0440\u0438\u0442\u0441\u044F:</p><p class="eng"><strong>\xAB\u0418\u043D\u0434\u0438\u0432\u0438\u0434\u0443\u0430\u043B\u044C\u043D\u043E\u0435 \u0441\u043E\u0437\u043D\u0430\u043D\u0438\u0435 \u2013 \u044D\u0442\u043E \u042F\xBB</strong>.</p><p class="eng">\u041E\u0434\u043D\u043E \u043B\u0438\u0448\u044C \u0432\u0435\u0440\u043D\u043E\u0435 \u0437\u043D\u0430\u043D\u0438\u0435 \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439 \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u0438 \u043F\u0440\u0438\u043D\u043E\u0441\u0438\u0442 \u043E\u0441\u0432\u043E\u0431\u043E\u0436\u0434\u0435\u043D\u0438\u0435, \u0430 \u043D\u0435\u0432\u0435\u0440\u043D\u043E\u0435 [\u0432\u0432\u0435\u0440\u0433\u0430\u0435\u0442] \u0432 \u0441\u0430\u043D\u0441\u0430\u0440\u0443.</p></div><div class="stanza"><a href="#s7" id="s7" class="num">7</a><p class="sans">\u0938 \u091A\u0948\u0915\u094B \u0926\u094D\u0935\u093F\u0930\u0942\u092A\u0938\u094D\u0924\u094D\u0930\u093F\u092E\u092F\u0936\u094D\u091A\u0924\u0941\u0930\u093E\u0924\u094D\u092E\u093E \u0938\u092A\u094D\u0924\u092A\u091E\u094D\u091A\u0915\u0938\u094D\u0935\u092D\u093E\u0935\u0903 \u0965\u096D\u0965</p><p class="trans">Sa caiko dvir\u016Bpastrimaya\u015Bcatur\u0101tm\u0101 saptapa\xF1cakasvabh\u0101va\u1E25 \u09657\u0965</p><p>\u0418 <em>(ca)</em>, \u0431\u0443\u0434\u0443\u0447\u0438 \u041E\u0434\u043D\u0438\u043C <em>(eka\u1E25)</em>, \u041E\u043D <em>(sa\u1E25)</em> [\u043E\u0431\u0440\u0435\u0442\u0430\u0435\u0442] \u0434\u0432\u0435 \u0444\u043E\u0440\u043C\u044B <em>(dvir\u016Bpa\u1E25)</em>, \u0442\u0440\u0438 \u043E\u0431\u043B\u0438\u043A\u0430 <em>(trimaya\u1E25)</em>, \u0447\u0435\u0442\u044B\u0440\u0435 \u0441\u0430\u043C\u043E\u0441\u0442\u0438 <em>(catur-\u0101tm\u0101)</em>, \u043F\u0440\u0438\u0440\u043E\u0434\u0443 <em>(sva-bh\u0101va\u1E25)</em> \u0441\u0435\u043C\u0438 <em>(sapta)</em> \u043F\u044F\u0442\u0451\u0440\u043E\u043A <em>(pa\xF1caka)</em>.</p><p class="eng"><strong>\u041A\u043E\u043C\u043C\u0435\u043D\u0442\u0430\u0440\u0438\u0439</strong><br> \u041D\u0430 \u043E\u0441\u043D\u043E\u0432\u0430\u043D\u0438\u0438 [\u044D\u0442\u043E\u0433\u043E \u0443\u0442\u0432\u0435\u0440\u0436\u0434\u0435\u043D\u0438\u044F \u044F\u0441\u043D\u043E], \u0447\u0442\u043E \u0442\u043E\u043B\u044C\u043A\u043E \u0438\u043C\u0435\u044E\u0449\u0438\u0439 \u043F\u0440\u0438\u0440\u043E\u0434\u0443 \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F \u0411\u043B\u0430\u0433\u043E\u0441\u043B\u043E\u0432\u0435\u043D\u043D\u044B\u0439 \u0428\u0438\u0432\u0430 \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u043F\u043E \u0441\u0432\u043E\u0435\u0439 \u043F\u0440\u0438\u0440\u043E\u0434\u0435 \xAB\u043E\u0434\u043D\u0438\u043C\xBB, \u0438 \u043D\u0438\u043A\u0442\u043E \u0434\u0440\u0443\u0433\u043E\u0439, \u043F\u043E\u0442\u043E\u043C\u0443 \u0447\u0442\u043E \u043D\u0435\u0432\u043E\u0437\u043C\u043E\u0436\u043D\u043E \u0440\u0430\u0437\u0434\u0435\u043B\u0438\u0442\u044C \u0421\u0432\u0435\u0442 \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F \u043D\u0430 \u043F\u0440\u043E\u0441\u0442\u0440\u0430\u043D\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u0435, \u0432\u0440\u0435\u043C\u0435\u043D\u043D\u044B\u0435 \u0438 \u0434\u0440\u0443\u0433\u0438\u0435 \u0440\u0430\u043C\u043A\u0438, \u0430 \u0442\u0430\u043A\u0436\u0435 \u043F\u043E\u0442\u043E\u043C\u0443, \u0447\u0442\u043E \u0441\u0443\u0431\u044A\u0435\u043A\u0442\u043E\u043C \u043F\u043E\u0437\u043D\u0430\u043D\u0438\u044F \u043D\u0435 \u043C\u043E\u0436\u0435\u0442 \u0431\u044B\u0442\u044C \u0438\u043D\u0435\u0440\u0442\u043D\u0430\u044F \u043C\u0430\u0442\u0435\u0440\u0438\u044F.</p><p class="eng">\u041A\u043E\u0433\u0434\u0430 \u0421\u0432\u0435\u0442 \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F \u0431\u043B\u0430\u0433\u043E\u0434\u0430\u0440\u044F \u0441\u0432\u043E\u0435\u0439 \u0441\u0430\u043C\u043E\u0435\u0441\u0442\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0441\u0442\u0438 \u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u0441\u044F \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D \u043F\u0440\u0430\u043D\u043E\u0439 \u0438 \u0442. \u0434. \u0438 \u043F\u0440\u0435\u0432\u0440\u0430\u0449\u0430\u0435\u0442\u0441\u044F \u0432 \u0441\u0443\u0431\u044A\u0435\u043A\u0442\u0430 \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u043E\u0433\u043E \u043E\u043F\u044B\u0442\u0430, \u0442\u043E \u0442\u0430\u043A\u043E\u0435 [\u043F\u043E\u043B\u043E\u0436\u0435\u043D\u0438\u0435, \u043A\u043E\u0433\u0434\u0430 \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0443\u044E\u0442] \u0444\u043E\u0440\u043C\u0430 \u0421\u0432\u0435\u0442\u0430 \u0438 \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u043E\u0435 \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u0435, [\u043D\u0430\u0437\u044B\u0432\u0430\u0435\u0442\u0441\u044F] \xAB\u0434\u0432\u0443\u043C\u044F \u0444\u043E\u0440\u043C\u0430\u043C\u0438\xBB.</p><p class="eng">\u041F\u043E \u043F\u0440\u0438\u0447\u0438\u043D\u0435 \u0441\u043E\u043A\u0440\u044B\u0442\u0438\u044F \u0441\u0435\u0431\u044F [\u0442\u0440\u0435\u043C\u044F] \u043D\u0435\u0447\u0438\u0441\u0442\u044B\u043C\u0438 \u043A\u0430\u0447\u0435\u0441\u0442\u0432\u0430\u043C\u0438, \u0430 \u0438\u043C\u0435\u043D\u043D\u043E \u0430\u043D\u0430\u0432\u043E\u0439, \u043C\u0430\u0439\u0438\u0435\u0439 \u0438 \u043A\u0430\u0440\u043C\u043E\u0439, [\u041E\u043D \u043D\u0430\u0437\u044B\u0432\u0430\u0435\u0442\u0441\u044F \u043F\u0440\u0438\u043D\u044F\u0432\u0448\u0438\u043C] \xAB\u0442\u0440\u0438 \u043E\u0431\u043B\u0438\u043A\u0430\xBB.</p><p class="eng">\u041E\u043D [\u043D\u0430\u0437\u044B\u0432\u0430\u0435\u0442\u0441\u044F \u0438\u043C\u0435\u044E\u0449\u0438\u043C] \xAB\u0447\u0435\u0442\u044B\u0440\u0435 \u043F\u0440\u0438\u0440\u043E\u0434\u044B\xBB \u0438\u0437-\u0437\u0430 \u0442\u043E\u0433\u043E, \u0447\u0442\u043E [\u043F\u0440\u043E\u0445\u043E\u0434\u0438\u0442 \u044D\u0442\u0430\u043F\u044B] \u043F\u0443\u0441\u0442\u043E\u0442\u044B, \u043F\u0440\u0430\u043D\u044B, \u0442\u043E\u043D\u043A\u043E\u0433\u043E \u0438 \u043F\u043B\u043E\u0442\u043D\u043E\u0433\u043E \u0442\u0435\u043B\u0430.</p><p class="eng">\xAB\u0422\u0440\u0438\u0434\u0446\u0430\u0442\u044C \u043F\u044F\u0442\u044C\xBB \u2013 \u044D\u0442\u043E \u0442\u0440\u0438\u0434\u0446\u0430\u0442\u044C \u0448\u0435\u0441\u0442\u044C \u0442\u0430\u0442\u0442\u0432, \xAB\u0441\u0443\u0449\u043D\u043E\u0441\u0442\u0435\u0439\xBB, \u043E\u0442 \u0428\u0438\u0432\u044B \u0434\u043E \u0441\u0442\u0438\u0445\u0438\u0438 \u0437\u0435\u043C\u043B\u0438. \u041D\u0430\u0447\u0438\u043D\u0430\u044F \u043E\u0442 \u0428\u0438\u0432\u044B \u0438 \u0437\u0430\u043A\u0430\u043D\u0447\u0438\u0432\u0430\u044F \u0441\u0430\u043A\u0430\u043B\u043E\u0439 [\u043D\u0430\u0441\u0447\u0438\u0442\u044B\u0432\u0430\u0435\u0442\u0441\u044F] \u0441\u0435\u0434\u044C\u043C\u0438\u0446\u0430 [\u0440\u043E\u0434\u043E\u0432] \u043F\u043E\u0437\u043D\u0430\u044E\u0449\u0438\u0445 \u0441\u0443\u0431\u044A\u0435\u043A\u0442\u043E\u0432. \u0425\u043E\u0442\u044F [\u043F\u043E \u0441\u0432\u043E\u0435\u0439 \u0441\u0443\u0442\u0438 \u0438\u043D\u0434\u0438\u0432\u0438\u0434 \u0438\u043C\u0435\u0435\u0442] \u0444\u043E\u0440\u043C\u0443 \u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F-\u0431\u043B\u0430\u0436\u0435\u043D\u0441\u0442\u0432\u0430-\u0432\u043E\u043B\u0438-\u0437\u043D\u0430\u043D\u0438\u044F-\u0434\u0435\u0439\u0441\u0442\u0432\u0438\u044F, \u043F\u043E\u0434 \u0432\u043E\u0437\u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0435\u043C \u043E\u043C\u0440\u0430\u0447\u0430\u044E\u0449\u0435\u0439 \u0441\u0438\u043B\u044B \u043E\u043D \u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u0441\u044F \u0441\u0432\u044F\u0437\u0430\u043D \u043F\u044F\u0442\u0435\u0440\u0438\u0446\u0435\u0439 \u0437\u0430\u0442\u043C\u0435\u0432\u0430\u044E\u0449\u0438\u0445 \u0441\u043B\u043E\u0435\u0432-\u043A\u0430\u043D\u0447\u0443\u043A, \u0430 \u0438\u043C\u0435\u043D\u043D\u043E: \u0444\u0440\u0430\u0433\u043C\u0435\u043D\u0442\u0430\u0440\u043D\u043E\u0441\u0442\u044C\u044E <em>(kal\u0430)</em>, \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u044B\u043C \u0437\u043D\u0430\u043D\u0438\u0435\u043C <em>(vidy\u0430)</em>, \u0441\u0442\u0440\u0430\u0441\u0442\u044C\u044E <em>(r\u0430ga)</em>, \u0432\u0440\u0435\u043C\u0435\u043D\u0435\u043C <em>(k\u0430la)</em> \u0438 \u0443\u043F\u043E\u0440\u044F\u0434\u043E\u0447\u0435\u043D\u043D\u043E\u0441\u0442\u044C\u044E <em>(niyati)</em>. \u0418 \u0442\u043E\u043B\u044C\u043A\u043E \u0443\u0437\u043D\u0430\u0432\u0430\u043D\u0438\u0435 \u0435\u0434\u0438\u043D\u043E\u0439 \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u0438 \u0428\u0438\u0432\u044B, \u043A\u043E\u0442\u043E\u0440\u0430\u044F [\u0440\u0430\u0437\u0432\u0438\u0432\u0430\u0435\u0442\u0441\u044F] \u0432 \u0442\u0440\u0438\u0434\u0446\u0430\u0442\u044C \u043F\u044F\u0442\u044C \u0442\u0430\u0442\u0442\u0432, \u0441\u0435\u043C\u044C \u0441\u0443\u0431\u044A\u0435\u043A\u0442\u043E\u0432 \u043F\u043E\u0437\u043D\u0430\u043D\u0438\u044F, \u043F\u044F\u0442\u0435\u0440\u0438\u0446\u0443 \u0448\u0430\u043A\u0442\u0438 \u043D\u0430\u0447\u0438\u043D\u0430\u044F \u0441 \u0448\u0430\u043A\u0442\u0438 \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F \u2013 \u0442\u043E\u043B\u044C\u043A\u043E \u043E\u043D\u043E \u0434\u0430\u0440\u0443\u0435\u0442 \u043E\u0441\u0432\u043E\u0431\u043E\u0436\u0434\u0435\u043D\u0438\u0435, \u0432 \u043F\u0440\u043E\u0442\u0438\u0432\u043D\u043E\u043C \u0441\u043B\u0443\u0447\u0430\u0435 \u043E\u043D\u0430 [\u0441\u0442\u0430\u043B\u0430 \u0431\u044B] \u0438\u0441\u0442\u043E\u0447\u043D\u0438\u043A\u043E\u043C \u0441\u0430\u043D\u0441\u0430\u0440\u044B. \u0418 \u0442\u0430\u043A\u0436\u0435:</p></div><div class="stanza"><a href="#s8" id="s8" class="num">8</a><p class="sans">\u0924\u0926\u094D\u092D\u0942\u092E\u093F\u0915\u093E\u0903 \u0938\u0930\u094D\u0935\u0926\u0930\u094D\u0936\u0928\u0938\u094D\u0925\u093F\u0924\u092F\u0903 \u0965\u096E\u0965</p><p class="trans">Tadbh\u016Bmik\u0101\u1E25 sarvadar\u015Banasthitaya\u1E25 \u09658\u0965</p><p>\u0412\u043E\u0437\u0437\u0440\u0435\u043D\u0438\u044F <em>(sthitaya\u1E25)</em> \u0432\u0441\u0435\u0445 <em>(sarva)</em> \u0444\u0438\u043B\u043E\u0441\u043E\u0444\u0441\u043A\u0438\u0445 \u0441\u0438\u0441\u0442\u0435\u043C <em>(dar\u015Bana)</em> [\u0441\u0443\u0442\u044C \u043B\u0438\u0448\u044C \u0440\u0430\u0437\u043B\u0438\u0447\u043D\u044B\u0435] \u043E\u0431\u043B\u0438\u0447\u044C\u044F <em>(bh\u016Bmik\u0101\u1E25)</em> \u044D\u0442\u043E\u0439 <em>(tad)</em> [\u0420\u0435\u0430\u043B\u044C\u043D\u043E\u0441\u0442\u0438].</p><p class="eng"><strong>\u041A\u043E\u043C\u043C\u0435\u043D\u0442\u0430\u0440\u0438\u0439</strong><br> \xAB\u0412\u043E\u0437\u0437\u0440\u0435\u043D\u0438\u044F\xBB, \u0442. \u0435. \u043E\u0441\u043D\u043E\u0432\u043E\u043F\u043E\u043B\u043E\u0436\u0435\u043D\u0438\u044F \xAB\u0432\u0441\u0435\u0445 \u0434\u0430\u0440\u0448\u0430\u043D\xBB, \u043D\u0430\u0447\u0438\u043D\u0430\u044F \u0441 \u0447\u0430\u0440\u0432\u0430\u043A\u0438, \u0441\u0443\u0442\u044C \u043F\u0440\u0438\u043D\u0438\u043C\u0430\u0435\u043C\u044B\u0435 \u044D\u0442\u0438\u043C \u042F \u043F\u043E \u0441\u0432\u043E\u0435\u0439 \u0432\u043E\u043B\u0435 \u0438\u0441\u043A\u0443\u0441\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u0435 \xAB\u043E\u0431\u043B\u0438\u0447\u044C\u044F\xBB, \u043F\u043E\u0434\u043E\u0431\u043D\u044B\u0435 \u043E\u0431\u043B\u0438\u0447\u044C\u044F\u043C \u0430\u043A\u0442\u0435\u0440\u0430.</p><p class="eng">\u0422\u0430\u043A, \u0447\u0430\u0440\u0432\u0430\u043A\u0438 [\u0437\u0430\u044F\u0432\u043B\u044F\u044E\u0442], \u0447\u0442\u043E \u043E\u0442\u043B\u0438\u0447\u0438\u0442\u0435\u043B\u044C\u043D\u044B\u043C \u043F\u0440\u0438\u0437\u043D\u0430\u043A\u043E\u043C \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0435\u0433\u043E \u0442\u043E\u0436\u0434\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0441\u0442\u044C \u0442\u0435\u043B\u0443. \u041D\u0430\u0439\u044F\u0438\u043A\u0438 \u0438 \u0434\u0440\u0443\u0433\u0438\u0435 \u0441\u0447\u0438\u0442\u0430\u044E\u0442 \u042F, [\u043A\u043E\u0433\u0434\u0430 \u042F] \u043F\u043E\u0434\u0432\u0435\u0440\u0436\u0435\u043D\u043E \u0442\u0440\u0430\u043D\u0441\u043C\u0438\u0433\u0440\u0430\u0446\u0438\u0438, \u043F\u043E\u0447\u0442\u0438 \u0442\u0435\u043C \u0436\u0435 \u0441\u0430\u043C\u044B\u043C, \u0447\u0442\u043E \u0438 \u0431\u0443\u0434\u0434\u0445\u0438, \u043A\u043E\u0442\u043E\u0440\u044B\u0439 \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u043E\u0441\u043D\u043E\u0432\u043E\u0439 \u0437\u043D\u0430\u043D\u0438\u044F \u0438 \u0434\u0440\u0443\u0433\u0438\u0445 \u043A\u0430\u0447\u0435\u0441\u0442\u0432; \u043F\u0440\u0438 \u043E\u0441\u0432\u043E\u0431\u043E\u0436\u0434\u0435\u043D\u0438\u0438 \u0436\u0435, \u043A\u043E\u0433\u0434\u0430 \u0431\u0443\u0434\u0434\u0445\u0438 \u0438\u0441\u0447\u0435\u0437\u0430\u0435\u0442, [\u042F \u0440\u0430\u0441\u0441\u043C\u0430\u0442\u0440\u0438\u0432\u0430\u0435\u0442\u0441\u044F \u0438\u043C\u0438 \u043A\u0430\u043A] \u043F\u043E\u0447\u0442\u0438 \u0438\u0434\u0435\u043D\u0442\u0438\u0447\u043D\u043E\u0435 \u043F\u0443\u0441\u0442\u043E\u0442\u0435.\u041C\u0438\u043C\u0430\u043D\u0441\u0430\u043A\u0438 \u0442\u043E\u0436\u0435 \u0441\u0432\u044F\u0437\u044B\u0432\u0430\u044E\u0442 \u042F \u0441 \u0431\u0443\u0434\u0434\u0445\u0438, \u0441\u0447\u0438\u0442\u0430\u044F, \u0447\u0442\u043E \u0442\u043E, \u0447\u0442\u043E \u0438\u0437\u0432\u0435\u0441\u0442\u043D\u043E \u0432 \u043F\u0440\u0435\u0434\u0441\u0442\u0430\u0432\u043B\u0435\u043D\u0438\u0438 \u043E \xAB\u044F\xBB, \u0438\u0441\u043A\u0430\u0436\u0435\u043D\u043D\u043E\u043C \u043F\u0440\u0438\u0432\u043D\u0435\u0441\u0435\u043D\u0438\u0435\u043C [\u0432 \u043D\u0435\u0433\u043E] \u0443\u0434\u043E\u0432\u043E\u043B\u044C\u0441\u0442\u0432\u0438\u044F, \u0441\u0442\u0440\u0430\u0434\u0430\u043D\u0438\u044F \u0438 \u0442. \u0434., \u0438 \u0435\u0441\u0442\u044C \u042F.</p><p class="eng">\u0414\u043B\u044F \u0441\u0442\u043E\u0440\u043E\u043D\u043D\u0438\u043A\u043E\u0432 \u0421\u0443\u0433\u0430\u0442\u044B \u0438\u0441\u0442\u0438\u043D\u043E\u0439 \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u043F\u043E\u0442\u043E\u043A \u0437\u043D\u0430\u043D\u0438\u044F; \u0442\u0430\u043A\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C, \u043E\u043D\u0438 \u0442\u043E\u0436\u0435 [\u0441\u0432\u044F\u0437\u044B\u0432\u0430\u044E\u0442 \u042F] \u0441 \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u044F\u043C\u0438 \u0431\u0443\u0434\u0434\u0445\u0438. \u041D\u0435\u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u043F\u043E\u0441\u043B\u0435\u0434\u043E\u0432\u0430\u0442\u0435\u043B\u0438 \u0432\u0435\u0434\u0430\u043D\u0442\u044B [\u0441\u0447\u0438\u0442\u0430\u044E\u0442], \u0447\u0442\u043E \u042F \u2013 \u044D\u0442\u043E \u043F\u0440\u0430\u043D\u0430. \u0417\u043D\u0430\u0442\u043E\u043A\u0438 \u0411\u0440\u0430\u0445\u043C\u0430\u043D\u0430, \u0433\u043E\u0432\u043E\u0440\u044F, \u0447\u0442\u043E \xAB\u044D\u0442\u043E\u0442 [\u043C\u0438\u0440 \u043A\u043E\u0433\u0434\u0430-\u0442\u043E] \u043D\u0435 \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u043E\u0432\u0430\u043B\xBB \u0438 [\u0440\u0443\u043A\u043E\u0432\u043E\u0434\u0441\u0442\u0432\u0443\u044F\u0441\u044C \u0442\u0430\u043A\u043E\u0439 \u0438\u0434\u0435\u0435\u0439] \u043D\u0435\u0431\u044B\u0442\u0438\u044F, \u043F\u0440\u0438\u043D\u0438\u043C\u0430\u044E\u0442 \u043F\u0443\u0441\u0442\u043E\u0442\u0443 \u0437\u0430 \u043E\u0441\u043D\u043E\u0432\u043E\u043F\u043E\u043B\u0430\u0433\u0430\u044E\u0449\u0438\u0439 \u043F\u0440\u0438\u043D\u0446\u0438\u043F.</p><p class="eng">\u041C\u0430\u0434\u0445\u044C\u044F\u043C\u0438\u043A\u0438 \u0442\u0430\u043A\u0436\u0435 \u0441\u043E\u0433\u043B\u0430\u0441\u043D\u044B \u0441 \u044D\u0442\u043E\u0439 [\u043F\u043E\u0437\u0438\u0446\u0438\u0435\u0439]. \u041F\u0430\u043D\u0447\u0430\u0440\u0430\u0442\u0440\u0438\u043D\u044B [\u043F\u043E\u043B\u0430\u0433\u0430\u044E\u0442], \u0447\u0442\u043E \u0432\u044B\u0441\u0448\u0435\u0439 [\u043C\u0430\u0442\u0435\u0440\u0438\u0430\u043B\u044C\u043D\u043E\u0439] \u043F\u0440\u0438\u0447\u0438\u043D\u043E\u0439 \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0413\u043E\u0441\u043F\u043E\u0434\u044C \u0412\u0430\u0441\u0443\u0434\u0435\u0432\u0430, \u0430 \u043E\u0442\u0434\u0435\u043B\u044C\u043D\u044B\u0435 \u0434\u0443\u0448\u0438 \u043F\u043E\u0434\u043E\u0431\u043D\u044B \u0438\u0441\u043A\u0440\u0430\u043C \u043E\u0442 \u0435\u0433\u043E [\u043A\u043E\u0441\u0442\u0440\u0430] \u0438 \u0441\u0443\u0442\u044C \u0442\u0440\u0430\u043D\u0441\u0444\u043E\u0440\u043C\u0430\u0446\u0438\u0438 \u044D\u0442\u043E\u0439 \u0412\u044B\u0441\u0448\u0435\u0439 \u041F\u0440\u0438\u0447\u0438\u043D\u044B. \u0422\u0430\u043A [\u0441\u0447\u0438\u0442\u0430\u044F, \u043F\u0430\u043D\u0447\u0430\u0440\u0430\u0442\u0440\u0438\u043D\u044B] \u0446\u0435\u043F\u043B\u044F\u044E\u0442\u0441\u044F \u0437\u0430 \u043D\u0435\u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u043D\u043E\u0435. \u0421\u0430\u043D\u043A\u0445\u044C\u044F\u0438\u043A\u0438 \u0438 \u0438\u043C \u043F\u043E\u0434\u043E\u0431\u043D\u044B\u0435 \u043E\u0441\u0442\u0430\u043D\u0430\u0432\u043B\u0438\u0432\u0430\u044E\u0442\u0441\u044F \u043D\u0430 \u0443\u0440\u043E\u0432\u043D\u0435, \u043F\u0440\u0438\u0431\u043B\u0438\u0437\u0438\u0442\u0435\u043B\u044C\u043D\u043E \u0441\u043E\u043E\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0443\u044E\u0449\u0435\u043C \u0432\u0438\u0434\u0436\u043D\u044F\u043D\u0430\u043A\u0430\u043B\u0430\u043C.</p><p class="eng">\xAB\u0412\u043D\u0430\u0447\u0430\u043B\u0435 \u0431\u044B\u043B\u043E \u0442\u043E\u043B\u044C\u043A\u043E \u041E\u0434\u043D\u043E\xBB \u2013 \u0442\u0430\u043A \u043F\u0440\u0438\u0432\u044F\u0437\u044B\u0432\u0430\u044E\u0442\u0441\u044F \u043A \u043F\u0440\u0438\u043D\u0446\u0438\u043F\u0443 \u0418\u0448\u0432\u0430\u0440\u044B \u0434\u0440\u0443\u0433\u0438\u0435 \u0432\u0435\u0434\u0430\u043D\u0442\u0438\u0441\u0442\u044B. \u0413\u0440\u0430\u043C\u043C\u0430\u0442\u0438\u0441\u0442\u044B \u0434\u0443\u043C\u0430\u044E\u0442, \u0447\u0442\u043E \u042F \u2013 \u044D\u0442\u043E [\u043F\u0440\u0438\u043D\u0446\u0438\u043F] \u0428\u0430\u0431\u0434\u0430\u0431\u0440\u0430\u0445\u043C\u0430\u043D \u0432 \u0444\u043E\u0440\u043C\u0435 \u043F\u0430\u0448\u044C\u044F\u043D\u0442\u0438, [\u0442\u0435\u043C \u0441\u0430\u043C\u044B\u043C] \u0441\u0442\u0430\u0432\u044F \u0435\u0433\u043E \u043D\u0430 \u0443\u0440\u043E\u0432\u0435\u043D\u044C \u0421\u0430\u0434\u0430\u0448\u0438\u0432\u044B. \u0422\u0430\u043A \u0436\u0435 \u043C\u043E\u0436\u043D\u043E \u043F\u0440\u0435\u0434\u0441\u0442\u0430\u0432\u0438\u0442\u044C \u0438 \u0434\u0440\u0443\u0433\u0438\u0435 \u0441\u0438\u0441\u0442\u0435\u043C\u044B.</p><p class="eng">\u0422\u0430\u043A \u0433\u043E\u0432\u043E\u0440\u0438\u0442\u0441\u044F \u0432 \u0430\u0433\u0430\u043C\u0430\u0445: \xAB\u0411\u0443\u0434\u0434\u0438\u0441\u0442\u044B \u0432\u0438\u0434\u044F\u0442 [\u042F \u0432 \u043F\u0440\u0438\u043D\u0446\u0438\u043F\u0435] \u0431\u0443\u0434\u0434\u0445\u0438, \u0430\u0440\u0445\u0430\u0442\u044B \u2013 \u0432 \u043A\u043E\u043C\u0431\u0438\u043D\u0430\u0446\u0438\u0438 \u0433\u0443\u043D, \u0437\u043D\u0430\u0442\u043E\u043A\u0438 \u0432\u0435\u0434 \u2013 \u0432 \u041F\u0443\u0440\u0443\u0448\u0435, \u0430 \u043F\u0430\u043D\u0447\u0430\u0440\u0430\u0442\u0440\u0438\u043A\u0438 \u2013 \u0432 \u043D\u0435\u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u043D\u043E\u0441\u0442\u0438\xBB.</p><p class="eng">\u0422\u0430\u043D\u0442\u0440\u0438\u043A\u0438 [\u0443\u0442\u0432\u0435\u0440\u0436\u0434\u0430\u044E\u0442], \u0447\u0442\u043E \u042F \u0437\u0430\u043F\u0440\u0435\u0434\u0435\u043B\u044C\u043D\u043E \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u043E\u0439. \u041F\u0440\u0438\u043D\u0430\u0434\u043B\u0435\u0436\u0430\u0449\u0438\u0435 \u043A \u0442\u0440\u0430\u0434\u0438\u0446\u0438\u0438 \u043A\u0443\u043B\u0430 \u0443\u0432\u0435\u0440\u0435\u043D\u044B, \u0447\u0442\u043E [\u042F] \u0441\u043E\u0432\u043F\u0430\u0434\u0430\u0435\u0442 \u0441\u043E \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u043E\u0439. \u0417\u043D\u0430\u0442\u043E\u043A\u0438 \u0442\u0440\u0438\u043A\u0438 \u0438 \u0442. \u043F. [\u0443\u0442\u0432\u0435\u0440\u0436\u0434\u0430\u044E\u0442, \u0447\u0442\u043E \u042F \u043E\u0434\u043D\u043E\u0432\u0440\u0435\u043C\u0435\u043D\u043D\u043E] \u0438 \u043F\u0440\u0435\u0432\u043E\u0441\u0445\u043E\u0434\u0438\u0442 \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u0443\u044E, \u0438 \u0441\u043E\u0432\u043F\u0430\u0434\u0430\u0435\u0442 \u0441 \u043D\u0435\u0439.</p><p class="eng">\u0422\u0430\u043A\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C, \u0432\u0441\u0435 \u044D\u0442\u0438 \u0440\u043E\u043B\u0438 \u0440\u0430\u0437\u044B\u0433\u0440\u044B\u0432\u0430\u044E\u0442\u0441\u044F \u043E\u0442\u043D\u043E\u0441\u044F\u0449\u0435\u0439\u0441\u044F \u043A \u0411\u0445\u0430\u0433\u0430\u0432\u0430\u043D\u0443 \u2013 \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u044C\u044E \u043A\u043E\u0442\u043E\u0440\u043E\u0433\u043E \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u0435 \u2013 \u0435\u0433\u043E c\u0430\u043C\u043E\u0435\u0441\u0442\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0441\u0442\u044C\u044E (\u0441\u0432\u0430\u0442\u0430\u043D\u0442\u0440\u044C\u0435\u0439), \u0438 \u043E\u043D\u0438 \u0440\u0430\u0437\u043B\u0438\u0447\u0430\u044E\u0442\u0441\u044F [\u0434\u0440\u0443\u0433 \u043E\u0442 \u0434\u0440\u0443\u0433\u0430] \u0442\u043E\u043B\u044C\u043A\u043E \u043F\u043E \u0440\u0430\u0437\u043D\u044B\u043C \u0441\u0442\u0435\u043F\u0435\u043D\u044F\u043C \u0443\u043A\u0440\u044B\u0432\u0430\u043D\u0438\u044F \u0438\u043B\u0438 \u0440\u0430\u0441\u043A\u0440\u044B\u0442\u0438\u044F \u0441\u0432\u0430\u0442\u0430\u043D\u0442\u0440\u044C\u0438. \u041F\u043E\u044D\u0442\u043E\u043C\u0443 \u043E\u0434\u0438\u043D \u043B\u0438\u0448\u044C \u0410\u0442\u043C\u0430\u043D \u0438 \u0438\u0441\u043F\u043E\u043B\u043D\u044F\u0435\u0442 \u0432\u0441\u0435 \u044D\u0442\u0438 [\u0440\u043E\u043B\u0438]. \u041E\u0434\u043D\u0430\u043A\u043E, \u043D\u0430\u0434\u0435\u043B\u0435\u043D\u043D\u044B\u0435 \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u044B\u043C \u0432\u0438\u0434\u0435\u043D\u0438\u0435\u043C, \u0432\u0441\u0435 \u044D\u0442\u0438 \u043F\u0440\u0435\u0434\u044B\u0434\u0443\u0449\u0438\u0435 \u0441\u0443\u0431\u044A\u0435\u043A\u0442\u044B, \u043A\u043E\u0442\u043E\u0440\u044B\u0435, \u0441\u043E\u0433\u043B\u0430\u0441\u043D\u043E \u0415\u0433\u043E \u0432\u043E\u043B\u0435, [\u0432\u044B\u0440\u0430\u0436\u0430\u044E\u0442] \u043F\u043E-\u0441\u0432\u043E\u0435\u043C\u0443 \u0440\u0430\u0437\u043D\u044B\u0435 [\u0415\u0433\u043E] \u0443\u0440\u043E\u0432\u043D\u0438, \u043E\u0442\u043E\u0436\u0434\u0435\u0441\u0442\u0432\u043B\u044F\u044E\u0442 [\u042F] \u0441 \u0442\u0435\u043B\u043E\u043C \u0438 \u0442. \u0434., \u0446\u0435\u043F\u043B\u044F\u044E\u0442\u0441\u044F \u0437\u0430 \u043E\u0448\u0438\u0431\u043E\u0447\u043D\u044B\u0435 \u0432\u043E\u0437\u0437\u0440\u0435\u043D\u0438\u044F, \u0438 \u043D\u0435 \u0441\u043F\u043E\u0441\u043E\u0431\u043D\u044B \u043F\u043E\u043D\u044F\u0442\u044C \u0431\u0435\u0437 \u043D\u0438\u0441\u0445\u043E\u0436\u0434\u0435\u043D\u0438\u044F \u041F\u0430\u0440\u0430\u0448\u0430\u043A\u0442\u0438 \u0432\u0435\u043B\u0438\u043A\u043E\u0433\u043E \u043F\u0440\u043E\u043D\u0438\u0437\u044B\u0432\u0430\u043D\u0438\u044F [\u0432\u0435\u0449\u0435\u0439 \u0410\u0442\u043C\u0430\u043D\u043E\u043C], \u043E \u043A\u043E\u0442\u043E\u0440\u043E\u043C \u0433\u043E\u0432\u043E\u0440\u0438\u043B\u043E\u0441\u044C \u0432\u044B\u0448\u0435.</p><p class="eng">\u041A\u0430\u043A \u0431\u044B\u043B\u043E \u0441\u043A\u0430\u0437\u0430\u043D\u043E: \xAB\u0412\u0430\u0439\u0448\u043D\u0430\u0432\u044B \u0438 \u0434\u0440\u0443\u0433\u0438\u0435, \u043E\u043F\u0443\u0442\u0430\u043D\u043D\u044B\u0435 \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u044B\u043C \u0437\u043D\u0430\u043D\u0438\u0435\u043C \u0438 \u0441\u0442\u0440\u0430\u0441\u0442\u044C\u044E, \u043D\u0435 \u0432\u0435\u0434\u0430\u044E\u0442 \u0412\u044B\u0441\u0448\u0435\u0433\u043E \u0411\u043E\u0433\u0430, \u0432\u0441\u0435\u0437\u043D\u0430\u044E\u0449\u0435\u0433\u043E, \u043D\u0430\u0434\u0435\u043B\u0435\u043D\u043D\u043E\u0433\u043E \u0438\u0441\u0442\u0438\u043D\u043D\u044B\u043C \u0437\u043D\u0430\u043D\u0438\u0435\u043C\xBB.</p><p class="eng">\u0413\u043E\u0432\u043E\u0440\u0438\u0442\u0441\u044F \u0438 \u0442\u0430\u043A: \xAB\u041E\u0434\u043D\u0430 \u043B\u0438\u0448\u044C \u043C\u0430\u0439\u044F \u0437\u0430\u0441\u0442\u0430\u0432\u043B\u044F\u0435\u0442 \u0438\u0445, \u0436\u0435\u043B\u0430\u044E\u0449\u0438\u0445 \u043E\u0441\u0432\u043E\u0431\u043E\u0434\u0438\u0442\u044C\u0441\u044F, \u0431\u043B\u0443\u0436\u0434\u0430\u0442\u044C \u0432\u043E \u0442\u044C\u043C\u0435 \xBB. \u0413\u043E\u0432\u043E\u0440\u0438\u0442\u0441\u044F \u0435\u0449\u0435, [\u0447\u0442\u043E] \xAB\u0441\u0442\u043E\u0440\u043E\u043D\u043D\u0438\u043A\u0438 [\u043B\u043E\u0436\u043D\u043E \u043F\u043E\u043D\u044F\u0442\u043E\u0433\u043E] \u0410\u0442\u043C\u0430\u043D\u0430 \u043D\u0435 \u0434\u043E\u0441\u0442\u0438\u0433\u0430\u044E\u0442 \u0432\u044B\u0441\u0448\u0435\u0439 \u0441\u0442\u0443\u043F\u0435\u043D\u0438 \u0428\u0438\u0432\u044B\xBB. \u0414\u0430\u043B\u0435\u0435, [\u0435\u0441\u043B\u0438 \u043F\u043E\u043D\u0438\u043C\u0430\u0442\u044C] \u043F\u043E\u0434 \xAB\u0432\u0441\u0435\u043C\u0438 \u0434\u0430\u0440\u0448\u0430\u043D\u0430\u043C\u0438\xBB \u0441\u043E\u0432\u043E\u043A\u0443\u043F\u043D\u043E\u0441\u0442\u044C \u0437\u043D\u0430\u043D\u0438\u0439 \u043E \u0432\u043D\u0435\u0448\u043D\u0435\u043C (\xAB\u0433\u043E\u043B\u0443\u0431\u043E\u0435\xBB) \u0438 \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0435\u043C (\xAB\u0441\u0447\u0430\u0441\u0442\u044C\u0435\xBB), [\u0442\u043E \u043E\u043D\u0438], \u043E\u043A\u0430\u0437\u044B\u0432\u0430\u044F\u0441\u044C \u043D\u0430 \u0441\u0430\u043C\u043E\u043C \u0434\u0435\u043B\u0435 \xAB\u043F\u0440\u0435\u043A\u0440\u0430\u0449\u0435\u043D\u0438\u0435\u043C\xBB, \u0441\u0442\u0430\u043D\u043E\u0432\u044F\u0442\u0441\u044F \u0434\u043B\u044F \u0422\u043E\u0433\u043E, \u043A\u0442\u043E \u0438\u043C\u0435\u0435\u0442 \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u044C \u0441\u0433\u0443\u0441\u0442\u043A\u0430 \u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F-\u0431\u043B\u0430\u0436\u0435\u043D\u0441\u0442\u0432\u0430, \u0441\u0440\u0435\u0434\u0441\u0442\u0432\u0430\u043C\u0438 \u0415\u0433\u043E \u0441\u0430\u043C\u043E\u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u044F. \u0422\u0430\u043A\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C, \u0432\u0441\u0435\u0433\u0434\u0430, \u043A\u043E\u0433\u0434\u0430 \u0432\u043D\u0435\u0448\u043D\u044F\u044F \u0444\u043E\u0440\u043C\u0430 [\u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F] \u043F\u0440\u0438\u0445\u043E\u0434\u0438\u0442 \u043A \u0441\u0432\u043E\u0435\u0439 \u043E\u0441\u043D\u043E\u0432\u0435, \u0432\u043D\u0435\u0448\u043D\u0438\u0435 \u043E\u0431\u044A\u0435\u043A\u0442\u044B \u0438\u0441\u0447\u0435\u0437\u0430\u044E\u0442.</p><p class="eng">\u0423\u0441\u043F\u043E\u043A\u043E\u0435\u043D\u0438\u0435 \u0432\u043E \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0435\u043C [\u043F\u0440\u0438\u043D\u043E\u0441\u0438\u0442] \u0441\u0442\u0430\u0431\u0438\u043B\u044C\u043D\u043E\u0441\u0442\u044C; \u0437\u0430\u0442\u0435\u043C \u043A\u043E\u043D\u0442\u0438\u043D\u0443\u0430\u043B\u044C\u043D\u043E\u0441\u0442\u044C \u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F \u0440\u0430\u0437\u0432\u0435\u0440\u0442\u044B\u0432\u0430\u0435\u0442\u0441\u044F \u0437\u0430\u043D\u043E\u0432\u043E. \u0422\u0430\u043A \u044D\u0442\u0430 \u0432\u0435\u043B\u0438\u043A\u043E\u043B\u0435\u043F\u043D\u0430\u044F \u0422\u0443\u0440\u0438\u044F \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F, \u0441\u043E\u0435\u0434\u0438\u043D\u044F\u044E\u0449\u0430\u044F \u0432\u043E\u0435\u0434\u0438\u043D\u043E \u0442\u0432\u043E\u0440\u0435\u043D\u0438\u0435, \u0441\u043E\u0445\u0440\u0430\u043D\u0435\u043D\u0438\u0435 \u0438 \u0440\u0430\u0441\u0442\u0432\u043E\u0440\u0435\u043D\u0438\u0435, \u0432\u0435\u0447\u043D\u043E \u0441\u0432\u0435\u0440\u043A\u0430\u0435\u0442, \u0442\u043E \u0440\u0430\u0437\u0432\u043E\u0440\u0430\u0447\u0438\u0432\u0430\u044F \u0442\u0430\u0442\u0442\u0432\u044B \u0432 \u0442\u0432\u043E\u0440\u0435\u043D\u0438\u0438, \u0442\u043E \u0441\u0432\u043E\u0440\u0430\u0447\u0438\u0432\u0430\u044F \u0438\u0445, \u0438 \u0432\u0441\u0435\u0433\u0434\u0430 \u043E\u0441\u0442\u0430\u0432\u0430\u044F\u0441\u044C \u0438 \u043F\u043E\u043B\u043D\u043E\u0439, \u0438 \u043F\u0440\u043E\u0438\u0437\u0432\u043E\u0434\u044F\u0449\u0435\u0439, \u0438 \u0442\u043E\u0439 \u0438 \u0434\u0440\u0443\u0433\u043E\u0439 [\u0441\u0440\u0430\u0437\u0443], \u0438 \u043D\u0438 \u0442\u043E\u0439 \u0438 \u043D\u0435 \u0434\u0440\u0443\u0433\u043E\u0439 [\u0441\u0440\u0430\u0437\u0443].</p><p class="eng">\u041A\u0430\u043A \u0433\u043E\u0432\u043E\u0440\u0438\u0442\u0441\u044F \u0432 \u041F\u0440\u0430\u0442\u044C\u044F\u0431\u0445\u0438\u0434\u0436\u043D\u044F-\u0442\u0440\u0438\u043A\u0435, \xAB\u043A\u043E\u0433\u0434\u0430 [\u0428\u0430\u043A\u0442\u0438] \u043F\u043E\u0433\u043B\u043E\u0449\u0430\u0435\u0442 \u043E\u0431\u044A\u0435\u043A\u0442\u044B, [\u041E\u043D\u0430] \u043E\u0431\u0440\u0435\u0442\u0430\u0435\u0442 \u043F\u043E\u043B\u043D\u043E\u0442\u0443\xBB. \u0418 \u044D\u0442\u0430 \u0431\u043B\u0430\u0433\u043E\u0434\u0430\u0442\u043D\u0430\u044F [\u0428\u0430\u043A\u0442\u0438] \u0448\u0430\u0433 \u0437\u0430 \u0448\u0430\u0433\u043E\u043C \u0432\u0435\u0434\u0435\u0442 \u043A \u0441\u0432\u043E\u0435\u0439 \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u0438 \u043F\u043E\u0434\u0440\u0430\u0436\u0430\u044E\u0449\u0435\u0433\u043E \u0435\u0439 \u0432\u0435\u0440\u043D\u043E\u0433\u043E. \u0415\u0441\u043B\u0438 \u0410\u0442\u043C\u0430\u043D \u0441\u0443\u0449\u0435\u0441\u0442\u0432 \u0438\u043C\u0435\u0435\u0442 [\u0442\u0430\u043A\u043E\u0435] \u0432\u0435\u043B\u0438\u0447\u0438\u0435, \u043F\u043E\u0447\u0435\u043C\u0443, \u0441\u043F\u0440\u0430\u0448\u0438\u0432\u0430\u0435\u0442\u0441\u044F, \u043E\u043D \u0444\u0440\u0430\u0433\u043C\u0435\u043D\u0442\u0430\u0440\u0435\u043D, \u0441\u0442\u044F\u043D\u0443\u0442 \u0443\u0437\u0430\u043C\u0438, \u043E\u0431\u043B\u0435\u043F\u043B\u0435\u043D \u043D\u0435\u0447\u0438\u0441\u0442\u044B\u043C\u0438 \u0442\u0430\u0442\u0442\u0432\u0430\u043C\u0438, \u0431\u043B\u0443\u0436\u0434\u0430\u0435\u0442 \u0432 \u0441\u0430\u043D\u0441\u0430\u0440\u0435? \u041D\u0430 \u044D\u0442\u043E \u043E\u0442\u0432\u0435\u0447\u0430\u044E\u0442:</p></div><div class="stanza"><a href="#s9" id="s9" class="num">9</a><p class="sans">\u091A\u093F\u0926\u094D\u0935\u0924\u094D\u0924\u091A\u094D\u091B\u0915\u094D\u0924\u093F\u0938\u0919\u094D\u0915\u094B\u091A\u093E\u0928\u094D\u092E\u0932\u093E\u0935\u0943\u0924\u0903 \u0938\u0902\u0938\u093E\u0930\u0940 \u0965\u096F\u0965</p><p class="trans">Cidvattacchaktisa\u1E45koc\u0101nmal\u0101v\u1E5Bta\u1E25 sa\u1E41s\u0101r\u012B \u09659\u0965</p><p>\u0412\u0441\u043B\u0435\u0434\u0441\u0442\u0432\u0438\u0435 \u044D\u0442\u043E\u0433\u043E \u0441\u0443\u0436\u0435\u043D\u0438\u044F <em>(sa\u1E45koc\u0101t)</em> \u0421\u0438\u043B\u044B <em>(\u015Bakti)</em>, \u0442\u0430 <em>(tad)</em> \u041F\u043E\u043B\u043D\u043E\u0442\u0430 \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F <em>(cit-vat)</em>, [\u043F\u0440\u0435\u0432\u0440\u0430\u0449\u0430\u0435\u0442\u0441\u044F \u0432] \u0441\u0430\u043D\u0441\u0430\u0440\u0438\u0447\u0435\u0441\u043A\u043E\u0435 \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u043E <em>(sa\u1E41s\u0101r\u012B)</em>, \u0441\u043A\u043E\u0432\u0430\u043D\u043D\u043E\u0435 <em>(av\u1E5Bta\u1E25)</em> \u0443\u0437\u0430\u043C\u0438 <em>(mala)</em>.</p><p class="eng"><strong>\u041A\u043E\u043C\u043C\u0435\u043D\u0442\u0430\u0440\u0438\u0439</strong><br> \u041A\u043E\u0433\u0434\u0430 \u041F\u0430\u0440\u0430\u043C\u0435\u0448\u0432\u0430\u0440\u0430, \u0438\u043C\u0435\u044E\u0449\u0438\u0439 \xAB\u0441\u0443\u0449\u043D\u043E\u0441\u0442\u044C \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F\xBB, \u043F\u043E \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439 \u0412\u043E\u043B\u0435 \u043E\u0441\u0442\u0430\u043D\u0430\u0432\u043B\u0438\u0432\u0430\u044F \u0440\u0430\u0441\u0448\u0438\u0440\u0435\u043D\u0438\u0435 \u043D\u0435\u0440\u0430\u0437\u043B\u0438\u0447\u0435\u043D\u0438\u044F, \u043F\u0440\u043E\u0438\u0437\u0432\u043E\u0434\u0438\u0442 \u0440\u0430\u0437\u043B\u0438\u0447\u0435\u043D\u0438\u0435, \u0442\u043E\u0433\u0434\u0430 \xAB\u044D\u0442\u0438 \u0435\u0433\u043E \u0438\u0447\u0447\u0445\u0430 \u0438 \u0434\u0440\u0443\u0433\u0438\u0435 \u0448\u0430\u043A\u0442\u0438\xBB, \u0445\u043E\u0442\u044F [\u043F\u043E \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0443] \u043E\u043D\u0438 \u0438 \u043D\u0435\u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u044B, \u0441\u0442\u0430\u043D\u043E\u0432\u044F\u0442\u0441\u044F \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u044B\u043C\u0438. \u0422\u043E\u0433\u0434\u0430 \u0438 \u043F\u043E\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u044D\u0442\u043E \xAB\u0441\u0430\u043D\u0441\u0430\u0440\u0438\u0447\u0435\u0441\u043A\u043E\u0435 \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u043E, \u043E\u0442\u044F\u0433\u043E\u0449\u0435\u043D\u043D\u043E\u0435 \u0443\u0437\u0430\u043C\u0438\xBB. \u0422\u043E\u0433\u0434\u0430 \u0438\u0447\u0447\u0445\u0430-\u0448\u0430\u043A\u0442\u0438, \u0431\u0443\u0434\u0443\u0447\u0438 \u043F\u043E \u043F\u0440\u0438\u0440\u043E\u0434\u0435 \u0441\u0432\u043E\u0435\u0439 \u043D\u0435 \u0432\u0441\u0442\u0440\u0435\u0447\u0430\u044E\u0449\u0435\u0439 \u043F\u043E\u043C\u0435\u0445 \u0410\u0431\u0441\u043E\u043B\u044E\u0442\u043D\u043E\u0439 \u0412\u043E\u043B\u0435\u0439, \u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u0441\u044F \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u043E\u0439, \u0438 \u044D\u0442\u043E \u0435\u0441\u0442\u044C \u0430\u043D\u0430\u0432\u0430-\u043C\u0430\u043B\u0430, [\u043A\u043E\u0442\u043E\u0440\u0430\u044F \u0441\u043E\u0441\u0442\u043E\u0438\u0442] \u0432 \u043F\u043E\u043D\u0438\u043C\u0430\u043D\u0438\u0438 [\u0441\u0435\u0431\u044F] \u043A\u0430\u043A \u043D\u0435\u0441\u043E\u0432\u0435\u0440\u0448\u0435\u043D\u043D\u043E\u0433\u043E. \u0414\u0436\u043D\u044F\u043D\u0430-\u0448\u0430\u043A\u0442\u0438, \u043F\u043E\u0441\u0442\u0435\u043F\u0435\u043D\u043D\u043E \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0438\u0432\u0430\u044F \u0441\u0435\u0431\u044F \u0432 \u043C\u0438\u0440\u0435 \u043E\u0431\u043E\u0441\u043E\u0431\u043B\u0435\u043D\u043D\u043E\u0441\u0442\u0438, \u0440\u0435\u0434\u0443\u0446\u0438\u0440\u0443\u0435\u0442 \u0441\u0432\u043E\u0435 \u0432\u0441\u0435\u0437\u043D\u0430\u043D\u0438\u0435 \u0434\u043E \u0437\u043D\u0430\u043D\u0438\u044F \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u043E\u0433\u043E. \u041E\u043A\u043E\u043D\u0447\u0430\u0442\u0435\u043B\u044C\u043D\u043E \u0441\u0443\u0436\u0438\u0432\u0430\u044F\u0441\u044C, \u043E\u043D\u0430 \u043F\u0440\u0438\u043E\u0431\u0440\u0435\u0442\u0430\u0435\u0442 \u043A\u043E\u043C\u043F\u043B\u0435\u043A\u0441 \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0438\u0445 \u043E\u0440\u0433\u0430\u043D\u043E\u0432, [\u043F\u0440\u0435\u0436\u0434\u0435 \u0432\u0441\u0435\u0433\u043E] \u0438\u043D\u0442\u0435\u043B\u043B\u0435\u043A\u0442, [\u0430 \u0442\u0430\u043A\u0436\u0435] \u0441\u043F\u043E\u0441\u043E\u0431\u043D\u043E\u0441\u0442\u044C \u0432\u043E\u0441\u043F\u0440\u0438\u044F\u0442\u0438\u044F, \u0438 \u043E\u0442\u044F\u0433\u043E\u0449\u0430\u0435\u0442\u0441\u044F \u043C\u0430\u0439\u0438\u044F-\u043C\u0430\u043B\u043E\u0439, \u0442. \u0435. \u0432\u0438\u0434\u0435\u043D\u0438\u0435\u043C \u0432\u0441\u0435\u0445 \u043E\u0431\u044A\u0435\u043A\u0442\u043E\u0432 \u043A\u0430\u043A \u0440\u0430\u0437\u043B\u0438\u0447\u043D\u044B\u0445. \u041A\u0440\u0438\u044F-\u0448\u0430\u043A\u0442\u0438 \u043F\u043E\u0441\u0442\u0435\u043F\u0435\u043D\u043D\u043E \u0432 \u043C\u0438\u0440\u0435 \u0440\u0430\u0437\u0434\u0435\u043B\u0435\u043D\u0438\u0439 \u0440\u0435\u0434\u0443\u0446\u0438\u0440\u0443\u0435\u0442 [\u0441\u0432\u043E\u044E \u0441\u043F\u043E\u0441\u043E\u0431\u043D\u043E\u0441\u0442\u044C] \u043D\u0435\u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u043E\u0433\u043E \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u044F \u0434\u043E \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u043E\u0433\u043E. \u041D\u0430\u0447\u0438\u043D\u0430\u044F \u0441\u0443\u0436\u0435\u043D\u0438\u0435 \u0441 \u043F\u0440\u0438\u043D\u044F\u0442\u0438\u044F \u043E\u0440\u0433\u0430\u043D\u043E\u0432 \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u044F, \u0432 \u043A\u043E\u043D\u0446\u0435 \u043A\u043E\u043D\u0446\u043E\u0432 [\u043E\u043D\u0430] \u043E\u0447\u0435\u043D\u044C \u0441\u0438\u043B\u044C\u043D\u043E \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0438\u0432\u0430\u0435\u0442\u0441\u044F, \u043E\u043A\u0443\u0442\u044B\u0432\u0430\u044F\u0441\u044C \u043A\u0430\u0440\u043C\u0430-\u043C\u0430\u043B\u043E\u0439, \u043A\u043E\u0442\u043E\u0440\u0430\u044F \u0441\u043E\u0441\u0442\u043E\u0438\u0442 \u0432 \u0441\u043E\u0432\u0435\u0440\u0448\u0435\u043D\u0438\u0438 \u0447\u0438\u0441\u0442\u044B\u0445 \u0438 \u043D\u0435\u0447\u0438\u0441\u0442\u044B\u0445 [\u0434\u0435\u044F\u043D\u0438\u0439]. \u0422\u0430\u043A\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C, \u0442\u0435 \u0448\u0430\u043A\u0442\u0438, \u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0438\u0432\u0430\u044E\u0442 \u0441\u0432\u043E\u0438 [\u0430\u0441\u043F\u0435\u043A\u0442\u044B] \u0432\u0441\u0435\u043C\u043E\u0433\u0443\u0449\u0435\u0441\u0442\u0432\u0430, \u0432\u0441\u0435\u0437\u043D\u0430\u043D\u0438\u044F, \u0441\u043E\u0432\u0435\u0440\u0448\u0435\u043D\u0441\u0442\u0432\u0430, \u0432\u0435\u0447\u043D\u043E\u0441\u0442\u0438, \u0432\u0435\u0437\u0434\u0435\u0441\u0443\u0449\u043D\u043E\u0441\u0442\u0438, \u043F\u0440\u0438\u043D\u0438\u043C\u0430\u044E\u0442 \u0441\u043E\u043E\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0435\u043D\u043D\u043E \u0430\u0441\u043F\u0435\u043A\u0442\u044B \u0444\u0440\u0430\u0433\u043C\u0435\u043D\u0442\u0430\u0440\u043D\u043E\u0441\u0442\u0438, \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u043E\u0433\u043E \u0437\u043D\u0430\u043D\u0438\u044F, \u0441\u0442\u0440\u0430\u0441\u0442\u043D\u043E\u0441\u0442\u0438, \u0432\u0440\u0435\u043C\u0435\u043D\u0438 \u0438 \u0443\u043F\u043E\u0440\u044F\u0434\u043E\u0447\u0435\u043D\u043D\u043E\u0441\u0442\u0438. \u041F\u043E\u044D\u0442\u043E\u043C\u0443 \u0438 \u043D\u0430\u0437\u044B\u0432\u0430\u0435\u0442\u0441\u044F \u044D\u0442\u043E\u0442 [\u0447\u0435\u043B\u043E\u0432\u0435\u043A], \u043B\u0438\u0448\u0435\u043D\u043D\u044B\u0439 \u0428\u0430\u043A\u0442\u0438, \u0441\u0430\u043D\u0441\u0430\u0440\u043D\u044B\u043C. \u041E\u0434\u043D\u0430\u043A\u043E \u0435\u0441\u043B\u0438 \u0435\u0433\u043E \u0448\u0430\u043A\u0442\u0438 \u0440\u0430\u0441\u043A\u0440\u043E\u044E\u0442\u0441\u044F, \u0442\u043E\u0433\u0434\u0430 [\u043E\u043D] \u2013 \u0441\u0430\u043C \u0428\u0438\u0432\u0430.</p><p class="eng">\u0422\u0443\u0442 \u0432\u043E\u0437\u043D\u0438\u043A\u0430\u0435\u0442 \u0432\u043E\u043F\u0440\u043E\u0441: \u043C\u043E\u0436\u043D\u043E \u043B\u0438 \u0443\u0437\u043D\u0430\u0442\u044C \u0428\u0438\u0432\u0443 \u043F\u043E \u043A\u0430\u043A\u043E\u043C\u0443-\u043D\u0438\u0431\u0443\u0434\u044C \u043F\u0440\u0438\u0437\u043D\u0430\u043A\u0443, \u043D\u0430\u0445\u043E\u0434\u044F\u0441\u044C \u0434\u0430\u0436\u0435 \u0432 \u0442\u0430\u043A\u043E\u043C \u0432\u043E\u0442 \u0441\u0430\u043D\u0441\u0430\u0440\u0438\u0447\u0435\u0441\u043A\u043E\u043C \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0438? \xAB\u041C\u043E\u0436\u043D\u043E\xBB, [\u043E\u0442\u0432\u0435\u0447\u0430\u0435\u043C], \u0438 \u0432\u043E\u0442 \u043F\u043E\u0447\u0435\u043C\u0443 \u2013</p></div><div class="stanza"><a href="#s10" id="s10" class="num">10</a><p class="sans">\u0924\u0925\u093E\u092A\u093F \u0924\u0926\u094D\u0935\u0924\u094D\u092A\u091E\u094D\u091A\u0915\u0943\u0924\u094D\u092F\u093E\u0928\u093F \u0915\u0930\u094B\u0924\u093F \u0965\u0967\u0966\u0965</p><p class="trans">Tath\u0101pi tadvatpa\xF1cak\u1E5Bty\u0101ni karoti \u096510\u0965</p><p>\u041D\u043E \u0434\u0430\u0436\u0435 <em>(api)</em> \u0432 \u044D\u0442\u043E\u043C \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0438 <em>(tath\u0101)</em> [\u0438\u043D\u0434\u0438\u0432\u0438\u0434] \u0441\u043E\u0432\u0435\u0440\u0448\u0430\u0435\u0442 <em>(karoti)</em> \u0442\u0435 \u0436\u0435 \u043F\u044F\u0442\u044C <em>(pa\xF1ca)</em> \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0439 <em>(k\u1E5Bty\u0101ni)</em>, \u0447\u0442\u043E \u0438 <em>(vat)</em> \u0422\u043E [\u0412\u044B\u0441\u0448\u0435\u0435 \u042F] <em>(tad)</em>.</p><p class="eng"><strong>\u041A\u043E\u043C\u043C\u0435\u043D\u0442\u0430\u0440\u0438\u0439</strong><br> \u0417\u0434\u0435\u0441\u044C \u0440\u0430\u0437\u043B\u0438\u0447\u0438\u0435 \u0441\u0438\u0441\u0442\u0435\u043C\u044B \u0442\u0440\u0438\u043A\u0430 \u043E\u0442 \u0431\u0440\u0430\u0445\u043C\u0430\u0432\u0430\u0434\u044B \u0437\u0430\u043A\u043B\u044E\u0447\u0430\u0435\u0442\u0441\u044F \u0432 \u0442\u043E\u043C, \u0447\u0442\u043E \u0411\u0445\u0430\u0433\u0430\u0432\u0430\u043D, \u043F\u0440\u0438\u0440\u043E\u0434\u0430 \u043A\u043E\u0442\u043E\u0440\u043E\u0433\u043E \u0441\u043E\u0441\u0442\u043E\u0438\u0442 \u0432 C\u043E\u0437\u043D\u0430\u043D\u0438\u0438, \u0432\u0441\u0435\u0433\u0434\u0430 \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u043F\u0440\u0438\u0447\u0438\u043D\u043E\u0439 \u043F\u044F\u0442\u0438 \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0439, \u043E \u0447\u0435\u043C \u0433\u043E\u0432\u043E\u0440\u0438\u0442\u0441\u044F \u0432 \u0421\u0432\u0430\u0447\u0447\u0445\u0430\u043D\u0434\u0430-[\u0442\u0430\u043D\u0442\u0440\u0435] \u0438 \u0432 \u0434\u0440\u0443\u0433\u0438\u0445 \u0441\u0432\u044F\u0449\u0435\u043D\u043D\u044B\u0445 \u0442\u0435\u043A\u0441\u0442\u0430\u0445, \u0430 \u0438\u043C\u0435\u043D\u043D\u043E: \xAB[\u041F\u043E\u043A\u043B\u043E\u043D\u044F\u044E\u0441\u044C] \u0411\u043E\u0433\u0443, [\u043A\u043E\u0442\u043E\u0440\u044B\u0439] \u0432\u044B\u0437\u044B\u0432\u0430\u0435\u0442 \u0442\u0432\u043E\u0440\u0435\u043D\u0438\u0435, \u043F\u043E\u0433\u043B\u043E\u0449\u0435\u043D\u0438\u0435, \u0441\u0430\u043C\u043E\u0441\u043E\u043A\u0440\u044B\u0442\u0438\u0435, \u0441\u043E\u0445\u0440\u0430\u043D\u0435\u043D\u0438\u0435, \u043D\u0438\u0441\u043F\u043E\u0441\u044B\u043B\u0430\u043D\u0438\u0435 \u043C\u0438\u043B\u043E\u0441\u0442\u0438 \u0438 [\u043A\u043E\u0442\u043E\u0440\u044B\u0439] \u0443\u0434\u0430\u043B\u044F\u0435\u0442 [\u0433\u0440\u0435\u0445\u0438 \u0442\u0435\u0445, \u043A\u0442\u043E] \u043F\u043E\u043A\u043B\u043E\u043D\u0438\u043B\u0441\u044F [\u0435\u043C\u0443]\xBB. \u0418 \u043A\u0430\u043A \u0411\u0445\u0430\u0433\u0430\u0432\u0430\u043D \u0432 \u043F\u0440\u043E\u0446\u0435\u0441\u0441\u0435 \xAB\u043D\u0435\u0447\u0438\u0441\u0442\u043E\u0433\u043E \u043F\u0443\u0442\u0438\xBB \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u043F\u0440\u0438\u0447\u0438\u043D\u043E\u0439 \u0442\u0432\u043E\u0440\u0435\u043D\u0438\u044F \u0438 \u0434\u0440\u0443\u0433\u0438\u0445 \u043C\u0430\u043D\u0438\u0444\u0435\u0441\u0442\u0430\u0446\u0438\u0439 \u0421\u0432\u043E\u0435\u0439 \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u0438, \u0442\u0430\u043A \u0434\u0430\u0436\u0435 \u043D\u0430 \u0443\u0440\u043E\u0432\u043D\u0435 \u0441\u0430\u043D\u0441\u0430\u0440\u044B, \u043A\u043E\u0433\u0434\u0430 \u0415\u0433\u043E \u0421\u0438\u043B\u0430 \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u0430, \u0438\u0441\u043F\u043E\u043B\u043D\u044F\u0435\u0442 \u041E\u043D \xAB\u043F\u044F\u0442\u044C \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0439\xBB. \u0413\u043E\u0432\u043E\u0440\u0438\u0442\u0441\u044F [\u0432 \u041F\u0440\u0430\u0442\u044C\u044F\u0431\u0445\u0438\u0434\u0436\u043D\u044F-\u043A\u0430\u0440\u0438\u043A\u0435]: \xAB\u0442\u0430\u043A\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C, \u0434\u0430\u0436\u0435 \u0432 \u044D\u043C\u043F\u0438\u0440\u0438\u0447\u0435\u0441\u043A\u043E\u043C \u043C\u0438\u0440\u0435 \u0413\u043E\u0441\u043F\u043E\u0434\u044C, \u0432\u0445\u043E\u0434\u044F \u0432 \u0442\u0435\u043B\u043E \u0438 \u0442. \u043F., \u0437\u0430\u0441\u0442\u0430\u0432\u043B\u044F\u0435\u0442 \u043E\u0431\u044A\u0435\u043A\u0442\u044B \u043F\u043E\u044F\u0432\u0438\u0442\u044C\u0441\u044F \u0432\u043E\u0432\u043D\u0435 \u043F\u043E \u0421\u0432\u043E\u0435\u0439 \u0432\u043E\u043B\u0435, \u0445\u043E\u0442\u044F \u043E\u043D\u0438, \u0432 \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u0438, \u043D\u0430\u0445\u043E\u0434\u044F\u0442\u0441\u044F \u0432 \u041D\u0435\u043C\xBB.</p><p class="eng">\u0412 \u0442\u043E\u043C \u0436\u0435 \u043F\u0440\u043E\u0438\u0437\u0432\u0435\u0434\u0435\u043D\u0438\u0438 \u0441\u043A\u0430\u0437\u0430\u043D\u043E, \u0447\u0442\u043E \u043A\u043E\u0433\u0434\u0430 \u0412\u0435\u043B\u0438\u043A\u0438\u0439 \u0418\u0448\u0432\u0430\u0440\u0430, \u0444\u043E\u0440\u043C\u0430 \u043A\u043E\u0442\u043E\u0440\u043E\u0433\u043E \u2013 \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u0435, \u0432\u0441\u0442\u0443\u043F\u0430\u0435\u0442 \u0432 \u0441\u0444\u0435\u0440\u0443 \u0442\u0435\u043B\u0430, \u043F\u0440\u0430\u043D\u044B \u0438 \u0442. \u043F. \u0438 \u043F\u043E \u043F\u0440\u0438\u0447\u0438\u043D\u0435 \u043E\u0431\u0440\u0430\u0449\u0435\u043D\u043D\u043E\u0441\u0442\u0438 \u043A\u043E \u0432\u043D\u0435\u0448\u043D\u0435\u043C\u0443 \u043F\u0440\u043E\u044F\u0432\u043B\u044F\u0435\u0442 \u043E\u0431\u044A\u0435\u043A\u0442\u044B, \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u044B\u0435 \u043F\u0440\u043E\u0441\u0442\u0440\u0430\u043D\u0441\u0442\u0432\u043E\u043C, \u0432\u0440\u0435\u043C\u0435\u043D\u0435\u043C \u0438 \u0442. \u0434., \u0442\u0438\u043F\u0430 \u0433\u043E\u043B\u0443\u0431\u043E\u0433\u043E [\u0446\u0432\u0435\u0442\u0430] \u0438 \u0434\u0440., \u044D\u0442\u043E [\u043D\u0430\u0437\u044B\u0432\u0430\u0435\u0442\u0441\u044F] \u0430\u043A\u0442\u043E\u043C \u0442\u0432\u043E\u0440\u0435\u043D\u0438\u044F; \u0432 \u043E\u0442\u043D\u043E\u0448\u0435\u043D\u0438\u0438 \u043A \u044F\u0432\u043B\u0435\u043D\u0438\u044F\u043C \u043E\u0431\u044A\u0435\u043A\u0442\u043E\u0432 \u0432 \u0434\u0440\u0443\u0433\u043E\u043C \u043F\u0440\u043E\u0441\u0442\u0440\u0430\u043D\u0441\u0442\u0432\u0435, \u0432\u0440\u0435\u043C\u0435\u043D\u0438 \u0438 \u0442. \u0434. \u2013 \u044D\u0442\u043E \u0440\u0430\u0441\u0442\u0432\u043E\u0440\u0435\u043D\u0438\u0435; \u0432 \u043E\u0442\u043D\u043E\u0448\u0435\u043D\u0438\u0438 \u043A \u043F\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u044E \u0433\u043E\u043B\u0443\u0431\u043E\u0433\u043E \u0438 \u0442. \u043F. [\u0438 \u0438\u0445 \u0441\u043E\u0445\u0440\u0430\u043D\u0435\u043D\u0438\u044F] \u2013 \u044D\u0442\u043E \u043F\u043E\u0434\u0434\u0435\u0440\u0436\u0430\u043D\u0438\u0435;</p><p class="eng">\u0432 \u043E\u0442\u043D\u043E\u0448\u0435\u043D\u0438\u0438 \u043A [\u0438\u0445] \u043F\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u044E \u043A\u0430\u043A \u0438\u043D\u043E\u0433\u043E \u2013 \u0441\u043E\u043A\u0440\u044B\u0442\u0438\u0435; \u0432 \u043E\u0442\u043D\u043E\u0448\u0435\u043D\u0438\u0438 \u043A [\u0438\u0445] \u0438\u0434\u0435\u043D\u0442\u0438\u0447\u043D\u043E\u0441\u0442\u0438 \u0421\u0432\u0435\u0442\u0443 \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F \u2013 \u043C\u0438\u043B\u043E\u0441\u0442\u044C. \u0410 \u043A\u0430\u043A\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C \u0411\u0445\u0430\u0433\u0430\u0432\u0430\u043D \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u043F\u0440\u0438\u0447\u0438\u043D\u043E\u0439 \u043F\u044F\u0442\u0435\u0440\u0438\u0446\u044B [\u0431\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u0445] \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0439, \u044D\u0442\u043E \u043C\u043D\u043E\u044E \u043F\u043E\u0434\u0440\u043E\u0431\u043D\u043E \u0440\u0430\u0437\u043E\u0431\u0440\u0430\u043D\u043E \u0432 \u0421\u043F\u0430\u043D\u0434\u0430\u0441\u0430\u043D\u0434\u043E\u0445\u0435.</p><p class="eng">\u0422\u0430\u043A\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C, \u0435\u0441\u043B\u0438 \u0438\u0441\u043A\u0440\u0435\u043D\u043D\u0438\u0439 \u043F\u0440\u0430\u043A\u0442\u0438\u043A\u0443\u044E\u0449\u0438\u0439 \u043F\u043E\u0441\u0442\u043E\u044F\u043D\u043D\u043E \u0444\u0438\u043A\u0441\u0438\u0440\u0443\u0435\u0442 [\u0441\u0432\u043E\u0435] \u0432\u043D\u0438\u043C\u0430\u043D\u0438\u0435 \u043D\u0430 \u0444\u0443\u043D\u043A\u0446\u0438\u043E\u043D\u0438\u0440\u043E\u0432\u0430\u043D\u0438\u0435 \u044D\u0442\u043E\u0439 \u043F\u044F\u0442\u0435\u0440\u0438\u0447\u043D\u043E\u0441\u0442\u0438 \u0432 \u0441\u0430\u043C\u043E\u043C \u0441\u0435\u0431\u0435, \u0412\u0435\u043B\u0438\u043A\u0430\u044F \u0418\u0448\u0432\u0430\u0440\u0438 \u043E\u0431\u044F\u0437\u0430\u0442\u0435\u043B\u044C\u043D\u043E \u043E\u0442\u043A\u0440\u043E\u0435\u0442 [\u0435\u043C\u0443] \u0421\u0435\u0431\u044F. \u041F\u043E\u044D\u0442\u043E\u043C\u0443 \u0442\u0435, \u043A\u0442\u043E \u0432\u0441\u0435\u0433\u0434\u0430 \u0441\u043E\u0441\u0440\u0435\u0434\u043E\u0442\u043E\u0447\u0435\u043D \u043D\u0430 \u044D\u0442\u043E\u0439 [\u0431\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439 \u043F\u044F\u0442\u0438\u0440\u0438\u0446\u0435], \u044F\u0432\u043B\u044F\u044E\u0442\u0441\u044F \u043E\u0441\u0432\u043E\u0431\u043E\u0436\u0434\u0435\u043D\u043D\u044B\u043C\u0438 \u043F\u0440\u0438 \u0436\u0438\u0437\u043D\u0438, \u0437\u043D\u0430\u044E\u0449\u0438\u043C\u0438 \u0421\u0443\u0449\u043D\u043E\u0441\u0442\u044C, \u043F\u0440\u043E\u044F\u0432\u043B\u044F\u044E\u0449\u0443\u044E \u0421\u0435\u0431\u044F \u0432\u043E \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u043E\u0439 \u2013 \u0442\u0430\u043A [\u0433\u043B\u0430\u0441\u0438\u0442] \u0441\u0430\u043A\u0440\u0430\u043B\u044C\u043D\u0430\u044F [\u0442\u0440\u0430\u0434\u0438\u0446\u0438\u044F].</p><p class="eng">\u0422\u0435 \u0436\u0435, \u043A\u0442\u043E \u0442\u0430\u043A \u043D\u0435 [\u043F\u0440\u0430\u043A\u0442\u0438\u043A\u0443\u0435\u0442], \u043A\u0442\u043E \u0441\u0447\u0438\u0442\u0430\u0435\u0442 \u043E\u0431\u044A\u0435\u043A\u0442\u044B \u0447\u0443\u0432\u0441\u0442\u0432 \u043E\u0431\u043E\u0441\u043E\u0431\u043B\u0435\u043D\u043D\u044B\u043C\u0438, \u0432\u0441\u0435\u0433\u0434\u0430 \u043E\u0441\u0442\u0430\u044E\u0442\u0441\u044F \u0432\u043E \u0442\u044C\u043C\u0435.</p><p class="eng">\u041D\u043E \u043D\u0435 \u0442\u043E\u043B\u044C\u043A\u043E \u0442\u0430\u043A [\u0444\u0443\u043D\u043A\u0446\u0438\u043E\u043D\u0438\u0440\u0443\u0435\u0442] \u043F\u044F\u0442\u0435\u0440\u0438\u0446\u0430 [\u0431\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u0445] \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0439 \u2013 \u0435\u0441\u0442\u044C \u0438 \u0434\u0440\u0443\u0433\u043E\u0439, \u0442\u0430\u0439\u043D\u044B\u0439 \u0441\u043F\u043E\u0441\u043E\u0431.</p><p class="eng">\u041E \u043D\u0435\u043C [\u0430\u0432\u0442\u043E\u0440] \u0433\u043E\u0432\u043E\u0440\u0438\u0442:</p></div><div class="stanza"><a href="#s11" id="s11" class="num">11</a><p class="sans">\u0906\u092D\u093E\u0938\u0928\u0930\u0915\u094D\u0924\u093F\u0935\u093F\u092E\u0930\u094D\u0936\u0928\u092C\u0940\u091C\u093E\u0935\u0938\u094D\u0925\u093E\u092A\u0928\u0935\u093F\u0932\u093E\u092A\u0928\u0924\u0938\u094D\u0924\u093E\u0928\u093F \u0965\u0967\u0967\u0965</p><p class="trans">\u0100bh\u0101sanaraktivimar\u015Banab\u012Bj\u0101vasth\u0101panavil\u0101panatast\u0101ni \u096511\u0965</p><p>\u041E\u043D\u0438 <em>(t\u0101ni)</em> \u0442\u0430\u043A\u0438\u0435 <em>(ta\u1E25)</em>: \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u0435 <em>(\u0101bh\u0101sana)</em>, \u043D\u0430\u0441\u043B\u0430\u0436\u0434\u0435\u043D\u0438\u0435 <em>(rakti)</em>, \u0441\u0430\u043C\u043E\u0441\u043E\u0437\u043D\u0430\u043D\u0438\u0435 <em>(vimar\u015Bana)</em>, \u0441\u0435\u044F\u043D\u0438\u0435 \u0441\u0435\u043C\u0435\u043D\u0438 <em>(b\u012Bja-avasth\u0101pana)</em>, \u0440\u0430\u0441\u0442\u0432\u043E\u0440\u0435\u043D\u0438\u0435 <em>(vil\u0101pana)</em>.</p><p class="eng"><strong>\u041A\u043E\u043C\u043C\u0435\u043D\u0442\u0430\u0440\u0438\u0439</strong><br> \xAB\u0418\u0441\u043F\u043E\u043B\u043D\u044F\u0435\u0442 \u043F\u044F\u0442\u044C \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0439\xBB \u2013 \u044D\u0442\u043E \u0441\u0432\u044F\u0437\u0430\u043D\u043E \u0441 \u043F\u0440\u0435\u0434\u044B\u0434\u0443\u0449\u0438\u043C [\u0438\u0437\u043B\u043E\u0436\u0435\u043D\u0438\u0435\u043C]. \u0421 \u0442\u043E\u0447\u043A\u0438 \u0437\u0440\u0435\u043D\u0438\u044F \u0432\u044B\u0441\u0448\u0435\u0439 \u0434\u043E\u043A\u0442\u0440\u0438\u043D\u044B, [\u043E\u0431\u044A\u0435\u043A\u0442\u044B] \u043F\u0440\u043E\u044F\u0432\u043B\u044F\u044E\u0442\u0441\u044F [\u0432 \u043C\u0438\u0440\u0435] \u0431\u043B\u0430\u0433\u043E\u0434\u0430\u0440\u044F \u043F\u043E\u0441\u0442\u0435\u043F\u0435\u043D\u043D\u043E\u043C\u0443 \u0440\u0430\u0437\u0432\u0435\u0440\u0442\u044B\u0432\u0430\u043D\u0438\u044E \u0431\u043E\u0433\u0438\u043D\u0438 \u0437\u0440\u0435\u043D\u0438\u044F \u0438 [\u0431\u043E\u0433\u0438\u043D\u044C] \u0434\u0440\u0443\u0433\u0438\u0445 [\u043E\u0440\u0433\u0430\u043D\u043E\u0432 \u0447\u0443\u0432\u0441\u0442\u0432]. \u0411\u043E\u0433\u0438\u043D\u044F \u043F\u043E\u0434\u0434\u0435\u0440\u0436\u0430\u043D\u0438\u044F \u0434\u0435\u0439\u0441\u0442\u0432\u0443\u0435\u0442 \u0442\u043E\u0433\u0434\u0430, \u043A\u043E\u0433\u0434\u0430 [\u042F] \u043D\u0430\u0441\u043B\u0430\u0436\u0434\u0430\u0435\u0442\u0441\u044F \u043E\u0431\u044A\u0435\u043A\u0442\u0430\u043C\u0438 \u0443\u0440\u043E\u0432\u043D\u044F \u0442\u0432\u043E\u0440\u0435\u043D\u0438\u044F, [\u043D\u0430\u0445\u043E\u0434\u044F\u0449\u0438\u043C\u0438\u0441\u044F] \u043E\u043F\u0440\u0435\u0434\u0435\u043B\u0435\u043D\u043D\u043E\u0435 \u0432\u0440\u0435\u043C\u044F \u0432 \u043F\u043E\u043B\u0435 [\u0435\u0433\u043E] \u0432\u043E\u0441\u043F\u0440\u0438\u044F\u0442\u0438\u044F.</p><p class="eng">\u0427\u0435\u0440\u0435\u0437 \u0432\u0438\u043C\u0430\u0440\u0448\u0443, \u0438\u043B\u0438, \u0438\u043D\u0430\u0447\u0435, \u0432\u0441\u043F\u043B\u0435\u0441\u043A \u0438\u0437\u0443\u043C\u043B\u0435\u043D\u0438\u044F, \u043E\u043D [\u043E\u0431\u044A\u0435\u043A\u0442] \u0438\u0441\u0447\u0435\u0437\u0430\u0435\u0442. \u041A\u0430\u043A \u0433\u043E\u0432\u043E\u0440\u0438\u0442 \u0420\u0430\u043C\u0430, \xAB[\u0446\u0435\u043B\u0443\u044E] \u0433\u043E\u0440\u0443 \u0440\u0430\u0437\u043B\u0438\u0447\u0438\u0439, \u043A\u043E\u0442\u043E\u0440\u0443\u044E \u043D\u0435 \u0432 \u0441\u0438\u043B\u0430\u0445 \u043E\u0434\u043E\u043B\u0435\u0442\u044C \u0434\u0430\u0436\u0435 [\u043F\u0440\u0430\u043A\u0442\u0438\u043A\u0443\u044E\u0449\u0438\u0435] \u0430\u043B\u043C\u0430\u0437\u043E\u043F\u043E\u0434\u043E\u0431\u043D\u043E\u0435 \u0441\u043E\u0441\u0440\u0435\u0434\u043E\u0442\u043E\u0447\u0435\u043D\u0438\u0435, \u0441\u043F\u043E\u0441\u043E\u0431\u043D\u044B \u0432\u043E\u0441\u043F\u0440\u0438\u043D\u044F\u0442\u044C \u043A\u0430\u043A \u043D\u0435\u043E\u0442\u0434\u0435\u043B\u0438\u043C\u0443\u044E \u043E\u0442 \u0441\u0435\u0431\u044F \u0438 \u0442\u0435\u043C \u0441\u0430\u043C\u044B\u043C \u0440\u0430\u0437\u0440\u0443\u0448\u0438\u0442\u044C \u0442\u0435, \u0447\u044C\u044F \u043C\u043E\u0449\u044C \u043F\u0440\u043E\u0438\u0441\u0442\u0435\u043A\u0430\u0435\u0442 \u043E\u0442 \u043F\u0440\u0435\u0434\u0430\u043D\u043D\u043E\u0441\u0442\u0438 \u0422\u0435\u0431\u0435\xBB.</p><p class="eng">\u041E\u0434\u043D\u0430\u043A\u043E, \u0435\u0441\u043B\u0438 \u0432 \u043F\u0435\u0440\u0438\u043E\u0434 \u0440\u0430\u0441\u0442\u0432\u043E\u0440\u0435\u043D\u0438\u044F \u044D\u0442\u043E\u0442 [\u043E\u0431\u044A\u0435\u043A\u0442 \u043E\u043F\u044B\u0442\u0430, \u043C\u0438\u0440] \u0441\u043E\u0445\u0440\u0430\u043D\u044F\u0435\u0442 \u0432\u043D\u0443\u0442\u0440\u0438 \u0440\u0430\u0437\u043B\u0438\u0447\u043D\u044B\u0435 \u0441\u043B\u0435\u0434\u044B, \u0432\u0440\u043E\u0434\u0435 \u0441\u043E\u043C\u043D\u0435\u043D\u0438\u044F \u0438 \u0442. \u043F., [\u044D\u0442\u043E \u0437\u043D\u0430\u0447\u0438\u0442, \u0447\u0442\u043E] \u0441\u0430\u043D\u0441\u0430\u0440\u0430, \u043E\u0441\u0442\u0430\u044E\u0449\u0430\u044F\u0441\u044F \u0432 \u0437\u0430\u0440\u043E\u0434\u044B\u0448\u0435, \u043F\u0440\u043E\u044F\u0432\u0438\u0442\u0441\u044F \u0432\u043D\u043E\u0432\u044C, \u0447\u0442\u043E \u043F\u0440\u0438\u0432\u0435\u0434\u0435\u0442 \u043A \u0441\u043E\u043A\u0440\u044B\u0442\u0438\u044E [\u0438\u0441\u0442\u0438\u043D\u043D\u043E\u0433\u043E \u042F].</p><p class="eng">\u0412 \u0442\u043E \u0436\u0435 \u0432\u0440\u0435\u043C\u044F, \u043A\u043E\u0433\u0434\u0430 \u044D\u0442\u043E\u0442 [\u043E\u0431\u044A\u0435\u043A\u0442] \u0432\u043E\u0441\u043F\u0440\u0438\u043D\u0438\u043C\u0430\u0435\u0442\u0441\u044F \u043A\u0430\u043A \u043D\u0435\u0447\u0442\u043E \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0435\u0435, \u043A\u0430\u043A \u0438\u043D\u043E\u0435, \u0447\u0435\u043C [\u0442\u0430\u043A\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C] \u043F\u0435\u0440\u0435\u0436\u0438\u0432\u0430\u0435\u043C\u043E\u0435, \u0442\u043E \u0432 \u043F\u0440\u043E\u0446\u0435\u0441\u0441\u0435 \u0445\u0430\u0442\u0445\u0430-\u043F\u0430\u043A\u0438 \u0438 \u043F\u0440\u0438\u0432\u0435\u0434\u0435\u043D\u0438\u044F \u043A \u0442\u043E\u0436\u0434\u0435\u0441\u0442\u0432\u0443 \u0441 [\u042F] [\u044D\u0442\u043E\u0442 \u043E\u0431\u044A\u0435\u043A\u0442] \u043F\u0440\u0438\u043E\u0431\u0440\u0435\u0442\u0430\u0435\u0442 \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u044C \u043E\u0433\u043D\u044F \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F, \u0438 \u0442\u043E\u0433\u0434\u0430 \u043E\u043D [\u0439\u043E\u0433\u0438\u043D], \u0434\u043E\u0441\u0442\u0438\u0433\u0430\u044F \u0441\u043E\u0432\u0435\u0440\u0448\u0435\u043D\u0441\u0442\u0432\u0430, \u043E\u0431\u0440\u0435\u0442\u0430\u0435\u0442 \u0431\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u0443\u044E \u043C\u0438\u043B\u043E\u0441\u0442\u044C.</p><p class="eng">\u041D\u043E \u044D\u0442\u0430 \u043F\u044F\u0442\u0435\u0440\u0438\u0446\u0430 \u0431\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u0445 \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0439, \u0445\u043E\u0442\u044F \u0438 \u0432\u0441\u0435\u0433\u0434\u0430 \u0432\u043E\u0437\u043C\u043E\u0436\u043D\u0430 \u0434\u043B\u044F \u043B\u044E\u0431\u043E\u0433\u043E [\u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0430], \u043D\u0435 \u043F\u0440\u043E\u044F\u0432\u0438\u0442\u0441\u044F \u0431\u0435\u0437 \u043F\u043E\u043C\u043E\u0449\u0438 \u0441\u0432\u044F\u0442\u043E\u0433\u043E \u043D\u0430\u0441\u0442\u0430\u0432\u043D\u0438\u043A\u0430. \u041F\u043E\u044D\u0442\u043E\u043C\u0443 \u043D\u0443\u0436\u043D\u043E \u043F\u043E\u0447\u0442\u0438\u0442\u0435\u043B\u044C\u043D\u043E \u0441\u043B\u0443\u0436\u0438\u0442\u044C \u0441\u0432\u044F\u0442\u043E\u043C\u0443 \u043D\u0430\u0441\u0442\u0430\u0432\u043D\u0438\u043A\u0443, \u0434\u0430\u0431\u044B \u044D\u0442\u0430 [\u043F\u044F\u0442\u0435\u0440\u0438\u0446\u0430 \u043F\u0440\u043E\u044F\u0432\u0438\u043B\u0430\u0441\u044C]. \u0422\u043E\u0442 \u0436\u0435, \u0443 \u043A\u043E\u0433\u043E \u0438\u0437-\u0437\u0430 \u043E\u0442\u0441\u0443\u0442\u0441\u0442\u0432\u0438\u044F \u043F\u043E\u043C\u043E\u0449\u0438 \u043D\u0430\u0441\u0442\u0430\u0432\u043D\u0438\u043A\u0430 \u043D\u0435 \u043F\u043E\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0438\u0441\u0442\u0438\u043D\u043D\u043E\u0435 \u0437\u043D\u0430\u043D\u0438\u0435, \u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u0441\u044F \u0441\u0431\u0438\u0442 \u0441 \u0442\u043E\u043B\u043A\u0443 \u0441\u0432\u043E\u0438\u043C\u0438 \u0436\u0435 \u0448\u0430\u043A\u0442\u0438, \u0438\u0431\u043E \u043F\u043E\u0434\u043B\u0438\u043D\u043D\u0430\u044F \u0438\u0445 \u0441\u0443\u0442\u044C \u0437\u0430\u043A\u0440\u044B\u0442\u0430 [\u043E\u0442 \u043D\u0435\u0433\u043E]. \u041F\u043E\u044D\u0442\u043E\u043C\u0443 \u0441\u043A\u0430\u0437\u0430\u043D\u043E:</p></div><div class="stanza"><a href="#s12" id="s12" class="num">12</a><p class="sans">\u0924\u0926\u092A\u0930\u093F\u091C\u094D\u091E\u093E\u0928\u0947 \u0938\u094D\u0935\u0936\u0915\u094D\u0924\u093F\u092D\u093F\u0930\u094D\u0935\u094D\u092F\u093E\u092E\u094B\u0939\u093F\u0924\u0924\u093E \u0938\u0902\u0938\u093E\u0930\u093F\u0924\u094D\u0935\u092E\u094D \u0965\u0967\u0968\u0965</p><p class="trans">Tadaparij\xF1\u0101ne sva\u015Baktibhirvy\u0101mohitat\u0101 sa\u1E41s\u0101ritvam \u096512\u0965</p><p>C\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435 \u0441\u0430\u043D\u0441\u0430\u0440\u044B <em>(sa\u1E41s\u0101ritvam)</em> \u2013 \u043E\u043C\u0440\u0430\u0447\u0435\u043D\u0438\u0435 <em>(vy\u0101mohitat\u0101)</em> \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u043C\u0438 <em>(sva)</em> \u044D\u043D\u0435\u0440\u0433\u0438\u044F\u043C\u0438 <em>(\u015Baktibhi\u1E25)</em> \u0438\u0437-\u0437\u0430 \u043D\u0435\u0437\u043D\u0430\u043D\u0438\u044F <em>(aparij\xF1\u0101ne)</em> \u044D\u0442\u0438\u0445 <em>(tad)</em> [\u043F\u044F\u0442\u0438 \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0439].</p><p class="eng"><strong>\u041A\u043E\u043C\u043C\u0435\u043D\u0442\u0430\u0440\u0438\u0439</strong><br> \xAB\u042D\u0442\u0438\u0445\xBB \u2013 \u0442. \u0435. \u0432\u0441\u0435\u0433\u0434\u0430 \u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u044F\u0449\u0438\u0445 \u043F\u044F\u0442\u0438 \u0431\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u0445 \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0439; \xAB\u043D\u0435\u0437\u043D\u0430\u043D\u0438\u0435\xBB \u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442 \u043E\u0442\u0441\u0443\u0442\u0441\u0442\u0432\u0438\u0435 \xAB\u0441\u0432\u0435\u0442\u0430\xBB, \u0438\u0437-\u0437\u0430 \u043D\u0435\u0440\u0430\u0441\u043A\u0440\u044B\u0442\u0438\u044F \u0415\u0433\u043E \u0441\u0438\u043B\u044B, \u0438\u0441\u0442\u043E\u0447\u043D\u0438\u043A\u0430 \u043D\u0438\u0441\u0445\u043E\u0436\u0434\u0435\u043D\u0438\u044F \u0428\u0430\u043A\u0442\u0438; \xAB\u043E\u043C\u0440\u0430\u0447\u0435\u043D\u0438\u0435 \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u043C\u0438 \u044D\u043D\u0435\u0440\u0433\u0438\u044F\u043C\u0438\xBB \u2013 \u044D\u0442\u043E \u043A\u043E\u0433\u0434\u0430 \u0438\u0437-\u0437\u0430 \u0441\u043E\u043C\u043D\u0435\u043D\u0438\u0439, \u0432\u043E\u0437\u043D\u0438\u043A\u0430\u044E\u0449\u0438\u0445 \u043E\u0442 \u0440\u0430\u0437\u043B\u0438\u0447\u043D\u044B\u0445 \u043C\u0438\u0440\u0441\u043A\u0438\u0445 \u043F\u0440\u0435\u0434\u0441\u0442\u0430\u0432\u043B\u0435\u043D\u0438\u0439 \u0438 [\u0441\u043E\u0434\u0435\u0440\u0436\u0430\u043D\u0438\u044F] \u0443\u0447\u0435\u043D\u044B\u0445 \u0442\u0440\u0430\u043A\u0442\u0430\u0442\u043E\u0432, \u043F\u043E\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \xAB\u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435 \u0441\u0430\u043D\u0441\u0430\u0440\u044B\xBB. \u0412 \u0421\u0430\u0440\u0432\u0430\u0432\u0438\u0440\u0430\u0431\u0445\u0430\u0442\u0442\u0430\u0440\u0430\u043A\u0435 \u0441\u043A\u0430\u0437\u0430\u043D\u043E:</p><p class="eng">\xAB\u0418\u0437-\u0437\u0430 \u043D\u0435\u0437\u043D\u0430\u043D\u0438\u044F \u0443 \u043B\u044E\u0434\u0435\u0439 [\u043F\u043E\u044F\u0432\u043B\u044F\u044E\u0442\u0441\u044F] \u0441\u043E\u043C\u043D\u0435\u043D\u0438\u044F, \u0430 \u043E\u0442 \u043D\u0438\u0445 \u2013 \u0440\u043E\u0436\u0434\u0435\u043D\u0438\u0435 \u0438 \u0441\u043C\u0435\u0440\u0442\u044C\xBB.</p><p class="eng">\u0418 \u0435\u0449\u0435: \xAB\u0412\u0441\u0435 \u043C\u0430\u043D\u0442\u0440\u044B \u0441\u043E\u0441\u0442\u043E\u044F\u0442 \u0438\u0437 \u0444\u043E\u043D\u0435\u043C, \u0432\u0441\u0435 \u0436\u0435 \u0444\u043E\u043D\u0435\u043C\u044B \u0438\u043C\u0435\u044E\u0442 \u043F\u0440\u0438\u0440\u043E\u0434\u0443 \u0428\u0438\u0432\u044B\xBB.</p><p class="eng">\u0422\u0430\u043A\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C, \u043D\u0435\u043E\u0442\u0434\u0435\u043B\u0435\u043D\u043D\u0430\u044F \u043E\u0442 \u0421\u0432\u0435\u0442\u0430 \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F, \u0432 \u0432\u0438\u0434\u0435 \u0432\u0435\u0447\u043D\u043E \u0437\u0432\u0443\u0447\u0430\u0449\u0435\u0439 \u0412\u0435\u043B\u0438\u043A\u043E\u0439 \u043C\u0430\u043D\u0442\u0440\u044B, \u0432 \u0444\u043E\u0440\u043C\u0435 \u0421\u043E\u0437\u043D\u0430\u0432\u0430\u043D\u0438\u044F \u0441\u043E\u0432\u0435\u0440\u0448\u0435\u043D\u043D\u043E\u0433\u043E \xAB\u042F\xBB, \u044D\u0442\u0430 \u0421\u0438\u043B\u0430 \u0412\u044B\u0441\u0448\u0435\u0439 \u0420\u0435\u0447\u0438, \u0441\u043E\u0434\u0435\u0440\u0436\u0430\u0449\u0430\u044F \u0432 \u0441\u0435\u0431\u0435 \u0432\u0441\u0435 \u0441\u043E\u0431\u0440\u0430\u043D\u0438\u0435 \u0448\u0430\u043A\u0442\u0438 \u043E\u0442 \u0430- \u0434\u043E \u043A\u0448\u0430-, \u043C\u0430\u043D\u0438\u0444\u0435\u0441\u0442\u0438\u0440\u0443\u0435\u0442 \u0432 \u0442\u043E\u0439 \u0436\u0435 \u043C\u0435\u0440\u0435 \u0441\u0442\u0443\u043F\u0435\u043D\u044C [\u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u043E\u0433\u043E] \u0441\u0443\u0431\u044A\u0435\u043A\u0442\u0430 \u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C \u043F\u043E\u0441\u043B\u0435\u0434\u043E\u0432\u0430\u0442\u0435\u043B\u044C\u043D\u043E\u0441\u0442\u0438 \u0442\u0430\u043A\u0438\u0445 \u044D\u0442\u0430\u043F\u043E\u0432 \u0440\u0435\u0447\u0438, \u043A\u0430\u043A \u0412\u0438\u0434\u044F\u0449\u0430\u044F, \u0421\u0440\u0435\u0434\u0438\u043D\u043D\u0430\u044F \u0438 \u0442. \u043F.</p><p class="eng">\u041F\u0440\u0438 \u044D\u0442\u043E\u043C \u0415\u0435 \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u044C, \u0415\u0435 \u0432\u044B\u0441\u0448\u0430\u044F \u0444\u043E\u0440\u043C\u0430 \u0441\u043A\u0440\u044B\u0432\u0430\u0435\u0442\u0441\u044F \u0432 \u0441\u0443\u0431\u044A\u0435\u043A\u0442\u0435, \u043E\u0431\u044A\u044F\u0442\u043E\u043C \u043C\u0430\u0439\u0435\u0439, \u043F\u0440\u043E\u0438\u0437\u0432\u043E\u0434\u044F [\u0432 \u043D\u0435\u043C] \u0442\u043E \u0438 \u0434\u0435\u043B\u043E, \u0432\u043D\u043E\u0432\u044C \u0438 \u0432\u043D\u043E\u0432\u044C, \u0440\u0430\u0437\u043B\u0438\u0447\u0430\u044E\u0449\u0443\u044E \u0434\u0435\u044F\u0442\u0435\u043B\u044C\u043D\u043E\u0441\u0442\u044C, [\u0442. \u0435.] \u0432\u044B\u0434\u0435\u043B\u0435\u043D\u0438\u0435 \u043E\u0431\u044A\u0435\u043A\u0442\u043E\u0432 \u043D\u0435\u043E\u043F\u0440\u0435\u0434\u0435\u043B\u0435\u043D\u043D\u044B\u0445 \u0438 \u043E\u0431\u043E\u0441\u043E\u0431\u043B\u0435\u043D\u043D\u044B\u0445. \u0411\u0443\u0434\u0443\u0447\u0438 \u043F\u043E \u0441\u0432\u043E\u0435\u0439 \u0441\u0443\u0442\u0438 \u0447\u0438\u0441\u0442\u043E\u0439 \u0438 \u043F\u0440\u0435\u0432\u043E\u0441\u0445\u043E\u0434\u044F\u0449\u0435\u0439 \u0440\u0430\u0437\u043B\u0438\u0447\u0435\u043D\u0438\u044F, \u041E\u043D\u0430 [\u0432\u0441\u0435-\u0442\u0430\u043A\u0438] \u0441\u043A\u0440\u044B\u0442\u0430 \u044D\u0442\u043E\u0439 [\u0440\u0430\u0437\u043B\u0438\u0447\u0430\u044E\u0449\u0435\u0439 \u0434\u0435\u044F\u0442\u0435\u043B\u044C\u043D\u043E\u0441\u0442\u044C\u044E]. \u0410 \u043F\u043E\u0442\u043E\u043C\u0443 \u043E\u043C\u0440\u0430\u0447\u0435\u043D\u043D\u044B\u0439 \u0447\u0435\u043B\u043E\u0432\u0435\u043A, \u0435\u0449\u0435 \u0438 \u043E\u0441\u043B\u0435\u043F\u043B\u0435\u043D\u043D\u044B\u0439 \u0440\u0430\u0437\u043B\u0438\u0447\u043D\u044B\u043C\u0438 \u0448\u0430\u043A\u0442\u0438 \u0432 \u0444\u043E\u0440\u043C\u0435 \u043A\u0430- \u0438 \u0442. \u0434., \u043A\u043E\u0442\u043E\u0440\u044B\u043C\u0438 \u043F\u0440\u0430\u0432\u044F\u0442 \u0411\u0440\u0430\u0445\u043C\u0438 \u0438 \u0434\u0440\u0443\u0433\u0438\u0435 \u0431\u043E\u0433\u0438\u043D\u0438, \u043F\u0440\u0438\u043D\u0438\u043C\u0430\u0435\u0442 \u0437\u0430 \u042F [\u0442\u0430\u043A\u0438\u0435] \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u044B\u0435 \u0438 \u043D\u0435\u0441\u0442\u043E\u0439\u043A\u0438\u0435 [\u0441\u0443\u0449\u043D\u043E\u0441\u0442\u0438], \u043A\u0430\u043A \u0442\u0435\u043B\u043E, \u043F\u0440\u0430\u043D\u0430 \u0438 \u0442. \u0434.</p><p class="eng">\u0411\u0440\u0430\u0445\u043C\u0438 \u0438 \u0434\u0440\u0443\u0433\u0438\u0435 \u0431\u043E\u0433\u0438\u043D\u0438 \u043D\u0430 \u0443\u0440\u043E\u0432\u043D\u0435 \u0420\u0430\u0431\u0430 \u0432 \u043E\u0442\u043D\u043E\u0448\u0435\u043D\u0438\u0438 \u043A \u0440\u0430\u0437\u043B\u0438\u0447\u0430\u044E\u0449\u0438\u043C\u0441\u044F \u043E\u0431\u044A\u0435\u043A\u0442\u0430\u043C \u043F\u0440\u043E\u0438\u0437\u0432\u043E\u0434\u044F\u0442 \u0442\u0432\u043E\u0440\u0435\u043D\u0438\u0435 \u0438 \u0441\u043E\u0445\u0440\u0430\u043D\u0435\u043D\u0438\u0435, \u0430 \u043A \u043D\u0435\u0440\u0430\u0437\u043B\u0438\u0447\u0430\u044E\u0449\u0438\u043C\u0441\u044F \u2013 \u0443\u043D\u0438\u0447\u0442\u043E\u0436\u0435\u043D\u0438\u0435, \u043D\u0430 \u0443\u0440\u043E\u0432\u043D\u0435 \u0436\u0435 \u0413\u043E\u0441\u043F\u043E\u0434\u0438\u043D\u0430 \u2013 \u0443\u043D\u0438\u0447\u0442\u043E\u0436\u0435\u043D\u0438\u0435 \u0440\u0430\u0437\u043B\u0438\u0447\u0438\u044F \u0438 \u043F\u043E\u0440\u043E\u0436\u0434\u0435\u043D\u0438\u0435-\u0441\u043E\u0445\u0440\u0430\u043D\u0435\u043D\u0438\u0435 \u043D\u0435\u0440\u0430\u0437\u043B\u0438\u0447\u0435\u043D\u0438\u044F. \u041F\u043E\u0441\u0442\u0435\u043F\u0435\u043D\u043D\u043E \u0443\u043C\u0435\u043D\u044C\u0448\u0430\u044F \u0440\u0430\u0437\u043B\u0438\u0447\u0435\u043D\u0438\u0435, [\u043E\u043D\u0438] \u043E\u0442\u043A\u0440\u044B\u0432\u0430\u044E\u0442 \u0441\u0442\u0443\u043F\u0435\u043D\u044C \u0412\u0435\u043B\u0438\u043A\u043E\u0433\u043E \u043D\u0435\u0440\u0430\u0437\u043B\u0438\u0447\u0435\u043D\u0438\u044F, \u0434\u0430\u044E\u0442 \u0432\u043E\u0439\u0442\u0438 \u0432 \u0431\u043B\u0430\u0433\u043E\u0441\u043B\u043E\u0432\u0435\u043D\u043D\u0443\u044E \u0431\u0445\u0430\u0439\u0440\u0430\u0432\u0430-\u043C\u0443\u0434\u0440\u0443.</p><p class="eng">\xAB\u0412\u0441\u044F\u043A\u0438\u0439, [\u043F\u043E\u0441\u0442\u0438\u0433\u0430\u044E\u0449\u0438\u0439] \u043C\u043E\u0435 \u0432\u0435\u043B\u0438\u0447\u0438\u0435 \u0432 \u044D\u0442\u043E\u043C [\u043C\u0438\u0440\u0435, \u043E\u0431\u0440\u0435\u0442\u0430\u0435\u0442 \u0442\u0430\u043A\u043E\u0435 \u0436\u0435] \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435; [\u0432\u0438\u0434\u044F] \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u0443\u044E \u043A\u0430\u043A [\u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u0435] \u042F, [\u043E\u043D \u043E\u0431\u0440\u0435\u0442\u0430\u0435\u0442] \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435 \u041C\u0430\u0445\u0435\u0448\u0438, \u0434\u0430\u0436\u0435 \u0435\u0441\u043B\u0438 \u0440\u0430\u0437\u043B\u0438\u0447\u0435\u043D\u0438\u044F \u043F\u0440\u043E\u0434\u043E\u043B\u0436\u0430\u044E\u0442 [\u0432 \u043D\u0435\u043C \u0432\u043E\u0437\u043D\u0438\u043A\u0430\u0442\u044C]\xBB. \u0422\u0430\u043A\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C, [\u043E\u043D\u0438] \u043F\u0440\u043E\u044F\u0432\u043B\u044F\u044E\u0442 \u0448\u0430\u043A\u0442\u0438 \u0447\u0438\u0441\u0442\u043E\u0433\u043E \u0440\u0430\u0437\u043B\u0438\u0447\u0435\u043D\u0438\u044F, \u043F\u043E\u0433\u0440\u0443\u0436\u0435\u043D\u043D\u0443\u044E \u0432 \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u0435, \u0411\u043B\u0430\u0436\u0435\u043D\u0441\u0442\u0432\u043E \u0438 \u0421\u0432\u043E\u0431\u043E\u0434\u0443. \u0421\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435 \u0436\u0435 \u0441\u0430\u043D\u0441\u0430\u0440\u043D\u043E\u0441\u0442\u0438, \u043A\u0430\u043A \u043E\u0442\u043C\u0435\u0447\u0430\u043B\u043E\u0441\u044C \u0432\u044B\u0448\u0435, \u0441\u043E\u0441\u0442\u043E\u0438\u0442 \u0432 \u043E\u043C\u0440\u0430\u0447\u0435\u043D\u0438\u0438, \u043A\u043E\u0442\u043E\u0440\u043E\u0435 \u043F\u0440\u0438\u0447\u0438\u043D\u044F\u044E\u0442 \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u0435 \u0448\u0430\u043A\u0442\u0438 [\u0438\u043D\u0434\u0438\u0432\u0438\u0434\u0430]. \u0414\u0430\u043B\u0435\u0435. \u042D\u0442\u0430 \u0411\u0445\u0430\u0433\u0430\u0432\u0430\u0442\u0438, \u0428\u0430\u043A\u0442\u0438-\u0412\u044B\u0441\u0448\u0435\u0435 \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u0435, \u0438\u0437\u0432\u0435\u0441\u0442\u043D\u0430 \u0438 \u043A\u0430\u043A \u0412\u0430\u043C\u0435\u0448\u0432\u0430\u0440\u0438, \u043F\u043E\u0442\u043E\u043C\u0443 \u0447\u0442\u043E \u041E\u043D\u0430 \xAB\u0438\u0437\u0432\u043B\u0435\u043A\u0430\u0435\u0442\xBB \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u0443\u044E, \u0430 \u0442\u0430\u043A\u0436\u0435 \u043F\u043E\u0442\u043E\u043C\u0443, \u0447\u0442\u043E [\u041E\u043D\u0430 \u0441\u043B\u0435\u0434\u0443\u0435\u0442] \u043A\u0443\u0440\u0441\u043E\u043C \u0441\u0430\u043D\u0441\u0430\u0440\u044B, \u043F\u0440\u043E\u0442\u0438\u0432\u043E\u043F\u043E\u043B\u043E\u0436\u043D\u044B\u043C [\u0410\u0431\u0441\u043E\u043B\u044E\u0442\u0443].</p><p class="eng">[\u041F\u0440\u0438\u043D\u0438\u043C\u0430\u044F] \u043D\u0430 \u0441\u0442\u0430\u0434\u0438\u0438 \u0420\u0430\u0431\u0430 \u0444\u043E\u0440\u043C\u044B \xAB\u043D\u0435\u0431\u0435\u0441\u043D\u0443\u044E\xBB, \xAB\u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u044E\u044E\xBB, \xAB\u043F\u0440\u043E\u0441\u0442\u0440\u0430\u043D\u0441\u0442\u0432\u0435\u043D\u043D\u0443\u044E\xBB \u0438 \xAB\u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0443\u044E\u0449\u0443\u044E\xBB, \u041E\u043D\u0430 \u0440\u0430\u0441\u043A\u0440\u044B\u0432\u0430\u0435\u0442 \u0441\u0435\u0431\u044F [\u0441\u043E\u043E\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0435\u043D\u043D\u043E] \u043A\u0430\u043A \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u044B\u0439 \u0441\u0443\u0431\u044A\u0435\u043A\u0442, \u043A\u0430\u043A \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0438\u0439 \u043E\u0440\u0433\u0430\u043D, \u043A\u0430\u043A \u043E\u0440\u0433\u0430\u043D\u044B \u0432\u043D\u0435\u0448\u043D\u0435\u0433\u043E \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u044F, \u043A\u0430\u043A \u0436\u0438\u0432\u044B\u0435 \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0430. \u041F\u043E\u043A\u043E\u044F\u0441\u044C \u0432 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0438 \u0448\u0443\u043D\u044C\u0438, \u0441\u043A\u0440\u044B\u0432 \u0441\u0432\u043E\u044E \u0432\u044B\u0441\u0448\u0443\u044E \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u044C \xAB\u043D\u0435\u0431\u0435\u0441\u043D\u043E\u0433\u043E \u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F\xBB, [\u041E\u043D\u0430] \u0441\u0432\u0435\u0442\u0438\u0442\u0441\u044F \u0432 \u0444\u043E\u0440\u043C\u0435 \u0433\u0440\u0443\u043F\u043F\u044B \xAB\u043D\u0435\u0431\u0435\u0441\u043D\u043E\u0439\xBB, \u0441\u043E\u0441\u0442\u043E\u044F\u0449\u0435\u0439 \u0438\u0437 \u0448\u0430\u043A\u0442\u0438 \u0444\u0440\u0430\u0433\u043C\u0435\u043D\u0442\u0430\u0440\u043D\u043E\u0441\u0442\u0438 \u0438 \u0442. \u0434., \u0442. \u0435. \u0438\u043C\u0435\u044E\u0449\u0435\u0439 \u043F\u0440\u0438\u0440\u043E\u0434\u0443 \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u043E\u0439 \u0434\u0435\u044F\u0442\u0435\u043B\u044C\u043D\u043E\u0441\u0442\u0438 \u0438 \u0442. \u0434. \u0421\u043A\u0440\u044B\u0432\u0430\u044F \u0441\u0432\u043E\u044E \u0432\u044B\u0441\u0448\u0443\u044E \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u044C, \u0441\u043E\u0441\u0442\u043E\u044F\u0449\u0443\u044E \u0432 \u043E\u0431\u0440\u0435\u0442\u0435\u043D\u0438\u0438 \u043D\u0435\u0440\u0430\u0437\u043B\u0438\u0447\u0435\u043D\u0438\u044F \u0438 \u0442. \u0434., [\u041E\u043D\u0430] \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0432 \u0432\u0438\u0434\u0435 \xAB\u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0435\u0439\xBB \u0433\u0440\u0443\u043F\u043F\u044B, \u0442. \u0435. \u0432 \u0444\u043E\u0440\u043C\u0435 \u0431\u043E\u0433\u0438\u043D\u0438, [\u0443\u043F\u0440\u0430\u0432\u043B\u044F\u044E\u0449\u0435\u0439] \u043F\u0441\u0438\u0445\u0438\u0447\u0435\u0441\u043A\u0438\u043C \u0441\u0443\u0431\u044A\u0435\u043A\u0442\u0438\u0432\u043D\u044B\u043C \u043A\u043E\u043C\u043F\u043B\u0435\u043A\u0441\u043E\u043C, \u043A\u043E\u0442\u043E\u0440\u044B\u0439 \u0441\u043E\u0441\u0442\u043E\u0438\u0442, [\u0432\u043E-\u043F\u0435\u0440\u0432\u044B\u0445] \u0438\u0437 \u0443\u0441\u0442\u0430\u043D\u043E\u0432\u043A\u0438 \u043D\u0430 \u0440\u0430\u0437\u043B\u0438\u0447\u0435\u043D\u0438\u0435, [\u0432\u043E-\u0432\u0442\u043E\u0440\u044B\u0445] \u0438\u0437 \u043E\u0442\u043E\u0436\u0434\u0435\u0441\u0442\u0432\u043B\u0435\u043D\u0438\u044F \u0441 \u0440\u0430\u0437\u043B\u0438\u0447\u043D\u044B\u043C, [\u0432-\u0442\u0440\u0435\u0442\u044C\u0438\u0445] \u0438\u0437 \u0432\u0438\u0434\u0435\u043D\u0438\u0438 \u0432\u0435\u0449\u0435\u0439 \u043A\u0430\u043A \u0440\u0430\u0437\u043B\u0438\u0447\u043D\u044B\u0445.</p><p class="eng">\u041A\u0430\u043A \u0431\u043E\u0436\u0435\u0441\u0442\u0432\u043E \u0432\u043D\u0435\u0448\u043D\u0438\u0445 \u0447\u0443\u0432\u0441\u0442\u0432, \u043E\u0441\u043D\u043E\u0432\u0430\u043D\u043D\u044B\u0445 \u043D\u0430 \u0440\u0430\u0437\u043B\u0438\u0447\u0435\u043D\u0438\u0438, [\u041E\u043D\u0430] \u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u0441\u044F \u0433\u0440\u0443\u043F\u043F\u043E\u0439 \xAB\u043F\u0440\u043E\u0441\u0442\u0440\u0430\u043D\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0441\u0442\u0438\xBB, \u0441\u043A\u0440\u044B\u0432\u0430\u044F \u0441\u0432\u043E\u044E \u0433\u043B\u0443\u0431\u0438\u043D\u043D\u0443\u044E \u0441\u0443\u0442\u044C, \u0441\u043E\u0441\u0442\u043E\u044F\u0449\u0443\u044E \u0432 \u043C\u0430\u043D\u0438\u0444\u0435\u0441\u0442\u0430\u0446\u0438\u0438 \u043D\u0435\u0440\u0430\u0437\u043B\u0438\u0447\u0435\u043D\u0438\u044F \u0438 \u0442. \u043F. \u0421\u043A\u0440\u044B\u0432\u0430\u044F \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u044C \u0412\u0441\u0435\u0433\u043E \u0438 \u043E\u043C\u0440\u0430\u0447\u0430\u044F \u0441\u0435\u0440\u0434\u0446\u0430 \u0437\u0430\u0432\u0438\u0441\u0438\u043C\u044B\u0445 \u0441\u0443\u0449\u0435\u0441\u0442\u0432, [\u041E\u043D\u0430] \u043F\u043E\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0438 \u0447\u0435\u0440\u0435\u0437 \u0433\u0440\u0443\u043F\u043F\u0443 \xAB\u0441\u0443\u0449\u0435\u0433\u043E\xBB \u0432 \u0444\u043E\u0440\u043C\u0435 \u043E\u0431\u044A\u0435\u043A\u0442\u043E\u0432 \u043F\u043E\u0437\u043D\u0430\u043D\u0438\u044F, \u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u043F\u043E\u0432\u0441\u0435\u043C\u0435\u0441\u0442\u043D\u043E \u0432\u044B\u0441\u0442\u0443\u043F\u0430\u044E\u0442 \u043A\u0430\u043A \u043E\u0431\u043E\u0441\u043E\u0431\u043B\u0435\u043D\u043D\u044B\u0435 \u0444\u0435\u043D\u043E\u043C\u0435\u043D\u044B.</p><p class="eng">\u041D\u0430 \u0441\u0442\u0430\u0434\u0438\u0438 \u0436\u0435 \u0413\u043E\u0441\u043F\u043E\u0434\u0438\u043D\u0430 \u041E\u043D\u0430 \u0432\u0438\u0431\u0440\u0438\u0440\u0443\u0435\u0442 \u043A\u0430\u043A \xAB\u043D\u0435\u0431\u0435\u0441\u043D\u043E\u0435 \u0441\u043E\u0437\u043D\u0430\u043D\u0438\u0435\xBB, \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u044C\u044E \u043A\u043E\u0442\u043E\u0440\u043E\u0433\u043E \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0432\u0441\u0435\u043E\u0431\u044A\u0435\u043C\u043B\u044E\u0449\u0430\u044F \u0434\u0435\u044F\u0442\u0435\u043B\u044C\u043D\u043E\u0441\u0442\u044C \u0438 \u0442. \u0434.; \u043A\u0430\u043A \xAB\u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0435\u0435 \u0434\u0432\u0438\u0436\u0435\u043D\u0438\u0435\xBB, \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u044C \u0435\u0435 \u2013 \u0443\u0441\u0442\u0430\u043D\u043E\u0432\u043A\u0430 \u043D\u0430 \u043D\u0435\u0440\u0430\u0437\u043B\u0438\u0447\u0435\u043D\u0438\u0435 \u0438 \u0442. \u043F.; \u043A\u0430\u043A \xAB\u043F\u0440\u043E\u0441\u0442\u0440\u0430\u043D\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0435 \u0434\u0432\u0438\u0436\u0435\u043D\u0438\u0435\xBB, \u0435\u0435 \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u044C \u2013 \u0432\u043E\u0441\u043F\u0440\u0438\u044F\u0442\u0438\u0435 \u043D\u0435\u0440\u0430\u0437\u043B\u0438\u0447\u0435\u043D\u0438\u044F \u0438 \u0442. \u0434.; \u043A\u0430\u043A \xAB\u0441\u0443\u0449\u0435\u0435\xBB, \u0435\u0435 \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u044C \u2013 \u043E\u0431\u044A\u0435\u043A\u0442\u044B, \u0438\u0434\u0435\u043D\u0442\u0438\u0447\u043D\u044B\u0435 [\u0441\u0443\u0431\u044A\u0435\u043A\u0442\u0443, \u043F\u043E\u0434\u043E\u0431\u043D\u043E] \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u043C \u0447\u043B\u0435\u043D\u0430\u043C. [\u0412\u0441\u0435\u043C \u044D\u0442\u0438\u043C \u041E\u043D\u0430] \u043E\u0442\u043A\u0440\u044B\u0432\u0430\u0435\u0442 \u0441\u0435\u0440\u0434\u0446\u0435 \u0413\u043E\u0441\u043F\u043E\u0434\u0438\u043D\u0430.</p><p class="eng">\u0411\u0445\u0430\u0442\u0442\u0430 \u0414\u0430\u043C\u043E\u0434\u0430\u0440\u0430, \u0437\u0430\u043F\u043E\u0432\u0435\u0434\u0443\u044F \u043D\u0435\u043F\u043E\u0434\u0434\u0435\u043B\u044C\u043D\u043E\u0435 \u0443\u0432\u0430\u0436\u0435\u043D\u0438\u0435, \u0431\u043B\u0430\u0433\u043E\u0434\u0430\u0440\u044F \u0441\u0432\u043E\u0435\u043C\u0443 \u0432\u0440\u043E\u0436\u0434\u0435\u043D\u043D\u043E\u043C\u0443 \u0432\u043E\u0441\u0442\u043E\u0440\u0433\u0443, \u0432 \u0441\u0432\u043E\u0438\u0445 \u0412\u0438\u043C\u0443\u043A\u0442\u0430\u043A\u0430\u0445 \u0433\u043E\u0432\u043E\u0440\u0438\u0442: \xAB\u0412\u0430\u043C\u0435\u0448\u0432\u0430\u0440\u0438 \u0438 \u0434\u0440\u0443\u0433\u0438\u0435 [\u0431\u043E\u0433\u0438\u043D\u0438, \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u044F \u0432 \u0441\u0444\u0435\u0440\u0430\u0445] \u043F\u043E\u0441\u0442\u0438\u0433\u0430\u044E\u0449\u0435\u0433\u043E \u0441\u0443\u0431\u044A\u0435\u043A\u0442\u0430, \u0435\u0433\u043E \u0432\u043D\u0435\u0448\u043D\u0438\u0445 \u0438 \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0438\u0445 \u043E\u0440\u0433\u0430\u043D\u043E\u0432, \u0432 \u043E\u0431\u044A\u0435\u043A\u0442\u0438\u0432\u043D\u043E\u043C \u043C\u0438\u0440\u0435, [\u0434\u0435\u043B\u0430\u044E\u0442 \u0438\u043D\u0434\u0438\u0432\u0438\u0434\u0430] \u0441\u043E\u0432\u0435\u0440\u0448\u0435\u043D\u043D\u044B\u043C, \u043E\u0441\u0432\u043E\u0431\u043E\u0436\u0434\u0430\u044F [\u0435\u0433\u043E] \u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C \u0438\u0441\u0442\u0438\u043D\u043D\u043E\u0433\u043E \u0437\u043D\u0430\u043D\u0438\u044F, [\u043B\u0438\u0431\u043E \u0434\u0435\u043B\u0430\u044E\u0442 \u0435\u0433\u043E] \u0437\u0430\u0432\u0438\u0441\u0438\u043C\u044B\u043C, \u043E\u043F\u0443\u0442\u044B\u0432\u0430\u044F \u0443\u0437\u0430\u043C\u0438 \u043D\u0435\u0432\u0435\u0434\u0435\u043D\u0438\u044F\xBB. \u0422\u0430\u043A\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C, \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435 \u0441\u0430\u043D\u0441\u0430\u0440\u043D\u043E\u0441\u0442\u0438 \u0441\u043E\u0441\u0442\u043E\u0438\u0442 \u0432 \u043E\u043C\u0440\u0430\u0447\u0435\u043D\u043D\u043E\u0441\u0442\u0438 \u0441\u0432\u043E\u0438\u043C\u0438 \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u043C\u0438 \u044D\u043D\u0435\u0440\u0433\u0438\u044F\u043C\u0438. \u0414\u0430\u043B\u0435\u0435, \u0412\u044B\u0441\u0448\u0438\u0439 \u0413\u043E\u0441\u043F\u043E\u0434\u044C, \u0447\u044C\u044F \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u044C \u2013 \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u0435, \u043D\u0430\u0434\u0435\u043B\u0435\u043D \u043F\u043E\u0441\u0442\u043E\u044F\u043D\u043D\u043E\u0439, \u0446\u0435\u043B\u043E\u0441\u0442\u043D\u043E\u0439, \u0434\u0435\u044F\u0442\u0435\u043B\u044C\u043D\u043E\u0441\u0442\u043D\u043E\u0439 \u043F\u043E \u0441\u0432\u043E\u0435\u0439 \u043F\u0440\u0438\u0440\u043E\u0434\u0435 \u0422\u0432\u043E\u0440\u044F\u0449\u0435\u0439 \u0421\u0438\u043B\u043E\u0439, \u0438\u043C\u0435\u044E\u0449\u0443\u044E \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u044C \u043F\u0443\u043B\u044C\u0441\u0430\u0446\u0438\u0438 \u0411\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0433\u043E \u0421\u0432\u0435\u0442\u0430.</p><p class="eng">\u041A\u043E\u0433\u0434\u0430 \u041E\u043D\u0430, \u0441\u043A\u0440\u044B\u0432\u0430\u044F \u0441\u0432\u043E\u044E \u0438\u0441\u0442\u0438\u043D\u043D\u0443\u044E \u0441\u0443\u0442\u044C \u043D\u0430 \u0441\u0442\u0430\u0434\u0438\u0438 \u0420\u0430\u0431\u0430, \u043F\u0440\u0438\u0447\u0438\u043D\u044F\u0435\u0442 \u043E\u043C\u0440\u0430\u0447\u0435\u043D\u0438\u0435 \u0447\u0435\u0440\u0435\u0437 \u0446\u0438\u043A\u043B\u044B \u043F\u0440\u0430\u043D\u0430-, \u0430\u043F\u0430\u043D\u0430- \u0438 \u0441\u0430\u043C\u0430\u043D\u0430-\u0448\u0430\u043A\u0442\u0438; \u0447\u0435\u0440\u0435\u0437 \u0441\u0442\u0443\u043F\u0435\u043D\u0438 \u0431\u043E\u0434\u0440\u0441\u0442\u0432\u043E\u0432\u0430\u043D\u0438\u044F, \u043B\u0435\u0433\u043A\u043E\u0433\u043E \u0438 \u0433\u043B\u0443\u0431\u043E\u043A\u043E\u0433\u043E \u0441\u043D\u0430; \u0447\u0435\u0440\u0435\u0437 \u0444\u0430\u0437\u044B \u043F\u043B\u043E\u0442\u043D\u043E\u0433\u043E \u0442\u0435\u043B\u0430, \u0434\u044B\u0445\u0430\u043D\u0438\u044F \u0438 \u0442\u043E\u043D\u043A\u043E\u0433\u043E \u0442\u0435\u043B\u0430, \u0442\u043E\u0433\u0434\u0430 \u044D\u0442\u0430 \u043E\u043C\u0440\u0430\u0447\u0430\u044E\u0449\u0430\u044F \u0434\u0435\u044F\u0442\u0435\u043B\u044C\u043D\u043E\u0441\u0442\u044C [\u043F\u0440\u0438\u0432\u043E\u0434\u0438\u0442] \u043A \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044E \u0441\u0430\u043D\u0441\u0430\u0440\u044B.</p><p class="eng">\u041A\u043E\u0433\u0434\u0430 \u0436\u0435 \u041E\u043D\u0430 \u0437\u0430\u0441\u0442\u0430\u0432\u043B\u044F\u0435\u0442 \u043F\u043E\u044F\u0432\u0438\u0442\u044C\u0441\u044F \u0432 \u0441\u0440\u0435\u0434\u0438\u043D\u043D\u043E\u043C \u043A\u0430\u043D\u0430\u043B\u0435 \u0443\u0434\u0430\u043D\u0430-\u0448\u0430\u043A\u0442\u0438, \u0438\u043C\u0435\u044E\u0449\u0443\u044E \u0445\u0430\u0440\u0430\u043A\u0442\u0435\u0440 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F \u0442\u0443\u0440\u044C\u044F; \u0432\u044C\u044F\u043D\u0430-\u0448\u0430\u043A\u0442\u0438, \u0438\u043C\u0435\u044E\u0449\u0443\u044E \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u044C \u043F\u0440\u043E\u043D\u0438\u0437\u044B\u0432\u0430\u043D\u0438\u044F \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u043E\u0439 \u0438 \u0441\u043E\u0432\u043F\u0430\u0434\u0430\u044E\u0449\u0443\u044E \u0441 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435\u043C \u0442\u0443\u0440\u044C\u044F\u0442\u0438\u0442\u0430, \u2014 [\u043E\u0431\u0435 \u043E\u043D\u0438 \u043D\u0430\u0434\u0435\u043B\u0435\u043D\u044B \u043F\u0440\u0438\u0440\u043E\u0434\u043E\u0439] \u044D\u0441\u0441\u0435\u043D\u0446\u0438\u0438 \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F \u0438 \u0411\u043B\u0430\u0436\u0435\u043D\u0441\u0442\u0432\u0430 \u2013 \u0442\u043E\u0433\u0434\u0430, \u0434\u0430\u0436\u0435 \u043E\u0431\u043B\u0430\u0434\u0430\u044F \u0442\u0435\u043B\u043E\u043C \u0438 \u0442. \u0434., \u0438\u043D\u0434\u0438\u0432\u0438\u0434 \u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u0441\u044F \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u043E\u043C, \u0434\u043E\u0441\u0442\u0438\u0433\u0448\u0438\u043C \u043E\u0441\u0432\u043E\u0431\u043E\u0436\u0434\u0435\u043D\u0438\u044F \u043F\u0440\u0438 \u0436\u0438\u0437\u043D\u0438, \u0413\u043E\u0441\u043F\u043E\u0434\u0438\u043D\u043E\u043C \u043F\u043E \u0441\u0443\u0442\u0438. \u0422\u0430\u043A\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C, \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435 \u043E\u043C\u0440\u0430\u0447\u0435\u043D\u043D\u043E\u0441\u0442\u0438 \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u043C\u0438 \u044D\u043D\u0435\u0440\u0433\u0438\u044F\u043C\u0438 \u0431\u044B\u043B\u043E \u043E\u0431\u044A\u044F\u0441\u043D\u0435\u043D\u043E \u0442\u0440\u043E\u044F\u043A\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C.</p><p class="eng">\u0412 \u0434\u0435\u0432\u044F\u0442\u043E\u0439 \u0441\u0443\u0442\u0440\u0435, o \xAB\u041F\u043E\u043B\u043D\u043E\u0442e \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F\xBB, \u0433\u043E\u0432\u043E\u0440\u0438\u043B\u043E\u0441\u044C \u0432 \u0442\u0430\u043A\u043E\u043C \u0441\u043C\u044B\u0441\u043B\u0435, \u0447\u0442\u043E \u0421\u0432\u0435\u0442 \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F, \u043F\u043E \u0441\u0432\u043E\u0435\u0439 \u0432\u043E\u043B\u0435 \u0441\u0443\u0436\u0430\u044F\u0441\u044C, [\u0434\u0435\u043B\u0430\u0435\u0442\u0441\u044F] \u0441\u0430\u043D\u0441\u0430\u0440\u0438\u043D\u043E\u043C; \u0437\u0434\u0435\u0441\u044C \u0436\u0435 \u0441\u043A\u0430\u0437\u0430\u043D\u043E, \u0441 \u0434\u0440\u0443\u0433\u043E\u0439 \u0442\u043E\u0447\u043A\u0438 \u0437\u0440\u0435\u043D\u0438\u044F, \u0447\u0442\u043E \u044D\u0442\u043E \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435 \u0441\u0430\u043D\u0441\u0430\u0440\u043D\u043E\u0441\u0442\u0438 \u0432\u044B\u0437\u044B\u0432\u0430\u0435\u0442\u0441\u044F \u043E\u043C\u0440\u0430\u0447\u0435\u043D\u0438\u0435\u043C [\u0438\u043D\u0434\u0438\u0432\u0438\u0434\u0430] \u0441\u0432\u043E\u0438\u043C\u0438 \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u043C\u0438 \u044D\u043D\u0435\u0440\u0433\u0438\u044F\u043C\u0438. \u041A\u0440\u043E\u043C\u0435 \u0442\u043E\u0433\u043E, [\u0435\u0441\u043B\u0438 \u0442\u043E\u043B\u044C\u043A\u043E \u0438\u043D\u0434\u0438\u0432\u0438\u0434], \u0434\u0430\u0436\u0435 \u043D\u0430\u0434\u0435\u043B\u0435\u043D\u043D\u044B\u0439 \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u044B\u043C\u0438 \u0441\u0438\u043B\u0430\u043C\u0438, \u0434\u0430\u0436\u0435 \u0438\u043C\u0435\u044F \u043F\u0440\u0430\u043D\u0438\u0447\u0435\u0441\u043A\u043E\u0435 \u0442\u0435\u043B\u043E \u0438 \u0434\u0440\u0443\u0433\u0438\u0435 [\u043F\u043E\u043C\u0435\u0445\u0438], \u043D\u0435 \u043E\u043C\u0440\u0430\u0447\u0435\u043D \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u043C\u0438 \u044D\u043D\u0435\u0440\u0433\u0438\u044F\u043C\u0438, \u0442\u043E, \u0441\u043E\u0433\u043B\u0430\u0441\u043D\u043E \u0441\u0432\u044F\u0449\u0435\u043D\u043D\u043E\u0439 \u0442\u0440\u0430\u0434\u0438\u0446\u0438\u0438, \u043E\u043D \u0432\u043E\u0441\u043F\u0440\u0438\u043D\u0438\u043C\u0430\u0435\u0442\u0441\u044F \u043A\u0430\u043A \xAB\u0412\u044B\u0441\u0448\u0438\u0439 \u0418\u0448\u0432\u0430\u0440\u0430 \u0432\u043E \u043F\u043B\u043E\u0442\u0438\xBB, \u043A\u0430\u043A \u0441\u0430\u043C \u0411\u043B\u0430\u0433\u043E\u0441\u043B\u043E\u0432\u0435\u043D\u043D\u044B\u0439 \u0428\u0438\u0432\u0430. \u041A\u0430\u043A [\u0433\u043E\u0432\u043E\u0440\u0438\u0442\u0441\u044F] \u0432 \u0430\u0433\u0430\u043C\u0435: \xAB\u0412 \u0447\u0435\u043B\u043E\u0432\u0435\u0447\u0435\u0441\u043A\u043E\u043C \u0442\u0435\u043B\u0435 \u0441\u043A\u0440\u044B\u0442\u043D\u043E \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u044E\u0442 \u0412\u044B\u0441\u0448\u0438\u0435 \u0411\u043E\u0436\u0435\u0441\u0442\u0432\u0430\xBB. \u0418\u043B\u0438 \u0442\u0430\u043A\u0436\u0435 \u0432 \u043A\u043E\u043C\u043C\u0435\u043D\u0442\u0430\u0440\u0438\u0438 \u043D\u0430 \u041F\u0440\u0430\u0442\u044C\u044F\u0431\u0445\u0438\u0434\u0436\u043D\u044E: \xAB\u0422\u0435, \u043A\u0442\u043E \u0444\u0438\u0437\u0438\u0447\u0435\u0441\u043A\u043E\u0435 \u0442\u0435\u043B\u043E \u0438\u043B\u0438 \u0434\u0430\u0436\u0435 \u043A\u0443\u0432\u0448\u0438\u043D \u0438 \u0442. \u043F. \u0432\u0438\u0434\u0438\u0442 \u043A\u0430\u043A \u0444\u043E\u0440\u043C\u0443 \u0428\u0438\u0432\u044B, \u0441\u043E\u0441\u0442\u043E\u044F\u0449\u0443\u044E \u0438\u0437 \u0442\u0440\u0438\u0434\u0446\u0430\u0442\u0438 \u0448\u0435\u0441\u0442\u0438 \u0442\u0430\u0442\u0442\u0432, \u0434\u043E\u0441\u0442\u0438\u0433\u0430\u044E\u0442 \u0441\u043E\u0432\u0435\u0440\u0448\u0435\u043D\u0441\u0442\u0432\u0430\xBB. \u0414\u043B\u044F \u0442\u043E\u0433\u043E, \u0447\u0442\u043E\u0431\u044B \u043F\u043E\u043A\u0430\u0437\u0430\u0442\u044C \u0438\u0441\u0442\u0438\u043D\u043D\u043E\u0435 \u043F\u043E\u043D\u0438\u043C\u0430\u043D\u0438\u0435, \u0441\u043C\u044B\u0441\u043B \u0432\u044B\u0448\u0435\u0443\u043F\u043E\u043C\u044F\u043D\u0443\u0442\u043E\u0439 \u0441\u0443\u0442\u0440\u044B \u0431\u044B\u043B \u043F\u0435\u0440\u0435\u0432\u0435\u0440\u043D\u0443\u0442:</p></div><div class="stanza"><a href="#s13" id="s13" class="num">13</a><p class="sans">\u0924\u0924\u094D\u092A\u0930\u093F\u091C\u094D\u091E\u093E\u0928\u0947 \u091A\u093F\u0924\u094D\u0924\u092E\u0947\u0935\u093E\u0928\u094D\u0924\u0930\u094D\u092E\u0941\u0916\u0940\u092D\u093E\u0935\u0947\u0928 \u091A\u0947\u0924\u0928\u093E\u092A\u0926\u093E\u0927\u094D\u092F\u093E\u0930\u094B\u0939\u093E\u091A\u094D\u091A\u093F\u0924\u093F\u0903 \u0965\u0967\u0969\u0965</p><p class="trans">Tatparij\xF1\u0101ne cittamev\u0101ntarmukh\u012Bbh\u0101vena cetan\u0101pad\u0101dhy\u0101roh\u0101cciti\u1E25 \u096513\u0965</p><p>[\u041E\u0431\u0440\u0435\u0442\u0430\u044F] \u043F\u043E\u043B\u043D\u043E\u0435 \u0437\u043D\u0430\u043D\u0438\u0435 <em>(parij\xF1\u0101ne)</em> \u043E\u0431 \u044D\u0442\u043E\u043C <em>(tad)</em>, \u0441\u0430\u043C\u043E <em>(eva)</em> \u0438\u043D\u0434\u0438\u0432\u0438\u0434\u0443\u0430\u043B\u044C\u043D\u043E\u0435 \u0441\u043E\u0437\u043D\u0430\u043D\u0438\u0435 <em>(cittam)</em>, \u0447\u0435\u0440\u0435\u0437 <em>(bh\u0101vena)</em> \u043E\u0431\u0440\u0430\u0449\u0435\u043D\u0438\u0435 \u0432\u043E\u0432\u043D\u0443\u0442\u0440\u044C <em>(antarmukh\u012B)</em>, \u0432\u043E\u0441\u0445\u043E\u0434\u044F <em>(adhy\u0101roh\u0101t)</em> \u0434\u043E \u0441\u0442\u0443\u043F\u0435\u043D\u0438 <em>(pada)</em> \u0447\u0438\u0441\u0442\u043E\u0433\u043E \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F <em>(cetana)</em>, [\u043F\u0440\u0435\u0432\u0440\u0430\u0449\u0430\u0435\u0442\u0441\u044F \u0432] \u0443\u043D\u0438\u0432\u0435\u0440\u0441\u0430\u043B\u044C\u043D\u043E\u0435 \u0441\u043E\u0437\u043D\u0430\u043D\u0438\u0435 <em>(citi\u1E25)</em>.</p><p class="eng"><strong>\u041A\u043E\u043C\u043C\u0435\u043D\u0442\u0430\u0440\u0438\u0439</strong><br> [\u0421\u043E\u0434\u0435\u0440\u0436\u0430\u043D\u0438\u0435] \u0434\u0430\u043D\u043D\u043E\u0439 \u0441\u0443\u0442\u0440\u044B \u0443\u0436\u0435 \u0431\u044B\u043B\u043E \u043F\u043E\u0434\u0440\u043E\u0431\u043D\u043E \u043E\u0441\u0432\u0435\u0449\u0435\u043D\u043E \u0432 \u043F\u0440\u0435\u0434\u044B\u0434\u0443\u0449\u0435\u0439 \u0441\u0443\u0442\u0440\u0435, \u0441 \u0442\u043E\u0447\u043A\u0438 \u0437\u0440\u0435\u043D\u0438\u044F \u043F\u043E\u0437\u043D\u0430\u0432\u0430\u0435\u043C\u044B\u0445 \u043E\u0431\u044A\u0435\u043A\u0442\u043E\u0432. \u0422\u0435\u043F\u0435\u0440\u044C [\u0442\u043E \u0436\u0435 \u0441\u0430\u043C\u043E\u0435] \u043E\u0431\u044A\u044F\u0441\u043D\u044F\u0435\u0442\u0441\u044F \u0441 \u0442\u043E\u0447\u043A\u0438 \u0437\u0440\u0435\u043D\u0438\u044F \u0441\u043B\u043E\u0432. \xAB\u041E\u0431 \u044D\u0442\u043E\u043C\xBB \u2013 \u0442. \u0435. \u043E\u0431 \u0438\u0441\u043F\u043E\u043B\u043D\u0435\u043D\u0438\u0438 \u0441\u0430\u043C\u0438\u043C \u042F \u043F\u044F\u0442\u0435\u0440\u0438\u0446\u044B [\u0431\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u0445] \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0439; [\u043E\u0431\u0440\u0435\u0442\u0435\u043D\u0438\u0435] \xAB\u043F\u043E\u043B\u043D\u043E\u0433\u043E \u0437\u043D\u0430\u043D\u0438\u044F\xBB \u2013 \u044D\u0442\u043E \u0443\u0434\u0430\u043B\u0435\u043D\u0438\u0435 \u043F\u0440\u0438\u0447\u0438\u043D, \u0432\u044B\u0437\u044B\u0432\u0430\u044E\u0449\u0438\u0445 \u043D\u0435\u0434\u043E\u0441\u0442\u0430\u0442\u043E\u0447\u043D\u043E\u0435 \u0437\u043D\u0430\u043D\u0438\u0435, \u043F\u0440\u0435\u043A\u0440\u0430\u0449\u0435\u043D\u0438\u0435 \u043E\u043C\u0440\u0430\u0447\u0435\u043D\u043D\u043E\u0441\u0442\u0438 \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u043C\u0438 \u044D\u043D\u0435\u0440\u0433\u0438\u044F\u043C\u0438, \u043E\u0431\u0440\u0435\u0442\u0435\u043D\u0438\u0435 \u0421\u043F\u043E\u043D\u0442\u0430\u043D\u043D\u043E\u0439 \u0412\u043E\u043B\u0438. \xAB\u0418\u043D\u0434\u0438\u0432\u0438\u0434\u0443\u0430\u043B\u044C\u043D\u043E\u0435 \u0441\u043E\u0437\u043D\u0430\u043D\u0438\u0435\xBB, \u043E \u043A\u043E\u0442\u043E\u0440\u043E\u043C \u0440\u0435\u0447\u044C \u0448\u043B\u0430 \u043F\u0440\u0435\u0436\u0434\u0435, \u043E\u0442\u0431\u0440\u0430\u0441\u044B\u0432\u0430\u0435\u0442 [\u0432\u0435\u0434\u0443\u0449\u0435\u0435] \u043A \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u0438\u044E \u0432\u043D\u0435\u0448\u043D\u0435\u0435 \u0441\u0442\u0430\u043D\u043E\u0432\u043B\u0435\u043D\u0438\u0435, \u0438 \xAB\u0447\u0435\u0440\u0435\u0437 \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0435\u0435 \u0432\u043E\u0441\u0441\u0442\u0430\u043D\u043E\u0432\u043B\u0435\u043D\u0438\u0435 \u0432\u043E\u0441\u0445\u043E\u0434\u0438\u0442 \u0434\u043E \u0441\u0442\u0443\u043F\u0435\u043D\u0438 \u0447\u0435\u0442\u0430\u043D\u0430\xBB, \u0442. \u0435. [\u043E\u043D\u043E], \u0448\u0430\u0433 \u0437\u0430 \u0448\u0430\u0433\u043E\u043C \u0440\u0430\u0441\u0442\u0432\u043E\u0440\u044F\u044F \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u0438\u044F \u043D\u0430 \u043F\u0443\u0442\u0438 \u043A \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044E \u0421\u0443\u0431\u044A\u0435\u043A\u0442\u0430, \u0434\u043E\u0441\u0442\u0438\u0433\u0430\u044F \u0441\u0432\u043E\u0435\u0439 \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u043D\u043E\u0439 \u043F\u0440\u0438\u0440\u043E\u0434\u044B, \u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u0441\u044F \xAB\u0443\u043D\u0438\u0432\u0435\u0440\u0441\u0430\u043B\u044C\u043D\u044B\u043C \u0441\u043E\u0437\u043D\u0430\u043D\u0438\u0435\u043C\xBB. \u041E\u043D\u043E \u0432\u0441\u0442\u0443\u043F\u0430\u0435\u0442 [\u0437\u0434\u0435\u0441\u044C] \u043D\u0430 \u0432\u044B\u0441\u0448\u0443\u044E \u0441\u0442\u0443\u043F\u0435\u043D\u044C \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F \u2013 \u0442\u0430\u043A\u043E\u0432 \u0441\u043C\u044B\u0441\u043B.</p><p class="eng">\u041C\u043E\u0433\u0443\u0442 \u0441\u043F\u0440\u043E\u0441\u0438\u0442\u044C: \u0435\u0441\u043B\u0438 \u0443 \u0427\u0438\u0442-\u0448\u0430\u043A\u0442\u0438 \u0432 [\u0435\u0435] \u0430\u0441\u043F\u0435\u043A\u0442\u0435 \u0432\u044B\u0441\u0448\u0435\u0439 \u0440\u0435\u0430\u043B\u044C\u043D\u043E\u0441\u0442\u0438 \u043E\u0442\u0441\u0443\u0442\u0441\u0442\u0432\u0443\u0435\u0442 \u0432\u0441\u044F\u0447\u0435\u0441\u043A\u0430\u044F \u0440\u0430\u0437\u0434\u0435\u043B\u0435\u043D\u043D\u043E\u0441\u0442\u044C, \u0442\u043E \u043D\u0435 \u0434\u043E\u043B\u0436\u043D\u0430 \u043B\u0438 \u043E\u043D\u0430 \u0441\u043E\u0445\u0440\u0430\u043D\u044F\u0442\u044C \u044D\u0442\u0443 \u0444\u043E\u0440\u043C\u0443 \u0438 \u043D\u0430 \u0441\u0442\u0443\u043F\u0435\u043D\u0438 \u043C\u0430\u0439\u044F, \u043F\u043E\u0434\u043E\u0431\u043D\u043E \u0442\u043E\u043C\u0443, \u043A\u0430\u043A \u0441\u043E\u043B\u043D\u0446\u0435, \u0434\u0430\u0436\u0435 \u0437\u0430\u0442\u0435\u043D\u0435\u043D\u043D\u043E\u0435 \u043E\u0431\u043B\u0430\u043A\u0430\u043C\u0438, \u0441\u043E\u0445\u0440\u0430\u043D\u044F\u0435\u0442 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435 \u0441\u0432\u0435\u0442\u0438\u043C\u043E\u0441\u0442\u0438? \u041D\u0430 \u044D\u0442\u043E\u0442 \u0432\u043E\u043F\u0440\u043E\u0441 [\u0430\u0432\u0442\u043E\u0440] \u043E\u0442\u0432\u0435\u0447\u0430\u0435\u0442:</p></div><div class="stanza"><a href="#s14" id="s14" class="num">14</a><p class="sans">\u091A\u093F\u0924\u093F\u0935\u0939\u094D\u0928\u093F\u0930\u0935\u0930\u094B\u0939\u092A\u0926\u0947 \u091B\u0928\u094D\u0928\u094B\u093D\u092A\u093F \u092E\u093E\u0924\u094D\u0930\u092F\u093E \u092E\u0947\u092F\u0947\u0928\u094D\u0927\u0928\u0902 \u092A\u094D\u0932\u0941\u0937\u094D\u092F\u0924\u093F \u0965\u0967\u096A\u0965</p><p class="trans">Citivahniravarohapade channo&#39;pi m\u0101tray\u0101 meyendhana\u1E41 plu\u1E63yati \u096514\u0965</p><p>\u041E\u0433\u043E\u043D\u044C <em>(vahni\u1E25)</em> \u0412\u044B\u0441\u0448\u0435\u0433\u043E \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F <em>(citi)</em>, \u0434\u0430\u0436\u0435 <em>(api)</em> \u0441\u043A\u043E\u0432\u0430\u043D\u043D\u044B\u0439 <em>(channa\u1E25)</em> \u043D\u0438\u0441\u0445\u043E\u0436\u0434\u0435\u043D\u0438\u0435\u043C [\u043D\u0430 \u043D\u0438\u0437\u0436\u0438\u0435] <em>(avaroha)</em> \u0441\u0442\u0443\u043F\u0435\u043D\u0438 <em>(pade)</em>, \u0447\u0430\u0441\u0442\u0438\u0447\u043D\u043E <em>(m\u0101tray\u0101)</em> \u0441\u0436\u0438\u0433\u0430\u0435\u0442 <em>(plu\u1E63yati)</em> \u0442\u043E\u043F\u043B\u0438\u0432\u043E <em>(indhanam)</em> \u043F\u043E\u0437\u043D\u0430\u0432\u0430\u0435\u043C\u044B\u0445 [\u043E\u0431\u044A\u0435\u043A\u0442\u043E\u0432] <em>(meya)</em>.</p><p class="eng"><strong>\u041A\u043E\u043C\u043C\u0435\u043D\u0442\u0430\u0440\u0438\u0439</strong><br> \xAB\u0412\u044B\u0441\u0448\u0435\u0435 \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u0435\xBB [\u043D\u0430\u0437\u0432\u0430\u043D\u043E] \xAB\u041E\u0433\u043D\u0435\u043C\xBB \u043F\u043E\u0442\u043E\u043C\u0443, \u0447\u0442\u043E \u041E\u043D\u043E \u043F\u043E\u0433\u043B\u043E\u0449\u0430\u0435\u0442 \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u0443\u044E. \u0425\u043E\u0442\u044F \u0438 \xAB\u043D\u0438\u0441\u0445\u043E\u0434\u044F\xBB \u0434\u043E \u0443\u0440\u043E\u0432\u043D\u044F \u0441\u0443\u0431\u044A\u0435\u043A\u0442\u0430 \u043C\u0430\u0439\u0438 \u0438 \u0431\u0443\u0434\u0443\u0447\u0438 \xAB\u043F\u043E\u043A\u0440\u044B\u0442\u043E\xBB [\u043C\u0430\u0439\u0435\u0439], \u041E\u043D\u043E, \u0432 \u0441\u0438\u043B\u0443 \u0441\u0432\u043E\u0435\u0439 \u0421\u043F\u043E\u043D\u0442\u0430\u043D\u043D\u043E\u0439 \u0412\u043E\u043B\u0438, \xAB\u0447\u0430\u0441\u0442\u0438\u0447\u043D\u043E\xBB \xAB\u0437\u0430\u0436\u0438\u0433\u0430\u0435\u0442\xBB \xAB\u0442\u043E\u043F\u043B\u0438\u0432\u043E \u043F\u043E\u0437\u043D\u0430\u0432\u0430\u0435\u043C\u044B\u0445 [\u043E\u0431\u044A\u0435\u043A\u0442\u043E\u0432]\xBB, [\u0442\u0430\u043A\u0438\u0445, \u043A\u0430\u043A] \u0433\u043E\u043B\u0443\u0431\u043E\u0435, \u0436\u0435\u043B\u0442\u043E\u0435 \u0438 \u0442. \u0434., \u043F\u043E\u0434\u043E\u0431\u043D\u043E \u0442\u043E\u043C\u0443, \u043A\u0430\u043A \u043E\u0433\u043E\u043D\u044C [\u043C\u043E\u0436\u0435\u0442 \u0437\u0430\u0436\u0435\u0447\u044C \u0442\u043E\u043F\u043B\u0438\u0432\u043E], \u0434\u0430\u0436\u0435 \u0435\u0441\u043B\u0438 \u043E\u043D \u043F\u043E\u043A\u0440\u044B\u0442 \u0433\u0443\u0441\u0442\u044B\u043C \u0441\u043B\u043E\u0435\u043C \u043F\u0435\u043F\u043B\u0430. \u0421\u043C\u044B\u0441\u043B \u0441\u043B\u043E\u0432\u0430 \xAB\u0447\u0430\u0441\u0442\u0438\u0447\u043D\u043E\xBB \u0442\u0430\u043A\u043E\u0432: \u0441\u0436\u0438\u0433\u0430\u044F [\u043F\u043E\u0437\u043D\u0430\u0432\u0430\u0435\u043C\u043E\u0435], \u041E\u043D\u043E \u043F\u043E\u0433\u043B\u043E\u0449\u0430\u0435\u0442 \u0435\u0433\u043E \u043D\u0435 \u0446\u0435\u043B\u0438\u043A\u043E\u043C, \u043D\u043E \u0447\u0430\u0441\u0442\u0438\u0447\u043D\u043E, [\u043F\u043E\u044D\u0442\u043E\u043C\u0443 \u041E\u043D\u043E \u0432\u043D\u043E\u0432\u044C] \u0432\u044B\u0437\u044B\u0432\u0430\u0435\u0442 \u0435\u0433\u043E \u043F\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u0435 \u0447\u0435\u0440\u0435\u0437 \u0432\u043F\u0435\u0447\u0430\u0442\u043B\u0435\u043D\u0438\u0435 \u043E \u043D\u0435\u043C.</p><p class="eng">\u0412 \u0442\u043E\u043C, \u0447\u0442\u043E \u0441\u043F\u043E\u0441\u043E\u0431\u043D\u043E\u0441\u0442\u044C \u043F\u043E\u0433\u043B\u043E\u0449\u0435\u043D\u0438\u044F \u0435\u0441\u0442\u044C \u0443 \u0432\u0441\u0435\u0445 \u0441\u0443\u0431\u044A\u0435\u043A\u0442\u043E\u0432, \u043C\u043E\u0436\u043D\u043E \u0443\u0434\u043E\u0441\u0442\u043E\u0432\u0435\u0440\u0438\u0442\u044C\u0441\u044F \u043D\u0430 \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u043C \u043E\u043F\u044B\u0442\u0435. \u041A\u0430\u043A \u0431\u044B\u043B\u043E \u0441\u043A\u0430\u0437\u0430\u043D\u043E \u0434\u043E\u0441\u0442\u043E\u043F\u043E\u0447\u0442\u0435\u043D\u043D\u044B\u043C \u0423\u0442\u043F\u0430\u043B\u0430\u0434\u0435\u0432\u043E\u0439 \u0432 \u0435\u0433\u043E \u0441\u0442\u043E\u0442\u0440\u0430\u0445, \xAB[\u0412\u0441\u0435] \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0430, \u0434\u0430\u0436\u0435 [\u0442\u0430\u043A\u0438\u0435] \u0437\u0430\u043F\u0440\u0435\u0434\u0435\u043B\u044C\u043D\u044B\u0435, \u043A\u0430\u043A \u0411\u0440\u0430\u0445\u043C\u0430, \u0418\u043D\u0434\u0440\u0430 \u0438 \u0412\u0438\u0448\u043D\u0443, \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0443\u044E\u0442 \u0447\u0435\u0440\u0435\u0437 \u043F\u043E\u0433\u043B\u043E\u0449\u0435\u043D\u0438\u0435 [\u043E\u0431\u044A\u0435\u043A\u0442\u043E\u0432]; \u0430 \u043F\u043E\u0442\u043E\u043C\u0443, \u043E \u0411\u043E\u0436\u0435, \u0434\u0430 \u043F\u043E\u0447\u0442\u0443 \u044F \u0442\u0435\u0431\u044F, \u0444\u043E\u0440\u043C\u043E\u0439 \u043A\u043E\u0442\u043E\u0440\u043E\u0433\u043E \u0432\u044B\u0441\u0442\u0443\u043F\u0430\u0435\u0442 \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u0430\u044F\xBB.</p><p class="eng">\u0414\u0430\u043B\u0435\u0435, \u043A\u043E\u0433\u0434\u0430 [\u043F\u0440\u0430\u043A\u0442\u0438\u043A\u0443\u044E\u0449\u0438\u0439], \u0438\u0441\u043F\u043E\u043B\u044C\u0437\u0443\u044F \u0441\u043F\u043E\u0441\u043E\u0431\u044B (\u043F\u0440\u0430\u043A\u0442\u0438\u043A\u0438) \xAB\u044D\u043C\u0430\u043D\u0430\u0446\u0438\u0438\xBB, \u043E\u0441\u0443\u0449\u0435\u0441\u0442\u0432\u043B\u044F\u0435\u0442 \u0440\u0430\u0441\u043A\u0440\u044B\u0442\u0438\u0435 \u0431\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u0445 \u043E\u0440\u0433\u0430\u043D\u043E\u0432 \u0447\u0443\u0432\u0441\u0442\u0432, \u0430 [\u0438\u0441\u043F\u043E\u043B\u044C\u0437\u0443\u044F \u0441\u043F\u043E\u0441\u043E\u0431\u044B (\u043F\u0440\u0430\u043A\u0442\u0438\u043A\u0438)] \xAB\u0440\u0430\u0441\u0442\u0432\u043E\u0440\u0435\u043D\u0438\u044F\xBB, [\u0438\u0445] \u0441\u043E\u043A\u0440\u044B\u0442\u0438\u0435, \u0442\u043E\u0433\u0434\u0430:</p></div><div class="stanza"><a href="#s15" id="s15" class="num">15</a><p class="sans">\u092C\u0932\u0932\u093E\u092D\u0947 \u0935\u093F\u0936\u094D\u0935\u092E\u093E\u0924\u094D\u092E\u0938\u093E\u0924\u094D\u0915\u0930\u094B\u0924\u093F \u0965\u0967\u096B\u0965</p><p class="trans">Balal\u0101bhe vi\u015Bvam\u0101tmas\u0101tkaroti \u096515\u0965</p><p>\u041E\u0431\u0440\u0435\u0442\u0430\u044F <em>(l\u0101bhe)</em> \u0421\u0438\u043B\u0443 <em>(bala)</em>, [\u041E\u043D] \u0441\u0432\u043E\u0434\u0438\u0442 <em>(karoti)</em> \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u0443\u044E <em>(vi\u015Bvam)</em> \u043A \u0421\u0435\u0431\u0435 <em>(\u0101tmas\u0101t)</em>.</p><p class="eng"><strong>\u041A\u043E\u043C\u043C\u0435\u043D\u0442\u0430\u0440\u0438\u0439</strong><br> \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u0435 [\u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u0441\u044F] \u0421\u0438\u043B\u043E\u0439, [\u043A\u043E\u0433\u0434\u0430 \u041E\u043D\u043E] \u0443\u0434\u0430\u043B\u044F\u0435\u0442 \u043F\u043E\u043A\u0440\u043E\u0432\u044B \u0442\u0435\u043B\u0435\u0441\u043D\u043E\u0439, \u043F\u0440\u0430\u043D\u0438\u0447\u0435\u0441\u043A\u043E\u0439 \u0438 \u0434\u0440\u0443\u0433\u0438\u0445 [\u043E\u0431\u043E\u043B\u043E\u0447\u0435\u043A, \u0438 \u043A\u043E\u0433\u0434\u0430 \u041E\u043D\u043E] \u0421\u0432\u043E\u044E \u0438\u0441\u043A\u043E\u043D\u043D\u0443\u044E \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u044C \u043F\u0440\u0438\u0432\u043E\u0434\u0438\u0442 \u043A \u043F\u043E\u043B\u043D\u043E\u043C\u0443 \u0440\u0430\u0441\u043A\u0440\u044B\u0442\u0438\u044E. \u041A\u0430\u043A \u0431\u044B\u043B\u043E \u0441\u043A\u0430\u0437\u0430\u043D\u043E, \xAB\u0422\u043E\u0433\u0434\u0430, \u0441\u0442\u0440\u0435\u043C\u044F\u0441\u044C \u043A [\u044D\u0442\u043E\u0439] \u0421\u0438\u043B\u0435, \u043C\u0430\u043D\u0442\u0440\u044B \u2026\xBB \u0422\u0430\u043A\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C, \xAB\u043E\u0431\u0440\u0435\u0442\u0435\u043D\u0438\u0435 \u0421\u0438\u043B\u044B\xBB [\u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442] \u043E\u0431\u0440\u0430\u0449\u0435\u043D\u0438\u0435 [\u043F\u0440\u0430\u043A\u0442\u0438\u043A\u0443\u044E\u0449\u0435\u0433\u043E] \u043A \u0440\u0430\u0441\u043A\u0440\u044B\u0442\u0438\u044E \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439 \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u0438: [\u043E\u043D] \xAB\u0441\u0432\u043E\u0434\u0438\u0442 \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u0443\u044E \u043A \u0441\u0435\u0431\u0435\xBB, \u043E\u0442 \u0441\u0442\u0438\u0445\u0438\u0438 \u0437\u0435\u043C\u043B\u044F \u0434\u043E [\u0441\u0442\u0443\u043F\u0435\u043D\u0438] \u0421\u0430\u0434\u0430\u0448\u0438\u0432\u0430, \u0434\u0435\u043B\u0430\u044F [\u0435\u0435] \u043D\u0435\u043E\u0442\u043B\u0438\u0447\u0438\u043C\u043E\u0439 \u043E\u0442 \u0441\u0430\u043C\u043E\u0433\u043E \u0441\u0435\u0431\u044F.</p><p class="eng">\u041E\u0431 \u044D\u0442\u043E\u043C \u0432 \u0445\u0430\u0440\u0430\u043A\u0442\u0435\u0440\u043D\u043E\u043C \u0441\u0442\u0438\u043B\u0435 \u0433\u043E\u0432\u043E\u0440\u0438\u043B\u0438 \u0432 \u041A\u0440\u0430\u043C\u0430-\u0441\u0443\u0442\u0440\u0430\u0445 \u0434\u0440\u0435\u0432\u043D\u0438\u0435 \u0443\u0447\u0438\u0442\u0435\u043B\u044F: \xAB\u041F\u043E\u0434\u043E\u0431\u043D\u043E \u0442\u043E\u043C\u0443, \u043A\u0430\u043A \u0440\u0430\u0437\u0433\u043E\u0440\u0435\u0432\u0448\u0438\u0439\u0441\u044F \u043E\u0433\u043E\u043D\u044C \u0441\u0436\u0438\u0433\u0430\u0435\u0442 \u0442\u043E\u043F\u043B\u0438\u0432\u043E, [\u043F\u0440\u0430\u043A\u0442\u0438\u043A\u0443\u044E\u0449\u0438\u0439] \u0434\u043E\u043B\u0436\u0435\u043D \u0441\u0436\u0435\u0447\u044C \u043E\u043A\u043E\u0432\u044B \u0432 \u0432\u0438\u0434\u0435 \u043E\u0431\u044A\u0435\u043A\u0442\u043E\u0432 \u0447\u0443\u0432\u0441\u0442\u0432\xBB. \u0412 \u041F\u0440\u0430\u0442\u044C\u044F\u0431\u0445\u0438\u0434\u0436\u043D\u0435 \u0441\u043A\u0430\u0437\u0430\u043D\u043E: \xAB\u041D\u0435\u0432\u0435\u0440\u043D\u043E \u0431\u044B\u043B\u043E \u0431\u044B \u0443\u0442\u0432\u0435\u0440\u0436\u0434\u0430\u0442\u044C: \u2018[\u041A\u043E\u0433\u0434\u0430 \u0427\u0438\u0442\u0438] \u0441\u0432\u043E\u0434\u0438\u0442 \u043A \u0441\u0435\u0431\u0435 \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u0443\u044E, [\u0435\u0435] \u0432\u0441\u0435\u043E\u0445\u0432\u0430\u0442\u043D\u043E\u0441\u0442\u044C \u0432\u0440\u0435\u043C\u0435\u043D\u043D\u0430. \u041A\u0430\u043A \u043C\u043E\u0436\u043D\u043E [\u0432 \u0442\u0430\u043A\u043E\u043C \u0441\u043B\u0443\u0447\u0430\u0435] \u0433\u043E\u0432\u043E\u0440\u0438\u0442\u044C [\u043E \u0432\u0441\u0435\u043E\u0445\u0432\u0430\u0442\u043D\u043E\u0441\u0442\u0438]?\u2019. \u0422\u043E\u043B\u044C\u043A\u043E \u0431\u043B\u0430\u0433\u043E\u0434\u0430\u0440\u044F \u0432\u043E\u0437\u043D\u0438\u043A\u043D\u043E\u0432\u0435\u043D\u0438\u044E \u0438 \u0438\u0441\u0447\u0435\u0437\u043D\u043E\u0432\u0435\u043D\u0438\u044E \u0442\u0435\u043B\u0430 \u0438 \u0442. \u0434. \u043E\u043D\u0430, [\u0432\u0441\u0435\u043E\u0445\u0432\u0430\u0442\u043D\u043E\u0441\u0442\u044C], \u043A\u0430\u0436\u0435\u0442\u0441\u044F \u0432\u0440\u0435\u043C\u0435\u043D\u043D\u043E\u0439. \u0412 \u0440\u0435\u0430\u043B\u044C\u043D\u043E\u0441\u0442\u0438 \u0436\u0435 \u044D\u0442\u043E \u0432\u0440\u0435\u043C\u0435\u043D\u043D\u043E\u0441\u0442\u044C \u043F\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u044F [\u0432\u0441\u0435\u043E\u0445\u0432\u0430\u0442\u043D\u043E\u0441\u0442\u0438 \u0427\u0438\u0442\u0438] \u0437\u0430\u0432\u0438\u0441\u0438\u0442 \u043E\u0442 \u0442\u0435\u043B\u0430 \u0438 \u0442. \u0434., \u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u0440\u0435\u0430\u043B\u0438\u0437\u0443\u044E\u0442\u0441\u044F \u0431\u043B\u0430\u0433\u043E\u0434\u0430\u0440\u044F \u0441\u043F\u043E\u043D\u0442\u0430\u043D\u043D\u043E\u0441\u0442\u0438 \u0441\u0430\u043C\u043E\u0439 \u0427\u0438\u0442\u0438.</p><p class="eng">\u041E\u0434\u043D\u0430\u043A\u043E \u044D\u0442\u0430 [\u0432\u0441\u0435\u043E\u0445\u0432\u0430\u0442\u043D\u043E\u0441\u0442\u044C \u0427\u0438\u0442\u0438] \u0432\u0441\u0435\u0433\u0434\u0430 \u043D\u0430\u0445\u043E\u0434\u0438\u0442\u0441\u044F \u0432 \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u043D\u043E\u0441\u0442\u0438: \u0432 \u043F\u0440\u043E\u0442\u0438\u0432\u043D\u043E\u043C \u0441\u043B\u0443\u0447\u0430\u0435 \u0434\u0430\u0436\u0435 \u0442\u0435\u043B\u043E \u0438 \u0442. \u0434. \u043D\u0435 [\u0441\u043C\u043E\u0433\u043B\u0438 \u0431\u044B \u0441\u0442\u0430\u0442\u044C] \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u043D\u044B\u043C\u0438. \u041F\u043E\u044D\u0442\u043E\u043C\u0443 \u043F\u0440\u0430\u043A\u0442\u0438\u043A\u0430 \u0440\u0435\u043A\u043E\u043C\u0435\u043D\u0434\u0443\u0435\u0442\u0441\u044F \u043D\u0435 \u0440\u0430\u0434\u0438 \u0434\u043E\u0441\u0442\u0438\u0436\u0435\u043D\u0438\u044F \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F \u0441\u0443\u0431\u044A\u0435\u043A\u0442\u043D\u043E\u0441\u0442\u0438, \u043A\u043E\u0442\u043E\u0440\u0430\u044F \u043F\u043E \u0441\u0432\u043E\u0435\u0439 \u043F\u0440\u0438\u0440\u043E\u0434\u0435 \u0432\u0441\u0435\u0433\u0434\u0430 \u0441\u0432\u0435\u0442\u043E\u0437\u0430\u0440\u043D\u0430, \u043D\u043E \u0434\u043B\u044F \u0442\u043E\u0433\u043E, \u0447\u0442\u043E\u0431\u044B \u0443\u0434\u0430\u043B\u0438\u0442\u044C \u043B\u043E\u0436\u043D\u0443\u044E \u0438\u0434\u0435\u043D\u0442\u0438\u0444\u0438\u043A\u0430\u0446\u0438\u044E \u0441\u0443\u0431\u044A\u0435\u043A\u0442\u0430 \u0441 \u0442\u0435\u043B\u043E\u043C \u0438 \u0442. \u0434.\xBB.</p><p>\u0418 \u0432\u043E\u0442:</p></div><div class="stanza"><a href="#s16" id="s16" class="num">16</a><p class="sans">\u091A\u093F\u0926\u093E\u0928\u0928\u094D\u0926\u0932\u093E\u092D\u0947 \u0926\u0947\u0939\u093E\u0926\u093F\u0937\u0941 \u091A\u0947\u0924\u094D\u092F\u092E\u093E\u0928\u0947\u0937\u094D\u0935\u092A\u093F \u091A\u093F\u0926\u0948\u0915\u093E\u0924\u094D\u092E\u094D\u092F\u092A\u094D\u0930\u0924\u093F\u092A\u0924\u094D\u0924\u093F\u0926\u093E\u0930\u094D\u0922\u094D\u092F\u0902 \u091C\u0940\u0935\u0928\u094D\u092E\u0941\u0915\u094D\u0924\u093F\u0903 \u0965\u0967\u096C\u0965</p><p class="trans">Cid\u0101nandal\u0101bhe deh\u0101di\u1E63u cetyam\u0101ne\u1E63vapi cidaik\u0101tmyapratipattid\u0101r\u1E0Dhya\u1E41 j\u012Bvanmukti\u1E25 \u096516\u0965</p><p>[\u0421\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435] \u043E\u0441\u0432\u043E\u0431\u043E\u0436\u0434\u0435\u043D\u043D\u043E\u0441\u0442\u0438 \u043F\u0440\u0438 \u0436\u0438\u0437\u043D\u0438 <em>(j\u012Bvanmukti\u1E25)</em> [\u0432\u043E\u0437\u043D\u0438\u043A\u0430\u0435\u0442] \u043F\u0440\u0438 \u0434\u043E\u0441\u0442\u0438\u0436\u0435\u043D\u0438\u0438 <em>(l\u0101bhe)</em> \u0431\u043B\u0430\u0436\u0435\u043D\u0441\u0442\u0432\u0430 <em>(\u0101nanda)</em> \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F <em>(cit)</em> \u0434\u0430\u0436\u0435 <em>(api)</em> \u043F\u0440\u0438 \u043F\u0435\u0440\u0435\u0436\u0438\u0432\u0430\u043D\u0438\u0438 <em>(cetyam\u0101ne\u1E63u)</em> \u0442\u0435\u043B\u0430 <em>(deha)</em> \u0438 \u0442. \u0434. <em>(\u0101di\u1E63u)</em>, \u0435\u0441\u043B\u0438 \u0432\u043D\u0438\u043C\u0430\u043D\u0438\u0435 <em>(pratipatti)</em> \u0442\u0432\u0435\u0440\u0434\u043E \u0443\u0441\u0442\u0430\u043D\u043E\u0432\u0438\u043B\u043E\u0441\u044C <em>(d\u0101r\u1E0Dhyam)</em> \u043D\u0430 \u0442\u043E\u0436\u0434\u0435\u0441\u0442\u0432\u0435 <em>(aik\u0101tmya)</em> \u0441 \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u0435\u043C <em>(cit)</em>.</p><p class="eng"><strong>\u041A\u043E\u043C\u043C\u0435\u043D\u0442\u0430\u0440\u0438\u0439</strong><br> \u041A\u043E\u0433\u0434\u0430 \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u0430\u044F \u043F\u0435\u0440\u0435\u0436\u0438\u0432\u0430\u0435\u0442\u0441\u044F \u043A\u0430\u043A \u0438\u0434\u0435\u043D\u0442\u0438\u0447\u043D\u0430\u044F \u0441 \u042F \u0432 \u043E\u043F\u044B\u0442\u0435 \u0441\u0430\u043C\u0430\u0432\u0435\u0448\u0438, \u0442. \u0435. \xAB\u043F\u0440\u0438 \u0434\u043E\u0441\u0442\u0438\u0436\u0435\u043D\u0438\u0438 \u0431\u043B\u0430\u0436\u0435\u043D\u0441\u0442\u0432\u0430 \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F\xBB, \u0442\u043E \u0434\u0430\u0436\u0435 \u0432 \u0431\u043E\u0434\u0440\u0441\u0442\u0432\u0443\u044E\u0449\u0435\u043C \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0438, \u0432 \u043A\u043E\u0442\u043E\u0440\u043E\u043C \u043F\u043B\u043E\u0442\u043D\u043E\u0435 \u0438 \u0442\u043E\u043D\u043A\u043E\u0435 \u0442\u0435\u043B\u0430, \u0432\u043D\u0435\u0448\u043D\u044F\u044F \u0438 \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u044F\u044F \u043E\u0431\u044A\u0435\u043A\u0442\u0438\u0432\u043D\u043E\u0441\u0442\u044C \u0438 \u0442. \u0434. \u0441\u0442\u0430\u043D\u043E\u0432\u044F\u0442\u0441\u044F \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0438\u0432\u0430\u044E\u0449\u0438\u043C\u0438 \u0443\u0441\u043B\u043E\u0432\u0438\u044F\u043C\u0438, [\u0432\u043E\u0437\u043C\u043E\u0436\u043D\u0430] \xAB\u0442\u0432\u0435\u0440\u0434\u0430\u044F \u0443\u0441\u0442\u0430\u043D\u043E\u0432\u043A\u0430 \u0432\u043D\u0438\u043C\u0430\u043D\u0438\u044F \u043D\u0430 \u0442\u043E\u0436\u0434\u0435\u0441\u0442\u0432\u0435 \u0441 \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u0435\u043C\xBB, \u0442. \u0435. \u0435\u0441\u0442\u044C \u0443\u0441\u0442\u043E\u0439\u0447\u0438\u0432\u043E\u0435, \u0434\u043B\u0438\u0442\u0435\u043B\u044C\u043D\u043E\u0435 \u043F\u0435\u0440\u0435\u0436\u0438\u0432\u0430\u043D\u0438\u0435 \u0435\u0434\u0438\u043D\u0441\u0442\u0432\u0430 \u0441 \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u0435\u043C.</p><p class="eng">\u042D\u0442\u043E [c\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435 \u0438\u0434\u0435\u043D\u0442\u0438\u0447\u043D\u043E\u0441\u0442\u0438 \u0441 \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u0435\u043C \u043D\u0430\u0437\u044B\u0432\u0430\u0435\u0442\u0441\u044F] \xAB\u043E\u0441\u0432\u043E\u0431\u043E\u0436\u0434\u0435\u043D\u043D\u043E\u0441\u0442\u044C\u044E \u043F\u0440\u0438 \u0436\u0438\u0437\u043D\u0438\xBB, \u0442. \u0435. \u043E\u0441\u0432\u043E\u0431\u043E\u0436\u0434\u0435\u043D\u0438\u0435\u043C \u0442\u043E\u0433\u043E, \u043A\u0442\u043E \u043D\u0430\u0434\u0435\u043B\u0435\u043D \u0436\u0438\u0437\u043D\u044C\u044E \u0438 \u0434\u044B\u0445\u0430\u043D\u0438\u0435\u043C:</p><p class="eng">\u0443\u0437\u043D\u0430\u0432\u0430\u044F \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u0443\u044E \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u044C, [\u0438\u043D\u0434\u0438\u0432\u0438\u0434] \u043F\u043E\u043B\u043D\u043E\u0441\u0442\u044C\u044E \u0440\u0430\u0437\u0440\u0443\u0448\u0430\u0435\u0442 \u043E\u043A\u043E\u0432\u044B \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u043E\u0441\u0442\u0438.</p><p class="eng">\u041A\u0430\u043A \u0441\u043A\u0430\u0437\u0430\u043D\u043E \u0432 \u0421\u043F\u0430\u043D\u0434\u0430\u0448\u0430\u0441\u0442\u0440\u0435, \xAB\u0422\u043E\u0442, \u043A\u0442\u043E \u043E\u0431\u043B\u0430\u0434\u0430\u0435\u0442 \u0437\u043D\u0430\u043D\u0438\u0435\u043C \u044D\u0442\u043E\u0433\u043E, \u043A\u0442\u043E \u0432\u0438\u0434\u0438\u0442 \u043C\u0438\u0440 \u043A\u0430\u043A \u0438\u0433\u0440\u0443 [\u0411\u043E\u0433\u0430], \u043A\u0442\u043E \u0432\u0441\u0435\u0433\u0434\u0430 \u0441\u043E\u0441\u0440\u0435\u0434\u043E\u0442\u043E\u0447\u0435\u043D [\u043D\u0430 \u0412\u044B\u0441\u0448\u0435\u043C], \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u043E\u0441\u0432\u043E\u0431\u043E\u0436\u0434\u0435\u043D\u043D\u044B\u043C \u043F\u0440\u0438 \u0436\u0438\u0437\u043D\u0438, \u0432 \u044D\u0442\u043E\u043C \u043D\u0435\u0442 \u0441\u043E\u043C\u043D\u0435\u043D\u0438\u044F\xBB. \u041A\u0430\u043A\u0438\u043C \u0436\u0435 \u043E\u0431\u0440\u0430\u0437\u043E\u043C \u0432\u043E\u0437\u043C\u043E\u0436\u043D\u043E \u0434\u043E\u0441\u0442\u0438\u0436\u0435\u043D\u0438\u0435 \u0431\u043B\u0430\u0436\u0435\u043D\u0441\u0442\u0432\u0430 \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F? \u041D\u0430 \u044D\u0442\u043E \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u043E\u0442\u0432\u0435\u0442:</p></div><div class="stanza"><a href="#s17" id="s17" class="num">17</a><p class="sans">\u092E\u0927\u094D\u092F\u0935\u093F\u0915\u093E\u0938\u093E\u091A\u094D\u091A\u093F\u0926\u093E\u0928\u0928\u094D\u0926\u0932\u093E\u092D\u0903 \u0965\u0967\u096D\u0965</p><p class="trans">Madhyavik\u0101s\u0101ccid\u0101nandal\u0101bha\u1E25 \u096517\u0965</p><p>\u0414\u043E\u0441\u0442\u0438\u0436\u0435\u043D\u0438\u0435 <em>(l\u0101bha\u1E25)</em> \u0431\u043B\u0430\u0436\u0435\u043D\u0441\u0442\u0432\u0430 <em>(\u0101nanda)</em> \u0410\u0431\u0441\u043E\u043B\u044E\u0442\u043D\u043E\u0433\u043E \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F <em>(cit)</em> [\u0432\u043E\u0437\u043C\u043E\u0436\u043D\u043E] \u0447\u0435\u0440\u0435\u0437 \u0440\u0430\u0437\u0432\u0438\u0442\u0438\u0435 <em>(vik\u0101s\u0101t)</em> \u0446\u0435\u043D\u0442\u0440\u0430 <em>(madhya)</em>.</p><p class="eng"><strong>\u041A\u043E\u043C\u043C\u0435\u043D\u0442\u0430\u0440\u0438\u0439</strong><br> \xAB\u0426\u0435\u043D\u0442\u0440\u043E\u043C\xBB [\u043D\u0430\u0437\u044B\u0432\u0430\u0435\u0442\u0441\u044F] \u0411\u043E\u0433\u0438\u043D\u044F \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F, [\u043A\u043E\u0433\u0434\u0430 \u041E\u043D\u0430 \u043F\u043E\u043D\u0438\u043C\u0430\u0435\u0442\u0441\u044F \u043A\u0430\u043A] \u0433\u043B\u0443\u0431\u0438\u043D\u043D\u0430\u044F \u0440\u0435\u0430\u043B\u044C\u043D\u043E\u0441\u0442\u044C \u0432\u0441\u0435\u0433\u043E, [\u043A\u043E\u0433\u0434\u0430 \u043E\u0447\u0435\u0432\u0438\u0434\u043D\u043E, \u0447\u0442\u043E] \u043D\u0438\u043A\u0430\u043A\u0430\u044F \u0432\u0435\u0449\u044C \u043D\u0435 \u0441\u043C\u043E\u0436\u0435\u0442 \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u043E\u0432\u0430\u0442\u044C, \u043D\u0435 \u0431\u0443\u0434\u0443\u0447\u0438 \u043F\u0440\u0438\u0432\u044F\u0437\u0430\u043D\u0430 \u043A \u041D\u0435\u0439 \u043A\u0430\u043A \u043A \u0441\u0432\u043E\u0435\u0439 \u043E\u0441\u043D\u043E\u0432\u0435. \u0418 \u0445\u043E\u0442\u044F \u044D\u0442\u043E \u0442\u0430\u043A, \u041E\u043D\u0430 \u043D\u0430 \u0441\u0442\u0443\u043F\u0435\u043D\u0438 \u043C\u0430\u0439\u044F \u0443\u0442\u0430\u0438\u0432\u0430\u0435\u0442 \u0441\u0432\u043E\u044E \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u044C, \u0432 \u0441\u043E\u043E\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0438\u0438 \u0441 \u0438\u0434\u0435\u0435\u0439, \u0447\u0442\u043E \xAB\u043D\u0430 \u0443\u0440\u043E\u0432\u043D\u0435 \u043F\u0440\u0430\u043D\u044B \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u0435 \u043E\u0431\u0440\u0430\u0449\u0435\u043D\u043E \u0432\u043E\u0432\u043D\u0435\xBB.</p><p class="eng">\u0422\u0430\u043A\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C, \u041E\u043D\u0430 \u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u0441\u044F \u043F\u0440\u0430\u043D\u0430-\u0448\u0430\u043A\u0442\u0438, \u0441\u043F\u0443\u0441\u043A\u0430\u044F\u0441\u044C \u043F\u043E\u0441\u0442\u0435\u043F\u0435\u043D\u043D\u043E \u043D\u0430 \u0443\u0440\u043E\u0432\u043D\u0438 \u0443\u043C\u0430, \u0442\u0435\u043B\u0430 \u0438 \u0442. \u0434., \u0438 \u0440\u0430\u0441\u0441\u0435\u0438\u0432\u0430\u0435\u0442\u0441\u044F \u0432 \u043F\u043E\u0442\u043E\u043A\u0438 \u0442\u044B\u0441\u044F\u0447 \u043D\u0430\u0434\u0438. \u041D\u043E \u0434\u0430\u0436\u0435 \u0437\u0434\u0435\u0441\u044C \u041E\u043D\u0430 \u0432\u044B\u0440\u0430\u0436\u0435\u043D\u0430 \u043F\u0440\u0435\u0436\u0434\u0435 \u0432\u0441\u0435\u0433\u043E \u043A\u0430\u043A \u0441\u0440\u0435\u0434\u0438\u043D\u043D\u044B\u0439 \u043A\u0430\u043D\u0430\u043B, \u0438\u043C\u0435\u044F \u043C\u0435\u0441\u0442\u043E\u043F\u0440\u0435\u0431\u044B\u0432\u0430\u043D\u0438\u0435\u043C \u0411\u0440\u0430\u0445\u043C\u0430\u043D\u0430 \u0432 \u0444\u043E\u0440\u043C\u0435 \u043F\u0440\u0430\u043D\u0430-\u0448\u0430\u043A\u0442\u0438, [\u043A\u043E\u0442\u043E\u0440\u0430\u044F \u0442\u044F\u043D\u0435\u0442\u0441\u044F] \u043E\u0442 \xAB\u0434\u044B\u0440\u044B \u0411\u0440\u0430\u0445\u043C\u044B\xBB \u0432\u043F\u043B\u043E\u0442\u044C \u0434\u043E \u0430\u043D\u0443\u0441\u0430, \u043F\u043E\u0434\u043E\u0431\u043D\u043E \u0433\u043B\u0430\u0432\u043D\u043E\u0439 \u0436\u0438\u043B\u043A\u0435 \u043B\u0438\u0441\u0442\u0430 \u043F\u0430\u043B\u0430\u0448\u0438.</p><p class="eng">\u041F\u043E\u044D\u0442\u043E\u043C\u0443 \u0438\u043C\u0435\u043D\u043D\u043E [\u0438\u0437 \u041D\u0435\u0435] \u0432\u043E\u0437\u043D\u0438\u043A\u0430\u044E\u0442 \u0432\u0441\u0435 \u043F\u0441\u0438\u0445\u0438\u0447\u0435\u0441\u043A\u0438\u0435 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F \u0438 [\u0432 \u041D\u0435\u0439] \u043E\u043D\u0438 \u0438\u0441\u0447\u0435\u0437\u0430\u044E\u0442. \u0422\u0435\u043C \u043D\u0435 \u043C\u0435\u043D\u0435\u0435 \u0415\u0435 \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u043D\u0430\u044F \u043F\u0440\u0438\u0440\u043E\u0434\u0430 \u043E\u0441\u0442\u0430\u0435\u0442\u0441\u044F \u0441\u043E\u043A\u0440\u044B\u0442\u043E\u0439 \u0434\u043B\u044F \u0437\u0430\u0432\u0438\u0441\u0438\u043C\u043E\u0433\u043E \u0441\u0443\u0431\u044A\u0435\u043A\u0442\u0430. \u041A\u043E\u0433\u0434\u0430 \u0436\u0435 \u0411\u043E\u0433\u0438\u043D\u044F-\u0421\u043E\u0437\u043D\u0430\u043D\u0438\u0435, \u0431\u0443\u0434\u0443\u0447\u0438 \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0438\u043C \u0446\u0435\u043D\u0442\u0440\u043E\u043C \u0432\u0441\u0435\u0445 \u0432\u0435\u0449\u0435\u0439, \u0440\u0430\u0437\u0432\u0438\u0432\u0430\u0435\u0442\u0441\u044F \u043F\u0443\u0442\u0435\u043C \u0432\u044B\u0448\u0435\u043E\u043F\u0438\u0441\u0430\u043D\u043D\u044B\u0445 \u043F\u0440\u0430\u043A\u0442\u0438\u043A \u0441\u043E\u0435\u0434\u0438\u043D\u0435\u043D\u0438\u044F \u0438\u043B\u0438 \u0435\u0441\u043B\u0438 \u0440\u0430\u0437\u0432\u0438\u0432\u0430\u0435\u0442\u0441\u044F \u0432 \u0432\u0438\u0434\u0435 \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0435\u0433\u043E \u0446\u0435\u043D\u0442\u0440\u0430, \u043A\u0430\u043A \u043F\u0440\u0435\u0434\u043F\u0438\u0441\u044B\u0432\u0430\u0435\u0442\u0441\u044F, \u043A\u0430\u043D\u0430\u043B \u0411\u0440\u0430\u0445\u043C\u044B, \u0442\u043E\u0433\u0434\u0430 \xAB\u043F\u0440\u0438 \u0440\u0430\u0437\u0432\u0438\u0442\u0438\u0438 \u0446\u0435\u043D\u0442\u0440\u0430\xBB \u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u0438\u0442 \xAB\u0434\u043E\u0441\u0442\u0438\u0436\u0435\u043D\u0438\u0435\xBB, \u0442. \u0435. \u043E\u0431\u0440\u0435\u0442\u0435\u043D\u0438\u0435 \xAB\u0431\u043B\u0430\u0436\u0435\u043D\u0441\u0442\u0432\u0430 \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F\xBB.</p><p class="eng">\u0418 \u044D\u0442\u043E, \u043A\u0430\u043A \u0433\u043E\u0432\u043E\u0440\u0438\u0442\u0441\u044F \u0432\u044B\u0448\u0435, \u0432\u0435\u0434\u0435\u0442 \u043A \u043E\u0441\u0432\u043E\u0431\u043E\u0436\u0434\u0435\u043D\u0438\u044E. \u0418\u043C\u0435\u044F \u0432 \u0432\u0438\u0434\u0443 \u0441\u043F\u043E\u0441\u043E\u0431\u044B \u0440\u0430\u0437\u0432\u0438\u0442\u0438\u044F \u0446\u0435\u043D\u0442\u0440\u0430, [\u0430\u0432\u0442\u043E\u0440] \u0433\u043E\u0432\u043E\u0440\u0438\u0442:</p></div><div class="stanza"><a href="#s18" id="s18" class="num">18</a><p class="sans">\u0935\u093F\u0915\u0932\u094D\u092A\u0915\u094D\u0937\u092F\u0936\u0915\u094D\u0924\u093F\u0938\u0916\u093C\u094B\u091A\u0935\u093F\u0915\u093E\u0938\u0935\u093E\u0939\u091A\u094D\u091B\u0947\u0926\u0926\u094D\u092F\u0928\u094D\u0924\u0915\u094B\u091F\u093F\u0928\u093F\u092D\u093E\u0932\u0928\u093E\u0926\u092F \u0907\u0939\u094B\u092A\u093E\u092F\u093E\u0903 \u0965\u0967\u096E\u0965</p><p class="trans">Vikalpak\u1E63aya\u015Baktisa\u1E45kocavik\u0101sav\u0101hacchedadyantako\u1E6Dinibh\u0101lan\u0101daya ihop\u0101y\u0101\u1E25 \u096518\u0965</p><p>\u0412\u043E\u0442 <em>(iha)</em> \u0441\u0440\u0435\u0434\u0441\u0442\u0432\u0430 <em>(up\u0101y\u0101\u1E25)</em>: \u0440\u0430\u0441\u0442\u0432\u043E\u0440\u0435\u043D\u0438\u0435 <em>(k\u1E63aya)</em> \u043C\u044B\u0441\u043B\u0435\u0439 <em>(vikalpa)</em>; \u0441\u0436\u0430\u0442\u0438\u0435 <em>(sa\u1E45koca)</em> \u0438 \u0440\u0430\u0437\u0432\u043E\u0440\u0430\u0447\u0438\u0432\u0430\u043D\u0438\u0435 <em>(vik\u0101sa)</em> \u0448\u0430\u043A\u0442\u0438 <em>(\u015Bakti)</em>; \u0443\u043D\u0438\u0447\u0442\u043E\u0436\u0435\u043D\u0438\u0435 \u0432\u0435\u0442\u0440\u043E\u0432 <em>(v\u0101ha-cheda)</em> \u0438 \u0442.\u0434. <em>(\u0101di)</em>; \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u043D\u0438\u0435 <em>(nibh\u0101lana)</em> \u043D\u0430\u0447\u0430\u043B\u0430 \u0438 \u043A\u043E\u043D\u0446\u0430 <em>(antako\u1E6Di)</em> \u0438 \u0442. \u0434. <em>(\u0101daya\u1E25)</em></p><p class="eng"><strong>\u041A\u043E\u043C\u043C\u0435\u043D\u0442\u0430\u0440\u0438\u0439</strong><br> \u041F\u0440\u0438 \u0440\u0430\u0437\u0432\u0438\u0442\u0438\u0438 \u0446\u0435\u043D\u0442\u0440\u0430\u043B\u044C\u043D\u043E\u0439 \u0448\u0430\u043A\u0442\u0438 \xAB\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u0430 \u0437\u0434\u0435\u0441\u044C [\u0442\u0430\u043A\u043E\u0432\u044B]: \u0440\u0430\u0441\u0442\u0432\u043E\u0440\u0435\u043D\u0438\u0435 \u0440\u0430\u0437\u043B\u0438\u0447\u0435\u043D\u0438\u044F \u0438 \u0442. \u043F.\xBB.</p><p class="eng">\u0420\u0430\u043D\u0435\u0435 \u0433\u043E\u0432\u043E\u0440\u0438\u043B\u043E\u0441\u044C, \u0447\u0442\u043E \u0440\u0430\u0441\u043A\u0440\u044B\u0442\u0438\u0435 \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F, \u043A\u043E\u0442\u043E\u0440\u043E\u0435 \u0441\u0443\u0442\u044C \u0446\u0435\u043D\u0442\u0440 \u0432\u0441\u0435\u0433\u043E, \u0434\u043E\u0441\u0442\u0438\u0433\u0430\u0435\u0442\u0441\u044F \u0447\u0435\u0440\u0435\u0437 \u0441\u043B\u0435\u0434\u043E\u0432\u0430\u043D\u0438\u0435 \u0432\u044B\u0448\u0435\u0443\u043F\u043E\u043C\u044F\u043D\u0443\u0442\u043E\u043C\u0443 \u043F\u044F\u0442\u0435\u0440\u0438\u0447\u043D\u043E\u043C\u0443 \u043A\u043E\u043C\u043F\u043B\u0435\u043A\u0441\u0443 \u0431\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u0445 \u0444\u0443\u043D\u043A\u0446\u0438\u0439. \u041E\u0434\u043D\u0430\u043A\u043E [\u0437\u0434\u0435\u0441\u044C] \u0433\u043E\u0432\u043E\u0440\u0438\u0442\u0441\u044F \u043E \u0434\u0440\u0443\u0433\u043E\u043C \u0441\u0440\u0435\u0434\u0441\u0442\u0432\u0435. \u0415\u0441\u0442\u044C \u043B\u0435\u0433\u043A\u043E\u0435 \u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E, \u0441 \u043F\u043E\u043C\u043E\u0449\u044C\u044E \u043A\u043E\u0442\u043E\u0440\u043E\u0433\u043E \u0440\u0430\u0441\u0441\u0435\u0438\u0432\u0430\u044E\u0442\u0441\u044F \u0442\u044F\u0433\u043E\u0442\u044B, [\u0432\u043E\u0437\u043D\u0438\u043A\u0430\u044E\u0449\u0438\u0435 \u043E\u0442] \u0442\u0440\u0443\u0434\u043E\u0435\u043C\u043A\u0438\u0445 \u0434\u0443\u0445\u043E\u0432\u043D\u044B\u0445 \u0434\u0438\u0441\u0446\u0438\u043F\u043B\u0438\u043D, \u043D\u0430\u043F\u0440\u0438\u043C\u0435\u0440, \u043F\u0440\u0430\u043D\u0430\u044F\u043C\u044B, \u043C\u0443\u0434\u0440\u044B, \u0431\u0430\u043D\u0434\u0445\u0438 \u0438 \u0434\u0440. [\u0415\u0441\u043B\u0438] \u0441\u043E\u0437\u043D\u0430\u043D\u0438\u0435 [\u043F\u0440\u0430\u043A\u0442\u0438\u043A\u0443\u044E\u0449\u0435\u0433\u043E] \u0441\u043E\u0441\u0440\u0435\u0434\u043E\u0442\u043E\u0447\u0438\u0432\u0430\u0435\u0442\u0441\u044F \u043D\u0430 \u0421\u0435\u0440\u0434\u0446\u0435, \u0440\u0430\u0441\u0441\u0435\u0438\u0432\u0430\u044F, \u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C \u0432\u044B\u0448\u0435\u0443\u043A\u0430\u0437\u0430\u043D\u043D\u043E\u0433\u043E \u043C\u0435\u0442\u043E\u0434\u0430, \u0440\u0430\u0437\u043B\u0438\u0447\u0430\u044E\u0449\u0438\u0435 \u043C\u044B\u0441\u043B\u0438, \u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u043F\u0440\u0435\u043F\u044F\u0442\u0441\u0442\u0432\u0443\u044E\u0442 \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u043D\u0438\u044E \u0432 \u0421\u0430\u043C\u043E\u0441\u0442\u0438, [\u0435\u0441\u043B\u0438 \u043E\u043D] \u043D\u0438 \u043E \u0447\u0435\u043C \u043D\u0435 \u0440\u0435\u0444\u043B\u0435\u043A\u0441\u0438\u0440\u0443\u0435\u0442, \u0432\u044B\u0445\u043E\u0434\u044F \u043D\u0430 \u0443\u0440\u043E\u0432\u0435\u043D\u044C \u043D\u0435\u0440\u0430\u0437\u043B\u0438\u0447\u0435\u043D\u0438\u044F, \u0442\u043E \u043E\u043D \u0438\u043C\u0435\u0435\u0442 \u0446\u0435\u043B\u044C\u043D\u043E\u0435 \u0432\u043E\u0441\u043F\u0440\u0438\u044F\u0442\u0438\u0435 \u0427\u0438\u0442 \u043A\u0430\u043A \u0438\u0441\u0442\u0438\u043D\u043D\u043E\u0433\u043E \u0441\u0443\u0431\u044A\u0435\u043A\u0442\u0430, \u043D\u0435\u0437\u0430\u0432\u0438\u0441\u0438\u043C\u043E\u0433\u043E \u043E\u0442 \u0442\u0435\u043B\u0430 \u0438 \u0442. \u043F., \u0438 \u043F\u043E\u044D\u0442\u043E\u043C\u0443 \u0443\u0436\u0435 \u0437\u0430 \u043A\u043E\u0440\u043E\u0442\u043A\u043E\u0435 \u0432\u0440\u0435\u043C\u044F \u043E\u043D \u043F\u043E\u0434\u043D\u0438\u043C\u0430\u0435\u0442\u0441\u044F \u043D\u0430 \u0443\u0440\u043E\u0432\u043D\u0438 \u0442\u0443\u0440\u044C\u044F \u0438 \u0442\u0443\u0440\u044C\u044F\u0442\u0438\u0442\u0430, \u0441\u0442\u0443\u043F\u0435\u043D\u0438 \u0440\u0430\u0441\u043A\u0440\u044B\u0442\u0438\u044F [\u042F].</p><p class="eng">\u041A\u0430\u043A \u0433\u043E\u0432\u043E\u0440\u0438\u0442\u0441\u044F \u0432 \u0428\u0440\u0438 \u041F\u0440\u0430\u0442\u044C\u044F\u0431\u0445\u0438\u0434\u0436\u043D\u0435, \xAB\u0431\u043B\u0430\u0433\u043E\u0434\u0430\u0440\u044F \u0441\u043E\u0441\u0440\u0435\u0434\u043E\u0442\u043E\u0447\u0435\u043D\u043D\u043E\u0441\u0442\u0438 \u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F, \u0443\u043D\u0438\u0447\u0442\u043E\u0436\u0430\u044E\u0449\u0435\u043C \u0440\u0430\u0437\u043B\u0438\u0447\u0435\u043D\u0438\u044F, \u0434\u043E\u0441\u0442\u0438\u0433\u0430\u0435\u0442\u0441\u044F \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435 \u0418\u0448\u0432\u0430\u0440\u044B\xBB. \u0422\u0430\u043A\u0436\u0435 \u0438 \u0432 \u0428\u0440\u0438 \u0421\u043F\u0430\u043D\u0434\u0435: \xAB\u041A\u043E\u0433\u0434\u0430 [\u0432 \u0441\u043E\u0437\u043D\u0430\u043D\u0438\u0438] \u0438\u0441\u0447\u0435\u0437\u043D\u0435\u0442 \u0432\u043E\u043B\u043D\u0435\u043D\u0438\u0435, \u0442\u043E\u0433\u0434\u0430 \u0431\u0443\u0434\u0435\u0442 \u043E\u0431\u0440\u0435\u0442\u0435\u043D\u043E \u0432\u044B\u0441\u0448\u0435\u0435 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435\xBB.</p><p class="eng">\u0418 \u0432 \u0428\u0440\u0438 \u0414\u0436\u043D\u044F\u043D\u0430\u0433\u0430\u0440\u0431\u0445\u0435: \xAB\u041E \u041C\u0430\u0442\u044C, \u0441\u0442\u043E\u0439\u043A\u0438\u0435 \u043B\u044E\u0434\u0438, \u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u043F\u0435\u0440\u0435\u0441\u0442\u0430\u044E\u0442 [\u0446\u0435\u043F\u043B\u044F\u0442\u044C\u0441\u044F] \u0437\u0430 \u0432\u0441\u0435 \u0442\u043E, \u0447\u0442\u043E \u043F\u043E\u0440\u043E\u0436\u0434\u0435\u043D\u043E \u0440\u0430\u0437\u043B\u0438\u0447\u0430\u044E\u0449\u0435\u0439 \u043C\u044B\u0441\u043B\u044C\u044E \u0438 \u043E\u0441\u0432\u043E\u0431\u043E\u0436\u0434\u0430\u044E\u0442\u0441\u044F \u043E\u0442 \u0447\u0443\u0432\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u0445 \u0432\u043B\u0435\u0447\u0435\u043D\u0438\u0439, \u043F\u0440\u0438\u0445\u043E\u0434\u044F\u0442 \u043A \u0447\u0438\u0441\u0442\u043E\u043C\u0443 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044E. \u042D\u0442\u043E \u0432\u044B\u0441\u0448\u0435\u0435 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435 \u043E\u0431\u0440\u0435\u0442\u0430\u0435\u0442\u0441\u044F \u0438\u043C\u0438 \u0441\u0440\u0430\u0437\u0443, \u043F\u043E \u0442\u0432\u043E\u0435\u0439 \u043C\u0438\u043B\u043E\u0441\u0442\u0438, \u043A\u043E\u0442\u043E\u0440\u0430\u044F [\u043F\u043E \u0441\u0432\u043E\u0435\u0439 \u043F\u0440\u0438\u0440\u043E\u0434\u0435 \u0435\u0441\u0442\u044C] \u043F\u043E\u0441\u0442\u043E\u044F\u043D\u043D\u043E\u0435 \u0438\u0441\u0442\u0435\u0447\u0435\u043D\u0438\u0435 \u043D\u0435\u0441\u0440\u0430\u0432\u043D\u0435\u043D\u043D\u043E\u0439 [\u0431\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439] \u0430\u043C\u0440\u0438\u0442\u044B\xBB.</p><p class="eng">\u041E\u0431 \u044D\u0442\u043E\u043C \u0441\u0440\u0435\u0434\u0441\u0442\u0432\u0435, \u0438\u0437\u043B\u0430\u0433\u0430\u0435\u043C\u043E\u043C \u0432 \u041F\u0440\u0430\u0442\u044C\u044F\u0431\u0445\u0438\u0434\u0436\u043D\u0435, \u0433\u043E\u0432\u043E\u0440\u0438\u0442\u0441\u044F \u043A\u0430\u043A \u043E \u0432\u044B\u0441\u0448\u0435\u043C. \u041D\u043E \u043C\u044B \u0442\u0430\u043A\u0436\u0435 \u043E\u043F\u0438\u0441\u044B\u0432\u0430\u0435\u043C \u0441\u0436\u0430\u0442\u0438\u0435 \u0438 \u0442. \u043F. \u0428\u0430\u043A\u0442\u0438, \u043D\u0435\u0441\u043C\u043E\u0442\u0440\u044F \u043D\u0430 \u0442\u043E, \u0447\u0442\u043E \u043E\u0431 \u044D\u0442\u043E\u043C \u043D\u0435 \u0433\u043E\u0432\u043E\u0440\u0438\u043B\u043E\u0441\u044C \u0432 \u041F\u0440\u0430\u0442\u044C\u044F\u0431\u0445\u0438\u0434\u0436\u043D\u0435, [\u043E\u043F\u0438\u0441\u044B\u0432\u0430\u0435\u043C], \u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u044D\u0442\u043E \u043D\u0430\u0445\u043E\u0434\u0438\u0442\u0441\u044F \u0432 \u0434\u0443\u0445\u0435 \u0441\u0432\u044F\u0449\u0435\u043D\u043D\u043E\u0439 \u0442\u0440\u0430\u0434\u0438\u0446\u0438\u0438. \u041A\u043E\u0433\u0434\u0430 \u043E\u043F\u0438\u0441\u044B\u0432\u0430\u0435\u0442\u0441\u044F \u043C\u043D\u043E\u0433\u043E\u043E\u0431\u0440\u0430\u0437\u0438\u0435 [\u0441\u0440\u0435\u0434\u0441\u0442\u0432], \u043A\u0430\u0436\u0434\u044B\u0439 [\u043C\u043E\u0436\u0435\u0442] \u0432\u044B\u0431\u0440\u0430\u0442\u044C \u0438\u0437 \u043D\u0438\u0445 \u043A\u0430\u043A\u043E\u0435-\u043D\u0438\u0431\u0443\u0434\u044C [\u0434\u043B\u044F \u0441\u0435\u0431\u044F]. \xAB\u0421\u0436\u0430\u0442\u0438\u0435 \u0428\u0430\u043A\u0442\u0438\xBB\u2014 [\u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442] \u043F\u0440\u043E\u0446\u0435\u0441\u0441 \u043E\u0442\u0432\u043B\u0435\u0447\u0435\u043D\u0438\u044F \u043E\u0442 \u0442\u043E\u0433\u043E, \u0447\u0442\u043E \u043F\u0440\u043E\u0445\u043E\u0434\u0438\u0442 \u0447\u0435\u0440\u0435\u0437 \u0432\u0440\u0430\u0442\u0430 \u0447\u0443\u0432\u0441\u0442\u0432, \u0438 \u043E\u0431\u0440\u0430\u0449\u0435\u043D\u0438\u0435 \u043A \u042F.</p><p class="eng">\u041A\u0430\u043A \u0431\u044B\u043B\u043E \u0441\u043A\u0430\u0437\u0430\u043D\u043E \u0432 \u043F\u0435\u0440\u0432\u043E\u0439 \u043C\u0430\u043D\u0442\u0440\u0435 \u0447\u0435\u0442\u0432\u0435\u0440\u0442\u043E\u0439 \u0433\u043B\u0430\u0432\u044B \u041A\u0430\u0442\u0445\u0430\u0432\u0430\u043B\u043B\u0438-\u0443\u043F\u0430\u043D\u0438\u0448\u0430\u0434\u044B, \u043F\u0440\u0438\u043D\u0430\u0434\u043B\u0435\u0436\u0430\u0449\u0435\u0439 \u043A \u0410\u0442\u0445\u0430\u0440\u0432\u0430\u043D\u0438\u043A\u0435: \xAB\u0421\u0430\u043C\u043E\u0441\u0443\u0449\u0438\u0439 \u043F\u0440\u043E\u0434\u0435\u043B\u0430\u043B \u0432\u043D\u0435\u0448\u043D\u0438\u0435 \u043E\u0442\u0432\u0435\u0440\u0441\u0442\u0438\u044F [\u0434\u043B\u044F \u0447\u0443\u0432\u0441\u0442\u0432], \u0438 \u043F\u043E\u044D\u0442\u043E\u043C\u0443 [\u043E\u0431\u044B\u0447\u043D\u044B\u0439 \u0447\u0435\u043B\u043E\u0432\u0435\u043A] \u0441\u043C\u043E\u0442\u0440\u0438\u0442 \u0432\u043E\u0432\u043D\u0435, \u0430 \u043D\u0435 \u0432\u043D\u0443\u0442\u0440\u044C \u0441\u0435\u0431\u044F. \u041D\u043E \u043C\u0443\u0434\u0440\u044B\u0439, \u0436\u0435\u043B\u0430\u044F \u0432\u043A\u0443\u0441\u0438\u0442\u044C \u0431\u0435\u0441\u0441\u043C\u0435\u0440\u0442\u0438\u044F, \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u0435\u0442 \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0435\u0435 \u042F \u0441 \u0437\u0430\u043A\u0440\u044B\u0442\u044B\u043C\u0438 \u0433\u043B\u0430\u0437\u0430\u043C\u0438\xBB. \u0418\u043B\u0438 \u0436\u0435 [\u0441\u0436\u0430\u0442\u0438\u0435 \u0428\u0430\u043A\u0442\u0438 \u043C\u043E\u0436\u0435\u0442 \u043E\u0431\u043E\u0437\u043D\u0430\u0447\u0430\u0442\u044C]\u2014 \u0441\u0442\u044F\u0433\u0438\u0432\u0430\u043D\u0438\u0435 \u0432 \u0441\u0435\u0440\u0434\u0446\u0435\u0432\u0438\u043D\u0443 \u0432\u0441\u0435\u0445 [\u0415\u0435] \u0432\u043D\u0435\u0448\u043D\u0438\u0445 \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u0439, \u043F\u043E\u0434\u043E\u0431\u043D\u043E \u0442\u043E\u043C\u0443 \u043A\u0430\u043A \u0447\u0435\u0440\u0435\u043F\u0430\u0445\u0430 \u0432 \u0441\u043B\u0443\u0447\u0430\u0435 \u043E\u043F\u0430\u0441\u043D\u043E\u0441\u0442\u0438 [\u0431\u044B\u0441\u0442\u0440\u043E] \u043F\u0440\u044F\u0447\u0435\u0442\u0441\u044F \u0432 \u043F\u0430\u043D\u0446\u0438\u0440\u0435.</p><p class="eng">\u041A\u0430\u043A \u0441\u043A\u0430\u0437\u0430\u043D\u043E: \xAB\u043A\u043E\u0433\u0434\u0430 [\u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u0438\u0442] \u0432\u043E\u0437\u0432\u0440\u0430\u0449\u0435\u043D\u0438\u0435, [\u0442\u043E \u0432\u043E\u0437\u043D\u0438\u043A\u0430\u0435\u0442] \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435 \u043F\u043E\u0441\u0442\u043E\u044F\u043D\u0441\u0442\u0432\u0430\xBB.</p><p class="eng">\xAB\u0420\u0430\u0437\u0432\u0438\u0442\u0438\u0435 \u0428\u0430\u043A\u0442\u0438\xBB, \u0441\u043E\u043A\u0440\u044B\u0442\u043E\u0439 \u0432\u043D\u0443\u0442\u0440\u0438, \u0431\u044B\u0432\u0430\u0435\u0442 \u0431\u043B\u0430\u0433\u043E\u0434\u0430\u0440\u044F \u0432\u043D\u0435\u0437\u0430\u043F\u043D\u043E\u043C\u0443 \u043E\u0442\u0432\u0435\u0440\u0437\u0430\u043D\u0438\u044E \u0432\u0441\u0435\u0445 \u043E\u0440\u0433\u0430\u043D\u043E\u0432 \u0447\u0443\u0432\u0441\u0442\u0432.</p><p class="eng">\xAB\u0426\u0435\u043B\u044C \u0441\u043B\u0435\u0434\u0443\u0435\u0442 [\u0432\u0438\u0434\u0435\u0442\u044C] \u0432\u043D\u0443\u0442\u0440\u0438; \u0432\u0435\u0434\u044C \u0432\u043D\u0435\u0448\u043D\u0435\u0435 \u043F\u043E\u043B\u0435 \u0437\u0440\u0435\u043D\u0438\u044F [\u0443\u0434\u0435\u0440\u0436\u0438\u0432\u0430\u0435\u0442\u0441\u044F \u0431\u0435\u0437 \u0442\u0440\u0443\u0434\u0430], \u043D\u0435\u0437\u0430\u0432\u0438\u0441\u0438\u043C\u043E \u043E\u0442 \u0442\u043E\u0433\u043E, \u0437\u0430\u043A\u0440\u044B\u0442\u044B \u0438\u043B\u0438 \u043E\u0442\u043A\u0440\u044B\u0442\u044B [\u0433\u043B\u0430\u0437\u0430]\xBB.</p><p class="eng">\u041F\u0440\u0438 \u0432\u0445\u043E\u0436\u0434\u0435\u043D\u0438\u0438 \u0432 \u0431\u0445\u0430\u0439\u0440\u0430\u0432\u0438-\u043C\u0443\u0434\u0440\u0443 [\u043D\u0435 \u0438\u0441\u0447\u0435\u0437\u0430\u0435\u0442] \u0447\u0443\u0432\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0435 \u0432\u043E\u0441\u043F\u0440\u0438\u044F\u0442\u0438\u0435.</p><p class="eng">\u041A\u0430\u043A \u0433\u043E\u0432\u043E\u0440\u0438\u0442\u0441\u044F \u0432 \u041A\u0430\u043A\u0448\u044C\u044F-\u0441\u0442\u043E\u0442\u0440\u0435, \xAB\u041F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C \u0432\u043E\u043B\u0438 \u043E\u0434\u043D\u043E\u0432\u0440\u0435\u043C\u0435\u043D\u043D\u043E \u0438 \u043F\u043E\u0432\u0441\u044E\u0434\u0443 \u043D\u0430\u043F\u0440\u0430\u0432\u043B\u044F\u044F \u0432\u0441\u0435 \u0441\u0438\u043B\u044B \u0447\u0443\u0432\u0441\u0442\u0432, \u0442\u0430\u043A\u0438\u0445 \u043A\u0430\u043A \u0437\u0440\u0435\u043D\u0438\u0435 \u0438 \u0442. \u0434., \u043D\u0430 \u0441\u043E\u043E\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0443\u044E\u0449\u0438\u0435 \u043E\u0431\u044A\u0435\u043A\u0442\u044B \u0438 \u0437\u0430\u043A\u0440\u0435\u043F\u043B\u044F\u044F\u0441\u044C \u0432 \u0441\u0435\u0440\u0434\u0446\u0435\u0432\u0438\u043D\u0435 [\u0447\u0443\u0432\u0441\u0442\u0432] \u0441\u043B\u043E\u0432\u043D\u043E \u0437\u043E\u043B\u043E\u0442\u043E\u0439 \u0441\u0442\u043E\u043B\u0431, \u0442\u044B, [\u0428\u0438\u0432\u0430], \u043E\u0434\u0438\u043D \u044F\u0432\u043B\u044F\u0435\u0448\u044C \u0441\u0435\u0431\u044F \u043A\u0430\u043A \u043E\u0441\u043D\u043E\u0432\u0430\u043D\u0438\u0435 \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u043E\u0439\xBB.</p><p class="eng">\u0422\u0430\u043A\u0436\u0435 \u0438 \u043F\u043E\u0447\u0442\u0435\u043D\u043D\u0435\u0439\u0448\u0438\u0439 \u041A\u0430\u043B\u043B\u0430\u0442\u0430 \u0443\u0442\u0432\u0435\u0440\u0436\u0434\u0430\u043B: \xAB\u041E\u0441\u0443\u0449\u0435\u0441\u0442\u0432\u043B\u0435\u043D\u0438\u0435 \u044D\u0442\u043E\u0433\u043E [\u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u0438\u0442] \u0431\u043B\u0430\u0433\u043E\u0434\u0430\u0440\u044F \u0442\u0440\u0430\u043D\u0441\u0444\u043E\u0440\u043C\u0430\u0446\u0438\u0438 [\u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F, \u043D\u0430\u043F\u0440\u0430\u0432\u043B\u0435\u043D\u043D\u043E\u0433\u043E \u043D\u0430] \u0444\u043E\u0440\u043C\u044B \u0438 \u0442. \u043F.\xBB.</p><p class="eng">\u0427\u0442\u043E \u043A\u0430\u0441\u0430\u0435\u0442\u0441\u044F \u0441\u0436\u0430\u0442\u0438\u044F <em>(sa\u0403koca)</em> \u0438 \u0440\u0430\u0437\u0432\u0438\u0442\u0438\u044F <em>(vik\u0430sa)</em>\u0428\u0430\u043A\u0442\u0438, [\u0442\u043E \u0432\u0438\u043A\u0430\u0441\u0430 \u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442] \u043F\u0440\u0430\u043A\u0442\u0438\u043A\u0443 \u0440\u0430\u0441\u0448\u0438\u0440\u0435\u043D\u0438\u044F \u0438 \u043E\u0441\u0442\u0430\u043D\u043E\u0432\u043A\u0438 [\u0428\u0430\u043A\u0442\u0438] \u043D\u0430 \u0441\u0442\u0430\u0434\u0438\u0438 \u043F\u043E\u0441\u0442\u0435\u043F\u0435\u043D\u043D\u043E\u0433\u043E \u0432\u043E\u0441\u0445\u043E\u0436\u0434\u0435\u043D\u0438\u044F \u043A\u0443\u043D\u0434\u0430\u043B\u0438\u043D\u0438 \u0447\u0435\u0440\u0435\u0437 \u043F\u043E\u0441\u043B\u0435\u0434\u043E\u0432\u0430\u0442\u0435\u043B\u044C\u043D\u0443\u044E \u0440\u0435\u0433\u0443\u043B\u044F\u0446\u0438\u044E \u043F\u043E\u0442\u043E\u043A\u043E\u0432 \u0442\u043E\u043D\u043A\u043E\u0439 \u043F\u0440\u0430\u043D\u0430-\u0448\u0430\u043A\u0442\u0438 \u0432 \u043D\u043E\u0437\u0434\u0440\u044F\u0445, [\u0430 \u0442\u0430\u043A\u0436\u0435] \u0447\u0435\u0440\u0435\u0437 [\u0441\u043E\u0441\u0440\u0435\u0434\u043E\u0442\u043E\u0447\u0435\u043D\u0438\u0435] \u043D\u0430 \u043F\u0440\u043E\u0441\u0442\u0440\u0430\u043D\u0441\u0442\u0432\u0435 \u043C\u0435\u0436\u0434\u0443 \u0431\u0440\u043E\u0432\u0435\u0439. \u041D\u0430 \u0441\u0442\u0430\u0434\u0438\u0438 \u043D\u0438\u0441\u0445\u043E\u0434\u044F\u0449\u0435\u0439 \u043A\u0443\u043D\u0434\u0430\u043B\u0438\u043D\u0438, [\u0441\u0442\u0440\u0435\u043C\u044F\u0449\u0435\u0439\u0441\u044F \u043A] \u0448\u0435\u0441\u0442\u043E\u043C\u0443 \u043E\u0442\u0432\u0435\u0440\u0441\u0442\u0438\u044E, \u043F\u0440\u0438 \u0440\u0430\u0441\u043F\u0440\u044F\u043C\u043B\u0435\u043D\u0438\u0438 [\u043F\u0440\u0430\u043D\u0430-] \u0448\u0430\u043A\u0442\u0438 \u043E\u0442\u043A\u0440\u044B\u0432\u0430\u0435\u0442\u0441\u044F \u0432\u0445\u043E\u0434 \u0432 \u0435\u0433\u043E \u043A\u043E\u0440\u0435\u043D\u044C, \u0432\u0435\u0440\u0448\u0438\u043D\u0443 \u0438 \u0441\u0435\u0440\u0435\u0434\u0438\u043D\u0443. \u0412 \u0412\u0438\u0434\u0436\u043D\u044F\u043D\u0430\u0431\u0445\u0430\u0439\u0440\u0430\u0432\u0435 (68) \u0433\u043E\u0432\u043E\u0440\u0438\u0442\u0441\u044F: \xAB\u0421\u043B\u0435\u0434\u0443\u0435\u0442 \u043D\u0430\u043F\u0440\u0430\u0432\u043B\u044F\u0442\u044C \u0441\u043E\u0437\u043D\u0430\u043D\u0438\u0435, \u043F\u043E\u043B\u043D\u043E\u0435 \u0441\u0447\u0430\u0441\u0442\u044C\u044F, \u0432 \u0441\u0435\u0440\u0435\u0434\u0438\u043D\u0443 \u043C\u0435\u0436\u0434\u0443 \xAB\u043E\u0433\u043D\u0435\u043C\xBB \u0438 \xAB\u044F\u0434\u043E\u043C\xBB, [\u0438 \u0442\u043E\u0433\u0434\u0430 \u0438\u0441\u043F\u044B\u0442\u0430\u0435\u0448\u044C] \u043B\u0438\u0431\u043E \u043E\u0442\u0440\u0435\u0448\u0435\u043D\u043D\u043E\u0441\u0442\u044C \u043E\u0442 \u0432\u0441\u0435\u0433\u043E, \u043B\u0438\u0431\u043E \xAB\u043D\u0430\u043F\u043E\u043B\u043D\u0435\u043D\u043D\u043E\u0441\u0442\u044C \u0432\u0435\u0442\u0440\u043E\u043C\xBB \u0447\u0435\u0440\u0435\u0437 \u0431\u043B\u0430\u0436\u0435\u043D\u0441\u0442\u0432\u043E \u0441\u0435\u043A\u0441\u0443\u0430\u043B\u044C\u043D\u043E\u0433\u043E \u0441\u043E\u0435\u0434\u0438\u043D\u0435\u043D\u0438\u044F \xBB.</p><p class="eng">\u0417\u0434\u0435\u0441\u044C \xAB\u043E\u0433\u043E\u043D\u044C\xBB \u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442 \u0441\u0442\u0443\u043F\u0435\u043D\u044C \u0441\u0436\u0430\u0442\u0438\u044F, \u0434\u043E\u0441\u0442\u0438\u0433\u0430\u0435\u043C\u0443\u044E \u0447\u0435\u0440\u0435\u0437 \u043F\u0440\u043E\u0446\u0435\u0441\u0441 \u0432\u0445\u043E\u0436\u0434\u0435\u043D\u0438\u044F [\u043F\u0440\u0430\u043D\u044B] \u0432 [\u043E\u0441\u043D\u043E\u0432\u0443] \u0438\u043D\u0434\u0438\u0432\u0438\u0434\u0443\u0430\u043B\u044C\u043D\u043E\u0441\u0442\u0438. \u0421\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435 \xAB\u044F\u0434\u0430\xBB \u2013 \u044D\u0442\u043E \u0441\u0442\u0443\u043F\u0435\u043D\u044C \u0440\u0430\u0437\u0432\u0438\u0442\u0438\u044F, \u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C \u0442\u0435\u0445\u043D\u0438\u043A\u0438 \u043F\u0440\u0430\u0441\u0430\u0440\u0430, \u0441\u043E\u0433\u043B\u0430\u0441\u043D\u043E \u044D\u0442\u0438\u043C\u043E\u043B\u043E\u0433\u0438\u0438 \u0441\u043B\u043E\u0432\u0430 \xAB\u044F\u0434\xBB, \u043A\u043E\u0442\u043E\u0440\u043E\u0435 \u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442 \xAB\u043F\u0440\u043E\u043D\u0438\u0437\u044B\u0432\u0430\u043D\u0438\u0435\xBB. \u041E\u0431\u0430 \xAB\u043F\u043E\u0442\u043E\u043A\u0430\xBB \u2013 \u044D\u0442\u043E \u043F\u0440\u0430\u043D\u0430 \u0438 \u0430\u043F\u0430\u043D\u0430, [\u0441\u0432\u044F\u0437\u0430\u043D\u043D\u044B\u0435 \u0441\u043E\u043E\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0435\u043D\u043D\u043E \u0441] \u043B\u0435\u0432\u044B\u043C \u0438 \u043F\u0440\u0430\u0432\u044B\u043C \u043A\u0430\u043D\u0430\u043B\u0430\u043C\u0438. \xAB\u0420\u0430\u0437\u0434\u0435\u043B\u0435\u043D\u0438\u0435\xBB [\u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442] \u043F\u0440\u0435\u043A\u0440\u0430\u0449\u0435\u043D\u0438\u0435, \u0442. \u0435. \u043E\u0441\u0442\u0430\u043D\u043E\u0432\u043A\u0443 \u0432\u043E \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0435\u043C, \u0432 \u0441\u0435\u0440\u0434\u0446\u0435, \u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C \u043F\u0440\u043E\u0438\u0437\u043D\u0435\u0441\u0435\u043D\u0438\u044F \u0441\u043E\u0433\u043B\u0430\u0441\u043D\u044B\u0445 \u0437\u0432\u0443\u043A\u043E\u0432 \u043A\u0430, \u0445\u0430 \u0438 \u0442. \u0434.</p><p class="eng">\u041A\u0430\u043A \u0433\u043E\u0432\u043E\u0440\u0438\u0442\u0441\u044F \u0432 \u0414\u0436\u043D\u044F\u043D\u0430\u0433\u0430\u0440\u0431\u0445\u0435, \xAB\u041A\u043E\u0433\u0434\u0430 \u0443\u043C \u043D\u0430\u0445\u043E\u0434\u0438\u0442\u0441\u044F \u043F\u043E\u0434 \u043A\u043E\u043D\u0442\u0440\u043E\u043B\u0435\u043C, \u043A\u043E\u0433\u0434\u0430 \u043E\u0431\u0430 \u043D\u0430\u0434\u0438, \u043F\u0440\u043E\u0441\u0442\u0438\u0440\u0430\u044E\u0449\u0438\u0435\u0441\u044F \u043F\u043E \u043E\u0431\u0435\u0438\u043C \u0441\u0442\u043E\u0440\u043E\u043D\u0430\u043C [\u0442\u0435\u043B\u0430, \u0443\u0441\u043F\u043E\u043A\u0430\u0438\u0432\u0430\u044E\u0442\u0441\u044F] \u043F\u043E\u0434 \u0432\u043E\u0437\u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0435\u043C \u0441\u043E\u0433\u043B\u0430\u0441\u043D\u043E\u0433\u043E \u0437\u0432\u0443\u043A\u0430 \u043A\u0430, \u043A\u043E\u0433\u0434\u0430 \u0442\u044B, [\u043E \u041C\u0430\u0442\u044C], \u0440\u0430\u0441\u0441\u0435\u0438\u0432\u0430\u0435\u0448\u044C \u0433\u0443\u0441\u0442\u0443\u044E \u0442\u044C\u043C\u0443, \u0432 \u0441\u0435\u0440\u0434\u0446\u0435-\u043B\u043E\u0442\u043E\u0441\u0435 \u043F\u043E\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u044D\u0442\u043E\u0442 \u0440\u043E\u0441\u0442\u043E\u043A \u0437\u043D\u0430\u043D\u0438\u044F, \u043A\u043E\u0442\u043E\u0440\u044B\u0439 \u0441\u043F\u043E\u0441\u043E\u0431\u0435\u043D \u0432\u044B\u0437\u0432\u0430\u0442\u044C \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435 \u041F\u0430\u0440\u0430\u043C\u0435\u0448\u0438 \u0434\u0430\u0436\u0435 \u0443 \u043F\u0430\u0448\u0443\xBB.</p><p class="eng">\xAB\u041F\u0435\u0440\u0432\u044B\u0439 \u043F\u0440\u0435\u0434\u0435\u043B\xBB \u2013 \u044D\u0442\u043E \u0441\u0435\u0440\u0434\u0446\u0435, \xAB\u043F\u043E\u0441\u043B\u0435\u0434\u043D\u0438\u0439 \u043F\u0440\u0435\u0434\u0435\u043B\xBB \u2013 \u043E\u0431\u043B\u0430\u0441\u0442\u044C \u0432\u0435\u043B\u0438\u0447\u0438\u043D\u043E\u0439 \u0432 \u0434\u0432\u0435\u043D\u0430\u0434\u0446\u0430\u0442\u044C \u043F\u0430\u043B\u044C\u0446\u0435\u0432. \xAB\u041D\u0438\u0431\u0445\u0430\u043B\u0430\u043D\u0430\xBB \u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442 \u043F\u0440\u0430\u043A\u0442\u0438\u043A\u0443 \u0441\u043E\u0441\u0440\u0435\u0434\u043E\u0442\u043E\u0447\u0435\u043D\u0438\u044F \u0443\u043C\u0430 \u043D\u0430 \u0443\u0432\u0435\u043B\u0438\u0447\u0438\u0432\u0430\u044E\u0449\u0435\u0439\u0441\u044F \u0438 \u0438\u0441\u0447\u0435\u0437\u0430\u044E\u0449\u0435\u0439 \u043F\u0440\u0430\u043D\u0435 [\u0432 \u043F\u0440\u043E\u0441\u0442\u0440\u0430\u043D\u0441\u0442\u0432\u0435 \u043C\u0435\u0436\u0434\u0443] \u043D\u0438\u043C\u0438. \u041A\u0430\u043A \u0433\u043E\u0432\u043E\u0440\u0438\u0442\u0441\u044F \u0432 \u0412\u0438\u0434\u0436\u043D\u044F\u043D\u0430\u0431\u0445\u0430\u0439\u0440\u0430\u0432\u0435 (49), \xAB\u041E \u0434\u0438\u0432\u043D\u0430\u044F, \u0442\u043E\u0442, \u043A\u0442\u043E \u043F\u043E\u0433\u0440\u0443\u0437\u0438\u043B\u0441\u044F \u0432 \u0433\u043B\u0443\u0431\u0438\u043D\u0443 \u0441\u0435\u0440\u0434\u0446\u0430, \u043A\u0442\u043E \u0432\u043E\u0448\u0435\u043B \u0432 \u043B\u043E\u0442\u043E\u0441-\u0441\u0435\u0440\u0434\u0446\u0435 \u0438 \u043E\u0442\u0432\u043B\u0435\u043A [\u0441\u0432\u043E\u0438] \u043C\u044B\u0441\u043B\u0438 \u043E\u0442 [\u0432\u0441\u0435\u0433\u043E] \u043E\u0441\u0442\u0430\u043B\u044C\u043D\u043E\u0433\u043E, \u0434\u043E\u0441\u0442\u0438\u0433\u0430\u0435\u0442 \u0432\u044B\u0441\u0448\u0435\u0433\u043E \u0431\u043B\u0430\u0436\u0435\u043D\u0441\u0442\u0432\u0430\xBB. \u0418 \u0435\u0449\u0435: \xAB[\u0415\u0441\u043B\u0438] \u043F\u043E\u0441\u0442\u043E\u044F\u043D\u043D\u043E \u0438 \u043F\u0440\u0438 \u043B\u044E\u0431\u044B\u0445 \u0443\u0441\u043B\u043E\u0432\u0438\u044F\u0445 \u0443\u0434\u0435\u0440\u0436\u0438\u0432\u0430\u0442\u044C \u0441\u043E\u0437\u043D\u0430\u043D\u0438\u0435 \u043D\u0430 \u043E\u0431\u043B\u0430\u0441\u0442\u0438 \u0434\u0432\u0430\u0434\u0430\u0448\u0430\u043D\u0442\u044B, \u043A\u043E\u043B\u0435\u0431\u0430\u043D\u0438\u044F \u0443\u043C\u0430 \u043F\u043E\u0441\u0442\u0435\u043F\u0435\u043D\u043D\u043E \u0431\u0443\u0434\u0443\u0442 \u0443\u0431\u044B\u0432\u0430\u0442\u044C, \u0442\u0430\u043A \u0447\u0442\u043E \u0437\u0430 \u043D\u0435\u0441\u043A\u043E\u043B\u044C\u043A\u043E \u0434\u043D\u0435\u0439 [\u0438\u043D\u0434\u0438\u0432\u0438\u0434] \u0434\u043E\u0441\u0442\u0438\u0433\u043D\u0435\u0442 \u043D\u0435\u043E\u043F\u0438\u0441\u0443\u0435\u043C\u043E\u0433\u043E\xBB.\u0421\u043B\u043E\u0432\u043E \xAB\u0438 \u0442\u0430\u043A \u0434\u0430\u043B\u0435\u0435\xBB \u043E\u0442\u043D\u043E\u0441\u0438\u0442\u0441\u044F \u043A \u043F\u0440\u0430\u043A\u0442\u0438\u043A\u0435 \u0432 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0438 \u0443\u043D\u043C\u0435\u0448\u0430. \u041A\u0430\u043A \u0433\u043E\u0432\u043E\u0440\u0438\u0442\u0441\u044F \u0432 \u0421\u043F\u0430\u043D\u0434\u0435, \xAB\u0442\u043E, \u0447\u0442\u043E \u043F\u043E\u0441\u0442\u0438\u0433\u0430\u0435\u0442\u0441\u044F \u043A\u0430\u043A \u0443\u043D\u043C\u0435\u0448\u0430, \u043C\u043E\u0436\u043D\u043E \u043D\u0430\u0431\u043B\u044E\u0434\u0430\u0442\u044C \u043D\u0430 \u0441\u0432\u043E\u0435\u043C \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u043C [\u043E\u043F\u044B\u0442\u0435]\xBB. \u042D\u0442\u043E \u0436\u0435 \u043E\u0442\u043D\u043E\u0441\u0438\u0442\u0441\u044F \u0438 \u043A \u0432\u043A\u0443\u0448\u0435\u043D\u0438\u044E \u0438 \u0442. \u0434. \u043F\u0440\u0438\u044F\u0442\u043D\u044B\u0445 \u043E\u0431\u044A\u0435\u043A\u0442\u043E\u0432. \u041A\u0430\u043A \u0441\u043A\u0430\u0437\u0430\u043D\u043E \u0432 \u0434\u043E\u0441\u0442\u043E\u043F\u043E\u0447\u0442\u0435\u043D\u043D\u043E\u0439 \u0412\u0438\u0434\u0436\u043D\u044F\u043D\u0430\u0431\u0445\u0430\u0439\u0440\u0430\u0432\u0435 (72 \u2013 74), \xAB\u041A\u043E\u0433\u0434\u0430 [\u043F\u0440\u0430\u043A\u0442\u0438\u043A\u0443\u044E\u0449\u0438\u0439] \u043E\u0449\u0443\u0449\u0430\u0435\u0442 \u0443\u0434\u043E\u0432\u043E\u043B\u044C\u0441\u0442\u0432\u0438\u0435, \u0432\u043E\u0437\u043D\u0438\u043A\u0430\u044E\u0449\u0435\u0435 \u043E\u0442 \u0435\u0434\u044B \u0438 \u043D\u0430\u043F\u0438\u0442\u043A\u043E\u0432, \u0435\u043C\u0443 \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0441\u043E\u0441\u0440\u0435\u0434\u043E\u0442\u043E\u0447\u0438\u0442\u044C\u0441\u044F \u043D\u0430 \u0441\u043E\u0432\u0435\u0440\u0448\u0435\u043D\u0441\u0442\u0432\u0435 [\u044D\u0442\u043E\u0433\u043E] \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F, [\u0438 \u0442\u043E\u0433\u0434\u0430] \u043E\u043D \u043C\u043E\u0436\u0435\u0442 \u043F\u0440\u0435\u0438\u0441\u043F\u043E\u043B\u043D\u0438\u0442\u044C\u0441\u044F \u0432\u0435\u043B\u0438\u043A\u043E\u0433\u043E \u0431\u043B\u0430\u0436\u0435\u043D\u0441\u0442\u0432\u0430. \u041A\u043E\u0433\u0434\u0430 \u0441\u043E\u0437\u043D\u0430\u043D\u0438\u0435 \u0439\u043E\u0433\u0438\u043D\u0430 \u0441\u043E\u0441\u0440\u0435\u0434\u043E\u0442\u043E\u0447\u0435\u043D\u043E \u043D\u0430 \u043D\u0438 \u0441 \u0447\u0435\u043C \u043D\u0435 \u0441\u0440\u0430\u0432\u043D\u0438\u043C\u043E\u043C \u0443\u0434\u043E\u0432\u043E\u043B\u044C\u0441\u0442\u0432\u0438\u0438 \u043E\u0442 \u043F\u0435\u0441\u043D\u0438 \u0438 \u0434\u0440\u0443\u0433\u0438\u0445 [\u043F\u043E\u0434\u043E\u0431\u043D\u044B\u0445] \u043E\u0431\u044A\u0435\u043A\u0442\u043E\u0432, \u0442\u043E\u0433\u0434\u0430 \u044D\u0442\u043E \u0435\u0433\u043E \u0441\u043E\u0437\u043D\u0430\u043D\u0438\u0435 \u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u0441\u044F \u043E\u0434\u043D\u0438\u043C \u0446\u0435\u043B\u044B\u043C \u0441 \u043D\u0438\u043C\u0438. \u041E\u0442 \u0447\u0435\u0433\u043E \u0431\u044B \u043C\u0430\u043D\u0430\u0441 \u043D\u0435 \u0438\u0441\u043F\u044B\u0442\u044B\u0432\u0430\u043B \u043D\u0430\u0441\u043B\u0430\u0436\u0434\u0435\u043D\u0438\u0435, \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u043A\u043E\u043D\u0446\u0435\u043D\u0442\u0440\u0438\u0440\u043E\u0432\u0430\u0442\u044C\u0441\u044F \u043D\u0430 \u044D\u0442\u043E\u043C, \u0438 \u0442\u043E\u0433\u0434\u0430 \u043F\u0440\u043E\u044F\u0432\u0438\u0442\u0441\u044F \u0432\u044B\u0441\u0448\u0435\u0435 \u0431\u043B\u0430\u0436\u0435\u043D\u0441\u0442\u0432\u043E\xBB.</p><p class="eng">\u0422\u0430\u043A\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C, \u043B\u044E\u0431\u043E\u0435 \u0434\u0440\u0443\u0433\u043E\u0435 \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u043D\u0438\u0435 \u0441\u0432\u043E\u0435\u0433\u043E \xAB\u044F\xBB \u043C\u043E\u0436\u0435\u0442 \u043F\u0440\u0438\u0432\u0435\u0441\u0442\u0438 \u043A \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044E \u0432\u044B\u0441\u0448\u0435\u0433\u043E \u0431\u043B\u0430\u0436\u0435\u043D\u0441\u0442\u0432\u0430. \u0417\u0434\u0435\u0441\u044C [\u0432\u044B\u0440\u0430\u0436\u0435\u043D\u0438\u0435] \xAB\u0438 \u0442\u0430\u043A \u0434\u0430\u043B\u0435\u0435\xBB [\u0443\u043A\u0430\u0437\u044B\u0432\u0430\u0435\u0442] \u043D\u0430 \u043C\u0435\u0442\u043E\u0434\u044B \u0440\u0430\u0437\u0432\u0438\u0442\u0438\u044F \u0441\u0440\u0435\u0434\u043D\u0435\u0433\u043E \u0446\u0435\u043D\u0442\u0440\u0430. \u041F\u0440\u0438 \u0440\u0430\u0437\u0432\u0438\u0442\u0438\u0438 \u0441\u0440\u0435\u0434\u043D\u0435\u0433\u043E \u0446\u0435\u043D\u0442\u0440\u0430 \u0434\u043E\u0441\u0442\u0438\u0433\u0430\u0435\u0442\u0441\u044F \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435 \u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F-\u0431\u043B\u0430\u0436\u0435\u043D\u0441\u0442\u0432\u0430. \u042D\u0442\u043E \u0432\u044B\u0441\u0448\u0435\u0435 \u0439\u043E\u0433\u0438\u0447\u0435\u0441\u043A\u043E\u0435 [\u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435] \u0435\u0441\u0442\u044C [\u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435] \u0441\u0430\u043C\u0430\u0434\u0445\u0438, [\u0438\u043D\u0430\u0447\u0435 \u043D\u0430\u0437\u044B\u0432\u0430\u0435\u043C\u043E\u0435] \u0441\u0430\u043C\u0430\u0432\u0435\u0448\u0435\u0439, \u0441\u0430\u043C\u0430\u043F\u0430\u0442\u0442\u0438 \u0438 \u0434\u0440\u0443\u0433\u0438\u043C\u0438 \u0442\u0435\u0440\u043C\u0438\u043D\u0430\u043C\u0438.</p><p class="eng">\u041E \u043C\u0435\u0442\u043E\u0434\u0435, [\u043A\u043E\u0442\u043E\u0440\u044B\u0439 \u043F\u043E\u0437\u0432\u043E\u043B\u044F\u0435\u0442] \u0441\u0434\u0435\u043B\u0430\u0442\u044C \u0435\u0433\u043E \u0443\u0441\u0442\u043E\u0439\u0447\u0438\u0432\u044B\u043C, \u0433\u043E\u0432\u043E\u0440\u0438\u0442\u0441\u044F [\u0442\u0430\u043A]:</p></div><div class="stanza"><a href="#s19" id="s19" class="num">19</a><p class="sans">\u0938\u092E\u093E\u0927\u093F\u0938\u0902\u0938\u094D\u0915\u093E\u0930\u0935\u0924\u093F \u0935\u094D\u092F\u0941\u0924\u094D\u0925\u093E\u0928\u0947 \u092D\u0942\u092F\u094B \u092D\u0942\u092F\u0936\u094D\u091A\u093F\u0926\u0948\u0915\u094D\u092F\u093E\u092E\u0930\u094D\u0936\u093E\u0928\u094D\u0928\u093F\u0924\u094D\u092F\u094B\u0926\u093F\u0924\u0938\u092E\u093E\u0927\u093F\u0932\u093E\u092D\u0903 \u0965\u0967\u096F\u0965</p><p class="trans">Sam\u0101dhisa\u1E41sk\u0101ravati vyutth\u0101ne bh\u016Byo bh\u016Bya\u015Bcidaiky\u0101mar\u015B\u0101nnityoditasam\u0101dhil\u0101bha\u1E25 \u096519\u0965</p><p>\u0412 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0438 \u0432\u044C\u044E\u0442\u0442\u0445\u0430\u043D\u0430 <em>(vyutth\u0101ne)</em>, \u043F\u0440\u0438 \u0441\u043E\u0445\u0440\u0430\u043D\u0435\u043D\u0438\u0438 \u043E\u0441\u0442\u0430\u0442\u043E\u0447\u043D\u044B\u0445 \u0441\u043B\u0435\u0434\u043E\u0432 <em>(sa\u1E41sk\u0101ravati)</em> \u0441\u0430\u043C\u0430\u0434\u0445\u0438 <em>(sam\u0101dhi)</em>, \u0432\u043E\u0437\u043C\u043E\u0436\u043D\u043E \u0434\u043E\u0441\u0442\u0438\u0436\u0435\u043D\u0438\u0435 <em>(l\u0101bha\u1E25)</em> \u043D\u0435\u043F\u0440\u0435\u0440\u044B\u0432\u043D\u043E\u0433\u043E <em>(nitya-udita)</em> \u0441\u0430\u043C\u0430\u0434\u0445\u0438 <em>(sam\u0101dhi)</em> \u0431\u043B\u0430\u0433\u043E\u0434\u0430\u0440\u044F \u0432\u0441\u0435 \u0431\u043E\u043B\u0435\u0435 \u0438 \u0431\u043E\u043B\u0435\u0435 <em>(bh\u016Byas bh\u016Byas)</em> \u0433\u043B\u0443\u0431\u043E\u043A\u043E\u0439 \u043A\u043E\u043D\u0446\u0435\u043D\u0442\u0440\u0430\u0446\u0438\u0438 <em>(\u0101mar\u015B\u0101t)</em> \u043D\u0430 \u0435\u0434\u0438\u043D\u0441\u0442\u0432\u0435 <em>(aikya)</em> \u0441 \u0410\u0431\u0441\u043E\u043B\u044E\u0442\u043D\u044B\u043C \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u0435\u043C <em>(cit)</em>.</p><p class="eng"><strong>\u041A\u043E\u043C\u043C\u0435\u043D\u0442\u0430\u0440\u0438\u0439</strong><br> \u041E\u043F\u044B\u0442\u043D\u044B\u0439 \u0439\u043E\u0433\u0438\u043D, \u0434\u043E\u0441\u0442\u0438\u0433\u0448\u0438\u0439 \u0441\u0430\u043C\u0430\u0432\u0435\u0448\u0438, \u0438\u0437-\u0437\u0430 \u043E\u0441\u0442\u0430\u0442\u043E\u0447\u043D\u044B\u0445 \u0441\u043B\u0435\u0434\u043E\u0432 \u0441\u043B\u0430\u0434\u043E\u0441\u0442\u043D\u043E\u0433\u043E \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F \u0441\u0430\u043C\u0430\u0434\u0445\u0438 \u0438\u0441\u043F\u044B\u0442\u044B\u0432\u0430\u0435\u0442 \u0438 \u0432 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0438 \u0432\u044C\u044E\u0442\u0442\u0445\u0430\u043D\u044B \u0440\u0430\u0434\u043E\u0441\u0442\u043D\u043E\u0435 \u0433\u043E\u043B\u043E\u0432\u043E\u043A\u0440\u0443\u0436\u0435\u043D\u0438\u0435, \u043A\u0430\u043A \u0443 \u043E\u043F\u044C\u044F\u043D\u0435\u043D\u043D\u043E\u0433\u043E. \u0420\u0430\u0437 \u0437\u0430 \u0440\u0430\u0437\u043E\u043C \u043E\u0431\u0440\u0430\u0449\u0430\u044F\u0441\u044C \u043A \u0433\u043B\u0443\u0431\u0438\u043D\u0430\u043C \u0441\u0430\u043C\u043E\u0433\u043E \u0441\u0435\u0431\u044F \u0438 \u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C \u043D\u0438\u043C\u0438\u043B\u0430\u043D\u0430-\u0441\u0430\u043C\u0430\u0434\u0445\u0438 \u043A\u043E\u043D\u0446\u0435\u043D\u0442\u0440\u0438\u0440\u0443\u044F\u0441\u044C \u043D\u0430 \u0441\u0432\u043E\u0435\u043C \u0435\u0434\u0438\u043D\u0441\u0442\u0432\u0435 \u0441 \u0427\u0438\u0442, \u043E\u043D \u0432\u0438\u0434\u0438\u0442, \u043A\u0430\u043A \u043C\u0438\u0440 \u043E\u0431\u044A\u0435\u043A\u0442\u0438\u0432\u043D\u044B\u0445 \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u0435\u0439 \u0438\u0441\u043F\u0430\u0440\u044F\u0435\u0442\u0441\u044F \u0432 \u043D\u0435\u0431\u0435-\u0441\u043E\u0437\u043D\u0430\u043D\u0438\u0438, \u0441\u043B\u043E\u0432\u043D\u043E \u0433\u0440\u0443\u0434\u0430 \u043E\u0431\u043B\u0430\u043A\u043E\u0432 \u0432 \u043E\u0441\u0435\u043D\u043D\u0435\u043C [\u043D\u0435\u0431\u0435]. [\u0422\u0430\u043A\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C], \u0434\u0430\u0436\u0435 \u0432\u043E \u0432\u044C\u044E\u0442\u0442\u0445\u0430\u043D\u0435 \u043E\u043D [\u043D\u0435 \u043F\u0435\u0440\u0435\u0441\u0442\u0430\u0435\u0442 \u0431\u044B\u0442\u044C] \u0435\u0434\u0438\u043D\u044B\u043C \u0441 \u043F\u043E\u043B\u043D\u043E\u0442\u043E\u0439 \u0441\u0430\u043C\u0430\u0434\u0445\u0438.</p><p class="eng">\u041A\u0430\u043A \u0433\u043E\u0432\u043E\u0440\u0438\u0442\u0441\u044F \u0432 \u041A\u0440\u0430\u043C\u0430\u0441\u0443\u0442\u0440\u0430\u0445, \xAB\u041F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C \u043A\u0440\u0430\u043C\u0430\u043C\u0443\u0434\u0440\u044B, \u0438\u043C\u0435\u044E\u0449\u0435\u0439 \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u044C\u044E \u043F\u043E\u0433\u0440\u0443\u0436\u0435\u043D\u043D\u043E\u0441\u0442\u044C \u0432 \u0441\u0435\u0431\u044F, \u0441\u0430\u0434\u0445\u0430\u043A\u0430 \u043E\u0441\u0442\u0430\u0435\u0442\u0441\u044F \u0432 \u0441\u043E\u0441\u0440\u0435\u0434\u043E\u0442\u043E\u0447\u0435\u043D\u043D\u043E\u0441\u0442\u0438 [\u0434\u0430\u0436\u0435] \u043F\u0440\u0438 \u0432\u043D\u0435\u0448\u043D\u0435\u043C \u0432\u043E\u0441\u043F\u0440\u0438\u044F\u0442\u0438\u0438. [\u0412\u043F\u0440\u043E\u0447\u0435\u043C], \u0432 \u044D\u0442\u043E\u0439 [\u043F\u0440\u0430\u043A\u0442\u0438\u043A\u0435], \u0431\u043B\u0430\u0433\u043E\u0434\u0430\u0440\u044F \u0441\u0438\u043B\u0435 \u0441\u043E\u0441\u0440\u0435\u0434\u043E\u0442\u043E\u0447\u0435\u043D\u043D\u043E\u0441\u0442\u0438, \u0441\u043D\u0430\u0447\u0430\u043B\u0430 \u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u0438\u0442 \xAB\u0432\u0445\u043E\u0436\u0434\u0435\u043D\u0438\u0435\xBB [\u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F] \u0438\u0437 \u0432\u043D\u0435\u0448\u043D\u0435\u0433\u043E \u0432\u043E \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0435\u0435, [\u0430 \u0437\u0430\u0442\u0435\u043C] \u0438\u0437 \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0435\u0433\u043E \u0432\u043E \u0432\u043D\u0435\u0448\u043D\u0435\u0435. \u0422\u0430\u043A\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C, \u044D\u0442\u0430 \u043C\u0443\u0434\u0440\u0430\u043A\u0440\u0430\u043C\u0430 [\u0441\u043E\u0447\u0435\u0442\u0430\u0435\u0442] \u0438 \u0432\u043D\u0435\u0448\u043D\u0435\u0435, \u0438 \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0435\u0435\xBB. \u0422\u0430\u043A\u043E\u0432 \u0437\u0434\u0435\u0441\u044C \u0441\u043C\u044B\u0441\u043B. \u0417\u0430\u043F\u0440\u0435\u0434\u0435\u043B\u044C\u043D\u0430\u044F \u044D\u043D\u0435\u0440\u0433\u0438\u0438 \u0427\u0438\u0442\u0438-\u0448\u0430\u043A\u0442\u0438 \u0434\u0435\u043B\u0430\u0435\u0442 \u0441\u0432\u043E\u0438\u043C \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u043C \u043F\u043E\u0441\u043B\u0435\u0434\u043E\u0432\u0430\u0442\u0435\u043B\u044C\u043D\u044B\u0439 \u0446\u0438\u043A\u043B \u0442\u0432\u043E\u0440\u0435\u043D\u0438\u044F, \u0441\u043E\u0445\u0440\u0430\u043D\u0435\u043D\u0438\u044F, \u0440\u0430\u0441\u0442\u0432\u043E\u0440\u0435\u043D\u0438\u044F, \u043A\u043E\u0442\u043E\u0440\u044B\u0439 [\u0432 \u0441\u0432\u0435\u0440\u043D\u0443\u0442\u043E\u043C \u0432\u0438\u0434\u0435] \u0441\u043E\u0434\u0435\u0440\u0436\u0438\u0442\u0441\u044F \u0432 \u0432\u044B\u0441\u0448\u0435\u043C \u042F. \xAB\u0421\u0430\u0434\u0445\u0430\u043A\u0430\xBB \u2013 \u044D\u0442\u043E \u0432\u044B\u0441\u0448\u0438\u0439 \u0442\u0438\u043F \u0439\u043E\u0433\u0438\u043D\u0430, \u043A\u043E\u0442\u043E\u0440\u044B\u0439 \xAB\u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C \u043A\u0440\u0430\u043C\u0430\u043C\u0443\u0434\u0440\u044B\xBB, \u043F\u043E \u0441\u0432\u043E\u0435\u0439 \u0441\u0443\u0442\u0438 \u044F\u0432\u043B\u044F\u044E\u0449\u0435\u0439\u0441\u044F \u0441\u043E\u0432\u0435\u0440\u0448\u0435\u043D\u043D\u044B\u043C \u042F, \xAB\u043E\u0441\u0442\u0430\u0435\u0442\u0441\u044F \u0432 \u0441\u043E\u0441\u0440\u0435\u0434\u043E\u0442\u043E\u0447\u0435\u043D\u043D\u043E\u0441\u0442\u0438\xBB \u043D\u0430 \u043F\u043E\u043B\u043D\u043E\u0442\u0435 \u041F\u0430\u0440\u0430\u0448\u0430\u043A\u0442\u0438 \u0434\u0430\u0436\u0435 \xAB\u043F\u0440\u0438 \u0432\u043D\u0435\u0448\u043D\u0435\u043C \u0432\u043E\u0441\u043F\u0440\u0438\u044F\u0442\u0438\u0438\xBB, \u0442. \u0435. [\u0432\u043E\u0441\u043F\u0440\u0438\u044F\u0442\u0438\u0438] \u0447\u0443\u0432\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u0445 \u043E\u0431\u044A\u0435\u043A\u0442\u043E\u0432. \u0417\u0434\u0435\u0441\u044C \u0447\u0435\u0440\u0435\u0437 \u0443\u043F\u043E\u0434\u043E\u0431\u043B\u0435\u043D\u0438\u0435 \xAB\u0432\u043D\u0435\u0448\u043D\u0435\u0433\u043E\xBB, \u0442. \u0435. \u043C\u043D\u043E\u0433\u043E\u043E\u0431\u0440\u0430\u0437\u0438\u044F \u043E\u0431\u044A\u0435\u043A\u0442\u043E\u0432 \u0447\u0443\u0432\u0441\u0442\u0432, \xAB\u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0435\u043C\u0443\xBB, \u0442. \u0435. \u0443\u0440\u043E\u0432\u043D\u044E \u0432\u044B\u0441\u0448\u0435\u0433\u043E \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F, \u0434\u043E\u0441\u0442\u0438\u0433\u0430\u0435\u0442\u0441\u044F \xAB\u0432\u0445\u043E\u0436\u0434\u0435\u043D\u0438\u0435\xBB \u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C \u0441\u0430\u043C\u043E\u0433\u043E \u043F\u0440\u043E\u0446\u0435\u0441\u0441\u0430 \u0443\u043F\u043E\u0434\u043E\u0431\u043B\u0435\u043D\u0438\u044F.</p><p class="eng">\xAB\u0418\u0437 \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0435\u0433\u043E\xBB, \u0442. \u0435. \u0438\u0437 \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u0438 \u0427\u0438\u0442\u0438-\u0448\u0430\u043A\u0442\u0438, \u043A\u043E\u0442\u043E\u0440\u0430\u044F \u0430\u043D\u0430\u043B\u043E\u0433\u0438\u0447\u043D\u0430 \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0435\u043C\u0443 \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u043D\u0438\u044E, \u0438\u043B\u0438 \xAB\u0441\u0438\u043B\u0435 \u0441\u043E\u0441\u0440\u0435\u0434\u043E\u0442\u043E\u0447\u0435\u043D\u043D\u043E\u0441\u0442\u0438\xBB, \u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u0438\u0442 \u0441\u043E\u0441\u0440\u0435\u0434\u043E\u0442\u043E\u0447\u0435\u043D\u043D\u043E\u0435 \xAB\u0432\u0445\u043E\u0436\u0434\u0435\u043D\u0438\u0435\xBB \xAB\u0432\u043E \u0432\u043D\u0435\u0448\u043D\u0435\u0435\xBB, \u0432 \u0442\u043E, \u0447\u0442\u043E \u0438\u043C\u0435\u0435\u0442 \u043F\u0440\u0438\u0440\u043E\u0434\u0443 \xAB\u044D\u0442\u043E\u0433\u043E\xBB, \u0442. \u0435. \u0432 \u043C\u0438\u0440 \u043E\u0431\u044A\u0435\u043A\u0442\u043E\u0432, \u0447\u0435\u0440\u0435\u0437 \u043F\u0440\u043E\u0446\u0435\u0441\u0441 \u043E\u0432\u043D\u0435\u0448\u043D\u0435\u043D\u0438\u044F. [\u0418\u043D\u0430\u0447\u0435 \u0433\u043E\u0432\u043E\u0440\u044F], \u044D\u0442\u043E \u0440\u0430\u0441\u0448\u0438\u0440\u0435\u043D\u0438\u0435 \u0441\u043E\u0441\u0440\u0435\u0434\u043E\u0442\u043E\u0447\u0435\u043D\u043D\u043E\u0441\u0442\u0438 \u0431\u043B\u0430\u0433\u043E\u0434\u0430\u0440\u044F \u043E\u043F\u043B\u043E\u0442\u043D\u0435\u043D\u0438\u044E \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F.</p><p class="eng">\xAB[\u041E\u0434\u043D\u043E\u0432\u0440\u0435\u043C\u0435\u043D\u043D\u043E\u0441\u0442\u044C] \u0432\u043D\u0435\u0448\u043D\u0435\u0433\u043E \u0438 \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0435\u0433\u043E\xBB \u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442 \u0432\u0435\u0447\u043D\u0443\u044E \u043F\u0440\u0438\u0440\u043E\u0434\u0443 \u0441\u0430\u043C\u0430\u0432\u0435\u0448\u0438.</p><p class="eng">\xAB\u041C\u0443\u0434\u0440\u043E\u0439\xBB [\u043D\u0430\u0437\u044B\u0432\u0430\u0435\u0442\u0441\u044F] \u0431\u043B\u0430\u0433\u043E\u0434\u0430\u0442\u044C \u0440\u0430\u0434\u043E\u0441\u0442\u0438, \u0438\u043C\u0435\u044E\u0449\u0435\u0439 \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u044C \u0432\u044B\u0441\u0448\u0435\u0433\u043E \u0431\u043B\u0430\u0436\u0435\u043D\u0441\u0442\u0432\u0430, [\u0430 \u0442\u0430\u043A\u0436\u0435] \u0440\u0430\u0437\u0440\u0443\u0448\u0435\u043D\u0438\u0435 \u0443\u0437, [\u0430 \u0442\u0430\u043A\u0436\u0435] \u0437\u0430\u043F\u0435\u0447\u0430\u0442\u044B\u0432\u0430\u043D\u0438\u0435 \u0438 \u0443\u0434\u0435\u0440\u0436\u0430\u043D\u0438\u0435 \u0432\u0441\u0435\u0433\u043E \u043C\u0438\u0440\u0430 \u0432\u043D\u0443\u0442\u0440\u0438 \u0437\u0430\u043F\u0440\u0435\u0434\u0435\u043B\u044C\u043D\u043E\u0433\u043E \u0431\u044B\u0442\u0438\u044F.</p><p class="eng">\xAB\u041A\u0440\u0430\u043C\u043E\u0439\xBB \u0436\u0435 \u043D\u0430\u0437\u044B\u0432\u0430\u0435\u0442\u0441\u044F \u043F\u0440\u0438\u0447\u0438\u043D\u0430 \u043F\u043E\u0441\u043B\u0435\u0434\u043E\u0432\u0430\u0442\u0435\u043B\u044C\u043D\u043E\u0439 \u043C\u0430\u043D\u0438\u0444\u0435\u0441\u0442\u0430\u0446\u0438\u0438 \u0442\u0432\u043E\u0440\u0435\u043D\u0438\u044F \u0438 \u0442. \u0434., \u0430 \u0442\u0430\u043A\u0436\u0435 \u0441\u0430\u043C\u0430 \u043F\u0440\u0438\u0440\u043E\u0434\u0430 \u044D\u0442\u043E\u0439 \u043F\u043E\u0441\u043B\u0435\u0434\u043E\u0432\u0430\u0442\u0435\u043B\u044C\u043D\u043E\u0441\u0442\u0438.</p><p class="eng">\u0422\u0435\u043F\u0435\u0440\u044C [\u0430\u0432\u0442\u043E\u0440] \u0440\u0430\u0441\u0441\u043A\u0430\u0437\u044B\u0432\u0430\u0435\u0442 \u043E \u043F\u043B\u043E\u0434\u0430\u0445 \u0434\u043E\u0441\u0442\u0438\u0436\u0435\u043D\u0438\u044F \u044D\u0442\u043E\u0433\u043E \u0441\u0430\u043C\u0430\u0434\u0445\u0438:</p></div><div class="stanza"><a href="#s20" id="s20" class="num">20</a><p class="sans">\u0924\u0926\u093E \u092A\u094D\u0930\u0915\u093E\u0936\u093E\u0928\u0928\u094D\u0926\u0938\u093E\u0930\u092E\u0939\u093E\u092E\u0928\u094D\u0924\u094D\u0930\u0935\u0940\u0930\u094D\u092F\u093E\u0924\u094D\u092E\u0915\u092A\u0942\u0930\u094D\u0923\u093E\u0939\u0928\u094D\u0924\u093E\u0935\u0947\u0936\u093E\u0924\u094D\u0938\u0926\u093E \u0938\u0930\u094D\u0935\u0938\u0930\u094D\u0917\u0938\u0902\u0939\u093E\u0930\u0915\u093E\u0930\u093F\u0928\u093F\u091C\u0938\u0902\u0935\u093F\u0926\u094D\u0926\u0947\u0935\u0924\u093E\u091A\u0915\u094D\u0930\u0947\u0936\u094D\u0935\u0930\u0924\u093E\u092A\u094D\u0930\u093E\u092A\u094D\u0924\u093F\u0930\u094D\u092D\u0935\u0924\u0940\u0924\u093F \u0936\u093F\u0935\u092E\u094D \u0965\u0968\u0966\u0965</p><p class="trans">Tad\u0101 prak\u0101\u015B\u0101nandas\u0101ramah\u0101mantrav\u012Bry\u0101tmakap\u016Br\u1E47\u0101hant\u0101ve\u015B\u0101tsad\u0101 sarvasargasa\u1E41h\u0101rak\u0101rinijasa\u1E41viddevat\u0101cakre\u015Bvarat\u0101pr\u0101ptirbhavat\u012Bti \u015Bivam \u096520\u0965</p><p>\u0422\u043E\u0433\u0434\u0430 <em>(tad\u0101)</em>, \u043F\u0440\u0438 \u0432\u0441\u0442\u0443\u043F\u043B\u0435\u043D\u0438\u0438 <em>(ve\u015B\u0101t)</em> \u0432 \u0441\u043E\u0432\u0435\u0440\u0448\u0435\u043D\u043D\u043E\u0435 <em>(p\u016Br\u1E47a)</em> \u042F <em>(ahant\u0101)</em>, \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u044C\u044E <em>(s\u0101ra)</em> [\u043A\u043E\u0442\u043E\u0440\u043E\u0433\u043E] \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0431\u043B\u0430\u0436\u0435\u043D\u0441\u0442\u0432\u043E <em>(\u0101nanda)</em> \u0421\u0432\u0435\u0442\u0430 \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F <em>(prak\u0101\u015Ba)</em>, \u0430 \u043F\u0440\u0438\u0440\u043E\u0434\u043E\u0439 <em>(\u0101tmaka)</em> \u2013 \u0432\u0435\u043B\u0438\u043A\u0430\u044F <em>(mah\u0101)</em> \u044D\u043D\u0435\u0440\u0433\u0438\u044F <em>(v\u012Brya)</em> \u043C\u0430\u043D\u0442\u0440\u044B <em>(mantra)</em>, \u0432\u0441\u0435\u0433\u0434\u0430 <em>(sad\u0101)</em> \u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u0438\u0442 <em>(bhavati)</em> \u043E\u0431\u0440\u0435\u0442\u0435\u043D\u0438\u0435 <em>(pr\u0101pti\u1E25)</em> \u0432\u043B\u0430\u0434\u044B\u0447\u0435\u0441\u0442\u0432\u0430 <em>(\u012B\u015Bvarat\u0101)</em> \u043D\u0430\u0434 \u043A\u0440\u0443\u0433\u043E\u043C <em>(cakra)</em> \u0431\u043E\u0436\u0435\u0441\u0442\u0432 <em>(devat\u0101)</em> \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0433\u043E <em>(nija)</em> \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F <em>(sa\u1E41vid)</em>, \u0432\u044B\u0437\u044B\u0432\u0430\u044E\u0449\u0438\u0445 <em>(k\u0101ri)</em> \u044D\u043C\u0430\u043D\u0438\u0440\u043E\u0432\u0430\u043D\u0438\u0435 <em>(sarga)</em> \u0438 \u0440\u0430\u0437\u0440\u0443\u0448\u0435\u043D\u0438\u0435 <em>(sa\u1E41h\u0101ra)</em> \u0432\u0441\u0435\u0433\u043E <em>(sarva)</em>, \u0438 \u044D\u0442\u043E \u0428\u0438\u0432\u0430 <em>(iti \u015Bivam)</em>.</p><p class="eng"><strong>\u041A\u043E\u043C\u043C\u0435\u043D\u0442\u0430\u0440\u0438\u0439</strong><br> \xAB\u0421\u0443\u0449\u043D\u043E\u0441\u0442\u044C \u0432\u044B\u0441\u0448\u0435\u0433\u043E \u0431\u043B\u0430\u0436\u0435\u043D\u0441\u0442\u0432\u0430 \u0421\u0432\u0435\u0442\u0430 \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F\xBB \u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442 \u0441\u0433\u0443\u0441\u0442\u043E\u043A \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F \u0438 \u041D\u0430\u0441\u043B\u0430\u0436\u0434\u0435\u043D\u0438\u044F;</p><p class="eng">\xAB\u044D\u043D\u0435\u0440\u0433\u0438\u044F \u0432\u0435\u043B\u0438\u043A\u043E\u0439 \u043C\u0430\u043D\u0442\u0440\u044B\xBB \u2013 \u043E\u0434\u0443\u0448\u0435\u0432\u043B\u044F\u044E\u0449\u0435\u0435 \u043D\u0430\u0447\u0430\u043B\u043E \u0432\u0441\u0435\u0445 \u043C\u0430\u043D\u0442\u0440. \xAB\u0421\u043E\u0432\u0435\u0440\u0448\u0435\u043D\u0441\u0442\u0432\u043E\xBB \u2013 \u044D\u0442\u043E \u0432\u044B\u0441\u0448\u0430\u044F \u0432\u0438\u043C\u0430\u0440\u0448\u0430, \u043A\u043E\u0442\u043E\u0440\u0430\u044F \u0435\u0441\u0442\u044C \xAB\u042F\xBB, \u0438\u043B\u0438 \u0435\u0441\u0442\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0435 \u0431\u043B\u0430\u0436\u0435\u043D\u0441\u0442\u0432\u043E \u0441\u0430\u043C\u043E\u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F. \u0422\u0435\u043C \u0441\u0430\u043C\u044B\u043C \xAB\u043F\u0440\u0438 \u0432\u0441\u0442\u0443\u043F\u043B\u0435\u043D\u0438\u0438\xBB \u2013 \u0442. \u0435. \u043E\u0442 \u041A\u0430\u043B\u0430\u0433\u043D\u0438 \u0434\u043E \u043F\u043E\u0441\u043B\u0435\u0434\u043D\u0435\u0439 \u0441\u0442\u0443\u043F\u0435\u043D\u0438 \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u043E\u0439 \u0434\u043E\u0441\u0442\u0438\u0433\u0430\u0435\u0442\u0441\u044F \u0441\u0442\u0430\u0431\u0438\u043B\u044C\u043D\u043E\u0435 \u0441\u0430\u043C\u0430\u0434\u0445\u0438.</p><p class="eng">\xAB\u042D\u043C\u0430\u043D\u0438\u0440\u043E\u0432\u0430\u043D\u0438\u0435 \u0438 \u0440\u0430\u0437\u0440\u0443\u0448\u0435\u043D\u0438\u0435\xBB \u2013 \u0440\u0430\u0437\u043B\u0438\u0447\u043D\u044B\u0435 [\u0446\u0438\u043A\u043B\u044B] \u0442\u0432\u043E\u0440\u0435\u043D\u0438\u044F \u0438 \u0440\u0430\u0441\u0442\u0432\u043E\u0440\u0435\u043D\u0438\u044F. \u0412\u043E\u0437\u043E\u0431\u043B\u0430\u0434\u0430\u043D\u0438\u0435 \u043D\u0430\u0434 \xAB\u0432\u044B\u0437\u044B\u0432\u0430\u044E\u0449\u0438\u043C\u0438 \u044D\u0442\u043E\xBB, \u0430 \u0438\u043C\u0435\u043D\u043D\u043E \xAB\u043E\u0431\u0440\u0435\u0442\u0435\u043D\u0438\u0435 \u0432\u043B\u0430\u0434\u044B\u0447\u0435\u0441\u0442\u0432\u0430 \u043D\u0430\u0434 \u043A\u0440\u0443\u0433\u043E\u043C \u0431\u043E\u0436\u0435\u0441\u0442\u0432 \u0432\u0435\u0447\u043D\u043E\u0433\u043E \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F\xBB \u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u0438\u0442 \u0443 \u0432\u044B\u0441\u0448\u0438\u0445 \u0439\u043E\u0433\u0438\u043D\u043E\u0432, [\u043E \u043A\u043E\u0442\u043E\u0440\u044B\u0445 \u0437\u0434\u0435\u0441\u044C \u0438] \u0438\u0434\u0435\u0442 \u0440\u0435\u0447\u044C. \u0422\u0430\u043A\u043E\u0432 \u0441\u043C\u044B\u0441\u043B \u0441\u043A\u0430\u0437\u0430\u043D\u043D\u043E\u0433\u043E. \xAB\u042D\u0442\u043E\xBB \u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442 \u0432\u0441\u0435 \u044D\u0442\u043E, \u0438\u043C\u0435\u044E\u0449\u0435\u0435 \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u044C \u0428\u0438\u0432\u044B, \u0442\u0430\u043A\u043E\u0439 [\u0437\u0434\u0435\u0441\u044C \u043C\u043E\u0436\u043D\u043E \u0441\u0434\u0435\u043B\u0430\u0442\u044C] \u0432\u044B\u0432\u043E\u0434.</p><p class="eng">\u0417\u0434\u0435\u0441\u044C \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u044C\u044E \u0442\u043E\u0433\u043E, \u0447\u0442\u043E \u043F\u043E\u0437\u043D\u0430\u0435\u0442\u0441\u044F, \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u043F\u043E\u0437\u043D\u0430\u043D\u0438\u0435. \u0421\u0443\u0449\u043D\u043E\u0441\u0442\u044C\u044E \u0436\u0435 \u043F\u043E\u0437\u043D\u0430\u043D\u0438\u044F \u2013 \u0441\u0443\u0431\u044A\u0435\u043A\u0442\u044B \u043F\u043E\u0437\u043D\u0430\u0432\u0430\u0442\u0435\u043B\u044C\u043D\u043E\u0433\u043E \u043E\u043F\u044B\u0442\u0430, \u043D\u0430\u043F\u0440\u0430\u0432\u043B\u0435\u043D\u043D\u044B\u0435 \u0432\u043D\u0443\u0442\u0440\u044C [\u0441\u0435\u0431\u044F].</p><p class="eng">\u0414\u0430\u043B\u0435\u0435, \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u044C\u044E \u043F\u043E\u0437\u043D\u0430\u0432\u0430\u0442\u0435\u043B\u044C\u043D\u044B\u0445 \u0441\u0443\u0431\u044A\u0435\u043A\u0442\u043E\u0432 \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0421\u0430\u0434\u0430\u0448\u0438\u0432\u0430-\u0418\u0448\u0432\u0430\u0440\u0430, \u0432 \u043A\u043E\u0442\u043E\u0440\u043E\u043C \u0438\u0441\u0447\u0435\u0437\u0430\u044E\u0442 \u0437\u0430\u0431\u043B\u0443\u0436\u0434\u0435\u043D\u0438\u044F \u043E \u0442\u0435\u043B\u0435\u0441\u043D\u043E\u043C \u0438 \u0434\u0440\u0443\u0433\u0438\u0445 [\u044D\u043B\u0435\u043C\u0435\u043D\u0442\u0430\u0445] \u0438 \u0442\u0435\u043B\u043E \u043A\u043E\u0442\u043E\u0440\u043E\u0433\u043E \u0431\u0435\u0441\u043A\u043E\u043D\u0435\u0447\u043D\u043E.</p><p class="eng">\u041D\u0430\u043A\u043E\u043D\u0435\u0446, \u043D\u0430\u0438\u0432\u044B\u0441\u0448\u0435\u0439 \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u044C\u044E \u043F\u043E\u0441\u043B\u0435\u0434\u043D\u0435\u0433\u043E \u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u0441\u044F \u0421\u0430\u043C \u0434\u043E\u0441\u0442\u043E\u0445\u0432\u0430\u043B\u044C\u043D\u044B\u0439 \u0413\u043E\u0441\u043F\u043E\u0434\u044C, \u043F\u0440\u0435\u0438\u0441\u043F\u043E\u043B\u043D\u0435\u043D\u043D\u044B\u0439 \u0431\u043B\u0430\u0436\u0435\u043D\u0441\u0442\u0432\u0430 \u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F \u0442\u043E\u0433\u043E, \u0447\u0442\u043E \u0432\u0435\u0441\u044C \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u043D\u044B\u0439 \u043C\u0438\u0440 \u043F\u0440\u0435\u0434\u0441\u0442\u0430\u0432\u043B\u044F\u0435\u0442 \u0441\u043E\u0431\u043E\u0439 \u0435\u0434\u0438\u043D\u043E\u0435 \u0446\u0435\u043B\u043E\u0435 \u0441\u043E \u0421\u0432\u0435\u0442\u043E\u043C \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F. \u0411\u0435\u0437 \u0432\u0445\u043E\u0436\u0434\u0435\u043D\u0438\u044F \u0432 \u0421\u0432\u0435\u0442 \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F, \u043A\u043E\u0442\u043E\u0440\u044B\u0439 \u0435\u0441\u0442\u044C \u0432\u044B\u0441\u0448\u0430\u044F \u0440\u0435\u0430\u043B\u044C\u043D\u043E\u0441\u0442\u044C, \u043D\u0435\u0442 \u043D\u0438\u043A\u0430\u043A\u043E\u0439 \u043C\u0430\u043D\u0438\u0444\u0435\u0441\u0442\u0430\u0446\u0438\u0438 [\u0432 \u044D\u0442\u043E\u043C \u043C\u0438\u0440\u0435].</p><p class="eng">\u0418 \u0412\u044B\u0441\u0448\u0438\u0439 \u0413\u043E\u0441\u043F\u043E\u0434\u044C \u043F\u043E\u043B\u043E\u043D \u043F\u043E\u0442\u043E\u043A\u0430 \u0431\u043B\u0430\u0436\u0435\u043D\u0441\u0442\u0432\u0430, \u2013 \u0438\u0437-\u0437\u0430 \u0442\u043E\u0433\u043E, \u0447\u0442\u043E \u0415\u0433\u043E \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u044C \u2013 \u0441\u0438\u043B\u0430 \u0441\u0430\u043C\u043E\u0435\u0441\u0442\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0441\u0442\u0438, \u0438\u0437-\u0437\u0430 \u0442\u043E\u0433\u043E, \u0447\u0442\u043E \u041E\u043D \u0430\u0431\u0441\u043E\u043B\u044E\u0442\u043D\u043E \u0441\u043E\u0432\u0435\u0440\u0448\u0435\u043D\u0435\u043D, \u0438\u0437-\u0437\u0430 \u0442\u043E\u0433\u043E, \u0447\u0442\u043E \u041E\u043D \u043B\u0438\u0448\u0435\u043D \u0432\u0441\u0435\u0445 \u0436\u0435\u043B\u0430\u043D\u0438\u0439, \u0438 \u0438\u0437-\u0437\u0430 \u0442\u043E\u0433\u043E, \u0447\u0442\u043E \u041E\u043D \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u0435\u0442 \u0432 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0438 \u0431\u0435\u0441\u043A\u043E\u043D\u0435\u0447\u043D\u043E\u0439 \u0434\u0436\u0430\u0433\u0430\u0434\u0430\u043D\u0430\u043D\u0434\u044B, \u0432 \u043A\u043E\u0442\u043E\u0440\u0443\u044E \u043F\u043E\u0433\u0440\u0443\u0437\u0438\u043B \u0432\u0435\u0441\u044C \u043C\u0438\u0440, \u0441\u043E\u0441\u0442\u043E\u044F\u0449\u0438\u0439 \u0438\u0437 \u043E\u0431\u043E\u0437\u043D\u0430\u0447\u0430\u044E\u0449\u0435\u0433\u043E \u0438 \u043E\u0431\u043E\u0437\u043D\u0430\u0447\u0430\u0435\u043C\u043E\u0433\u043E, [\u043F\u043E\u0433\u0440\u0443\u0437\u0438\u043B] \u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C \u0421\u0438\u043B\u044B \u0420\u0435\u0444\u043B\u0435\u043A\u0441\u0438\u0438, [\u043D\u0430\u043F\u0440\u0430\u0432\u043B\u0435\u043D\u043D\u043E\u0439 \u043D\u0430] \u0441\u043E\u0432\u043E\u043A\u0443\u043F\u043D\u043E\u0441\u0442\u044C \u043D\u0435 \u043E\u0442\u043D\u043E\u0441\u044F\u0449\u0438\u0445\u0441\u044F \u043A \u0446\u0430\u0440\u0441\u0442\u0432\u0443 \u043C\u0430\u0439\u0438 \u0444\u043E\u043D\u0435\u043C \u043E\u0442 \u0410 \u0434\u043E \u041A\u0448\u0430. \u0418 \u043F\u043E\u044D\u0442\u043E\u043C\u0443 \u0432\u0441\u044F \u044D\u0442\u0430 \u0433\u0440\u043E\u043C\u0430\u0434\u043D\u0430\u044F \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u0430\u044F, \u043D\u0430\u0447\u0438\u043D\u0430\u044F \u043E\u0442 \u0431\u0443\u043A\u0432\u044B \u0410, \u043F\u0440\u0438\u0440\u043E\u0434\u0443 \u043A\u043E\u0442\u043E\u0440\u043E\u0439 \u0441\u043E\u0441\u0442\u0430\u0432\u043B\u044F\u0435\u0442 \u043D\u0435\u043F\u0440\u0435\u0432\u0437\u043E\u0439\u0434\u0435\u043D\u043D\u0430\u044F akula, \u0438 \u0437\u0430\u043A\u0430\u043D\u0447\u0438\u0432\u0430\u044F \u0431\u0443\u043A\u0432\u043E\u0439 \u0425\u0430, \u043E\u0431\u043E\u0437\u043D\u0430\u0447\u0430\u044E\u0449\u0435\u0439 \u0440\u0430\u0437\u0432\u0435\u0440\u0442\u044B\u0432\u0430\u043D\u0438\u0435 \u0428\u0430\u043A\u0442\u0438 (\u0431\u0443\u043A\u0432\u0430 \u041A\u0448\u0430 \u043E\u0431\u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442 \u0444\u043E\u0440\u043C\u0443 \u043F\u0440\u0435\u043A\u0440\u0430\u0449\u0435\u043D\u0438\u044F \u044D\u0442\u043E\u0433\u043E \u0440\u0430\u0437\u0432\u0435\u0440\u0442\u044B\u0432\u0430\u043D\u0438\u044F) \u2013 \u0432\u0441\u044F \u043E\u043D\u0430 \u043F\u043E\u043A\u043E\u0438\u0442\u0441\u044F \u0432 \u041D\u0435\u043F\u0440\u0435\u0432\u0437\u043E\u0439\u0434\u0435\u043D\u043D\u043E\u043C \u0432 \u0444\u043E\u0440\u043C\u0435 \u0431\u0438\u043D\u0434\u0443, \u043A\u043E\u0442\u043E\u0440\u044B\u0439 \u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442 \u043D\u0435\u0434\u0438\u0444\u0444\u0435\u0440\u0435\u043D\u0446\u0438\u0440\u043E\u0432\u0430\u043D\u043D\u043E\u0435 \u0441\u043E\u0437\u043D\u0430\u043D\u0438\u0435.</p><p class="eng">\u0422\u0430\u043A\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C, \u044D\u0442\u0430 \u0441\u0430\u043C\u043E\u0435\u0441\u0442\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u0430\u044F \u0421\u0438\u043B\u0430 \u0420\u0435\u0444\u043B\u0435\u043A\u0441\u0438\u0438 \u043D\u0430\u0434\u0435\u043B\u0435\u043D\u0430 \u043F\u0440\u0438\u0440\u043E\u0434\u043E\u0439 \u0441\u043E\u0432\u043E\u043A\u0443\u043F\u043D\u043E\u0441\u0442\u0438 \u0441\u043B\u043E\u0432.</p><p class="eng">\u041A\u0430\u043A \u0441\u043A\u0430\u0437\u0430\u043D\u043E, \xAB\u0443\u0441\u043F\u043E\u043A\u043E\u0435\u043D\u0438\u0435 [\u043C\u0438\u0440\u043E\u0432\u043E\u0433\u043E \u0434\u0432\u0438\u0436\u0435\u043D\u0438\u044F] \u0432 \u0433\u043B\u0443\u0431\u0438\u043D\u0435 \u0421\u0432\u0435\u0442\u0430 \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0431\u044B\u0442\u0438\u0435\u043C \u042F. \u042D\u0442\u043E \u0443\u043F\u043E\u043C\u044F\u043D\u0443\u0442\u043E\u0435 \u0443\u0441\u043F\u043E\u043A\u043E\u0435\u043D\u0438\u0435 \u0435\u0441\u0442\u044C \u0440\u0430\u0437\u0440\u0443\u0448\u0435\u043D\u0438\u0435 \u0432\u0441\u0435\u0445 \u043E\u0442\u043D\u043E\u0448\u0435\u043D\u0438\u0439, \u0438 \u043F\u043E\u044D\u0442\u043E\u043C\u0443 \u043E\u043D\u043E \u0442\u0430\u043A\u0436\u0435 \u0435\u0441\u0442\u044C \u0421\u0430\u043C\u043E\u0435\u0441\u0442\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0441\u0442\u044C, \u0418\u0441\u0442\u043E\u0447\u043D\u0438\u043A \u0434\u0435\u044F\u0442\u0435\u043B\u044C\u043D\u043E\u0441\u0442\u0438, \u0418\u0437\u043D\u0430\u0447\u0430\u043B\u044C\u043D\u043E\u0435 \u0438 \u0412\u043B\u0430\u0434\u044B\u0447\u0435\u0441\u0442\u0432\u043E\xBB.</p><p class="eng">\u042D\u0442\u043E \u0432\u044B\u0441\u0448\u0435\u0435 \u042F \u2013 \u0441\u0442\u0443\u043F\u0435\u043D\u044C \u0432\u0435\u043B\u0438\u043A\u043E\u0433\u043E \u043C\u043E\u0433\u0443\u0449\u0435\u0441\u0442\u0432\u0430: \u0438\u0437 \u043D\u0435\u0435 \u0432\u043E\u0437\u043D\u0438\u043A\u0430\u044E\u0442 \u0438 \u0432 \u043D\u0435\u0439 \u0443\u0441\u043F\u043E\u043A\u0430\u0438\u0432\u0430\u044E\u0442\u0441\u044F \u0432\u0441\u0435 \u043C\u0430\u043D\u0442\u0440\u044B; \u0441 \u043F\u043E\u043C\u043E\u0449\u044C\u044E \u0435\u0435 \u0441\u0438\u043B\u044B \u0432\u043E\u0437\u043C\u043E\u0436\u043D\u043E \u043E\u0441\u0443\u0449\u0435\u0441\u0442\u0432\u043B\u0435\u043D\u0438\u0435 \u043B\u044E\u0431\u044B\u0445 \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0439. \u041E\u0431 \u044D\u0442\u043E\u043C \u0433\u043E\u0432\u043E\u0440\u0438\u0442\u0441\u044F \u0432 \u0428\u0440\u0438 \u0421\u043F\u0430\u043D\u0434\u0435, \u0441\u043E \u0441\u043B\u043E\u0432 \xAB\u043C\u0430\u043D\u0442\u0440\u044B, \u043F\u0440\u0438\u043E\u0431\u0440\u0435\u0442\u0430\u044F \u044D\u0442\u0443 \u0441\u0438\u043B\u0443\u2026\xBB \u0438 \u0434\u043E \u0441\u043B\u043E\u0432 \xAB\u2026 \u044D\u0442\u0438 [\u043C\u0430\u043D\u0442\u0440\u044B] \u043D\u0430\u0434\u0435\u043B\u0435\u043D\u044B \u043F\u0440\u0438\u0437\u043D\u0430\u043A\u0430\u043C\u0438 \u0428\u0438\u0432\u044B\xBB. \u0410 \u0442\u0430\u043A\u0436\u0435 \u0432 \u0428\u0438\u0432\u0430-\u0441\u0443\u0442\u0440\u0430\u0445 : \xAB\u041E\u0442 \u043F\u043E\u0433\u0440\u0443\u0436\u0435\u043D\u0438\u044F \u0432 \u0412\u0435\u043B\u0438\u043A\u043E\u0435 \u043E\u0437\u0435\u0440\u043E \u2013 \u043E\u0431\u0440\u0435\u0442\u0435\u043D\u0438\u0435 \u0441\u0438\u043B\u044B \u043C\u0430\u043D\u0442\u0440\xBB.</p><p class="eng">\u0417\u0434\u0435\u0441\u044C \xAB\u0432\u0445\u043E\u0436\u0434\u0435\u043D\u0438\u0435\xBB \u0432 \u0432\u044B\u0441\u0448\u0435\u0435 \u042F, \u0438\u043C\u0435\u044E\u0449\u0435\u0435 \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u044C \u0441\u0438\u043B\u044B \u0432\u0435\u043B\u0438\u043A\u043E\u0439 \u043C\u0430\u043D\u0442\u0440\u044B, \u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442 \u0441\u043E\u0435\u0434\u0438\u043D\u0435\u043D\u0438\u0435 \u0441 \u043D\u0438\u043C \u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C \u0440\u0430\u0441\u0442\u0432\u043E\u0440\u0435\u043D\u0438\u044F [\u0432 \u043D\u0435\u043C] \u0442\u0435\u043B\u0430, \u043F\u0440\u0430\u043D\u044B \u0438 \u0442. \u0434., \u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C \u0443\u0441\u0442\u043E\u0439\u0447\u0438\u0432\u043E\u0441\u0442\u0438 \u0432 \u0434\u043E\u0441\u0442\u0438\u0436\u0435\u043D\u0438\u0438 \u044D\u0442\u043E\u0439 \u0441\u0442\u0443\u043F\u0435\u043D\u0438, \u0430 \u0442\u0430\u043A\u0436\u0435 \u0431\u043B\u0430\u0433\u043E\u0434\u0430\u0440\u044F \u043F\u043E\u0433\u0440\u0443\u0436\u0435\u043D\u0438\u044E \u0432 \u0441\u0430\u043C\u0443 \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u044C [\u042F \u043E\u0449\u0443\u0449\u0435\u043D\u0438\u0439 \u043E\u0442 \u0441\u0432\u043E\u0435\u0433\u043E] \u0442\u0435\u043B\u0430, \u0432\u043D\u0435\u0448\u043D\u0435\u0433\u043E \u0447\u0443\u0432\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0433\u043E \u043E\u043F\u044B\u0442\u0430 \u0438 \u0442. \u043F.</p><p class="eng">\u041F\u043E\u044D\u0442\u043E\u043C\u0443 \u0432\u043E \u0432\u0441\u0435\u0445 \u0441\u043B\u0443\u0447\u0430\u044F\u0445, [\u043A\u043E\u0433\u0434\u0430] \u0443 \u043A\u043E\u0433\u043E-\u0442\u043E \u0432\u043E\u0437\u043D\u0438\u043A\u0430\u0435\u0442 [\u043E\u0449\u0443\u0449\u0435\u043D\u0438\u0435] \u0442\u0435\u043B\u0430, [\u043F\u0435\u0440\u0435\u0436\u0438\u0432\u0430\u043D\u0438\u044F] \u0432\u043D\u0435\u0448\u043D\u0435\u0433\u043E \u0438\u043B\u0438 \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0435\u0433\u043E \u0438 \u0442. \u0434., [\u043A\u043E\u0433\u0434\u0430] \u043E\u043D [\u0447\u0442\u043E-\u0442\u043E] \u043F\u0440\u0435\u0434\u0441\u0442\u0430\u0432\u043B\u044F\u0435\u0442, [\u043E \u0447\u0435\u043C-\u0442\u043E] \u0432\u0441\u043F\u043E\u043C\u0438\u043D\u0430\u0435\u0442 \u0438\u043B\u0438 [\u043D\u0435\u0447\u0442\u043E] \u0430\u043D\u0430\u043B\u0438\u0437\u0438\u0440\u0443\u0435\u0442, \u2013 [\u0432\u0441\u0435\u0433\u0434\u0430] \u0434\u0435\u0439\u0441\u0442\u0432\u0443\u0435\u0442 \u0432\u0438\u0431\u0440\u0438\u0440\u0443\u044E\u0449\u0430\u044F \u0431\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u0430\u044F \u0427\u0438\u0442\u0438-\u0448\u0430\u043A\u0442\u0438, \u043E\u0441\u043D\u043E\u0432\u0430 \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u043E\u0433\u043E [\u043E\u043F\u044B\u0442\u0430].</p><p class="eng">\u0418 \u043A\u0430\u043A [\u0441\u043F\u0440\u0430\u0432\u0435\u0434\u043B\u0438\u0432\u043E] \u0433\u043E\u0432\u043E\u0440\u044F\u0442, \xAB\u0431\u0435\u0437 \u0435\u0435 \u0432\u0438\u0431\u0440\u0438\u0440\u0443\u044E\u0449\u0435\u0433\u043E \u0434\u0432\u0438\u0436\u0435\u043D\u0438\u044F \u0432\u043E\u043E\u0431\u0449\u0435 \u043D\u0438\u0447\u0435\u0433\u043E \u043D\u0435 \u0434\u0432\u0438\u0436\u0435\u0442\u0441\u044F\xBB.</p><p class="eng">\u0422\u043E\u043B\u044C\u043A\u043E \u0442\u043E\u0433\u0434\u0430, \u043A\u043E\u0433\u0434\u0430 \u043E\u043D\u0430 \u0434\u0432\u0438\u0436\u0435\u0442\u0441\u044F \u0442\u0430\u043A\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C, \u043E\u043D\u0430 \u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C \u044D\u0442\u043E\u0439 \u043C\u0430\u0439\u044F-\u0448\u0430\u043A\u0442\u0438 \u043A\u0430\u043A \u0431\u044B \u043F\u0440\u0438\u0441\u0432\u0430\u0438\u0432\u0430\u0435\u0442 \u0442\u0443 \u0438\u043B\u0438 \u0438\u043D\u0443\u044E \u0444\u043E\u0440\u043C\u0443, \u043F\u043E \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u043C\u0443 \u0436\u0435\u043B\u0430\u043D\u0438\u044E \u0440\u0430\u0441\u0441\u043C\u0430\u0442\u0440\u0438\u0432\u0430\u044F \u0441\u0435\u0431\u044F \u043A\u0430\u043A \u0442\u0435\u043B\u043E, \u043A\u0430\u043A \u0432\u043D\u0435\u0448\u043D\u0438\u0435 \u043E\u0431\u044A\u0435\u043A\u0442\u044B \u0438 \u0442. \u043F.</p><p class="eng">\u0410 \u0441\u0443\u0431\u044A\u0435\u043A\u0442\u044B \u043C\u0430\u0439\u0438 \u043F\u0440\u0438\u043D\u0438\u043C\u0430\u044E\u0442 \u0435\u0435 [\u0434\u0432\u0438\u0436\u0435\u043D\u0438\u0435] \u0437\u0430 [\u043F\u0440\u043E\u0446\u0435\u0441\u0441] \u043F\u043E\u0437\u043D\u0430\u043D\u0438\u044F, \u043F\u0440\u0435\u0434\u0441\u0442\u0430\u0432\u043B\u0435\u043D\u0438\u0435, \u0443\u043C\u043E\u0437\u0430\u043A\u043B\u044E\u0447\u0435\u043D\u0438\u0435, \u0438 \u0442. \u043F.</p><p class="eng">\u0412 \u0440\u0435\u0430\u043B\u044C\u043D\u043E\u0441\u0442\u0438 \u0436\u0435 \u044D\u0442\u0430 \u0427\u0438\u0442\u0438-\u0448\u0430\u043A\u0442\u0438 [\u0432\u0441\u0435\u0433\u0434\u0430] \u043E\u0434\u043D\u0430 \u0438 \u0442\u0430 \u0436\u0435.</p><p class="eng">\u041A\u0430\u043A \u0441\u043A\u0430\u0437\u0430\u043D\u043E, \xAB\u0442\u043E \u0441\u0430\u043C\u043E\u0435 \u0441\u043E\u0437\u043D\u0430\u043D\u0438\u0435, \u043A\u043E\u0442\u043E\u0440\u043E\u0435 \u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u0441\u044F \u043E\u0434\u043D\u0438\u043C \u0446\u0435\u043B\u044B\u043C \u0441 \u0447\u0435\u0440\u0435\u0434\u043E\u0439 \u0440\u0430\u0437\u043B\u0438\u0447\u043D\u044B\u0445 \u043E\u0431\u044A\u0435\u043A\u0442\u043E\u0432, \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0412\u0435\u043B\u0438\u043A\u0438\u043C \u0413\u043E\u0441\u043F\u043E\u0434\u043E\u043C, \u0412\u044B\u0441\u0448\u0438\u043C \u0421\u0443\u0431\u044A\u0435\u043A\u0442\u043E\u043C \u043F\u043E\u0437\u043D\u0430\u043D\u0438\u044F, \u0438\u043C\u0435\u044E\u0449\u0438\u043C \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u044C \u0432\u0435\u0447\u043D\u043E\u0433\u043E, \u0431\u0435\u0441\u043A\u043E\u043D\u0435\u0447\u043D\u043E\u0433\u043E \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F\xBB.</p><p class="eng">\u0410 \u0442\u0430\u043A\u0436\u0435 [\u0431\u044B\u043B\u043E \u0441\u043A\u0430\u0437\u0430\u043D\u043E, \u0447\u0442\u043E] \xAB\u0431\u043B\u0430\u0433\u043E\u0434\u0430\u0440\u044F \u043C\u0430\u0439\u044F-\u0448\u0430\u043A\u0442\u0438 \u0411\u043E\u0433\u0430 \u043E\u043D\u043E (\u0441\u043E\u0437\u043D\u0430\u043D\u0438\u0435 \u2013 \u0421. \u041F.) \u043E\u0431\u044A\u0435\u0434\u0438\u043D\u044F\u0435\u0442\u0441\u044F \u0441 \u0440\u0430\u0437\u043B\u0438\u0447\u043D\u044B\u043C\u0438 \u043F\u043E\u0437\u043D\u0430\u0432\u0430\u0435\u043C\u044B\u043C\u0438 \u043E\u0431\u044A\u0435\u043A\u0442\u0430\u043C\u0438, [\u0438 \u044D\u0442\u043E\u0442 \u043F\u0440\u043E\u0446\u0435\u0441\u0441] \u043D\u0430\u0437\u044B\u0432\u0430\u0435\u0442\u0441\u044F \u043F\u043E-\u0440\u0430\u0437\u043D\u043E\u043C\u0443: \u043F\u043E\u0437\u043D\u0430\u043D\u0438\u0435\u043C, \u043F\u0440\u0435\u0434\u0441\u0442\u0430\u0432\u043B\u0435\u043D\u0438\u0435\u043C, \u0443\u043C\u043E\u0437\u0430\u043A\u043B\u044E\u0447\u0435\u043D\u0438\u0435\u043C \u0438 \u0442. \u0434.\xBB.</p><p class="eng">\u0418\u0442\u0430\u043A, \u0432\u043E \u0432\u0441\u0435\u0445 \u0441\u0438\u0442\u0443\u0430\u0446\u0438\u044F\u0445 \u043E\u0431\u043D\u0430\u0440\u0443\u0436\u0438\u0432\u0430\u0435\u0442\u0441\u044F \u043E\u0434\u043D\u0430 \u0438 \u0442\u0430 \u0436\u0435 \u0427\u0438\u0442\u0438-\u0448\u0430\u043A\u0442\u0438. \u0415\u0441\u043B\u0438 \u043E\u043D\u0430 \u043E\u0431\u0440\u0435\u0442\u0430\u0435\u0442\u0441\u044F \u0447\u0435\u0440\u0435\u0437 \u0441\u043B\u0435\u0434\u043E\u0432\u0430\u043D\u0438\u0435 \u0437\u0430 \u043D\u0435\u0439 \u0438 \u0442\u0432\u0435\u0440\u0434\u043E\u0435 \u0441\u043E\u0441\u0440\u0435\u0434\u043E\u0442\u043E\u0447\u0435\u043D\u0438\u0435 \u043D\u0430 \u043D\u0435\u0435, \u0442\u043E\u0433\u0434\u0430, \u0447\u0435\u0440\u0435\u0437 \u0432\u0445\u043E\u0436\u0434\u0435\u043D\u0438\u0435 \u0432 \u043D\u0435\u0435, \u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C \u0432\u044B\u0448\u0435\u043E\u043F\u0438\u0441\u0430\u043D\u043D\u043E\u0433\u043E \u0441\u043F\u043E\u0441\u043E\u0431\u0430, \u0442. \u0435. \u043F\u043E\u0441\u043B\u0435\u0434\u043E\u0432\u0430\u0442\u0435\u043B\u044C\u043D\u044B\u043C \u043E\u0442\u043A\u0440\u044B\u0432\u0430\u043D\u0438\u0435\u043C \u0438 \u0437\u0430\u043A\u0440\u044B\u0432\u0430\u043D\u0438\u0435\u043C \u043E\u0440\u0433\u0430\u043D\u043E\u0432 \u0447\u0443\u0432\u0441\u0442\u0432, \u0438\u0437-\u0437\u0430 \u0442\u043E\u0433\u043E, \u0447\u0442\u043E \u0432\u0441\u0435 \u0441\u043E\u0441\u0442\u043E\u0438\u0442 \u0438\u0437 \u0432\u0441\u0435\u0433\u043E, \u0434\u0430\u0436\u0435 \u0442\u043E\u0433\u0434\u0430, \u043A\u043E\u0433\u0434\u0430 \u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u0438\u0442 \u043F\u043E\u0433\u043B\u043E\u0449\u0435\u043D\u0438\u0435 \u0438 \u0442. \u043F. \u0440\u0435\u0430\u043B\u044C\u043D\u043E\u0441\u0442\u0438, \u0432\u044B\u0441\u0448\u0438\u0439 \u0439\u043E\u0433\u0438\u043D \u043E\u0431\u0440\u0435\u0442\u0430\u0435\u0442 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435 \u041F\u0430\u0440\u0430\u0431\u0445\u0430\u0439\u0440\u0430\u0432\u044B \u0438 \xAB\u0432\u043B\u0430\u0434\u044B\u0447\u0435\u0441\u0442\u0432\u043E\xBB \u043D\u0430\u0434 \xAB\u043A\u0440\u0443\u0433\u043E\u043C \u0431\u043E\u0436\u0435\u0441\u0442\u0432 \u0432\u0435\u0447\u043D\u043E\u0433\u043E \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F\xBB, \u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u0432\u0441\u0435\u0433\u0434\u0430 \xAB\u0432\u044B\u0437\u044B\u0432\u0430\u044E\u0442 \u044D\u043C\u0430\u043D\u0438\u0440\u043E\u0432\u0430\u043D\u0438\u0435 \u0438 \u0440\u0430\u0437\u0440\u0443\u0448\u0435\u043D\u0438\u0435 \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u043E\u0439\xBB, \u0432 \u0442\u043E\u043C \u0447\u0438\u0441\u043B\u0435 \u043D\u0430\u0434 [\u0433\u0440\u0443\u043F\u043F\u043E\u0439] \u043D\u0435\u043C\u0430\u0439\u0438\u0447\u0435\u0441\u043A\u0438\u0445 [\u0431\u043E\u0436\u0435\u0441\u0442\u0432] \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0438\u0445 \u0438 \u0432\u043D\u0435\u0448\u043D\u0438\u0445 \u0447\u0443\u0432\u0441\u0442\u0432.</p><p class="eng">[\u0412 \u0421\u043F\u0430\u043D\u0434\u0430\u043A\u0430\u0440\u0438\u043A\u0435 (III. 19)] \u0433\u043E\u0432\u043E\u0440\u0438\u0442\u0441\u044F: \xAB\u041A\u043E\u0433\u0434\u0430 [\u0438\u043D\u0434\u0438\u0432\u0438\u0434] \u0441\u043E\u0441\u0440\u0435\u0434\u043E\u0442\u043E\u0447\u0435\u043D \u0432 \u043E\u0434\u043D\u043E\u043C \u043C\u0435\u0441\u0442\u0435, \u0442\u043E\u0433\u0434\u0430, \u043A\u043E\u043D\u0442\u0440\u043E\u043B\u0438\u0440\u0443\u044F \u043F\u043E\u0433\u043B\u043E\u0449\u0435\u043D\u0438\u0435 \u0438 \u0432\u043E\u0437\u043D\u0438\u043A\u043D\u043E\u0432\u0435\u043D\u0438\u0435 (\u0435\u0433\u043E), \u043E\u043D \u0434\u043E\u0441\u0442\u0438\u0433\u0430\u0435\u0442 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F [\u043F\u043E\u0434\u043B\u0438\u043D\u043D\u043E\u0439] \u0441\u0443\u0431\u044A\u0435\u043A\u0442\u0438\u0432\u043D\u043E\u0441\u0442\u0438 \u0438 \u0442\u0435\u043C \u0441\u0430\u043C\u044B\u043C \u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u0441\u044F \u0433\u043E\u0441\u043F\u043E\u0434\u0438\u043D\u043E\u043C \u0447\u0430\u043A\u0440\u044B \xBB. \u0417\u0434\u0435\u0441\u044C \xAB\u043E\u0434\u043D\u043E \u043C\u0435\u0441\u0442\u043E\xBB \u043E\u0431\u044A\u044F\u0441\u043D\u044F\u0435\u0442\u0441\u044F [\u0432 \u0421\u043F\u0430\u043D\u0434\u0430\u043A\u0430\u0440\u0438\u043A\u0435, III. 12]: \xAB\u0412\u0441\u0435 \u0434\u043E\u043B\u0436\u043D\u043E \u0431\u044B\u0442\u044C \u0441\u0432\u0435\u0434\u0435\u043D\u043E \u043A \u043E\u0434\u043D\u043E\u043C\u0443 \u043C\u0435\u0441\u0442\u0443\xBB. [\u042D\u0442\u043E\u0442 \u0442\u0435\u0440\u043C\u0438\u043D ] \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u043F\u043E\u043D\u0438\u043C\u0430\u0442\u044C \u043A\u0430\u043A [\u043E\u0431\u043E\u0437\u043D\u0430\u0447\u0435\u043D\u0438\u0435] \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F \u043E\u0431\u0449\u0435\u0439 \u0432\u0438\u0431\u0440\u0430\u0446\u0438\u0438 \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F, \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435, \u0438\u043C\u0435\u044E\u0449\u0435\u0435 \u0444\u043E\u0440\u043C\u0443 \u0443\u043D\u043C\u0435\u0448\u0438. \u0422\u043E\u0433\u0434\u0430 \u0432\u044B\u0448\u0435\u0443\u043F\u043E\u043C\u044F\u043D\u0443\u0442\u043E\u0435 \u0441\u043B\u043E\u0432\u043E \xAB\u0435\u0433\u043E\xBB \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0438\u043D\u0442\u0435\u0440\u043F\u0440\u0435\u0442\u0438\u0440\u043E\u0432\u0430\u0442\u044C \u043A\u0430\u043A \xAB\u0442\u043E\u043D\u043A\u043E\u0435 \u0442\u0435\u043B\u043E\xBB, \u2013 \u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u0438 \u0434\u0440\u0443\u0433\u043E\u0439 \u043F\u0430\u0441\u0441\u0430\u0436 [\u0421\u043F\u0430\u043D\u0434\u0430\u043A\u0430\u0440\u0438\u043A\u0438] \u043D\u0430\u0447\u0438\u043D\u0430\u0435\u0442\u0441\u044F \u0441\u043E \u0441\u043B\u043E\u0432 \xAB\u0443\u0434\u0435\u0440\u0436\u0430\u043D\u043D\u044B\u0439 \u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C \u0442\u043E\u043D\u043A\u043E\u0433\u043E \u0442\u0435\u043B\u0430\u2026\xBB, \u2013 \u0430 \u043D\u0435 \u0441\u043B\u0435\u0434\u043E\u0432\u0430\u0442\u044C \u0438\u0441\u0442\u043E\u043B\u043A\u043E\u0432\u0430\u043D\u0438\u044E, \u043F\u0440\u0435\u0434\u043B\u043E\u0436\u0435\u043D\u043D\u043E\u043C\u0443 [\u0430\u0432\u0442\u043E\u0440\u043E\u043C \u043A\u043E\u043C\u043C\u0435\u043D\u0442\u0430\u0440\u0438\u044F] \u0412\u0438\u0432\u0430\u0440\u0430\u043D\u0430: \xAB\xBB\u0432 \u043E\u0434\u043D\u043E\u043C \u043C\u0435\u0441\u0442\u0435\xBB \u2013 \u0442. \u0435. \u0432 \u0442\u043E\u043D\u043A\u043E\u043C \u0438\u043B\u0438 \u043F\u043B\u043E\u0442\u043D\u043E\u043C \u0442\u0435\u043B\u0435 \xBB.</p><p class="eng">\u0418 \u043A\u0430\u043A \u044F \u043F\u0438\u0441\u0430\u043B \u0432 \u0433\u0438\u043C\u043D\u0435: \xAB\u0422\u043E\u0433\u043E, \u043A\u0442\u043E \u0441\u0442\u0430\u043B \u043D\u0435\u0437\u0430\u0432\u0438\u0441\u0438\u043C\u044B\u043C \u0432\u043B\u0430\u0441\u0442\u0435\u043B\u0438\u043D\u043E\u043C \u0427\u0438\u0442\u0438-\u0447\u0430\u043A\u0440\u044B \u0438 \u0432\u0435\u043B\u0438\u043A\u0438\u043C \u0413\u043E\u0441\u043F\u043E\u0434\u043E\u043C, \u043E\u0432\u043B\u0430\u0434\u0435\u0432\u0448\u0438\u043C \u0433\u0440\u0443\u043F\u043F\u043E\u0439 \u0431\u043E\u0436\u0435\u0441\u0442\u0432 \u0447\u0443\u0432\u0441\u0442\u0432, \u043D\u0438\u043A\u0442\u043E \u043D\u0435 \u043C\u043E\u0436\u0435\u0442 \u043F\u0440\u0435\u0432\u0437\u043E\u0439\u0442\u0438\xBB.</p><p class="eng">\u0421\u043B\u043E\u0432\u043E \xAB\u0438\u0442\u0438\xBB [\u0432 \u0441\u0443\u0442\u0440\u0435 \u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442] \u0432\u044B\u0432\u043E\u0434. \u0412\u0441\u0435 \u0442\u0435\u043B\u043E \u0432\u044B\u0448\u0435\u043F\u0440\u0438\u0432\u0435\u0434\u0435\u043D\u043D\u043E\u0439 [\u0441\u0443\u0442\u0440\u044B] \u0435\u0441\u0442\u044C \xAB\u0428\u0438\u0432\u0430\xBB, \u043F\u043E\u0442\u043E\u043C\u0443 \u0447\u0442\u043E \u043E\u043D\u043E \u2013 \u0438\u0441\u0442\u043E\u0447\u043D\u0438\u043A \u0434\u043E\u0441\u0442\u0438\u0436\u0435\u043D\u0438\u044F [\u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F] \u0428\u0438\u0432\u044B; \u043F\u043E\u0442\u043E\u043C\u0443 \u0447\u0442\u043E \u043E\u043D\u043E \u2014 \u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u0438\u0442 \u043E\u0442 \u0428\u0438\u0432\u044B; \u043F\u043E\u0442\u043E\u043C\u0443 \u0447\u0442\u043E \u043E\u043D\u043E \u2014 \u043D\u0435 \u043E\u0442\u043B\u0438\u0447\u0430\u0435\u0442\u0441\u044F \u043E\u0442 \u0438\u0441\u0442\u0438\u043D\u043D\u043E\u0439 \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u0438 \u0428\u0438\u0432\u044B; \u043F\u043E\u0442\u043E\u043C\u0443 \u0447\u0442\u043E \u043E\u043D\u043E \u2014 \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0442\u0435\u043B\u044C\u043D\u043E \u0438\u043C\u0435\u0435\u0442 \u0444\u043E\u0440\u043C\u0443 \u0428\u0438\u0432\u044B.</p><p class="eng">\u0427\u0435\u043B\u043E\u0432\u0435\u043A, \u0438\u0441\u043F\u044B\u0442\u044B\u0432\u0430\u044E\u0449\u0438\u0439 \u043F\u043E\u0441\u0442\u043E\u044F\u043D\u043D\u044B\u0435 \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u0438\u044F \u0438\u0437-\u0437\u0430 \u0442\u0435\u043B\u0430, \u0436\u0438\u0437\u043D\u0435\u043D\u043D\u043E\u0441\u0442\u0438, \u0443\u0434\u043E\u0432\u043E\u043B\u044C\u0441\u0442\u0432\u0438\u0439 \u0438 \u0442. \u0434., \u043D\u0435 \u0443\u0437\u043D\u0430\u0435\u0442 \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u0443\u044E \u0413\u043E\u0441\u043F\u043E\u0436\u0443 \u0427\u0438\u0442\u0438, \u0438\u0441\u043F\u043E\u043B\u043D\u0435\u043D\u043D\u0443\u044E \u0432\u044B\u0441\u0448\u0435\u0433\u043E \u0431\u043B\u0430\u0436\u0435\u043D\u0441\u0442\u0432\u0430. \u0422\u043E\u043B\u044C\u043A\u043E \u0442\u043E\u0433\u043E, \u043A\u0442\u043E \u0431\u043B\u0430\u0433\u043E\u0434\u0430\u0440\u044F [\u043C\u043E\u0435\u043C\u0443] \u043D\u0430\u0441\u0442\u0430\u0432\u043B\u0435\u043D\u0438\u044E \u0432\u0438\u0434\u0438\u0442 \u0432\u0435\u0437\u0434\u0435 \u0432 \u043E\u043A\u0435\u0430\u043D\u0435 \u043D\u0435\u043A\u0442\u0430\u0440\u0430 \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u0443\u044E \u043A\u0430\u043A \u043C\u0430\u0441\u0441\u0443 [\u043E\u043A\u0435\u0430\u043D\u0441\u043A\u043E\u0439] \u043F\u0435\u043D\u044B, \u043C\u043E\u0436\u043D\u043E \u043D\u0430\u0437\u0432\u0430\u0442\u044C \u0428\u0438\u0432\u043E\u0439. \u042D\u0442\u043E \u043D\u0430\u0441\u0442\u0430\u0432\u043B\u0435\u043D\u0438\u0435, \u043F\u043E\u0438\u0441\u0442\u0438\u043D\u0435, [\u043F\u0440\u0435\u0434\u043D\u0430\u0437\u043D\u0430\u0447\u0435\u043D\u043E] \u0434\u043B\u044F \u0442\u0435\u0445, \u043A\u043E\u0442\u043E\u0440\u044B\u0435, \u0445\u043E\u0442\u044F \u043E\u043D\u0438 \u0438 \u043E\u0449\u0443\u0442\u0438\u043B\u0438 \u043D\u0438\u0441\u043F\u043E\u0441\u043B\u0430\u043D\u043D\u044B\u0439 \u043D\u0430 \u043D\u0438\u0445 \u0428\u0438\u0432\u043E\u0439 \u043F\u043E\u0442\u043E\u043A \u0428\u0430\u043A\u0442\u0438, \u043F\u043E \u043F\u0440\u0438\u0447\u0438\u043D\u0435 \u0441\u043B\u0430\u0431\u044B\u0445 \u043D\u0430\u0432\u044B\u043A\u043E\u0432 \u043A \u043B\u043E\u0433\u0438\u0447\u0435\u0441\u043A\u043E\u0439 \u0430\u0440\u0433\u0443\u043C\u0435\u043D\u0442\u0430\u0446\u0438\u0438 \u043D\u0435\u0441\u043F\u043E\u0441\u043E\u0431\u043D\u044B \u043F\u043E\u0441\u0442\u0438\u0447\u044C [\u0443\u0447\u0435\u043D\u0438\u0435] \u043E\u0431 \u0443\u0437\u043D\u0430\u0432\u0430\u043D\u0438\u0438 \u0413\u043E\u0441\u043F\u043E\u0434\u0430.</p></div><p>\u041D\u0430 \u044D\u0442\u043E\u043C [\u0442\u0440\u0430\u043A\u0442\u0430\u0442] \xAB\u0421\u0443\u0449\u043D\u043E\u0441\u0442\u044C \u0423\u0437\u043D\u0430\u0432\u0430\u043D\u0438\u044F\xBB \u0437\u0430\u0432\u0435\u0440\u0448\u0435\u043D.</p><p>\u041D\u0430\u043F\u0438\u0441\u0430\u043B \u043F\u043E\u0447\u0442\u0435\u043D\u043D\u044B\u0439 \u0443\u0447\u0438\u0442\u0435\u043B\u044C \u0420\u0430\u0434\u0436\u0430\u043D\u0430\u043A\u0430 \u041A\u0448\u0435\u043C\u0430\u0440\u0430\u0434\u0436\u0430, \u043F\u0440\u0438\u043F\u0430\u0432\u0448\u0438\u0439 \u043F\u0435\u0440\u0435\u0434 \u043B\u043E\u0442\u043E\u0441\u043E\u0432\u044B\u043C\u0438 \u0441\u0442\u043E\u043F\u0430\u043C\u0438 \u0432\u0435\u043B\u0438\u0447\u0430\u0439\u0448\u0435\u0433\u043E \u0441\u0440\u0435\u0434\u0438 \u0432\u0441\u0435\u0445, \u043A\u0442\u043E \u0443\u0447\u0438\u0442 \u043E \u0412\u0435\u043B\u0438\u043A\u043E\u043C \u0413\u043E\u0441\u043F\u043E\u0434\u0435, \u2013 \u0434\u043E\u0441\u0442\u043E\u043F\u043E\u0447\u0442\u0435\u043D\u043D\u043E\u0433\u043E \u0410\u0431\u0445\u0438\u043D\u0430\u0432\u0430\u0433\u0443\u043F\u0442\u044B.</p><p>\u0414\u0430 \u0431\u0443\u0434\u0435\u0442 \u0431\u043B\u0430\u0433\u043E!</p>',25),c=[n];function t(l,i,r,g,d,v){return e(),s("div",null,c)}var k=a(m,[["render",t]]);export{o as __pageData,k as default};
